INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('parris_harvard_dropout', 'Samuel Parris leaves Harvard without graduating', 'Samuel Parris attended Harvard College but left in 1673 when his father died, to manage the family''s sugar plantation in Barbados. He never graduated, which gave him a merchant''s knowledge of trade but meant he lacked the full classical education of his ministerial peers.', '1673', 'year', 'biographical', 'education', NULL, 'samuel_parris', 'occupational_knowledge_map.md', 'Samuel Parris leaves Harvard without graduating. Samuel Parris attended Harvard College but left in 1673 when his father died, to manage the family''s sugar plantation in Barbados. He never graduated, which gave him a merchant''s knowledge of trade but meant he lacked the full classical education of his ministerial peers.', 'public', '["education","harvard","barbados"]', 'salem_project', 1.0, NULL, 1775266565623, 1775266565623, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('parris_barbados_merchant', 'Parris works as merchant in Barbados then Boston', 'After leaving Harvard, Parris managed a sugar plantation in Barbados, then worked as a merchant in Boston where he owned a wharf and warehouse. He entered the ministry late, driven by commercial failure rather than spiritual calling.', '1673', 'approximate', 'biographical', 'career', NULL, 'samuel_parris', 'occupational_knowledge_map.md', 'Parris works as merchant in Barbados then Boston. After leaving Harvard, Parris managed a sugar plantation in Barbados, then worked as a merchant in Boston where he owned a wharf and warehouse. He entered the ministry late, driven by commercial failure rather than spiritual calling.', 'semi_private', '["barbados","merchant","ministry"]', 'salem_project', 1.0, NULL, 1775266565623, 1775266565623, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('parris_hired_salem_village', 'Samuel Parris hired as Salem Village minister', 'Parris was hired June 18, 1689 at a salary of 66 pounds per year (one-third money, two-thirds provisions). His contract also included the parsonage and firewood. These terms would become a source of bitter dispute.', '1689-06-18', 'exact', 'biographical', 'career', NULL, 'samuel_parris', 'micro_events_daily_chronicle.md', 'Samuel Parris hired as Salem Village minister. Parris was hired June 18, 1689 at a salary of 66 pounds per year (one-third money, two-thirds provisions). His contract also included the parsonage and firewood. These terms would become a source of bitter dispute.', 'public', '["ministry","salary","contract"]', 'salem_project', 1.0, NULL, 1775266565623, 1775266565623, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('parris_marriage_elizabeth_eldridge', 'Parris married to Elizabeth Eldridge, connected to Sewall family', 'Samuel Parris married Elizabeth Eldridge, connecting him to the Sewall family. This gave him a link to Samuel Sewall, who would serve as one of the nine judges on the Court of Oyer and Terminer.', NULL, NULL, 'biographical', 'marriage', NULL, 'samuel_parris', 'occupational_knowledge_map.md', 'Parris married to Elizabeth Eldridge, connected to Sewall family. Samuel Parris married Elizabeth Eldridge, connecting him to the Sewall family. This gave him a link to Samuel Sewall, who would serve as one of the nine judges on the Court of Oyer and Terminer.', 'public', '["marriage","sewall","connections"]', 'salem_project', 1.0, NULL, 1775266565623, 1775266565623, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('thomas_putnam_jr_birth', 'Thomas Putnam Jr. born', 'Thomas Putnam Jr. born 1652 in Salem Village. Son of Thomas Putnam Sr. and his first wife Ann Holyoke. Would become the driving force behind the witch accusations, filing or co-signing complaints against 43+ accused witches.', '1652', 'year', 'biographical', 'birth', NULL, 'thomas_putnam_jr', 'village_names_research.md', 'Thomas Putnam Jr. born. Thomas Putnam Jr. born 1652 in Salem Village. Son of Thomas Putnam Sr. and his first wife Ann Holyoke. Would become the driving force behind the witch accusations, filing or co-signing complaints against 43+ accused witches.', 'public', '["birth","putnam_family"]', 'salem_project', 1.0, NULL, 1775266565623, 1775266565623, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('thomas_putnam_jr_marriage', 'Thomas Putnam Jr. marries Ann Carr', 'Thomas Putnam Jr. married Ann Carr on November 25, 1678. Ann''s family suffered devastating frontier losses — her sister Mary Carr Bailey died in 1688 after her three children died in succession, and her father George Carr disinherited her, leaving the estate to his wife and sons.', '1678-11-25', 'exact', 'biographical', 'marriage', NULL, 'thomas_putnam_jr', 'social_bonds_marriages.md', 'Thomas Putnam Jr. marries Ann Carr. Thomas Putnam Jr. married Ann Carr on November 25, 1678. Ann''s family suffered devastating frontier losses — her sister Mary Carr Bailey died in 1688 after her three children died in succession, and her father George Carr disinherited her, leaving the estate to his wife and sons.', 'public', '["marriage","carr_family","putnam_family"]', 'salem_project', 1.0, NULL, 1775266565623, 1775266565623, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('thomas_putnam_jr_king_philips_war', 'Thomas Putnam Jr. serves in King Philip''s War', 'Thomas Putnam Jr. served in King Philip''s War, obtaining the rank of sergeant. This military experience shaped his worldview and gave him authority in the village. He later filed militia paperwork as parish clerk.', '1675', 'year', 'biographical', 'military', NULL, 'thomas_putnam_jr', 'frontier_war_timeline_research.md', 'Thomas Putnam Jr. serves in King Philip''s War. Thomas Putnam Jr. served in King Philip''s War, obtaining the rank of sergeant. This military experience shaped his worldview and gave him authority in the village. He later filed militia paperwork as parish clerk.', 'public', '["king_philips_war","militia","veteran"]', 'salem_project', 1.0, NULL, 1775266565623, 1775266565623, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('thomas_putnam_jr_inheritance_dispute', 'Thomas Putnam Jr. cheated of inheritance by stepmother', 'When Thomas Putnam Sr. died, his second wife Mary Veren Putnam manipulated the will, diverting the bulk of the estate away from the children of the first marriage. Thomas Jr. received far less than he expected. This grievance fueled decades of resentment and shaped his combative approach to village politics.', NULL, NULL, 'biographical', 'legal', NULL, 'thomas_putnam_jr', 'village_disputes_research.md', 'Thomas Putnam Jr. cheated of inheritance by stepmother. When Thomas Putnam Sr. died, his second wife Mary Veren Putnam manipulated the will, diverting the bulk of the estate away from the children of the first marriage. Thomas Jr. received far less than he expected. This grievance fueled decades of resentment and shaped his combative approach to village politics.', 'semi_private', '["inheritance","grievance","putnam_family"]', 'salem_project', 1.0, NULL, 1775266565623, 1775266565623, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('thomas_putnam_death', 'Thomas Putnam Jr. dies age 47', 'Thomas Putnam Jr. died June 3, 1699, age 47, of an unknown illness. His wife Ann Sr. died just five days later on June 8, 1699, of the same illness. Their children were orphaned; Ann Jr. (19) raised nine younger siblings.', '1699-06-03', 'exact', 'biographical', 'death', NULL, 'thomas_putnam_jr', 'births_deaths_illness_research.md', 'Thomas Putnam Jr. dies age 47. Thomas Putnam Jr. died June 3, 1699, age 47, of an unknown illness. His wife Ann Sr. died just five days later on June 8, 1699, of the same illness. Their children were orphaned; Ann Jr. (19) raised nine younger siblings.', 'public', '["death","orphans","putnam_family"]', 'salem_project', 1.0, NULL, 1775266565623, 1775266565623, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('ann_putnam_sr_losses', 'Ann Putnam Sr.''s devastating personal losses before 1692', 'Ann Putnam Sr. suffered cumulative losses that severely undermined her mental stability: her sister Mary Carr Bailey died in 1688 after her three children died in succession; her father George Carr died and disinherited her, leaving the estate to his wife and sons; and in 1689 she lost an infant daughter.', '1688', 'year', 'biographical', 'grief', NULL, 'ann_putnam_sr', 'births_deaths_illness_research.md', 'Ann Putnam Sr.''s devastating personal losses before 1692. Ann Putnam Sr. suffered cumulative losses that severely undermined her mental stability: her sister Mary Carr Bailey died in 1688 after her three children died in succession; her father George Carr died and disinherited her, leaving the estate to his wife and sons; and in 1689 she lost an infant daughter.', 'semi_private', '["grief","death","mental_health","carr_family"]', 'salem_project', 1.0, NULL, 1775266565624, 1775266565624, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('ann_putnam_sr_death', 'Ann Putnam Sr. dies five days after husband Thomas', 'Ann Putnam Sr. died June 8, 1699, of the same unknown illness that killed her husband Thomas Jr. five days earlier on June 3. Their daughter Ann Jr. (age 19) was left to raise nine younger siblings alone.', '1699-06-08', 'exact', 'biographical', 'death', NULL, 'ann_putnam_sr', 'births_deaths_illness_research.md', 'Ann Putnam Sr. dies five days after husband Thomas. Ann Putnam Sr. died June 8, 1699, of the same unknown illness that killed her husband Thomas Jr. five days earlier on June 3. Their daughter Ann Jr. (age 19) was left to raise nine younger siblings alone.', 'public', '["death","orphans"]', 'salem_project', 1.0, NULL, 1775266565624, 1775266565624, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('ann_putnam_jr_apology', 'Ann Putnam Jr. publicly apologizes for her role as accuser', 'On August 25, 1706, Ann Putnam Jr. stood in the Salem Village meetinghouse while Rev. Joseph Green read her apology aloud. She was the only accuser to ever publicly apologize. She declared she had acted ''ignorantly'' and asked forgiveness, stating she ''desired to lie in the dust'' and be ''humbled for it.'' She had been raising her nine younger siblings alone since her parents'' deaths in 1699.', '1706-08-25', 'exact', 'biographical', 'aftermath', NULL, 'ann_putnam_jr', 'micro_events_daily_chronicle.md', 'Ann Putnam Jr. publicly apologizes for her role as accuser. On August 25, 1706, Ann Putnam Jr. stood in the Salem Village meetinghouse while Rev. Joseph Green read her apology aloud. She was the only accuser to ever publicly apologize. She declared she had acted ''ignorantly'' and asked forgiveness, stating she ''desired to lie in the dust'' and be ''humbled for it.'' She had been raising her nine younger siblings alone since her parents'' deaths in 1699.', 'public', '["apology","aftermath","accuser"]', 'salem_project', 1.0, NULL, 1775266565624, 1775266565624, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('philip_english_birth_jersey', 'Philip English born Philippe d''Anglois on Isle of Jersey', 'Philip English was born Philippe d''Anglois (sometimes rendered L''Anglois or L''Anglais) on the Isle of Jersey, the largest of the Channel Islands, likely around 1651. Jersey was a Crown dependency — technically English territory but geographically just off the coast of Normandy, France, and culturally Franco-Norman. His name literally means ''the Englishman'' in French.', '1651', 'approximate', 'biographical', 'origin', NULL, 'philip_english', 'philip_english_merchant_research.md', 'Philip English born Philippe d''Anglois on Isle of Jersey. Philip English was born Philippe d''Anglois (sometimes rendered L''Anglois or L''Anglais) on the Isle of Jersey, the largest of the Channel Islands, likely around 1651. Jersey was a Crown dependency — technically English territory but geographically just off the coast of Normandy, France, and culturally Franco-Norman. His name literally means ''the Englishman'' in French.', 'public', '["birth","french","jersey","channel_islands"]', 'salem_project', 1.0, NULL, 1775266565624, 1775266565624, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('philip_english_french_accent', 'Philip English spoke English with a French accent his entire life', 'Jersey''s native language was Jerriais (Jersey French), a Norman-French dialect. Philip English almost certainly grew up speaking Jerriais as his mother tongue and French as his literary language. He spoke English with a noticeable French accent for his entire life. In 1692, with King William''s War raging against France, this made him suspect — ''French'' meant ''Catholic'' meant ''agent of the Devil'' to many Puritans.', NULL, NULL, 'biographical', 'language', NULL, 'philip_english', 'philip_english_merchant_research.md', 'Philip English spoke English with a French accent his entire life. Jersey''s native language was Jerriais (Jersey French), a Norman-French dialect. Philip English almost certainly grew up speaking Jerriais as his mother tongue and French as his literary language. He spoke English with a noticeable French accent for his entire life. In 1692, with King William''s War raging against France, this made him suspect — ''French'' meant ''Catholic'' meant ''agent of the Devil'' to many Puritans.', 'public', '["french","language","accent","suspicion"]', 'salem_project', 1.0, NULL, 1775266565624, 1775266565624, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('philip_english_fleet', 'Philip English owned at least 21 sailing vessels', 'Philip English owned at least 21 sailing vessels by 1692 — the largest private shipowner in New England. Most Salem merchants owned one or two; three or four was considered substantial. His fleet included ketches, sloops, brigantines, and smaller craft. With 21 vessels, English had ships simultaneously in multiple ports — Caribbean, Virginia, Atlantic crossings. He employed dozens of shipmasters and hundreds of sailors, making him one of the largest employers in Essex County.', NULL, NULL, 'biographical', 'wealth', NULL, 'philip_english', 'philip_english_merchant_research.md', 'Philip English owned at least 21 sailing vessels. Philip English owned at least 21 sailing vessels by 1692 — the largest private shipowner in New England. Most Salem merchants owned one or two; three or four was considered substantial. His fleet included ketches, sloops, brigantines, and smaller craft. With 21 vessels, English had ships simultaneously in multiple ports — Caribbean, Virginia, Atlantic crossings. He employed dozens of shipmasters and hundreds of sailors, making him one of the largest employers in Essex County.', 'public', '["fleet","vessels","wealth","employer"]', 'salem_project', 1.0, NULL, 1775266565624, 1775266565624, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('philip_english_14_buildings', 'Philip English owned 14 buildings in Salem', 'Philip English owned 14 buildings in Salem plus extensive landholdings — commercial properties, rental properties, agricultural land. His mansion on Essex Street was the finest and largest private dwelling in Salem, remaining the largest house in Salem for roughly 100 years until its demolition in 1833.', NULL, NULL, 'biographical', 'property', NULL, 'philip_english', 'philip_english_merchant_research.md', 'Philip English owned 14 buildings in Salem. Philip English owned 14 buildings in Salem plus extensive landholdings — commercial properties, rental properties, agricultural land. His mansion on Essex Street was the finest and largest private dwelling in Salem, remaining the largest house in Salem for roughly 100 years until its demolition in 1833.', 'public', '["property","buildings","wealth","mansion"]', 'salem_project', 1.0, NULL, 1775266565624, 1775266565624, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('philip_english_marriage_hollingworth', 'Philip English marries Mary Hollingworth', 'Philip English married Mary Hollingworth around 1675. She was the daughter of Eleanor and William Hollingworth, established Salem merchants. The marriage brought Philip social legitimacy and local commercial networks, linking the ''French outsider'' to an established English merchant family.', '1675', 'approximate', 'biographical', 'marriage', NULL, 'philip_english', 'philip_english_merchant_research.md', 'Philip English marries Mary Hollingworth. Philip English married Mary Hollingworth around 1675. She was the daughter of Eleanor and William Hollingworth, established Salem merchants. The marriage brought Philip social legitimacy and local commercial networks, linking the ''French outsider'' to an established English merchant family.', 'public', '["marriage","hollingworth","social_legitimacy"]', 'salem_project', 1.0, NULL, 1775266565624, 1775266565624, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('mary_english_death', 'Mary English dies from effects of imprisonment', 'Mary English died in 1694, roughly two years after the trials. Her death was attributed to the effects of her imprisonment. She never fully recovered from the ordeal. She is among the indirect casualties of the Salem witch trials.', '1694', 'year', 'biographical', 'death', NULL, 'mary_english', 'philip_english_merchant_research.md', 'Mary English dies from effects of imprisonment. Mary English died in 1694, roughly two years after the trials. Her death was attributed to the effects of her imprisonment. She never fully recovered from the ordeal. She is among the indirect casualties of the Salem witch trials.', 'public', '["death","imprisonment","casualty"]', 'salem_project', 1.0, NULL, 1775266565624, 1775266565624, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('philip_english_anglican_convert', 'Philip English leaves Puritan church for Anglican St. Peter''s', 'After the trials, Philip English left the Puritan congregation and joined St. Peter''s Episcopal (Anglican) Church in Salem — rejecting the establishment that had persecuted him. This was a significant public statement of alienation from the Puritan community that had nearly killed him and his wife.', NULL, NULL, 'biographical', 'aftermath', NULL, 'philip_english', 'philip_english_merchant_research.md', 'Philip English leaves Puritan church for Anglican St. Peter''s. After the trials, Philip English left the Puritan congregation and joined St. Peter''s Episcopal (Anglican) Church in Salem — rejecting the establishment that had persecuted him. This was a significant public statement of alienation from the Puritan community that had nearly killed him and his wife.', 'public', '["anglican","church","alienation","aftermath"]', 'salem_project', 1.0, NULL, 1775266565624, 1775266565624, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('philip_english_death', 'Philip English dies in his 80s, never having forgiven', 'Philip English partially rebuilt his fortune and remained a prominent but embittered Salem merchant until his death around 1736, living into his 80s. He never forgave those who participated in the trials.', '1736', 'approximate', 'biographical', 'death', NULL, 'philip_english', 'philip_english_merchant_research.md', 'Philip English dies in his 80s, never having forgiven. Philip English partially rebuilt his fortune and remained a prominent but embittered Salem merchant until his death around 1736, living into his 80s. He never forgave those who participated in the trials.', 'public', '["death","aftermath","bitterness"]', 'salem_project', 1.0, NULL, 1775266565624, 1775266565624, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('rebecca_nurse_birth', 'Rebecca Towne born in Great Yarmouth, Norfolk, England', 'Rebecca Towne was born circa 1621 in Great Yarmouth, Norfolk, England, daughter of William Towne and Joanna Blessing. She was the eldest of the three Towne sisters who would all be accused of witchcraft in 1692.', '1621', 'approximate', 'biographical', 'birth', NULL, 'rebecca_nurse', 'topsfield_names_research.md', 'Rebecca Towne born in Great Yarmouth, Norfolk, England. Rebecca Towne was born circa 1621 in Great Yarmouth, Norfolk, England, daughter of William Towne and Joanna Blessing. She was the eldest of the three Towne sisters who would all be accused of witchcraft in 1692.', 'public', '["birth","towne_family","england"]', 'salem_project', 1.0, NULL, 1775266565624, 1775266565624, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('rebecca_nurse_eight_children', 'Rebecca and Francis Nurse had eight children', 'Rebecca and Francis Nurse had eight children: John, Rebecca Jr., Samuel, Mary, Elizabeth, Francis Jr., Sarah, and Benjamin. All survived to adulthood and married, an unusual achievement for the period. The Nurse family was well-established and respected in Salem Village.', NULL, NULL, 'biographical', 'family', NULL, 'rebecca_nurse', 'topsfield_names_research.md', 'Rebecca and Francis Nurse had eight children. Rebecca and Francis Nurse had eight children: John, Rebecca Jr., Samuel, Mary, Elizabeth, Francis Jr., Sarah, and Benjamin. All survived to adulthood and married, an unusual achievement for the period. The Nurse family was well-established and respected in Salem Village.', 'public', '["children","family","nurse_family"]', 'salem_project', 1.0, NULL, 1775266565624, 1775266565624, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('rebecca_nurse_300_acre_farm', 'Francis Nurse''s 300-acre Bishop Farm lease-to-own', 'Francis Nurse obtained a lease-to-own arrangement for the 300-acre Bishop Farm (also called the Endicott Orchard Farm), one of the largest individual holdings in Salem Village. This brought the Nurse family into direct boundary conflict with the Putnam family, who claimed overlapping acreage.', NULL, NULL, 'biographical', 'property', NULL, 'francis_nurse', 'village_disputes_research.md', 'Francis Nurse''s 300-acre Bishop Farm lease-to-own. Francis Nurse obtained a lease-to-own arrangement for the 300-acre Bishop Farm (also called the Endicott Orchard Farm), one of the largest individual holdings in Salem Village. This brought the Nurse family into direct boundary conflict with the Putnam family, who claimed overlapping acreage.', 'public', '["property","boundary_dispute","putnam_conflict"]', 'salem_project', 1.0, NULL, 1775266565624, 1775266565624, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('rebecca_nurse_execution', 'Rebecca Nurse hanged on Gallows Hill', 'Rebecca Nurse was hanged on July 19, 1692 on Gallows Hill, Salem. She was approximately 71 years old. The jury had initially returned a verdict of not guilty, but Chief Justice Stoughton sent them back to reconsider. Nurse, who was hard of hearing, failed to respond to a question that the jury interpreted as an admission of guilt. The verdict was reversed to guilty.', '1692-07-19', 'exact', 'biographical', 'death', NULL, 'rebecca_nurse', 'micro_events_daily_chronicle.md', 'Rebecca Nurse hanged on Gallows Hill. Rebecca Nurse was hanged on July 19, 1692 on Gallows Hill, Salem. She was approximately 71 years old. The jury had initially returned a verdict of not guilty, but Chief Justice Stoughton sent them back to reconsider. Nurse, who was hard of hearing, failed to respond to a question that the jury interpreted as an admission of guilt. The verdict was reversed to guilty.', 'public', '["execution","hanging","verdict_reversed"]', 'salem_project', 1.0, NULL, 1775266565624, 1775266565624, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('mary_easty_birth', 'Mary Towne Easty born, sister of Rebecca Nurse', 'Mary Towne was born circa 1634, daughter of William Towne and Joanna Blessing. She married Isaac Easty circa 1655 and had nine children: Isaac Jr., Joseph, Sarah, John, Hannah, Benjamin, Samuel, Jacob, and Joshua. She was a full communicant of the church.', '1634', 'approximate', 'biographical', 'birth', NULL, 'mary_easty', 'topsfield_names_research.md', 'Mary Towne Easty born, sister of Rebecca Nurse. Mary Towne was born circa 1634, daughter of William Towne and Joanna Blessing. She married Isaac Easty circa 1655 and had nine children: Isaac Jr., Joseph, Sarah, John, Hannah, Benjamin, Samuel, Jacob, and Joshua. She was a full communicant of the church.', 'public', '["birth","towne_family","topsfield"]', 'salem_project', 1.0, NULL, 1775266565624, 1775266565624, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('mary_easty_execution', 'Mary Easty hanged on Gallows Hill', 'Mary Easty was hanged on September 22, 1692. Before her death, she wrote the most moving document of the trials — her farewell petition pleading not for her own life but for the lives of others who would follow.', '1692-09-22', 'exact', 'biographical', 'death', NULL, 'mary_easty', 'micro_events_daily_chronicle.md', 'Mary Easty hanged on Gallows Hill. Mary Easty was hanged on September 22, 1692. Before her death, she wrote the most moving document of the trials — her farewell petition pleading not for her own life but for the lives of others who would follow.', 'public', '["execution","hanging","farewell_petition"]', 'salem_project', 1.0, NULL, 1775266565624, 1775266565624, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('sarah_cloyce_biography', 'Sarah Towne Cloyce — youngest of the three accused Towne sisters', 'Sarah Towne was born circa 1637-1641, the youngest of the three Towne sisters. She married Edmund Bridges Jr. on January 11, 1659/60, then after his death married Peter Cloyce circa 1682. She had eight or more children. She survived the trials and lived until circa 1703.', '1637', 'approximate', 'biographical', 'family', NULL, 'sarah_cloyce', 'topsfield_names_research.md', 'Sarah Towne Cloyce — youngest of the three accused Towne sisters. Sarah Towne was born circa 1637-1641, the youngest of the three Towne sisters. She married Edmund Bridges Jr. on January 11, 1659/60, then after his death married Peter Cloyce circa 1682. She had eight or more children. She survived the trials and lived until circa 1703.', 'public', '["birth","towne_family","survivor"]', 'salem_project', 1.0, NULL, 1775266565624, 1775266565624, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('william_towne_genealogy', 'William Towne and Joanna Blessing — parents of three accused sisters', 'William Towne (c.1598-1672/73) married Joanna Blessing (c.1595-1682). Their daughters Rebecca (Nurse), Mary (Easty), and Sarah (Cloyce) were all accused of witchcraft in 1692. Their surviving sons were Jacob Towne (c.1632-1704) and Joseph Towne (c.1639-1713).', '1598', 'approximate', 'biographical', 'genealogy', NULL, 'rebecca_nurse', 'topsfield_names_research.md', 'William Towne and Joanna Blessing — parents of three accused sisters. William Towne (c.1598-1672/73) married Joanna Blessing (c.1595-1682). Their daughters Rebecca (Nurse), Mary (Easty), and Sarah (Cloyce) were all accused of witchcraft in 1692. Their surviving sons were Jacob Towne (c.1632-1704) and Joseph Towne (c.1639-1713).', 'public', '["genealogy","towne_family","topsfield"]', 'salem_project', 1.0, NULL, 1775266565624, 1775266565624, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('elizabeth_proctor_pregnancy', 'Elizabeth Proctor arrested while pregnant', 'Elizabeth Proctor was arrested April 4, 1692. Convicted August 5, 1692 alongside husband John. Her execution was stayed because she was pregnant (''reprieve for the belly''). Baby born January 27, 1693 — a son named John Proctor III, born while Elizabeth was still imprisoned. Released May 1693. She had no legal rights as a convicted witch. John''s will excluded her; she received no inheritance. His estate had been confiscated.', '1692-04-04', 'exact', 'biographical', 'pregnancy', NULL, 'elizabeth_proctor', 'births_deaths_illness_research.md', 'Elizabeth Proctor arrested while pregnant. Elizabeth Proctor was arrested April 4, 1692. Convicted August 5, 1692 alongside husband John. Her execution was stayed because she was pregnant (''reprieve for the belly''). Baby born January 27, 1693 — a son named John Proctor III, born while Elizabeth was still imprisoned. Released May 1693. She had no legal rights as a convicted witch. John''s will excluded her; she received no inheritance. His estate had been confiscated.', 'public', '["pregnancy","reprieve","imprisonment"]', 'salem_project', 1.0, NULL, 1775266565624, 1775266565624, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('elizabeth_proctor_remarriage', 'Elizabeth Proctor remarries Daniel Richards seven years after John''s execution', 'Elizabeth Proctor remarried Daniel Richards on September 22, 1699, seven years after John Proctor''s execution on August 19, 1692.', '1699-09-22', 'exact', 'biographical', 'aftermath', NULL, 'elizabeth_proctor', 'births_deaths_illness_research.md', 'Elizabeth Proctor remarries Daniel Richards seven years after John''s execution. Elizabeth Proctor remarried Daniel Richards on September 22, 1699, seven years after John Proctor''s execution on August 19, 1692.', 'public', '["remarriage","aftermath"]', 'salem_project', 1.0, NULL, 1775266565624, 1775266565624, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('john_proctor_execution', 'John Proctor hanged on Gallows Hill', 'John Proctor was hanged on August 19, 1692. He was the most outspoken early opponent of the trials, publicly declaring the accusers were frauds and should be whipped. His outspokenness was precisely what doomed him — he was targeted because of his vocal opposition.', '1692-08-19', 'exact', 'biographical', 'death', NULL, 'john_proctor', 'micro_events_daily_chronicle.md', 'John Proctor hanged on Gallows Hill. John Proctor was hanged on August 19, 1692. He was the most outspoken early opponent of the trials, publicly declaring the accusers were frauds and should be whipped. His outspokenness was precisely what doomed him — he was targeted because of his vocal opposition.', 'public', '["execution","hanging","opposition"]', 'salem_project', 1.0, NULL, 1775266565624, 1775266565624, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('sarah_good_poverty', 'Sarah Good reduced to begging door-to-door', 'Sarah Good and her husband William had sold their property and were left impoverished and homeless. She wandered door to door asking for charity. Her habit of scolding and cursing neighbors who refused her generated a wealth of testimony at trial. Her muttering was universally interpreted as cursing.', NULL, NULL, 'biographical', 'economic', NULL, 'sarah_good', 'micro_events_daily_chronicle.md', 'Sarah Good reduced to begging door-to-door. Sarah Good and her husband William had sold their property and were left impoverished and homeless. She wandered door to door asking for charity. Her habit of scolding and cursing neighbors who refused her generated a wealth of testimony at trial. Her muttering was universally interpreted as cursing.', 'public', '["poverty","begging","muttering"]', 'salem_project', 1.0, NULL, 1775266565624, 1775266565624, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('sarah_good_baby_death', 'Sarah Good''s baby Mercy dies in prison', 'Sarah Good was pregnant at time of arrest in late February/early March 1692. She gave birth to a daughter named Mercy while imprisoned (likely Ipswich jail). The baby died before her mother''s execution from harsh prison conditions.', '1692-07-19', 'approximate', 'biographical', 'death', NULL, 'sarah_good', 'births_deaths_illness_research.md', 'Sarah Good''s baby Mercy dies in prison. Sarah Good was pregnant at time of arrest in late February/early March 1692. She gave birth to a daughter named Mercy while imprisoned (likely Ipswich jail). The baby died before her mother''s execution from harsh prison conditions.', 'public', '["infant_death","prison","pregnancy"]', 'salem_project', 1.0, NULL, 1775266565624, 1775266565624, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('sarah_good_execution', 'Sarah Good hanged, age approximately 39', 'Sarah Good was executed July 19, 1692, age approximately 39. On the scaffold, she told Rev. Nicholas Noyes: ''I am no more a witch than you are a wizard, and if you take away my life God will give you blood to drink.'' Noyes died of an internal hemorrhage in 1717, choking on his own blood — many viewed this as fulfillment of Good''s curse.', '1692-07-19', 'exact', 'biographical', 'death', NULL, 'sarah_good', 'births_deaths_illness_research.md', 'Sarah Good hanged, age approximately 39. Sarah Good was executed July 19, 1692, age approximately 39. On the scaffold, she told Rev. Nicholas Noyes: ''I am no more a witch than you are a wizard, and if you take away my life God will give you blood to drink.'' Noyes died of an internal hemorrhage in 1717, choking on his own blood — many viewed this as fulfillment of Good''s curse.', 'public', '["execution","hanging","curse","prophecy"]', 'salem_project', 1.0, NULL, 1775266565624, 1775266565624, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('griggs_biography', 'Dr. William Griggs — Salem Village''s only physician', 'Dr. William Griggs was born circa 1615, making him in his late 70s in 1692. Probably self-taught with no documented formal medical education. He was the only physician in the Salem Village area. His wife was Rachel Hubbard Griggs. Elizabeth Hubbard (Rachel''s great-niece) was their maidservant and became one of the most active accusers.', NULL, NULL, 'biographical', 'career', NULL, 'william_griggs', 'births_deaths_illness_research.md', 'Dr. William Griggs — Salem Village''s only physician. Dr. William Griggs was born circa 1615, making him in his late 70s in 1692. Probably self-taught with no documented formal medical education. He was the only physician in the Salem Village area. His wife was Rachel Hubbard Griggs. Elizabeth Hubbard (Rachel''s great-niece) was their maidservant and became one of the most active accusers.', 'public', '["physician","self_taught","elizabeth_hubbard"]', 'salem_project', 1.0, NULL, 1775266565624, 1775266565624, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('mercy_lewis_parents_killed', 'Mercy Lewis''s parents killed in Falmouth attack', 'Mercy Lewis was born circa 1675 in Falmouth (Portland), Maine. Her father Philip Lewis was a blacksmith on Hog Island in Casco Bay. On August 20, 1689, combined French and Wabanaki forces destroyed Falmouth, killing both of Mercy''s parents. She was approximately sixteen years old. She survived and was taken in by Rev. George Burroughs at Wells, Maine, before entering service in Thomas Putnam''s household in Salem Village.', '1689-08-20', 'exact', 'biographical', 'trauma', NULL, 'mercy_lewis', 'frontier_war_timeline_research.md', 'Mercy Lewis''s parents killed in Falmouth attack. Mercy Lewis was born circa 1675 in Falmouth (Portland), Maine. Her father Philip Lewis was a blacksmith on Hog Island in Casco Bay. On August 20, 1689, combined French and Wabanaki forces destroyed Falmouth, killing both of Mercy''s parents. She was approximately sixteen years old. She survived and was taken in by Rev. George Burroughs at Wells, Maine, before entering service in Thomas Putnam''s household in Salem Village.', 'public', '["orphan","frontier_attack","trauma","falmouth"]', 'salem_project', 1.0, NULL, 1775266565624, 1775266565624, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('mercy_lewis_accuser_role', 'Mercy Lewis accused 50+ individuals, testified in 16 cases', 'During the Salem witch trials, Mercy Lewis was one of the most active and violent accusers. She accused more than 50 individuals and testified in 16 cases. Her extreme behavior may have been driven by the severe trauma of losing both parents in the Falmouth massacre and the resulting PTSD.', NULL, NULL, 'biographical', 'crisis', NULL, 'mercy_lewis', 'frontier_war_timeline_research.md', 'Mercy Lewis accused 50+ individuals, testified in 16 cases. During the Salem witch trials, Mercy Lewis was one of the most active and violent accusers. She accused more than 50 individuals and testified in 16 cases. Her extreme behavior may have been driven by the severe trauma of losing both parents in the Falmouth massacre and the resulting PTSD.', 'public', '["accuser","testimony","trauma"]', 'salem_project', 1.0, NULL, 1775266565624, 1775266565624, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('mercy_lewis_aftermath', 'Mercy Lewis has illegitimate child, marries man from Falmouth', 'After the trials, Mercy Lewis had an illegitimate child. She married a man named Allen from Falmouth in 1701, returning to the region where her parents had been killed.', '1701', 'year', 'biographical', 'aftermath', NULL, 'mercy_lewis', 'frontier_war_timeline_research.md', 'Mercy Lewis has illegitimate child, marries man from Falmouth. After the trials, Mercy Lewis had an illegitimate child. She married a man named Allen from Falmouth in 1701, returning to the region where her parents had been killed.', 'semi_private', '["aftermath","illegitimate_child","marriage"]', 'salem_project', 1.0, NULL, 1775266565624, 1775266565624, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('betty_parris_afflictions', 'Betty Parris (age 9) begins showing affliction symptoms', 'Betty Parris, age 9, daughter of Rev. Samuel Parris, began showing affliction symptoms in mid-January 1692: absentmindedness, staring, animal noises, seizures, screaming. She crawled under furniture, barked like a dog, threw a Bible. She was eventually sent away to her cousin Stephen Sewall''s household and recovered.', '1692-01-15', 'approximate', 'biographical', 'crisis', NULL, 'betty_parris', 'births_deaths_illness_research.md', 'Betty Parris (age 9) begins showing affliction symptoms. Betty Parris, age 9, daughter of Rev. Samuel Parris, began showing affliction symptoms in mid-January 1692: absentmindedness, staring, animal noises, seizures, screaming. She crawled under furniture, barked like a dog, threw a Bible. She was eventually sent away to her cousin Stephen Sewall''s household and recovered.', 'public', '["affliction","fits","beginning"]', 'salem_project', 1.0, NULL, 1775266565624, 1775266565624, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('betty_parris_later_life', 'Betty Parris marries Benjamin Baron, lives to age 77', 'Betty Parris married Benjamin Baron in 1710. She had four children and died in 1760 at age 77, having apparently recovered fully from the events of 1692.', '1710', 'year', 'biographical', 'aftermath', NULL, 'betty_parris', 'births_deaths_illness_research.md', 'Betty Parris marries Benjamin Baron, lives to age 77. Betty Parris married Benjamin Baron in 1710. She had four children and died in 1760 at age 77, having apparently recovered fully from the events of 1692.', 'public', '["aftermath","marriage","recovery"]', 'salem_project', 1.0, NULL, 1775266565625, 1775266565625, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('giles_corey_pressing', 'Giles Corey pressed to death over two to three days', 'Giles Corey was stripped naked, a board placed on his chest, and heavy stones piled on. The pressing lasted two to three days (September 17-19, 1692). He demanded ''More weight!'' when asked to enter a plea. His tongue was pressed out of his mouth and the Sheriff used his cane to force it back in. By refusing to plead, his estate could not be forfeited — his family kept the land. He was the first and only person pressed to death in American history.', '1692-09-19', 'exact', 'biographical', 'death', NULL, 'giles_corey', 'births_deaths_illness_research.md', 'Giles Corey pressed to death over two to three days. Giles Corey was stripped naked, a board placed on his chest, and heavy stones piled on. The pressing lasted two to three days (September 17-19, 1692). He demanded ''More weight!'' when asked to enter a plea. His tongue was pressed out of his mouth and the Sheriff used his cane to force it back in. By refusing to plead, his estate could not be forfeited — his family kept the land. He was the first and only person pressed to death in American history.', 'public', '["pressing","peine_forte_et_dure","death","property_protection"]', 'salem_project', 1.0, NULL, 1775266565625, 1775266565625, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('dorothy_good_imprisoned', 'Dorothy Good (age 4-5) arrested and chained in dungeon', 'Dorothy (Dorcas) Good, four or five years old, was arrested on March 24, 1692 and chained in the dungeon for 7-8 months. She was ''so hardly used and terrified that she hath ever since been very chargeable, having little or no reason to govern herself.'' She was permanently mentally damaged, and as an adult ''bounced from home to home.''', '1692-03-24', 'exact', 'biographical', 'imprisonment', NULL, 'dorothy_good', 'births_deaths_illness_research.md', 'Dorothy Good (age 4-5) arrested and chained in dungeon. Dorothy (Dorcas) Good, four or five years old, was arrested on March 24, 1692 and chained in the dungeon for 7-8 months. She was ''so hardly used and terrified that she hath ever since been very chargeable, having little or no reason to govern herself.'' She was permanently mentally damaged, and as an adult ''bounced from home to home.''', 'public', '["child","imprisonment","mental_damage","chains"]', 'salem_project', 1.0, NULL, 1775266565625, 1775266565625, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('tituba_imprisonment', 'Tituba imprisoned 13 months because Parris refused to pay jail fees', 'After the trials ended, Rev. Parris refused to pay Tituba''s jail fees. She remained imprisoned approximately thirteen months until an unknown person paid seven pounds for her release. Her ultimate fate after release is unknown.', NULL, NULL, 'biographical', 'imprisonment', NULL, 'tituba', 'births_deaths_illness_research.md', 'Tituba imprisoned 13 months because Parris refused to pay jail fees. After the trials ended, Rev. Parris refused to pay Tituba''s jail fees. She remained imprisoned approximately thirteen months until an unknown person paid seven pounds for her release. Her ultimate fate after release is unknown.', 'semi_private', '["imprisonment","jail_fees","abandonment"]', 'salem_project', 1.0, NULL, 1775266565625, 1775266565625, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('abigail_faulkner_pregnancy_reprieve', 'Abigail Faulkner Sr. convicted but saved by pregnancy', 'Abigail Faulkner Sr. of Andover, age 40, was convicted September 17, 1692. Execution was delayed because she was pregnant with her seventh child. She petitioned Phips: her husband was an invalid, children had no caretaker, ''little or nothing to subsist on.'' Governor Phips pardoned her. Baby born March 20, 1693, named Ammi Ruhamah — Hebrew meaning ''my people had mercy'' — because the baby saved her life. She was officially cleared in 1703.', '1692-09-17', 'exact', 'biographical', 'pregnancy', NULL, 'abigail_faulkner', 'births_deaths_illness_research.md', 'Abigail Faulkner Sr. convicted but saved by pregnancy. Abigail Faulkner Sr. of Andover, age 40, was convicted September 17, 1692. Execution was delayed because she was pregnant with her seventh child. She petitioned Phips: her husband was an invalid, children had no caretaker, ''little or nothing to subsist on.'' Governor Phips pardoned her. Baby born March 20, 1693, named Ammi Ruhamah — Hebrew meaning ''my people had mercy'' — because the baby saved her life. She was officially cleared in 1703.', 'public', '["pregnancy","reprieve","pardon","andover"]', 'salem_project', 1.0, NULL, 1775266565625, 1775266565625, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('mary_bradbury_escape', 'Mary Bradbury (age 72-77) escapes execution', 'Mary Bradbury was approximately 72-77 years old at arrest. Over 100 neighbors testified on her behalf — she was still convicted. Her husband reportedly bribed the jailer and took her to Maine in a horse and cart. She lived until 1700, dying at approximately 85.', '1692-09', 'month', 'biographical', 'escape', NULL, 'mary_bradbury', 'births_deaths_illness_research.md', 'Mary Bradbury (age 72-77) escapes execution. Mary Bradbury was approximately 72-77 years old at arrest. Over 100 neighbors testified on her behalf — she was still convicted. Her husband reportedly bribed the jailer and took her to Maine in a horse and cart. She lived until 1700, dying at approximately 85.', 'semi_private', '["escape","bribery","elderly","petition"]', 'salem_project', 1.0, NULL, 1775266565625, 1775266565625, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('susannah_sheldon_refugee', 'Susannah Sheldon — twice-displaced Maine refugee', 'Susannah Sheldon, born circa 1674, came from a family in Saco, Maine. Driven from Saco during King Philip''s War (1676) as a baby. The family returned to the frontier, then was driven out again during King William''s War. Age 18 during the trials. She accused eleven people. Her symptoms were consistent with PTSD or conversion disorder.', NULL, NULL, 'biographical', 'trauma', NULL, 'susannah_sheldon', 'frontier_war_timeline_research.md', 'Susannah Sheldon — twice-displaced Maine refugee. Susannah Sheldon, born circa 1674, came from a family in Saco, Maine. Driven from Saco during King Philip''s War (1676) as a baby. The family returned to the frontier, then was driven out again during King William''s War. Age 18 during the trials. She accused eleven people. Her symptoms were consistent with PTSD or conversion disorder.', 'public', '["refugee","frontier","ptsd","accuser"]', 'salem_project', 1.0, NULL, 1775266565625, 1775266565625, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('sarah_churchill_refugee', 'Sarah Churchill — Maine refugee, servant to George Jacobs Sr.', 'Sarah Churchill, born circa 1667 in Saco, Maine. Her family was driven to Marblehead by Wabanaki attack. She worked as servant to George Jacobs Sr. During the trials, she confessed after being accused, then privately recanted, expressing the impossible bind of the accused.', NULL, NULL, 'biographical', 'origin', NULL, 'sarah_churchill', 'frontier_war_timeline_research.md', 'Sarah Churchill — Maine refugee, servant to George Jacobs Sr.. Sarah Churchill, born circa 1667 in Saco, Maine. Her family was driven to Marblehead by Wabanaki attack. She worked as servant to George Jacobs Sr. During the trials, she confessed after being accused, then privately recanted, expressing the impossible bind of the accused.', 'public', '["refugee","servant","confession","recantation"]', 'salem_project', 1.0, NULL, 1775266565625, 1775266565625, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('abigail_hobbs_devil_in_maine', 'Abigail Hobbs confessed meeting the Devil in the woods of Maine', 'Abigail Hobbs, born circa 1678, had ties to Casco Bay/Falmouth. She confessed to meeting the Devil in the woods of Maine — placing the encounter explicitly in frontier territory, Satan''s domain in Puritan theology. This confession reinforced the connection between the frontier wilderness and satanic evil.', NULL, NULL, 'biographical', 'confession', NULL, 'abigail_hobbs', 'frontier_war_timeline_research.md', 'Abigail Hobbs confessed meeting the Devil in the woods of Maine. Abigail Hobbs, born circa 1678, had ties to Casco Bay/Falmouth. She confessed to meeting the Devil in the woods of Maine — placing the encounter explicitly in frontier territory, Satan''s domain in Puritan theology. This confession reinforced the connection between the frontier wilderness and satanic evil.', 'public', '["confession","devil","frontier","wilderness"]', 'salem_project', 1.0, NULL, 1775266565625, 1775266565625, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('stoughton_biography', 'William Stoughton — Chief Justice, hardliner, never expressed remorse', 'William Stoughton was born 1631 in England. Harvard 1650, Oxford MA 1653. Former clergyman who left ministry for politics. No legal education. He was appointed Lieutenant Governor on May 14, 1692 and Chief Magistrate of the Court of Oyer and Terminer on May 27. He acted as both chief judge and prosecutor, allowed spectral evidence despite its exclusion from English courts, and never admitted error or expressed remorse. After Phips dissolved the court, Stoughton was furious and continued pursuing convictions.', NULL, NULL, 'biographical', 'career', NULL, 'william_stoughton', 'political_events_charter_research.md', 'William Stoughton — Chief Justice, hardliner, never expressed remorse. William Stoughton was born 1631 in England. Harvard 1650, Oxford MA 1653. Former clergyman who left ministry for politics. No legal education. He was appointed Lieutenant Governor on May 14, 1692 and Chief Magistrate of the Court of Oyer and Terminer on May 27. He acted as both chief judge and prosecutor, allowed spectral evidence despite its exclusion from English courts, and never admitted error or expressed remorse. After Phips dissolved the court, Stoughton was furious and continued pursuing convictions.', 'public', '["judge","hardliner","spectral_evidence"]', 'salem_project', 1.0, NULL, 1775266565625, 1775266565625, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('hathorne_biography', 'John Hathorne — the most aggressive examiner', 'John Hathorne was born August 5, 1641 in Salem. Son of William Hathorne, who arrived on the Arabella with John Winthrop in 1630. Wealthy merchant with England and West Indies trade. He was the most aggressive examiner, conducting pretrial examinations in an accusatory tone, proceeding to badger the accused in an attempt to drive out confessions. Historian Charles Upham noted his examination was conducted based on a foregone conclusion of the prisoner''s guilt. He never expressed remorse and died May 10, 1717. He was the ancestor of Nathaniel Hawthorne, who added the ''w'' to distance himself from this legacy.', '1641-08-05', 'exact', 'biographical', 'career', NULL, 'john_hathorne', 'political_events_charter_research.md', 'John Hathorne — the most aggressive examiner. John Hathorne was born August 5, 1641 in Salem. Son of William Hathorne, who arrived on the Arabella with John Winthrop in 1630. Wealthy merchant with England and West Indies trade. He was the most aggressive examiner, conducting pretrial examinations in an accusatory tone, proceeding to badger the accused in an attempt to drive out confessions. Historian Charles Upham noted his examination was conducted based on a foregone conclusion of the prisoner''s guilt. He never expressed remorse and died May 10, 1717. He was the ancestor of Nathaniel Hawthorne, who added the ''w'' to distance himself from this legacy.', 'public', '["judge","examiner","hawthorne_ancestor"]', 'salem_project', 1.0, NULL, 1775266565625, 1775266565625, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('sewall_biography', 'Samuel Sewall — the judge who publicly repented', 'Samuel Sewall was born March 28, 1652 in Bishopstoke, Hampshire, England. Arrived in Massachusetts 1661. Harvard 1671, MA 1674. Married Hannah Hull, daughter of the colonial mint master (her dowry reportedly included her weight in silver shillings). By 1692 he was a member of the Governor''s Council. He was the only judge to publicly repent his role in the trials, standing in the Old South Meeting House on January 14, 1697 while Rev. Willard read his confession aloud.', '1652-03-28', 'exact', 'biographical', 'career', NULL, 'samuel_sewall', 'political_events_charter_research.md', 'Samuel Sewall — the judge who publicly repented. Samuel Sewall was born March 28, 1652 in Bishopstoke, Hampshire, England. Arrived in Massachusetts 1661. Harvard 1671, MA 1674. Married Hannah Hull, daughter of the colonial mint master (her dowry reportedly included her weight in silver shillings). By 1692 he was a member of the Governor''s Council. He was the only judge to publicly repent his role in the trials, standing in the Old South Meeting House on January 14, 1697 while Rev. Willard read his confession aloud.', 'public', '["judge","repentance","diary"]', 'salem_project', 1.0, NULL, 1775266565625, 1775266565625, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('saltonstall_resignation', 'Nathaniel Saltonstall resigns from Court of Oyer and Terminer', 'Nathaniel Saltonstall, age 53, resigned from the Court of Oyer and Terminer on June 13, 1692, reportedly dissatisfied with the proceedings and particularly the use of spectral evidence. He was the only judge to resign. He was later accused of witchcraft himself, though never arrested. Jonathan Corwin replaced him on the court.', '1692-06-13', 'exact', 'biographical', 'crisis', NULL, 'nathaniel_saltonstall', 'political_events_charter_research.md', 'Nathaniel Saltonstall resigns from Court of Oyer and Terminer. Nathaniel Saltonstall, age 53, resigned from the Court of Oyer and Terminer on June 13, 1692, reportedly dissatisfied with the proceedings and particularly the use of spectral evidence. He was the only judge to resign. He was later accused of witchcraft himself, though never arrested. Jonathan Corwin replaced him on the court.', 'public', '["resignation","spectral_evidence","conscience"]', 'salem_project', 1.0, NULL, 1775266565625, 1775266565625, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('walcott_biography', 'Captain Jonathan Walcott — militia captain, King Philip''s War veteran', 'Captain Jonathan Walcott (1639-1699) was a King Philip''s War veteran who made wheels for guns at the Winter Island fort. Elected captain of the Salem Village military company in 1690. He married Deliverance Putnam (Thomas Putnam Jr.''s sister) on April 23, 1685, cementing the Putnam-Walcott military-political alliance. His daughter Mary Walcott became one of the afflicted girls.', NULL, NULL, 'biographical', 'military', NULL, 'jonathan_walcott', 'frontier_war_timeline_research.md', 'Captain Jonathan Walcott — militia captain, King Philip''s War veteran. Captain Jonathan Walcott (1639-1699) was a King Philip''s War veteran who made wheels for guns at the Winter Island fort. Elected captain of the Salem Village military company in 1690. He married Deliverance Putnam (Thomas Putnam Jr.''s sister) on April 23, 1685, cementing the Putnam-Walcott military-political alliance. His daughter Mary Walcott became one of the afflicted girls.', 'public', '["militia","veteran","putnam_alliance"]', 'salem_project', 1.0, NULL, 1775266565625, 1775266565625, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('joseph_putnam_porter_marriage', 'Joseph Putnam marries Elizabeth Porter — factional betrayal', 'Joseph Putnam, youngest son of Thomas Putnam Sr., married Elizabeth Porter on April 21, 1690. This was viewed by the Putnam family as a factional betrayal — a Putnam marrying into the rival Porter clan. Joseph became an outspoken opponent of the trials, threatening armed resistance against anyone who tried to arrest members of his household.', '1690-04-21', 'exact', 'biographical', 'marriage', NULL, 'joseph_putnam', 'social_bonds_marriages.md', 'Joseph Putnam marries Elizabeth Porter — factional betrayal. Joseph Putnam, youngest son of Thomas Putnam Sr., married Elizabeth Porter on April 21, 1690. This was viewed by the Putnam family as a factional betrayal — a Putnam marrying into the rival Porter clan. Joseph became an outspoken opponent of the trials, threatening armed resistance against anyone who tried to arrest members of his household.', 'public', '["marriage","faction","betrayal","porter_alliance"]', 'salem_project', 1.0, NULL, 1775266565625, 1775266565625, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('israel_porter_hathorne_marriage', 'Israel Porter marries Elizabeth Hathorne — Judge Hathorne''s sister', 'Israel Porter married Elizabeth Hathorne on November 20, 1672. Elizabeth was the sister of Judge John Hathorne, who would preside over the witch examinations. This cross-factional family connection created an awkward dynamic — Hathorne was examining people accused by the faction opposing his own sister''s husband.', '1672-11-20', 'exact', 'biographical', 'marriage', NULL, 'israel_porter', 'social_bonds_marriages.md', 'Israel Porter marries Elizabeth Hathorne — Judge Hathorne''s sister. Israel Porter married Elizabeth Hathorne on November 20, 1672. Elizabeth was the sister of Judge John Hathorne, who would preside over the witch examinations. This cross-factional family connection created an awkward dynamic — Hathorne was examining people accused by the faction opposing his own sister''s husband.', 'public', '["marriage","faction","hathorne","porter"]', 'salem_project', 1.0, NULL, 1775266565625, 1775266565625, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('daniel_andrew_sarah_porter_marriage', 'Daniel Andrew marries Sarah Porter', 'Daniel Andrew married Sarah Porter circa 1677, merging Andrew''s ambition with Porter wealth and connections. Andrew would later build an independent wharf on Frost Fish Brook in February 1692, challenging the Putnam economic grip. He was accused of witchcraft and fled.', '1677', 'approximate', 'biographical', 'marriage', NULL, 'daniel_andrew', 'social_bonds_marriages.md', 'Daniel Andrew marries Sarah Porter. Daniel Andrew married Sarah Porter circa 1677, merging Andrew''s ambition with Porter wealth and connections. Andrew would later build an independent wharf on Frost Fish Brook in February 1692, challenging the Putnam economic grip. He was accused of witchcraft and fled.', 'public', '["marriage","porter_alliance","merchant"]', 'salem_project', 1.0, NULL, 1775266565625, 1775266565625, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('john_willard_refused_arrests', 'Deputy constable John Willard refuses to make further arrests, is hanged', 'John Willard served as deputy constable and initially carried out arrest warrants. After witnessing the proceedings, he refused to make further arrests. He was then accused of witchcraft himself and hanged on August 19, 1692. His transformation from enforcer to victim illustrates the crisis''s self-consuming nature.', '1692-05', 'month', 'biographical', 'crisis', NULL, 'john_willard', 'occupational_knowledge_map.md', 'Deputy constable John Willard refuses to make further arrests, is hanged. John Willard served as deputy constable and initially carried out arrest warrants. After witnessing the proceedings, he refused to make further arrests. He was then accused of witchcraft himself and hanged on August 19, 1692. His transformation from enforcer to victim illustrates the crisis''s self-consuming nature.', 'public', '["constable","refusal","accused","hanged"]', 'salem_project', 1.0, NULL, 1775266565625, 1775266565625, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('john_hale_biography', 'Rev. John Hale — Beverly minister who changed his mind', 'Rev. John Hale was born June 3, 1636, graduated Harvard 1657, ordained September 20, 1667 as first minister of Beverly. First wife Rebecca Byley (married December 15, 1664, died April 13, 1683). Second wife Sarah Noyes (married December 15, 1684). Children: Rebecca (1666-1681), Robert (November 3, 1668), James (October 14, 1685), Samuel (August 13, 1687). Hale initially supported the trials but reversed his position after his own wife Sarah was accused on November 14, 1692.', '1636-06-03', 'exact', 'biographical', 'career', NULL, 'john_hale', 'beverly_names_research.md', 'Rev. John Hale — Beverly minister who changed his mind. Rev. John Hale was born June 3, 1636, graduated Harvard 1657, ordained September 20, 1667 as first minister of Beverly. First wife Rebecca Byley (married December 15, 1664, died April 13, 1683). Second wife Sarah Noyes (married December 15, 1684). Children: Rebecca (1666-1681), Robert (November 3, 1668), James (October 14, 1685), Samuel (August 13, 1687). Hale initially supported the trials but reversed his position after his own wife Sarah was accused on November 14, 1692.', 'public', '["minister","beverly","changed_mind"]', 'salem_project', 1.0, NULL, 1775266565625, 1775266565625, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('sarah_hale_accused', 'Sarah Noyes Hale (wife of Rev. Hale) accused of witchcraft', 'On November 14, 1692, Mary Herrick (age 17) accused Sarah Noyes Hale, the second wife of Rev. John Hale of Beverly. Sarah was never arrested. The accusation of a minister''s wife was a turning point — it convinced Hale that the proceedings had gone too far and he wrote ''A Modest Enquiry into the Nature of Witchcraft'' (published posthumously 1702).', '1692-11-14', 'exact', 'biographical', 'crisis', NULL, 'john_hale', 'beverly_names_research.md', 'Sarah Noyes Hale (wife of Rev. Hale) accused of witchcraft. On November 14, 1692, Mary Herrick (age 17) accused Sarah Noyes Hale, the second wife of Rev. John Hale of Beverly. Sarah was never arrested. The accusation of a minister''s wife was a turning point — it convinced Hale that the proceedings had gone too far and he wrote ''A Modest Enquiry into the Nature of Witchcraft'' (published posthumously 1702).', 'public', '["accusation","turning_point","ministers_wife"]', 'salem_project', 1.0, NULL, 1775266565625, 1775266565625, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('martha_carrier_smallpox_blame', 'Martha Carrier blamed for Andover smallpox — 13 dead including 7 Carriers', 'In 1690, a smallpox outbreak in Andover killed 13 townspeople including 7 Carrier family members. The community blamed the Carrier family for bringing the disease. This grudge directly fueled Martha''s accusation in 1692. During her trial, the afflicted girls claimed to see ghosts of the thirteen smallpox dead. Cotton Mather called her ''a rampant hag'' and ''Queen of Hell.'' She was hanged August 19, 1692.', '1690', 'year', 'biographical', 'grudge', NULL, 'martha_carrier', 'births_deaths_illness_research.md', 'Martha Carrier blamed for Andover smallpox — 13 dead including 7 Carriers. In 1690, a smallpox outbreak in Andover killed 13 townspeople including 7 Carrier family members. The community blamed the Carrier family for bringing the disease. This grudge directly fueled Martha''s accusation in 1692. During her trial, the afflicted girls claimed to see ghosts of the thirteen smallpox dead. Cotton Mather called her ''a rampant hag'' and ''Queen of Hell.'' She was hanged August 19, 1692.', 'public', '["smallpox","grudge","andover","queen_of_hell"]', 'salem_project', 1.0, NULL, 1775266565625, 1775266565625, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('bridget_bishop_first_executed', 'Bridget Bishop — first person executed in Salem witch trials', 'Bridget Bishop was the first person executed in the Salem witch trials, hanged on June 10, 1692. She owned two taverns where she allowed younger men to play shuffleboard and gamble late into the night — violations of Puritan codes. She was ''critical of her neighbors, and reluctant to pay her bills.'' Multiple neighbors claimed illness or spectral torment after arguments with her.', '1692-06-10', 'exact', 'biographical', 'death', NULL, 'bridget_bishop', 'micro_events_daily_chronicle.md', 'Bridget Bishop — first person executed in Salem witch trials. Bridget Bishop was the first person executed in the Salem witch trials, hanged on June 10, 1692. She owned two taverns where she allowed younger men to play shuffleboard and gamble late into the night — violations of Puritan codes. She was ''critical of her neighbors, and reluctant to pay her bills.'' Multiple neighbors claimed illness or spectral torment after arguments with her.', 'public', '["first_execution","hanging","tavern_keeper"]', 'salem_project', 1.0, NULL, 1775266565625, 1775266565625, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('phips_biography', 'Governor William Phips — illiterate shepherd turned treasure hunter turned governor', 'William Phips was born 1651 in frontier Maine. Illiterate until his late teens. Rose from shepherd to ship''s carpenter to treasure salvager. In 1687 he salvaged approximately 207,000 pounds worth of Spanish treasure from the wrecked Concepción off Hispaniola. Knighted by King James II. Married Mary Spencer Hull in 1673. Led the failed Quebec expedition of October 1690 (~1,000 men lost). Arrived in Boston May 14, 1692 as first royal governor under the new charter, stepping directly into the witch crisis.', '1651', 'year', 'biographical', 'career', NULL, 'william_phips', 'piracy_privateering_maritime_research.md', 'Governor William Phips — illiterate shepherd turned treasure hunter turned governor. William Phips was born 1651 in frontier Maine. Illiterate until his late teens. Rose from shepherd to ship''s carpenter to treasure salvager. In 1687 he salvaged approximately 207,000 pounds worth of Spanish treasure from the wrecked Concepción off Hispaniola. Knighted by King James II. Married Mary Spencer Hull in 1673. Led the failed Quebec expedition of October 1690 (~1,000 men lost). Arrived in Boston May 14, 1692 as first royal governor under the new charter, stepping directly into the witch crisis.', 'public', '["governor","treasure","knight","illiterate"]', 'salem_project', 1.0, NULL, 1775266565625, 1775266565625, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('burroughs_salem_minister', 'George Burroughs — former Salem Village minister, accused and hanged', 'George Burroughs served as Salem Village minister from 1680-1683. His salary was always in arrears. His wife Hannah died in childbirth, and he borrowed 15 pounds from John Putnam for the funeral. He was arrested on May 3, 1683 for this debt — an unjust prosecution. He left Salem for Wells, Maine. In 1692, he was arrested at Wells on May 4 and brought back to Salem. He was hanged August 19, 1692, famously reciting the Lord''s Prayer perfectly on the scaffold — something a witch was believed unable to do.', NULL, NULL, 'biographical', 'career', NULL, 'george_burroughs', 'village_disputes_research.md', 'George Burroughs — former Salem Village minister, accused and hanged. George Burroughs served as Salem Village minister from 1680-1683. His salary was always in arrears. His wife Hannah died in childbirth, and he borrowed 15 pounds from John Putnam for the funeral. He was arrested on May 3, 1683 for this debt — an unjust prosecution. He left Salem for Wells, Maine. In 1692, he was arrested at Wells on May 4 and brought back to Salem. He was hanged August 19, 1692, famously reciting the Lord''s Prayer perfectly on the scaffold — something a witch was believed unable to do.', 'public', '["minister","execution","lords_prayer","wells_maine"]', 'salem_project', 1.0, NULL, 1775266565625, 1775266565625, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('afflicted_girls_ages', 'The afflicted girls — ages and backgrounds', 'The afflicted accusers with their ages during the trials: Betty Parris (9), Abigail Williams (11), Ann Putnam Jr. (12), Mary Walcott (16-17), Elizabeth Hubbard (17), Susannah Sheldon (18), Elizabeth Booth (18), Mercy Lewis (19), Mary Warren (20), Sarah Churchill (~25). Several were orphans or refugees from frontier attacks. Most were servants in other households.', NULL, NULL, 'biographical', 'group', NULL, 'betty_parris', 'social_bonds_daily_life.md', 'The afflicted girls — ages and backgrounds. The afflicted accusers with their ages during the trials: Betty Parris (9), Abigail Williams (11), Ann Putnam Jr. (12), Mary Walcott (16-17), Elizabeth Hubbard (17), Susannah Sheldon (18), Elizabeth Booth (18), Mercy Lewis (19), Mary Warren (20), Sarah Churchill (~25). Several were orphans or refugees from frontier attacks. Most were servants in other households.', 'public', '["afflicted_girls","accusers","ages","group"]', 'salem_project', 1.0, NULL, 1775266565625, 1775266565625, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('dorcas_hoar_biography', 'Dorcas Hoar of Beverly — convicted but reprieved', 'Dorcas Hoar, born circa 1634, was a widow from Beverly (husband William Hoar died winter 1691/92). Arrested April 30, examined May 2, tried September 6, convicted. She was reprieved September 21, 1692, the first convicted witch to receive a reprieve. Released spring 1693. She had 6 children. She lived until 1711.', NULL, NULL, 'biographical', 'career', NULL, 'dorcas_hoar', 'beverly_names_research.md', 'Dorcas Hoar of Beverly — convicted but reprieved. Dorcas Hoar, born circa 1634, was a widow from Beverly (husband William Hoar died winter 1691/92). Arrested April 30, examined May 2, tried September 6, convicted. She was reprieved September 21, 1692, the first convicted witch to receive a reprieve. Released spring 1693. She had 6 children. She lived until 1711.', 'public', '["reprieve","beverly","survivor"]', 'salem_project', 1.0, NULL, 1775266565625, 1775266565625, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('ingersoll_tavern_license', 'Nathaniel Ingersoll licensed to keep an ordinary', 'Nathaniel Ingersoll was licensed in 1677 to ''keep a hous of entertainment for strangers and othes by seling beere and sider and lickers and provision.'' His tavern became the nerve center of Salem Village life: eating and drinking establishment, inn, community center, and de facto holding cell during the crisis. About 30 accused persons were held prisoner in its upstairs rooms.', '1677', 'year', 'biographical', 'career', NULL, 'nathaniel_ingersoll', 'occupational_knowledge_map.md', 'Nathaniel Ingersoll licensed to keep an ordinary. Nathaniel Ingersoll was licensed in 1677 to ''keep a hous of entertainment for strangers and othes by seling beere and sider and lickers and provision.'' His tavern became the nerve center of Salem Village life: eating and drinking establishment, inn, community center, and de facto holding cell during the crisis. About 30 accused persons were held prisoner in its upstairs rooms.', 'public', '["tavern","ordinary","license"]', 'salem_project', 1.0, NULL, 1775266565625, 1775266565625, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('ingersoll_militia_background', 'Lt. Nathaniel Ingersoll — served as corporal, sergeant, then lieutenant', 'Nathaniel Ingersoll served in the militia, progressing from corporal to sergeant to lieutenant. His military background gave him quiet authority as tavern keeper and community leader. He filed 11 complaints against accused witches during April and May 1692, despite his wife Hannah having witnessed the afflicted girls'' ''for sport'' confession.', NULL, NULL, 'biographical', 'military', NULL, 'nathaniel_ingersoll', 'frontier_war_timeline_research.md', 'Lt. Nathaniel Ingersoll — served as corporal, sergeant, then lieutenant. Nathaniel Ingersoll served in the militia, progressing from corporal to sergeant to lieutenant. His military background gave him quiet authority as tavern keeper and community leader. He filed 11 complaints against accused witches during April and May 1692, despite his wife Hannah having witnessed the afflicted girls'' ''for sport'' confession.', 'public', '["militia","lieutenant","complaints"]', 'salem_project', 1.0, NULL, 1775266565625, 1775266565625, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('quote_sarah_good_scaffold', 'Sarah Good''s curse from the scaffold', 'On the gallows, Rev. Nicholas Noyes urged Sarah Good to confess. She replied with this curse. Noyes died in 1717 of an internal hemorrhage, choking on his own blood — many viewed this as fulfillment of her prophecy.', '1692-07-19', 'exact', 'quote', 'execution', NULL, 'sarah_good', 'births_deaths_illness_research.md', 'Sarah Good''s curse from the scaffold. On the gallows, Rev. Nicholas Noyes urged Sarah Good to confess. She replied with this curse. Noyes died in 1717 of an internal hemorrhage, choking on his own blood — many viewed this as fulfillment of her prophecy.', 'public', '["curse","scaffold","prophecy"]', 'salem_project', 1.0, NULL, 1775266565625, 1775266565625, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('quote_giles_corey_more_weight', 'Giles Corey demands ''More weight!''', 'During his pressing to death, when asked to enter a plea, Giles Corey''s only response was to demand more weight be added. As Robert Calef recorded: ''In the pressing, Giles Corey''s tongue was pressed out of his mouth; the Sheriff, with his cane, forced it in again.''', '1692-09-19', 'exact', 'quote', 'execution', NULL, 'giles_corey', 'births_deaths_illness_research.md', 'Giles Corey demands ''More weight!''. During his pressing to death, when asked to enter a plea, Giles Corey''s only response was to demand more weight be added. As Robert Calef recorded: ''In the pressing, Giles Corey''s tongue was pressed out of his mouth; the Sheriff, with his cane, forced it in again.''', 'public', '["pressing","defiance","last_words"]', 'salem_project', 1.0, NULL, 1775266565626, 1775266565626, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('quote_proctor_hang_them', 'John Proctor declares accusers should be hanged', 'John Proctor publicly confronted the proceedings, declaring the accusers were frauds who should be punished rather than believed. His outspokenness was precisely what led to his own accusation and execution.', '1692-03', 'month', 'quote', 'opposition', NULL, 'john_proctor', 'micro_events_daily_chronicle.md', 'John Proctor declares accusers should be hanged. John Proctor publicly confronted the proceedings, declaring the accusers were frauds who should be punished rather than believed. His outspokenness was precisely what led to his own accusation and execution.', 'public', '["opposition","accusers","defiance"]', 'salem_project', 1.0, NULL, 1775266565626, 1775266565626, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('quote_proctor_prison_letter', 'John Proctor''s letter from prison to Boston clergy', 'Written from prison to Boston clergy, Proctor described torture of prisoners: being tied ''neck and heels'' until blood ran from their noses. He called these ''Popish cruelties'' and pleaded for ministers to attend his trial.', '1692-07-23', 'exact', 'quote', 'petition', NULL, 'john_proctor', 'micro_events_daily_chronicle.md', 'John Proctor''s letter from prison to Boston clergy. Written from prison to Boston clergy, Proctor described torture of prisoners: being tied ''neck and heels'' until blood ran from their noses. He called these ''Popish cruelties'' and pleaded for ministers to attend his trial.', 'public', '["prison_letter","torture","innocence"]', 'salem_project', 1.0, NULL, 1775266565626, 1775266565626, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('quote_proctor_torture_details', 'Proctor describes prisoners tied ''neck and heels''', 'In his prison letter, Proctor detailed how his son William Proctor was beaten until ''blood was ready to come out their noses.'' One officer showed mercy by releasing William, though threatening to keep him bound 24 hours. Proctor called these methods ''very like the Popish cruelties'' and requested trials be moved to Boston or magistrates changed.', '1692-07-23', 'exact', 'quote', 'petition', NULL, 'john_proctor', 'micro_events_daily_chronicle.md', 'Proctor describes prisoners tied ''neck and heels''. In his prison letter, Proctor detailed how his son William Proctor was beaten until ''blood was ready to come out their noses.'' One officer showed mercy by releasing William, though threatening to keep him bound 24 hours. Proctor called these methods ''very like the Popish cruelties'' and requested trials be moved to Boston or magistrates changed.', 'semi_private', '["torture","prison","popish"]', 'salem_project', 1.0, NULL, 1775266565626, 1775266565626, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('quote_easty_farewell_petition', 'Mary Easty''s farewell petition — ''no more innocent blood be shed''', 'Written from prison before her execution on September 22, 1692. Widely considered the most moving document from the trials. She pleaded not for her own life but for others who would follow. Reportedly, many in the audience wept as she said farewell at the gallows.', '1692-09', 'month', 'quote', 'petition', NULL, 'mary_easty', 'micro_events_daily_chronicle.md', 'Mary Easty''s farewell petition — ''no more innocent blood be shed''. Written from prison before her execution on September 22, 1692. Widely considered the most moving document from the trials. She pleaded not for her own life but for others who would follow. Reportedly, many in the audience wept as she said farewell at the gallows.', 'public', '["farewell","petition","innocence","moving"]', 'salem_project', 1.0, NULL, 1775266565626, 1775266565626, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('quote_easty_belied_themselves', 'Mary Easty declares accusers ''belied themselves''', 'In her farewell petition, Mary Easty declared her confidence that the truth would emerge, even if only in the next world.', '1692-09', 'month', 'quote', 'petition', NULL, 'mary_easty', 'micro_events_daily_chronicle.md', 'Mary Easty declares accusers ''belied themselves''. In her farewell petition, Mary Easty declared her confidence that the truth would emerge, even if only in the next world.', 'public', '["farewell","accusers","lies"]', 'salem_project', 1.0, NULL, 1775266565626, 1775266565626, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('quote_easty_tribunal_seat', 'Mary Easty — ''I know not the least thing of witchcraft''', 'Mary Easty''s final plea, invoking divine judgment as her witness.', '1692-09', 'month', 'quote', 'petition', NULL, 'mary_easty', 'micro_events_daily_chronicle.md', 'Mary Easty — ''I know not the least thing of witchcraft''. Mary Easty''s final plea, invoking divine judgment as her witness.', 'public', '["farewell","innocence","divine_judgment"]', 'salem_project', 1.0, NULL, 1775266565626, 1775266565626, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('quote_corey_gospel_woman', 'Martha Corey declares herself ''a gospel woman''', 'At her examination on March 21, 1692, Martha Corey boldly maintained her innocence. The afflicted girls mockingly called her ''a gospel witch'' in response.', '1692-03-21', 'exact', 'quote', 'examination', NULL, 'martha_corey', 'micro_events_daily_chronicle.md', 'Martha Corey declares herself ''a gospel woman''. At her examination on March 21, 1692, Martha Corey boldly maintained her innocence. The afflicted girls mockingly called her ''a gospel witch'' in response.', 'public', '["examination","innocence","defiance"]', 'salem_project', 1.0, NULL, 1775266565626, 1775266565626, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('quote_joseph_putnam_threat', 'Joseph Putnam threatens armed resistance to his brother''s family', 'Joseph Putnam, youngest brother of the persecuting Thomas Putnam, confronted Ann Putnam Sr. directly. For six months afterward, one of his fleetest horses was kept saddled at all times and his family was armed to guarantee their escape.', NULL, NULL, 'quote', 'opposition', NULL, 'joseph_putnam', 'micro_events_daily_chronicle.md', 'Joseph Putnam threatens armed resistance to his brother''s family. Joseph Putnam, youngest brother of the persecuting Thomas Putnam, confronted Ann Putnam Sr. directly. For six months afterward, one of his fleetest horses was kept saddled at all times and his family was armed to guarantee their escape.', 'semi_private', '["threat","armed_resistance","family_split"]', 'salem_project', 1.0, NULL, 1775266565626, 1775266565626, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('quote_warren_dissemble', 'Mary Warren declares ''the afflicted persons did but dissemble''', 'After John Proctor put her to work at the spinning wheel and threatened to beat her if she pretended to have fits, Mary Warren''s fits ceased. She confessed that the afflictions were fabricated. She was then accused of witchcraft by the other girls on April 18 and reversed her recantation under pressure in prison.', '1692-04-03', 'exact', 'quote', 'recantation', NULL, 'mary_warren', 'micro_events_daily_chronicle.md', 'Mary Warren declares ''the afflicted persons did but dissemble''. After John Proctor put her to work at the spinning wheel and threatened to beat her if she pretended to have fits, Mary Warren''s fits ceased. She confessed that the afflictions were fabricated. She was then accused of witchcraft by the other girls on April 18 and reversed her recantation under pressure in prison.', 'public', '["recantation","dissemble","fabrication"]', 'salem_project', 1.0, NULL, 1775266565626, 1775266565626, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('quote_for_sport', 'Afflicted girls admit they are doing it ''for sport''', 'William Rayment and Daniel Elliot were at Ingersoll''s tavern with some of the afflicted girls. When one girl declared ''Goody Proctor, old witch, I''ll have her hang,'' Hannah Collins Ingersoll (Nathaniel''s wife) rebuked them. The girls then admitted they were doing it ''for sport, they must have some sport.'' This is one of the most damning admissions in the entire record — the accusers openly confessing in Ingersoll''s barroom that they were sending innocent people to their deaths for entertainment.', '1692-03-28', 'exact', 'quote', 'admission', NULL, 'nathaniel_ingersoll', 'micro_events_daily_chronicle.md', 'Afflicted girls admit they are doing it ''for sport''. William Rayment and Daniel Elliot were at Ingersoll''s tavern with some of the afflicted girls. When one girl declared ''Goody Proctor, old witch, I''ll have her hang,'' Hannah Collins Ingersoll (Nathaniel''s wife) rebuked them. The girls then admitted they were doing it ''for sport, they must have some sport.'' This is one of the most damning admissions in the entire record — the accusers openly confessing in Ingersoll''s barroom that they were sending innocent people to their deaths for entertainment.', 'semi_private', '["admission","for_sport","fraud","ingersoll"]', 'salem_project', 1.0, NULL, 1775266565626, 1775266565626, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('quote_parris_satan_sermon', 'Parris warns of Satan''s drift to ''pull it all down''', 'Well before the afflictions, Parris''s January 3, 1692 sermon warned of satanic invasion. This sermon primed the community to interpret the forthcoming afflictions through a supernatural lens.', '1692-01-03', 'exact', 'quote', 'sermon', NULL, 'samuel_parris', 'occupational_knowledge_map.md', 'Parris warns of Satan''s drift to ''pull it all down''. Well before the afflictions, Parris''s January 3, 1692 sermon warned of satanic invasion. This sermon primed the community to interpret the forthcoming afflictions through a supernatural lens.', 'public', '["sermon","satan","warning"]', 'salem_project', 1.0, NULL, 1775266565626, 1775266565626, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('quote_parris_witches_covenant', 'Parris declares witches in covenant with the Devil are among them', 'In a February 1692 sermon, Parris declared the existence of witches in New England. This sermon was heard by the entire congregation and shaped their interpretation of the girls'' afflictions.', '1692-02', 'month', 'quote', 'sermon', NULL, 'samuel_parris', 'occupational_knowledge_map.md', 'Parris declares witches in covenant with the Devil are among them. In a February 1692 sermon, Parris declared the existence of witches in New England. This sermon was heard by the entire congregation and shaped their interpretation of the girls'' afflictions.', 'public', '["sermon","witches","covenant"]', 'salem_project', 1.0, NULL, 1775266565626, 1775266565626, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('quote_parris_precious_vile', 'Parris on separating ''the precious & the vile''', 'Parris''s sermon urged a purification of the church community, implicitly justifying the identification and removal of hidden enemies.', '1692-02', 'month', 'quote', 'sermon', NULL, 'samuel_parris', 'occupational_knowledge_map.md', 'Parris on separating ''the precious & the vile''. Parris''s sermon urged a purification of the church community, implicitly justifying the identification and removal of hidden enemies.', 'public', '["sermon","purification","church_purity"]', 'salem_project', 1.0, NULL, 1775266565626, 1775266565626, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('quote_mather_frenchman_witch', 'Cotton Mather reportedly calls Philip English ''a Frenchman and a witch''', 'Cotton Mather reportedly used this phrase to describe Philip English, linking his French birth with suspicion of witchcraft. In 1692, ''French'' meant ''Catholic'' meant ''agent of the Devil'' to many Puritans.', NULL, NULL, 'quote', 'accusation', NULL, 'philip_english', 'philip_english_merchant_research.md', 'Cotton Mather reportedly calls Philip English ''a Frenchman and a witch''. Cotton Mather reportedly used this phrase to describe Philip English, linking his French birth with suspicion of witchcraft. In 1692, ''French'' meant ''Catholic'' meant ''agent of the Devil'' to many Puritans.', 'semi_private', '["french","prejudice","cotton_mather"]', 'salem_project', 1.0, NULL, 1775266565626, 1775266565626, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('quote_dorothy_good_damage', 'Dorothy Good ''so hardly used'' she lost her reason', 'William Good''s later testimony about his daughter Dorothy''s permanent mental damage from 7-8 months chained in the dungeon at age 4-5.', NULL, NULL, 'quote', 'aftermath', NULL, 'dorothy_good', 'births_deaths_illness_research.md', 'Dorothy Good ''so hardly used'' she lost her reason. William Good''s later testimony about his daughter Dorothy''s permanent mental damage from 7-8 months chained in the dungeon at age 4-5.', 'public', '["child","mental_damage","testimony"]', 'salem_project', 1.0, NULL, 1775266565626, 1775266565626, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('quote_brattle_letter', 'Thomas Brattle''s letter — ''a milestone in American literature''', 'Thomas Brattle''s letter to an unnamed English clergyman was a devastatingly logical critique of the proceedings. He challenged how accused witches could supposedly cast the afflicted into fits by a look yet not afflict every fearful woman who beheld them. He exposed how judges would order suspects to ''grasp harder'' until the afflicted came out of fits — which would happen naturally with time. Perry Miller called it ''a milestone in American literature'' for its satirical tone.', '1692-10-08', 'exact', 'quote', 'opposition', NULL, NULL, 'micro_events_daily_chronicle.md', 'Thomas Brattle''s letter — ''a milestone in American literature''. Thomas Brattle''s letter to an unnamed English clergyman was a devastatingly logical critique of the proceedings. He challenged how accused witches could supposedly cast the afflicted into fits by a look yet not afflict every fearful woman who beheld them. He exposed how judges would order suspects to ''grasp harder'' until the afflicted came out of fits — which would happen naturally with time. Perry Miller called it ''a milestone in American literature'' for its satirical tone.', 'public', '["critique","logic","brattle_letter","opposition"]', 'salem_project', 1.0, NULL, 1775266565626, 1775266565626, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('quote_wise_ipswich_revolt', 'Rev. John Wise leads Ipswich Tax Revolt against Andros', 'Rev. John Wise led the citizens of Ipswich in refusing Governor Andros''s tax, delivering one of the earliest articulations of no-taxation-without-representation in American history. Wise and others were arrested, tried in Boston, imprisoned, and fined heavily.', '1687-08-23', 'exact', 'quote', 'resistance', NULL, NULL, 'political_events_charter_research.md', 'Rev. John Wise leads Ipswich Tax Revolt against Andros. Rev. John Wise led the citizens of Ipswich in refusing Governor Andros''s tax, delivering one of the earliest articulations of no-taxation-without-representation in American history. Wise and others were arrested, tried in Boston, imprisoned, and fined heavily.', 'public', '["ipswich","tax_revolt","andros","resistance"]', 'salem_project', 1.0, NULL, 1775266565626, 1775266565626, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('quote_waldron_bite_now', 'Native warriors taunt Major Waldron: ''bite now''', 'During the Dover massacre, Major Richard Waldron (age 73) was dragged from his bed, placed in a chair, tortured with his own sword. His nose and ears were cut off, his fingers forced into his mouth with the taunt ''bite now'' — revenge for his treachery in 1676 when he tricked ~200 Indians into a sham training exercise and sold many into slavery.', '1689-06-27', 'exact', 'quote', 'military', NULL, NULL, 'frontier_war_timeline_research.md', 'Native warriors taunt Major Waldron: ''bite now''. During the Dover massacre, Major Richard Waldron (age 73) was dragged from his bed, placed in a chair, tortured with his own sword. His nose and ears were cut off, his fingers forced into his mouth with the taunt ''bite now'' — revenge for his treachery in 1676 when he tricked ~200 Indians into a sham training exercise and sold many into slavery.', 'public', '["dover_massacre","revenge","frontier_war"]', 'salem_project', 1.0, NULL, 1775266565626, 1775266565626, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('quote_calef_corey_tongue', 'Robert Calef records Sheriff forcing Corey''s tongue back in', 'Robert Calef''s eyewitness account of Giles Corey''s pressing, recording the gruesome detail of the Sheriff''s intervention.', '1692-09-19', 'exact', 'quote', 'execution', NULL, 'giles_corey', 'births_deaths_illness_research.md', 'Robert Calef records Sheriff forcing Corey''s tongue back in. Robert Calef''s eyewitness account of Giles Corey''s pressing, recording the gruesome detail of the Sheriff''s intervention.', 'public', '["pressing","eyewitness","calef"]', 'salem_project', 1.0, NULL, 1775266565626, 1775266565626, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('quote_andros_land_titles', 'Contemporary on Andros''s land title challenge — ''exasperation of the Colonists''', 'A contemporary writer captured the horror of Andros''s claim that no inhabitant of Massachusetts had valid title to their land, requiring expensive new Crown patents for land families had worked for decades.', NULL, NULL, 'quote', 'political', NULL, NULL, 'political_events_charter_research.md', 'Contemporary on Andros''s land title challenge — ''exasperation of the Colonists''. A contemporary writer captured the horror of Andros''s claim that no inhabitant of Massachusetts had valid title to their land, requiring expensive new Crown patents for land families had worked for decades.', 'public', '["andros","land_titles","exasperation"]', 'salem_project', 1.0, NULL, 1775266565626, 1775266565626, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('quote_griggs_evil_hand', 'Dr. Griggs declares the girls are ''under an Evil Hand''', 'After ruling out epilepsy and finding medications ineffective, Dr. William Griggs declared the afflicted girls were ''under an Evil Hand.'' This medical diagnosis of supernatural causation was the pivotal moment that transformed a household crisis into a community-wide witch hunt.', '1692-02', 'month', 'quote', 'diagnosis', NULL, 'william_griggs', 'births_deaths_illness_research.md', 'Dr. Griggs declares the girls are ''under an Evil Hand''. After ruling out epilepsy and finding medications ineffective, Dr. William Griggs declared the afflicted girls were ''under an Evil Hand.'' This medical diagnosis of supernatural causation was the pivotal moment that transformed a household crisis into a community-wide witch hunt.', 'public', '["diagnosis","evil_hand","supernatural","pivotal"]', 'salem_project', 1.0, NULL, 1775266565626, 1775266565626, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('quote_nurse_petition', '39 signers testify they ''have knowne her for many years''', '39 Salem residents signed a petition for Rebecca Nurse, testifying that they ''have knowne her for many years'' and ''her Life and conversation was Acording to her profession.'' The petition was organized by her husband Francis Nurse.', '1692-06', 'month', 'quote', 'petition', NULL, 'rebecca_nurse', 'micro_events_daily_chronicle.md', '39 signers testify they ''have knowne her for many years''. 39 Salem residents signed a petition for Rebecca Nurse, testifying that they ''have knowne her for many years'' and ''her Life and conversation was Acording to her profession.'' The petition was organized by her husband Francis Nurse.', 'public', '["petition","character_witness","39_signers"]', 'salem_project', 1.0, NULL, 1775266565626, 1775266565626, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('quote_jail_conditions', 'Salem jail — ''perpetually dark, bitterly cold''', 'Description of the Salem jail dungeons where accused witches were chained. At its peak, 150 accused were held in a building approximately 20 feet square.', NULL, NULL, 'quote', 'prison', NULL, NULL, 'births_deaths_illness_research.md', 'Salem jail — ''perpetually dark, bitterly cold''. Description of the Salem jail dungeons where accused witches were chained. At its peak, 150 accused were held in a building approximately 20 feet square.', 'public', '["jail","conditions","darkness","chains"]', 'salem_project', 1.0, NULL, 1775266565626, 1775266565626, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('quote_lighting_room', 'Lighting an entire room ''beyond the settler''s wildest dreams''', 'A single tallow candle could not light a room. The profound darkness of colonial interiors was far beyond what modern people can imagine.', NULL, NULL, 'quote', 'sensory', NULL, NULL, 'physical_sensory_details_research.md', 'Lighting an entire room ''beyond the settler''s wildest dreams''. A single tallow candle could not light a room. The profound darkness of colonial interiors was far beyond what modern people can imagine.', 'public', '["lighting","candles","darkness"]', 'salem_project', 1.0, NULL, 1775266565626, 1775266565626, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('quote_sewall_bread_rattled', 'Sewall records communion bread ''rattled sadly into the plates''', 'Samuel Sewall''s diary entry recording that the communion bread froze in the unheated meetinghouse and made noise when broken onto the communion plates — a vivid detail about Puritan worship conditions.', NULL, NULL, 'quote', 'sensory', NULL, 'samuel_sewall', 'physical_sensory_details_research.md', 'Sewall records communion bread ''rattled sadly into the plates''. Samuel Sewall''s diary entry recording that the communion bread froze in the unheated meetinghouse and made noise when broken onto the communion plates — a vivid detail about Puritan worship conditions.', 'public', '["cold","communion","meetinghouse","winter"]', 'salem_project', 1.0, NULL, 1775266565626, 1775266565626, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('quote_funeral_silence', 'Puritan funerals — ''completely silent, avoiding any appearance of papistry''', 'Puritan funerals had no sermons, eulogies, or music — the silence was deliberate to avoid any resemblance to Catholic rites. Bodies were wrapped in coffins ''in tar with canvas.'' The community was summoned by tolling bells.', NULL, NULL, 'quote', 'custom', NULL, NULL, 'births_deaths_illness_research.md', 'Puritan funerals — ''completely silent, avoiding any appearance of papistry''. Puritan funerals had no sermons, eulogies, or music — the silence was deliberate to avoid any resemblance to Catholic rites. Bodies were wrapped in coffins ''in tar with canvas.'' The community was summoned by tolling bells.', 'public', '["funeral","silence","papistry","custom"]', 'salem_project', 1.0, NULL, 1775266565626, 1775266565626, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('quote_laymen_on_courts', 'Colonial courts — ''laymen such as artisans could be found sitting on higher courts''', 'Most colonial magistrates had no formal legal training. The Court of Oyer and Terminer''s nine judges judged capital cases based on instinct and what they knew of English law rather than professional legal education.', NULL, NULL, 'quote', 'legal', NULL, NULL, 'occupational_knowledge_map.md', 'Colonial courts — ''laymen such as artisans could be found sitting on higher courts''. Most colonial magistrates had no formal legal training. The Court of Oyer and Terminer''s nine judges judged capital cases based on instinct and what they knew of English law rather than professional legal education.', 'public', '["legal","courts","untrained","magistrates"]', 'salem_project', 1.0, NULL, 1775266565626, 1775266565626, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('quote_constable_neighbor', 'The constable''s burden — arresting neighbors he had known for decades', 'A constable''s duties during the crisis meant knocking on the door of a neighbor he had known for decades, showing a warrant, and taking them into custody. People he had worked beside at harvest, worshipped beside on Sunday, shared cider with at Ingersoll''s.', NULL, NULL, 'quote', 'emotional', NULL, NULL, 'occupational_knowledge_map.md', 'The constable''s burden — arresting neighbors he had known for decades. A constable''s duties during the crisis meant knocking on the door of a neighbor he had known for decades, showing a warrant, and taking them into custody. People he had worked beside at harvest, worshipped beside on Sunday, shared cider with at Ingersoll''s.', 'public', '["constable","emotional_burden","neighbors"]', 'salem_project', 1.0, NULL, 1775266565626, 1775266565626, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('quote_first_paper_money', 'Massachusetts issues first paper bills of credit in Western world', 'Massachusetts issued the first paper bills of credit in the Western world in 1690, driven by the need to pay soldiers from the failed Quebec expedition. This was a revolutionary financial innovation born of desperation.', '1690', 'year', 'quote', 'economic', NULL, NULL, 'occupational_knowledge_map.md', 'Massachusetts issues first paper bills of credit in Western world. Massachusetts issued the first paper bills of credit in the Western world in 1690, driven by the need to pay soldiers from the failed Quebec expedition. This was a revolutionary financial innovation born of desperation.', 'public', '["paper_money","bills_of_credit","innovation"]', 'salem_project', 1.0, NULL, 1775266565626, 1775266565626, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('quote_noyes_firebrands', 'Rev. Noyes calls the eight hanged bodies ''firebrands of Hell''', 'After the last executions on September 22, 1692, Rev. Nicholas Noyes turned to the eight bodies hanging on Gallows Hill and made this statement. He would later die choking on his own blood in 1717 — some viewed it as fulfillment of Sarah Good''s scaffold curse.', '1692-09-22', 'exact', 'quote', 'execution', NULL, 'nicholas_noyes', 'micro_events_daily_chronicle.md', 'Rev. Noyes calls the eight hanged bodies ''firebrands of Hell''. After the last executions on September 22, 1692, Rev. Nicholas Noyes turned to the eight bodies hanging on Gallows Hill and made this statement. He would later die choking on his own blood in 1717 — some viewed it as fulfillment of Sarah Good''s scaffold curse.', 'public', '["firebrands","last_executions","noyes"]', 'salem_project', 1.0, NULL, 1775266565626, 1775266565626, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('quote_parris_devils_saints', 'Parris warns: ''There are Devils as well as Saints in Christs Church''', 'In his March 27, 1692 sermon on John 6:70, Parris declared ''dreadful Witchcraft broke out here a few weeks past'' and warned ''There are Devils as well as Saints in Christs Church.'' He noted that one member of his own church was ''vehemently suspected for Shee-Witches.''', '1692-03-27', 'exact', 'quote', 'sermon', NULL, 'samuel_parris', 'micro_events_daily_chronicle.md', 'Parris warns: ''There are Devils as well as Saints in Christs Church''. In his March 27, 1692 sermon on John 6:70, Parris declared ''dreadful Witchcraft broke out here a few weeks past'' and warned ''There are Devils as well as Saints in Christs Church.'' He noted that one member of his own church was ''vehemently suspected for Shee-Witches.''', 'public', '["sermon","devils","saints","church"]', 'salem_project', 1.0, NULL, 1775266565626, 1775266565626, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('quote_lewis_pitchforks', 'Mercy Lewis: ''I would not writ if he had throwed me down on one hundred pitchforks''', 'Mercy Lewis''s testimony at George Burroughs''s trial: Burroughs ''flew her to the top of a mountain'' and promised her ''all the kingdoms if only she would sign in his book.'' Her defiant response captured the dramatic spectacle of the trials.', '1692-08', 'month', 'quote', 'testimony', NULL, 'mercy_lewis', 'micro_events_daily_chronicle.md', 'Mercy Lewis: ''I would not writ if he had throwed me down on one hundred pitchforks''. Mercy Lewis''s testimony at George Burroughs''s trial: Burroughs ''flew her to the top of a mountain'' and promised her ''all the kingdoms if only she would sign in his book.'' Her defiant response captured the dramatic spectacle of the trials.', 'public', '["testimony","pitchforks","burroughs","mountain"]', 'salem_project', 1.0, NULL, 1775266565627, 1775266565627, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('quote_susannah_martin_folly', 'Susannah Martin to magistrate: ''Well I may at such folly''', 'When the magistrate asked Susannah Martin ''What do you laugh at it?'' during her examination, she boldly replied with contempt for the proceedings. She was executed July 19.', '1692-05-02', 'exact', 'quote', 'examination', NULL, NULL, 'micro_events_daily_chronicle.md', 'Susannah Martin to magistrate: ''Well I may at such folly''. When the magistrate asked Susannah Martin ''What do you laugh at it?'' during her examination, she boldly replied with contempt for the proceedings. She was executed July 19.', 'public', '["defiance","laughter","examination"]', 'salem_project', 1.0, NULL, 1775266565627, 1775266565627, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('quote_hale_walked_in_clouds', 'Rev. Hale: ''We walked in the clouds and could not see our way''', 'After his own wife was accused, Rev. John Hale wrote a book reassessing the trials. This phrase captured the collective blindness that gripped the community during the crisis.', NULL, NULL, 'quote', 'aftermath', NULL, 'john_hale', 'micro_events_daily_chronicle.md', 'Rev. Hale: ''We walked in the clouds and could not see our way''. After his own wife was accused, Rev. John Hale wrote a book reassessing the trials. This phrase captured the collective blindness that gripped the community during the crisis.', 'public', '["reflection","blindness","hale"]', 'salem_project', 1.0, NULL, 1775266565627, 1775266565627, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('quote_watts_brother_against_brother', 'Watts laments: ''Brother is against brother...all quarreling and smiting one another''', 'Jeremiah Watts captured the deep divisions in Salem Village a full decade before the witch crisis, showing that the factional warfare had roots far deeper than 1692.', '1682-04', 'month', 'quote', 'social', NULL, NULL, 'village_disputes_research.md', 'Watts laments: ''Brother is against brother...all quarreling and smiting one another''. Jeremiah Watts captured the deep divisions in Salem Village a full decade before the witch crisis, showing that the factional warfare had roots far deeper than 1692.', 'public', '["lament","division","1682"]', 'salem_project', 1.0, NULL, 1775266565627, 1775266565627, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('quote_increase_mather_ten_escape', 'Increase Mather: ''Better ten suspected witches escape than one innocent condemned''', 'Increase Mather addressed a gathering of ministers with his Cases of Conscience Concerning Evil Spirits, arguing that spectral evidence was insufficient for conviction. This was one of the key statements that helped end the trials.', '1692-10-03', 'exact', 'quote', 'opposition', NULL, NULL, 'micro_events_daily_chronicle.md', 'Increase Mather: ''Better ten suspected witches escape than one innocent condemned''. Increase Mather addressed a gathering of ministers with his Cases of Conscience Concerning Evil Spirits, arguing that spectral evidence was insufficient for conviction. This was one of the key statements that helped end the trials.', 'public', '["increase_mather","better_ten","spectral_evidence"]', 'salem_project', 1.0, NULL, 1775266565627, 1775266565627, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('quote_parris_going_to_devil', 'Parris on the witch cake: ''going to the Devil for help against the Devil''', 'When Parris discovered that Mary Sibley had instructed Tituba to bake a witch cake, he was furious at the use of folk magic to counter suspected witchcraft. He gave Sibley a stern private lecture before requiring her public confession.', '1692-03', 'month', 'quote', 'rebuke', NULL, 'samuel_parris', 'micro_events_daily_chronicle.md', 'Parris on the witch cake: ''going to the Devil for help against the Devil''. When Parris discovered that Mary Sibley had instructed Tituba to bake a witch cake, he was furious at the use of folk magic to counter suspected witchcraft. He gave Sibley a stern private lecture before requiring her public confession.', 'semi_private', '["witch_cake","folk_magic","rebuke"]', 'salem_project', 1.0, NULL, 1775266565627, 1775266565627, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('hearings_relocated_march_1', 'First examinations relocated from Ingersoll''s to Meetinghouse', 'The initial examinations of Tituba, Sarah Good, and Sarah Osborne were scheduled for Ingersoll''s barroom. When hundreds of spectators arrived, the proceedings were moved to the Salem Village Meetinghouse. Judges, spectators, and accused returned to the tavern afterward for meals and drinks during recesses.', '1692-03-01', 'exact', 'incident', 'examination', NULL, 'tituba', 'micro_events_daily_chronicle.md', 'First examinations relocated from Ingersoll''s to Meetinghouse. The initial examinations of Tituba, Sarah Good, and Sarah Osborne were scheduled for Ingersoll''s barroom. When hundreds of spectators arrived, the proceedings were moved to the Salem Village Meetinghouse. Judges, spectators, and accused returned to the tavern afterward for meals and drinks during recesses.', 'public', '["first_examinations","crowd","relocated"]', 'salem_project', 1.0, NULL, 1775266565627, 1775266565627, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('lawson_arrival_walcott_bite', 'Lawson arrives at Ingersoll''s, Mary Walcott shows bite marks', 'Rev. Deodat Lawson, former Salem Village minister (1684-1688), arrived at Ingersoll''s Ordinary from Boston. He had been summoned after hearing a confessor claimed his wife and child had perished by witchcraft. Mary Walcott (17) came to speak with him, and as she prepared to leave, claimed to have been bitten on her wrist. Lawson and Ingersoll examined the wrist and observed what looked like upper and lower teeth marks. Historian Frances Hill suggests this may have been the first example of deliberately fraudulent behavior by the accusers.', '1692-03-19', 'exact', 'incident', 'affliction', NULL, 'mary_walcott', 'micro_events_daily_chronicle.md', 'Lawson arrives at Ingersoll''s, Mary Walcott shows bite marks. Rev. Deodat Lawson, former Salem Village minister (1684-1688), arrived at Ingersoll''s Ordinary from Boston. He had been summoned after hearing a confessor claimed his wife and child had perished by witchcraft. Mary Walcott (17) came to speak with him, and as she prepared to leave, claimed to have been bitten on her wrist. Lawson and Ingersoll examined the wrist and observed what looked like upper and lower teeth marks. Historian Frances Hill suggests this may have been the first example of deliberately fraudulent behavior by the accusers.', 'public', '["lawson","bite_marks","fraud","affliction"]', 'salem_project', 1.0, NULL, 1775266565627, 1775266565627, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('spectral_duel_burroughs', 'Abigail Williams and Benjamin Hutchinson fight Burroughs''s specter at Ingersoll''s', 'Abigail Williams, walking past the ordinary, claimed to see the specter of accused witch George Burroughs standing in the road. Benjamin Hutchinson (Ingersoll''s foster son) threw his pitchfork at the invisible entity. Williams entered the barroom, still claiming to see the apparition. Hutchinson drew his rapier and attempted to stab the invisible entity while Williams directed his movements. She also claimed a ghostly cat was present, which Hutchinson allegedly fought and killed — visible only to Williams. This entire episode played out in the public barroom before witnesses.', '1692-04-21', 'exact', 'incident', 'spectral', NULL, 'abigail_williams', 'micro_events_daily_chronicle.md', 'Abigail Williams and Benjamin Hutchinson fight Burroughs''s specter at Ingersoll''s. Abigail Williams, walking past the ordinary, claimed to see the specter of accused witch George Burroughs standing in the road. Benjamin Hutchinson (Ingersoll''s foster son) threw his pitchfork at the invisible entity. Williams entered the barroom, still claiming to see the apparition. Hutchinson drew his rapier and attempted to stab the invisible entity while Williams directed his movements. She also claimed a ghostly cat was present, which Hutchinson allegedly fought and killed — visible only to Williams. This entire episode played out in the public barroom before witnesses.', 'public', '["specter","burroughs","spectral_combat","tavern"]', 'salem_project', 1.0, NULL, 1775266565627, 1775266565627, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('john_indian_performances', 'John Indian performs fits and accusations while tending bar', 'John Indian (Tituba''s husband), enslaved by Rev. Samuel Parris, sometimes worked the tavern bar at Ingersoll''s. He displayed scars to travelers and claimed witches had attacked him. He became one of the accusers, throwing fits and making dramatic accusations while tending bar. He testified against John Proctor, among others.', NULL, NULL, 'incident', 'affliction', NULL, 'tituba', 'micro_events_daily_chronicle.md', 'John Indian performs fits and accusations while tending bar. John Indian (Tituba''s husband), enslaved by Rev. Samuel Parris, sometimes worked the tavern bar at Ingersoll''s. He displayed scars to travelers and claimed witches had attacked him. He became one of the accusers, throwing fits and making dramatic accusations while tending bar. He testified against John Proctor, among others.', 'public', '["john_indian","performances","tavern","accuser"]', 'salem_project', 1.0, NULL, 1775266565627, 1775266565627, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('bishop_flogs_john_indian', 'Edward Bishop Jr. flogs John Indian at Ingersoll''s to cure his ''affliction''', 'Edward Bishop Jr. was present at Ingersoll''s during a hearing (likely Sarah Cloyce''s in April 1692). Hearing John Indian give what Bishop considered false testimony, Bishop cured the servant of his ''affliction'' with a good flogging, and declared his belief that he could likewise cure the whole company of afflicted persons in the same manner.', '1692-04', 'month', 'incident', 'confrontation', NULL, 'nathaniel_ingersoll', 'micro_events_daily_chronicle.md', 'Edward Bishop Jr. flogs John Indian at Ingersoll''s to cure his ''affliction''. Edward Bishop Jr. was present at Ingersoll''s during a hearing (likely Sarah Cloyce''s in April 1692). Hearing John Indian give what Bishop considered false testimony, Bishop cured the servant of his ''affliction'' with a good flogging, and declared his belief that he could likewise cure the whole company of afflicted persons in the same manner.', 'public', '["flogging","cure","skepticism","bishop"]', 'salem_project', 1.0, NULL, 1775266565627, 1775266565627, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('ingersoll_files_complaints', 'Nathaniel Ingersoll files 11 complaints despite wife hearing ''for sport'' confession', 'Ingersoll himself, with two other men, filed 11 complaints against accused witches during April and May 1692, despite his wife Hannah having witnessed the afflicted girls'' ''for sport'' confession on March 28. This remains one of the deepest ambiguities of the crisis.', '1692-04', 'month', 'incident', 'legal', NULL, 'nathaniel_ingersoll', 'micro_events_daily_chronicle.md', 'Nathaniel Ingersoll files 11 complaints despite wife hearing ''for sport'' confession. Ingersoll himself, with two other men, filed 11 complaints against accused witches during April and May 1692, despite his wife Hannah having witnessed the afflicted girls'' ''for sport'' confession on March 28. This remains one of the deepest ambiguities of the crisis.', 'public', '["complaints","ambiguity","for_sport"]', 'salem_project', 1.0, NULL, 1775266565627, 1775266565627, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('good_begging_abbey', 'Sarah Good lodges with the Abbeys, expelled, their cattle sicken', 'Samuel and Mary Abbey gave Sarah Good lodgings for a time. They later testified she was ''so turbulent a spirit, spiteful and so maliciously bent'' that they expelled her. Afterward, their cattle mysteriously sickened — testimony they used against her at trial.', NULL, NULL, 'incident', 'confrontation', NULL, 'sarah_good', 'micro_events_daily_chronicle.md', 'Sarah Good lodges with the Abbeys, expelled, their cattle sicken. Samuel and Mary Abbey gave Sarah Good lodgings for a time. They later testified she was ''so turbulent a spirit, spiteful and so maliciously bent'' that they expelled her. Afterward, their cattle mysteriously sickened — testimony they used against her at trial.', 'public', '["begging","cattle","witchcraft_evidence"]', 'salem_project', 1.0, NULL, 1775266565627, 1775266565627, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('good_begging_gadge', 'Sarah Good refused by Sarah Gadge, cow dies next day', 'Sarah Gadge refused Good entry to her home. Good ''muttered something under her breath'' as she walked away. Gadge''s cow died the next day — presented as evidence of witchcraft at trial.', NULL, NULL, 'incident', 'confrontation', NULL, 'sarah_good', 'micro_events_daily_chronicle.md', 'Sarah Good refused by Sarah Gadge, cow dies next day. Sarah Gadge refused Good entry to her home. Good ''muttered something under her breath'' as she walked away. Gadge''s cow died the next day — presented as evidence of witchcraft at trial.', 'public', '["begging","muttering","cow_death","witchcraft_evidence"]', 'salem_project', 1.0, NULL, 1775266565627, 1775266565627, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('corey_examination_march_21', 'Martha Corey''s examination — laughing at the accusers, shoe thrown at her head', 'Lawson''s eyewitness account: ''About twelve of the Clock, they went into the Meeting-House, which was Thronged with Spectators.'' Corey asked to deliver an opening prayer, ''which was much wondred at, in the presence of so many hundred people.'' The magistrates refused. The afflicted mimicked her every movement — when she bit her lip, they were bitten; when she pinched her fingers, they were pinched. Bathsheba Pope threw first her muff and then her shoe at Corey, hitting her in the head. Mercy Lewis called out a man whispered in Corey''s ear. Ann Putnam Jr. cried out Corey had a yellow bird sucking on her hand.', '1692-03-21', 'exact', 'incident', 'examination', NULL, 'martha_corey', 'micro_events_daily_chronicle.md', 'Martha Corey''s examination — laughing at the accusers, shoe thrown at her head. Lawson''s eyewitness account: ''About twelve of the Clock, they went into the Meeting-House, which was Thronged with Spectators.'' Corey asked to deliver an opening prayer, ''which was much wondred at, in the presence of so many hundred people.'' The magistrates refused. The afflicted mimicked her every movement — when she bit her lip, they were bitten; when she pinched her fingers, they were pinched. Bathsheba Pope threw first her muff and then her shoe at Corey, hitting her in the head. Mercy Lewis called out a man whispered in Corey''s ear. Ann Putnam Jr. cried out Corey had a yellow bird sucking on her hand.', 'public', '["examination","mimicry","spectacle","shoe"]', 'salem_project', 1.0, NULL, 1775266565627, 1775266565627, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('proctor_cures_warren_spinning', 'John Proctor cures Mary Warren''s fits by putting her to work', 'When his servant Mary Warren began having fits in March 1692, John Proctor put her to work at the spinning wheel, threatening to beat her if she pretended to have any more fits. Her fits ceased immediately — demonstrating that at least some afflictions could be cured by the threat of physical discipline rather than spiritual intervention.', '1692-03', 'month', 'incident', 'confrontation', NULL, 'john_proctor', 'micro_events_daily_chronicle.md', 'John Proctor cures Mary Warren''s fits by putting her to work. When his servant Mary Warren began having fits in March 1692, John Proctor put her to work at the spinning wheel, threatening to beat her if she pretended to have any more fits. Her fits ceased immediately — demonstrating that at least some afflictions could be cured by the threat of physical discipline rather than spiritual intervention.', 'semi_private', '["cure","spinning_wheel","discipline","fits"]', 'salem_project', 1.0, NULL, 1775266565627, 1775266565627, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('cloyce_walkout', 'Sarah Cloyce slams the meetinghouse door in protest', 'On Sacrament Day, April 3, 1692, when Parris announced his biblical text would be John 6:70 — ''Have not I chosen you twelve, and one is a devil'' — covenanted church member Sarah Cloyce, sister of the already-accused Rebecca Nurse, violently fled the meetinghouse and ''flung the door after her.'' This act of protest and solidarity with her sister led directly to her own accusation of witchcraft.', '1692-04-03', 'exact', 'incident', 'protest', NULL, 'sarah_cloyce', 'micro_events_daily_chronicle.md', 'Sarah Cloyce slams the meetinghouse door in protest. On Sacrament Day, April 3, 1692, when Parris announced his biblical text would be John 6:70 — ''Have not I chosen you twelve, and one is a devil'' — covenanted church member Sarah Cloyce, sister of the already-accused Rebecca Nurse, violently fled the meetinghouse and ''flung the door after her.'' This act of protest and solidarity with her sister led directly to her own accusation of witchcraft.', 'public', '["walkout","protest","sacrament_day","solidarity"]', 'salem_project', 1.0, NULL, 1775266565627, 1775266565627, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('warren_recovery_notice', 'Mary Warren posts recovery notice on meetinghouse door', 'On April 2, 1692, Mary Warren posted a recovery notice on the Meeting House door after her fits stopped under Proctor''s discipline. The next day, Parris read her note to church members. Some interpreted her words to mean the girls had lied. Warren told them she felt better and could tell the difference between reality and visions.', '1692-04-02', 'exact', 'incident', 'recantation', NULL, 'mary_warren', 'micro_events_daily_chronicle.md', 'Mary Warren posts recovery notice on meetinghouse door. On April 2, 1692, Mary Warren posted a recovery notice on the Meeting House door after her fits stopped under Proctor''s discipline. The next day, Parris read her note to church members. Some interpreted her words to mean the girls had lied. Warren told them she felt better and could tell the difference between reality and visions.', 'public', '["recovery","recantation","meetinghouse_door"]', 'salem_project', 1.0, NULL, 1775266565627, 1775266565627, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('warren_accused_april_18', 'Mary Warren accused of witchcraft for telling the truth', 'On April 18, 1692, the other afflicted girls turned on Mary Warren. She was formally accused of witchcraft because she had told the court ''that all the girls were lying that they saw the devil.'' Under pressure in prison, she reversed her recantation and resumed her role as accuser.', '1692-04-18', 'exact', 'incident', 'accusation', NULL, 'mary_warren', 'micro_events_daily_chronicle.md', 'Mary Warren accused of witchcraft for telling the truth. On April 18, 1692, the other afflicted girls turned on Mary Warren. She was formally accused of witchcraft because she had told the court ''that all the girls were lying that they saw the devil.'' Under pressure in prison, she reversed her recantation and resumed her role as accuser.', 'public', '["accused","truth_telling","silenced"]', 'salem_project', 1.0, NULL, 1775266565627, 1775266565627, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('margaret_jacobs_recantation', 'Margaret Jacobs recants testimony against her grandfather', 'Margaret Jacobs accused her own grandfather George Jacobs Sr. to save herself. After his death sentence was pronounced, she had a change of heart, wrote to magistrates to retract her testimony and her own confession, explained her regret to her grandfather, and he forgave her. On August 20, 1692, the day after his execution, she formally recanted her testimony.', '1692-08-20', 'exact', 'incident', 'recantation', NULL, 'george_jacobs_sr', 'micro_events_daily_chronicle.md', 'Margaret Jacobs recants testimony against her grandfather. Margaret Jacobs accused her own grandfather George Jacobs Sr. to save herself. After his death sentence was pronounced, she had a change of heart, wrote to magistrates to retract her testimony and her own confession, explained her regret to her grandfather, and he forgave her. On August 20, 1692, the day after his execution, she formally recanted her testimony.', 'public', '["recantation","grandfather","forgiveness","guilt"]', 'salem_project', 1.0, NULL, 1775266565627, 1775266565627, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('physical_examination_june_2', 'Nine women physically examine six accused witches for ''witch marks''', 'On June 2, 1692, nine women examined Bridget Bishop, Elizabeth Proctor, Rebecca Nurse, Alice Parker, Susannah Martin, and Sarah Good. They found ''a preternatural excrescence of flesh between the pudendum and anus much like to teats'' on Bishop, Nurse, and Proctor. Six hours later, marks had disappeared on Proctor and Bishop; Nurse''s appeared to be only dry skin.', '1692-06-02', 'exact', 'incident', 'examination', NULL, 'bridget_bishop', 'births_deaths_illness_research.md', 'Nine women physically examine six accused witches for ''witch marks''. On June 2, 1692, nine women examined Bridget Bishop, Elizabeth Proctor, Rebecca Nurse, Alice Parker, Susannah Martin, and Sarah Good. They found ''a preternatural excrescence of flesh between the pudendum and anus much like to teats'' on Bishop, Nurse, and Proctor. Six hours later, marks had disappeared on Proctor and Bishop; Nurse''s appeared to be only dry skin.', 'semi_private', '["physical_examination","witch_marks","teats"]', 'salem_project', 1.0, NULL, 1775266565627, 1775266565627, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('english_hides_in_laundry', 'Philip English hides under dirty laundry to avoid capture', 'Philip English had advance warning of his arrest and fled to friend George Hollard''s home in Boston. On May 6, officers came to Hollard''s house; English hid under a pile of dirty laundry and avoided capture. Eventually arrested with his wife Mary; both jailed in Boston before escaping to New York with Rev. Moody''s help.', '1692-05-06', 'exact', 'incident', 'escape', NULL, 'philip_english', 'philip_english_merchant_research.md', 'Philip English hides under dirty laundry to avoid capture. Philip English had advance warning of his arrest and fled to friend George Hollard''s home in Boston. On May 6, officers came to Hollard''s house; English hid under a pile of dirty laundry and avoided capture. Eventually arrested with his wife Mary; both jailed in Boston before escaping to New York with Rev. Moody''s help.', 'semi_private', '["escape","hiding","laundry","boston"]', 'salem_project', 1.0, NULL, 1775266565627, 1775266565627, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('english_corwin_corpse', 'Philip English seizes Sheriff Corwin''s corpse to settle debt', 'When Sheriff George Corwin died in 1697 (age ~30), Philip English reportedly seized or threatened to seize Corwin''s body, refusing to allow burial until his claims were settled. According to tradition, Corwin''s body was initially buried secretly in the basement of the Corwin house (''the Witch House'') to prevent English from seizing it. The Corwin family paid English a settlement of approximately 60 pounds, 3 shillings — a small fraction of the 1,183 pounds in seized property.', '1697', 'year', 'incident', 'aftermath', NULL, 'philip_english', 'philip_english_merchant_research.md', 'Philip English seizes Sheriff Corwin''s corpse to settle debt. When Sheriff George Corwin died in 1697 (age ~30), Philip English reportedly seized or threatened to seize Corwin''s body, refusing to allow burial until his claims were settled. According to tradition, Corwin''s body was initially buried secretly in the basement of the Corwin house (''the Witch House'') to prevent English from seizing it. The Corwin family paid English a settlement of approximately 60 pounds, 3 shillings — a small fraction of the 1,183 pounds in seized property.', 'public', '["corpse","corwin","revenge","settlement"]', 'salem_project', 1.0, NULL, 1775266565628, 1775266565628, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('porter_faction_seizes_committee', 'Porter faction seizes control of village committee, cuts Parris''s salary', 'On October 16, 1691, the Porter faction seized control of the village committee. New selectmen included Daniel Andrew (a Porter in-law), Joseph Hutchinson, Francis Nurse (involved in a bitter boundary dispute with Nathaniel Putnam), and Joseph Porter. They immediately voted down Parris''s salary tax, infuriating Thomas Putnam Jr. The accused — Daniel Andrew, Philip English, Francis Nurse, George Burroughs — mapped almost perfectly onto the Porter faction''s leadership.', '1691-10-16', 'exact', 'incident', 'political', NULL, 'daniel_andrew', 'micro_events_daily_chronicle.md', 'Porter faction seizes control of village committee, cuts Parris''s salary. On October 16, 1691, the Porter faction seized control of the village committee. New selectmen included Daniel Andrew (a Porter in-law), Joseph Hutchinson, Francis Nurse (involved in a bitter boundary dispute with Nathaniel Putnam), and Joseph Porter. They immediately voted down Parris''s salary tax, infuriating Thomas Putnam Jr. The accused — Daniel Andrew, Philip English, Francis Nurse, George Burroughs — mapped almost perfectly onto the Porter faction''s leadership.', 'public', '["committee","porter_faction","salary","political"]', 'salem_project', 1.0, NULL, 1775266565628, 1775266565628, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('prisoners_held_upstairs', 'Approximately 30 accused held prisoner in Ingersoll''s upstairs rooms', 'Those charged with witchcraft were brought to the tavern before magistrate hearings and held under lock in upstairs rooms. The three initial accused (Tituba, Good, Osborne) were among the first held there. Approximately 30 individuals total were imprisoned in the building over the course of 1692.', NULL, NULL, 'incident', 'imprisonment', NULL, 'nathaniel_ingersoll', 'micro_events_daily_chronicle.md', 'Approximately 30 accused held prisoner in Ingersoll''s upstairs rooms. Those charged with witchcraft were brought to the tavern before magistrate hearings and held under lock in upstairs rooms. The three initial accused (Tituba, Good, Osborne) were among the first held there. Approximately 30 individuals total were imprisoned in the building over the course of 1692.', 'public', '["prisoners","tavern","holding_cell"]', 'salem_project', 1.0, NULL, 1775266565628, 1775266565628, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('lawson_sermon_interrupted', 'Rev. Lawson''s sermon interrupted by afflicted girls'' fits', 'On March 20, 1692, Rev. Deodat Lawson preached at the Salem Village meetinghouse. During the service, afflicted girls disrupted the proceedings by claiming to see the spirit of Martha Corey. Abigail Williams shouted out during the sermon. Corey herself boldly attended the service, maintaining her stance as ''a gospel woman'' with visible contempt for the proceedings.', '1692-03-20', 'exact', 'incident', 'spectacle', NULL, 'martha_corey', 'micro_events_daily_chronicle.md', 'Rev. Lawson''s sermon interrupted by afflicted girls'' fits. On March 20, 1692, Rev. Deodat Lawson preached at the Salem Village meetinghouse. During the service, afflicted girls disrupted the proceedings by claiming to see the spirit of Martha Corey. Abigail Williams shouted out during the sermon. Corey herself boldly attended the service, maintaining her stance as ''a gospel woman'' with visible contempt for the proceedings.', 'public', '["sermon","interruption","lawson","spectacle"]', 'salem_project', 1.0, NULL, 1775266565628, 1775266565628, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('nurse_verdict_reversed', 'Rebecca Nurse jury returns not guilty, Stoughton sends them back', 'The jury initially returned a verdict of not guilty for Rebecca Nurse. Chief Justice Stoughton sent them back to reconsider. Nurse, who was hard of hearing, failed to respond to a question about a statement she had made during the trial. The jury interpreted her silence as an admission of guilt. The verdict was reversed to guilty.', '1692-07', 'month', 'incident', 'trial', NULL, 'rebecca_nurse', 'micro_events_daily_chronicle.md', 'Rebecca Nurse jury returns not guilty, Stoughton sends them back. The jury initially returned a verdict of not guilty for Rebecca Nurse. Chief Justice Stoughton sent them back to reconsider. Nurse, who was hard of hearing, failed to respond to a question about a statement she had made during the trial. The jury interpreted her silence as an admission of guilt. The verdict was reversed to guilty.', 'public', '["verdict","reversed","deaf","stoughton"]', 'salem_project', 1.0, NULL, 1775266565628, 1775266565628, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('burroughs_lords_prayer', 'George Burroughs recites Lord''s Prayer perfectly on the scaffold', 'On August 19, 1692, George Burroughs stood on the scaffold and recited the Lord''s Prayer perfectly — something a witch was believed to be incapable of doing. Many spectators were moved. Cotton Mather, present on horseback, urged the crowd not to be deceived, arguing the Devil could disguise himself as an angel of light.', '1692-08-19', 'exact', 'incident', 'execution', NULL, 'george_burroughs', 'micro_events_daily_chronicle.md', 'George Burroughs recites Lord''s Prayer perfectly on the scaffold. On August 19, 1692, George Burroughs stood on the scaffold and recited the Lord''s Prayer perfectly — something a witch was believed to be incapable of doing. Many spectators were moved. Cotton Mather, present on horseback, urged the crowd not to be deceived, arguing the Devil could disguise himself as an angel of light.', 'public', '["lords_prayer","scaffold","cotton_mather"]', 'salem_project', 1.0, NULL, 1775266565628, 1775266565628, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('woodlot_axe_confrontation', 'Putnam and Topsfield men threaten each other with axes in woodlots', 'In the Topsfield border dispute, Putnam clan workmen and rival Topsfield men ''threatened each other with their axes in a decidedly un-Christian manner'' in distant woodlots. The dispute originated from a 1639 clerical error in boundary records and escalated over decades.', NULL, NULL, 'incident', 'dispute', NULL, 'thomas_putnam_jr', 'micro_events_daily_chronicle.md', 'Putnam and Topsfield men threaten each other with axes in woodlots. In the Topsfield border dispute, Putnam clan workmen and rival Topsfield men ''threatened each other with their axes in a decidedly un-Christian manner'' in distant woodlots. The dispute originated from a 1639 clerical error in boundary records and escalated over decades.', 'public', '["axes","topsfield","border_dispute","confrontation"]', 'salem_project', 1.0, NULL, 1775266565628, 1775266565628, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('louder_bishop_creature', 'John Louder chases deformed creature, finds Bridget Bishop fleeing', 'John Louder testified he suspected Bridget Bishop of witchcraft after he chased off a deformed creature in his room, followed it out the back of the building, and found Bridget Bishop fleeing through her apple orchard toward her house.', NULL, NULL, 'incident', 'spectral', NULL, 'bridget_bishop', 'micro_events_daily_chronicle.md', 'John Louder chases deformed creature, finds Bridget Bishop fleeing. John Louder testified he suspected Bridget Bishop of witchcraft after he chased off a deformed creature in his room, followed it out the back of the building, and found Bridget Bishop fleeing through her apple orchard toward her house.', 'public', '["creature","spectral","testimony","bishop"]', 'salem_project', 1.0, NULL, 1775266565628, 1775266565628, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('witch_cake_february_25', 'The witch cake — urine and rye flour baked and fed to a dog', 'While the Parris family was away, neighbor Mary Sibley instructed Tituba and John Indian to bake a cake from the afflicted girls'' urine and rye flour and feed it to a dog — a folk diagnostic for witchcraft. When Parris discovered this, he was furious: ''going to the Devil for help against the Devil.'' On March 25, Mary Sibley publicly and tearfully confessed her error before the congregation.', '1692-02-25', 'exact', 'incident', 'folk_magic', NULL, 'tituba', 'micro_events_daily_chronicle.md', 'The witch cake — urine and rye flour baked and fed to a dog. While the Parris family was away, neighbor Mary Sibley instructed Tituba and John Indian to bake a cake from the afflicted girls'' urine and rye flour and feed it to a dog — a folk diagnostic for witchcraft. When Parris discovered this, he was furious: ''going to the Devil for help against the Devil.'' On March 25, Mary Sibley publicly and tearfully confessed her error before the congregation.', 'semi_private', '["witch_cake","folk_magic","urine","dog"]', 'salem_project', 1.0, NULL, 1775266565628, 1775266565628, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('abigail_interrupts_lawson_sermon', 'Abigail Williams interrupts Lawson''s sermon — ''suckling her Yellow bird!''', 'During Rev. Lawson''s guest sermon on March 20, 1692, Abigail Williams interrupted by pointing at Martha Corey and shouting: ''Look where Goodwife Cloyce sits on the beam suckling her yellow bird between her fingers!'' Then the bird supposedly swooped down and ''perched atop Lawson''s hat.'' Mrs. Bathsheba Pope also had fits during the service.', '1692-03-20', 'exact', 'incident', 'spectacle', NULL, 'abigail_williams', 'micro_events_daily_chronicle.md', 'Abigail Williams interrupts Lawson''s sermon — ''suckling her Yellow bird!''. During Rev. Lawson''s guest sermon on March 20, 1692, Abigail Williams interrupted by pointing at Martha Corey and shouting: ''Look where Goodwife Cloyce sits on the beam suckling her yellow bird between her fingers!'' Then the bird supposedly swooped down and ''perched atop Lawson''s hat.'' Mrs. Bathsheba Pope also had fits during the service.', 'public', '["interruption","yellow_bird","sermon","spectacle"]', 'salem_project', 1.0, NULL, 1775266565628, 1775266565628, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('betty_parris_black_man_vision', 'Betty Parris (age 9) reports the ''great Black Man'' offered her a golden city', 'Betty Parris, age 9, reported that ''the great Black Man'' offered her a golden city if she would obey him. This was one of the early spectral visions that established the narrative of the Devil actively recruiting Salem residents.', '1692-03-25', 'exact', 'incident', 'vision', NULL, 'betty_parris', 'micro_events_daily_chronicle.md', 'Betty Parris (age 9) reports the ''great Black Man'' offered her a golden city. Betty Parris, age 9, reported that ''the great Black Man'' offered her a golden city if she would obey him. This was one of the early spectral visions that established the narrative of the Devil actively recruiting Salem residents.', 'public', '["vision","black_man","golden_city","devil"]', 'salem_project', 1.0, NULL, 1775266565628, 1775266565628, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('mercy_lewis_resistance_vision', 'Mercy Lewis resists witch sacrament — ''I will not Eat, I will not Drink, it is Blood''', 'During the public fast (March 31-April 1), Mercy Lewis described resisting a witch''s sacrament, crying: ''I will not Eat, I will not Drink, it is Blood.'' She then described seeing ''a White man'' in ''a glorious place with multitudes singing psalms.'' This placed her as a heroic resister of Satan''s temptation.', '1692-03-31', 'exact', 'incident', 'vision', NULL, 'mercy_lewis', 'micro_events_daily_chronicle.md', 'Mercy Lewis resists witch sacrament — ''I will not Eat, I will not Drink, it is Blood''. During the public fast (March 31-April 1), Mercy Lewis described resisting a witch''s sacrament, crying: ''I will not Eat, I will not Drink, it is Blood.'' She then described seeing ''a White man'' in ''a glorious place with multitudes singing psalms.'' This placed her as a heroic resister of Satan''s temptation.', 'public', '["vision","sacrament","blood","resistance"]', 'salem_project', 1.0, NULL, 1775266565628, 1775266565628, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('susannah_martin_laughing', 'Susannah Martin laughs at her examiners — ''Well I may at such folly''', 'As soon as Susannah Martin entered the meetinghouse, many fell into fits. Ann Putnam threw her glove at Martin. The magistrate asked: ''What do you laugh at it?'' Martin replied: ''Well I may at such folly.'' When Mercy Lewis cried out that Martin had hurt her, Martin laughed again. She was executed July 19, 1692.', '1692-05-02', 'exact', 'incident', 'examination', NULL, 'ann_putnam_jr', 'micro_events_daily_chronicle.md', 'Susannah Martin laughs at her examiners — ''Well I may at such folly''. As soon as Susannah Martin entered the meetinghouse, many fell into fits. Ann Putnam threw her glove at Martin. The magistrate asked: ''What do you laugh at it?'' Martin replied: ''Well I may at such folly.'' When Mercy Lewis cried out that Martin had hurt her, Martin laughed again. She was executed July 19, 1692.', 'public', '["laughing","defiance","examination"]', 'salem_project', 1.0, NULL, 1775266565628, 1775266565628, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('alden_examination_coached', 'John Alden''s examination — accuser coached by man whispering in her ear', 'Captain John Alden Jr. (son of Mayflower Pilgrims) was accused. At his examination, one accuser pointed several times at Captain Hill (a different person), not at Alden. A man standing behind the accuser ''stooped down to her ear'' — then she suddenly cried out ''Aldin, Aldin afflicted her.'' When asked if she had ever seen Alden, she answered no. When asked how she knew it was Alden, she said ''the man told her so.'' When Alden stood on a chair far from the accusers, they still claimed he was pinching them.', '1692-05-31', 'exact', 'incident', 'examination', NULL, NULL, 'micro_events_daily_chronicle.md', 'John Alden''s examination — accuser coached by man whispering in her ear. Captain John Alden Jr. (son of Mayflower Pilgrims) was accused. At his examination, one accuser pointed several times at Captain Hill (a different person), not at Alden. A man standing behind the accuser ''stooped down to her ear'' — then she suddenly cried out ''Aldin, Aldin afflicted her.'' When asked if she had ever seen Alden, she answered no. When asked how she knew it was Alden, she said ''the man told her so.'' When Alden stood on a chair far from the accusers, they still claimed he was pinching them.', 'public', '["alden","coached","mayflower","fraud"]', 'salem_project', 1.0, NULL, 1775266565628, 1775266565628, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('alden_escape', 'John Alden escapes Boston jail, flees to New York on horseback', 'Captain John Alden Jr. escaped from Boston jail between September 12-16 with help from friends and fled to New York on horseback. Edward and Sarah Bishop also escaped Boston jail during this same period.', '1692-09-12', 'approximate', 'incident', 'escape', NULL, 'george_corwin', 'micro_events_daily_chronicle.md', 'John Alden escapes Boston jail, flees to New York on horseback. Captain John Alden Jr. escaped from Boston jail between September 12-16 with help from friends and fled to New York on horseback. Edward and Sarah Bishop also escaped Boston jail during this same period.', 'public', '["escape","alden","horseback","new_york"]', 'salem_project', 1.0, NULL, 1775266565628, 1775266565628, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('andover_touch_test', 'Andover touch test — blindfolded accused forced to touch afflicted, 17 arrested', 'Rev. Barnard of Andover ordered all accused to the Andover meetinghouse. Accused persons were blindfolded, led to afflicted girls having fits, and forced to touch them. When fits stopped, it was taken as proof of guilt. One accused described: ''we were blindfolded, and our hands were laid upon the afflicted persons...then they said they were well and that we were guilty of afflicting them.'' This resulted in 17 arrests in a single day.', '1692-09-07', 'exact', 'incident', 'examination', NULL, NULL, 'micro_events_daily_chronicle.md', 'Andover touch test — blindfolded accused forced to touch afflicted, 17 arrested. Rev. Barnard of Andover ordered all accused to the Andover meetinghouse. Accused persons were blindfolded, led to afflicted girls having fits, and forced to touch them. When fits stopped, it was taken as proof of guilt. One accused described: ''we were blindfolded, and our hands were laid upon the afflicted persons...then they said they were well and that we were guilty of afflicting them.'' This resulted in 17 arrests in a single day.', 'public', '["touch_test","andover","blindfolded","mass_arrest"]', 'salem_project', 1.0, NULL, 1775266565628, 1775266565628, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('nehemiah_abbott_released', 'Nehemiah Abbott — the only person released after examination', 'During the mass examination on April 22, 1692, Nehemiah Abbott was the only person released — the afflicted girls could not agree that he was their tormentor. He is the sole example of the accusation process failing to produce a conviction at the examination stage.', '1692-04-22', 'exact', 'incident', 'examination', NULL, NULL, 'micro_events_daily_chronicle.md', 'Nehemiah Abbott — the only person released after examination. During the mass examination on April 22, 1692, Nehemiah Abbott was the only person released — the afflicted girls could not agree that he was their tormentor. He is the sole example of the accusation process failing to produce a conviction at the examination stage.', 'public', '["released","only_one","acquitted_at_examination"]', 'salem_project', 1.0, NULL, 1775266565628, 1775266565628, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('carrier_queen_of_hell', 'Martha Carrier ''vehemently denied charges and charged accusers with insanity''', 'The afflicted claimed Martha Carrier led a 300-strong witch army and had been promised she would be ''Queen of Hell'' by the Devil. During examination, ''the afflicted people were so tortured that everyone expected their death.'' Martha ''vehemently denied these charges and in turn charged her accusers with insanity.'' Even from the scaffold on August 19, ''her voice was heard asserting her innocence refusing to confess to a falsehood so filthy.''', '1692-05-31', 'exact', 'incident', 'examination', NULL, 'martha_carrier', 'micro_events_daily_chronicle.md', 'Martha Carrier ''vehemently denied charges and charged accusers with insanity''. The afflicted claimed Martha Carrier led a 300-strong witch army and had been promised she would be ''Queen of Hell'' by the Devil. During examination, ''the afflicted people were so tortured that everyone expected their death.'' Martha ''vehemently denied these charges and in turn charged her accusers with insanity.'' Even from the scaffold on August 19, ''her voice was heard asserting her innocence refusing to confess to a falsehood so filthy.''', 'public', '["queen_of_hell","defiance","300_witches"]', 'salem_project', 1.0, NULL, 1775266565628, 1775266565628, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('tituba_confession_details', 'Tituba''s confession imagery — hog, black dog, cats, yellow bird, hairy creature', 'Tituba described: a tall, white-haired man in a dark serge coat from Boston (Satan); a hog, a great black dog, a red cat, a black cat, a yellow bird, and ''a hairy creature that walked on two legs'' with ''wings and two legs and a head like a woman.'' Two rats — red and black — said ''serve me.'' She confessed to riding ''upon a stick or pole'' with Good and Osborne: ''We ride taking hold of one another.'' She saw nine marks in the Devil''s book — meaning six more witches were at large.', '1692-03-01', 'exact', 'incident', 'confession', NULL, 'tituba', 'micro_events_daily_chronicle.md', 'Tituba''s confession imagery — hog, black dog, cats, yellow bird, hairy creature. Tituba described: a tall, white-haired man in a dark serge coat from Boston (Satan); a hog, a great black dog, a red cat, a black cat, a yellow bird, and ''a hairy creature that walked on two legs'' with ''wings and two legs and a head like a woman.'' Two rats — red and black — said ''serve me.'' She confessed to riding ''upon a stick or pole'' with Good and Osborne: ''We ride taking hold of one another.'' She saw nine marks in the Devil''s book — meaning six more witches were at large.', 'public', '["confession","imagery","animals","nine_marks"]', 'salem_project', 1.0, NULL, 1775266565628, 1775266565628, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('burroughs_superhuman_strength', 'Burroughs accused of superhuman strength — lifting musket by one finger', 'Evidence at George Burroughs''s trial included claims of superhuman strength: lifting a seven-foot musket by inserting his finger into the barrel, and carrying a barrel of molasses by inserting only two fingers. Mercy Lewis testified Burroughs ''flew her to the top of a mountain'' and promised her ''all the kingdoms if only she would sign in his book.'' She declared: ''I would not writ if he had throwed me down on one hundred pitchforks.''', '1692-08-19', 'exact', 'incident', 'trial', NULL, 'george_burroughs', 'micro_events_daily_chronicle.md', 'Burroughs accused of superhuman strength — lifting musket by one finger. Evidence at George Burroughs''s trial included claims of superhuman strength: lifting a seven-foot musket by inserting his finger into the barrel, and carrying a barrel of molasses by inserting only two fingers. Mercy Lewis testified Burroughs ''flew her to the top of a mountain'' and promised her ''all the kingdoms if only she would sign in his book.'' She declared: ''I would not writ if he had throwed me down on one hundred pitchforks.''', 'public', '["superhuman","musket","molasses","mountain"]', 'salem_project', 1.0, NULL, 1775266565628, 1775266565628, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('hubbard_wolf_february', 'Elizabeth Hubbard claims a large wolf stalks her on an errand', 'On February 27, 1692, Elizabeth Hubbard claimed a large wolf stalked her on an errand — a witch in disguise or sent by one. This was one of the early affliction reports that expanded the crisis beyond the Parris household to the Griggs household.', '1692-02-27', 'exact', 'incident', 'affliction', NULL, 'elizabeth_hubbard', 'micro_events_daily_chronicle.md', 'Elizabeth Hubbard claims a large wolf stalks her on an errand. On February 27, 1692, Elizabeth Hubbard claimed a large wolf stalked her on an errand — a witch in disguise or sent by one. This was one of the early affliction reports that expanded the crisis beyond the Parris household to the Griggs household.', 'public', '["wolf","specter","affliction"]', 'salem_project', 1.0, NULL, 1775266565628, 1775266565628, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('willard_stumbles_prayer', 'John Willard stumbles reciting Lord''s Prayer — ''I think I am bewitcht as well''', 'After being captured in Lancaster, deputy constable John Willard was asked to recite the Lord''s Prayer. He stumbled. Nervously laughing, he said: ''I think I am bewitcht as well as they'' and ''it is these wicked ones that do so overcome me.'' His failure to recite the prayer was taken as evidence of guilt. He was executed August 19.', '1692-05', 'month', 'incident', 'examination', NULL, 'john_willard', 'micro_events_daily_chronicle.md', 'John Willard stumbles reciting Lord''s Prayer — ''I think I am bewitcht as well''. After being captured in Lancaster, deputy constable John Willard was asked to recite the Lord''s Prayer. He stumbled. Nervously laughing, he said: ''I think I am bewitcht as well as they'' and ''it is these wicked ones that do so overcome me.'' His failure to recite the prayer was taken as evidence of guilt. He was executed August 19.', 'public', '["lords_prayer","stumble","bewitched"]', 'salem_project', 1.0, NULL, 1775266565628, 1775266565628, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('dorothy_good_snake_finger', 'Dorothy Good (age 4) reveals a snake sucks her finger — ''her mother gave it to her''', 'During Dorothy Good''s examination on March 26, the four-year-old child revealed having a small snake that sucked her finger, claiming her mother gave it to her. Examiners noted a red spot on her finger ''resembling a flea-bite.'' Mary Walcott and Ann Putnam Jr. claimed the child was deranged and repeatedly bit them ''as if she were an animal.''', '1692-03-26', 'exact', 'incident', 'examination', NULL, 'dorothy_good', 'micro_events_daily_chronicle.md', 'Dorothy Good (age 4) reveals a snake sucks her finger — ''her mother gave it to her''. During Dorothy Good''s examination on March 26, the four-year-old child revealed having a small snake that sucked her finger, claiming her mother gave it to her. Examiners noted a red spot on her finger ''resembling a flea-bite.'' Mary Walcott and Ann Putnam Jr. claimed the child was deranged and repeatedly bit them ''as if she were an animal.''', 'public', '["child","snake","familiar","examination"]', 'salem_project', 1.0, NULL, 1775266565628, 1775266565628, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('mather_horseback_intervention', 'Cotton Mather intervenes from horseback after Burroughs''s prayer', 'After George Burroughs perfectly recited the Lord''s Prayer on the scaffold and the crowd was ''greatly moved,'' Cotton Mather immediately intervened from horseback: ''The Devil has often been transformed into an Angel of Light.'' He reminded the crowd Burroughs had never been ordained and was convicted in a court of law. Mather spoke convincingly enough that four more executions proceeded that day.', '1692-08-19', 'exact', 'incident', 'execution', NULL, 'george_burroughs', 'micro_events_daily_chronicle.md', 'Cotton Mather intervenes from horseback after Burroughs''s prayer. After George Burroughs perfectly recited the Lord''s Prayer on the scaffold and the crowd was ''greatly moved,'' Cotton Mather immediately intervened from horseback: ''The Devil has often been transformed into an Angel of Light.'' He reminded the crowd Burroughs had never been ordained and was convicted in a court of law. Mather spoke convincingly enough that four more executions proceeded that day.', 'public', '["cotton_mather","horseback","angel_of_light"]', 'salem_project', 1.0, NULL, 1775266565629, 1775266565629, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('easty_released_then_rearrested', 'Mary Easty released, then re-arrested when accusers protest', 'Mary Easty was released on May 18, 1692. When the accusers protested — renewing their fits and claiming her specter returned to torment them — she was immediately re-arrested. This demonstrated the accusers'' veto power over judicial mercy.', '1692-05-18', 'exact', 'incident', 'legal', NULL, 'mary_easty', 'micro_events_daily_chronicle.md', 'Mary Easty released, then re-arrested when accusers protest. Mary Easty was released on May 18, 1692. When the accusers protested — renewing their fits and claiming her specter returned to torment them — she was immediately re-arrested. This demonstrated the accusers'' veto power over judicial mercy.', 'public', '["released","rearrested","accuser_veto"]', 'salem_project', 1.0, NULL, 1775266565629, 1775266565629, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('mather_congratulates_stoughton', 'Cotton Mather congratulates Stoughton on ''extinguishing devilism''', 'On September 2, 1692, Cotton Mather wrote congratulating Chief Justice Stoughton on ''extinguishing of as wonderful a piece of devilism as has been seen in the world.'' This letter was written just days before the final wave of executions.', '1692-09-02', 'exact', 'incident', 'letter', NULL, 'william_stoughton', 'micro_events_daily_chronicle.md', 'Cotton Mather congratulates Stoughton on ''extinguishing devilism''. On September 2, 1692, Cotton Mather wrote congratulating Chief Justice Stoughton on ''extinguishing of as wonderful a piece of devilism as has been seen in the world.'' This letter was written just days before the final wave of executions.', 'semi_private', '["cotton_mather","stoughton","congratulation"]', 'salem_project', 1.0, NULL, 1775266565629, 1775266565629, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('barn_raising_communal', 'Barn raising required 15-30 men — neighbors expected reciprocity', 'The construction of a barn frame required 15-30 men working simultaneously to lift and set massive timber bents. No single family had enough hands. Neighbors gathered, worked a full day, and expected reciprocity when their own barn needed raising. This mutual dependence meant that taking sides in the witch crisis had economic consequences.', NULL, NULL, 'incident', 'communal_labor', NULL, NULL, 'economic_interdependence_research.md', 'Barn raising required 15-30 men — neighbors expected reciprocity. The construction of a barn frame required 15-30 men working simultaneously to lift and set massive timber bents. No single family had enough hands. Neighbors gathered, worked a full day, and expected reciprocity when their own barn needed raising. This mutual dependence meant that taking sides in the witch crisis had economic consequences.', 'public', '["barn_raising","communal_labor","reciprocity"]', 'salem_project', 1.0, NULL, 1775266565629, 1775266565629, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('fence_mandatory', 'Fencing was mandatory by law — ''fence viewer'' appointed to inspect', 'Massachusetts Bay Colony law made fencing mandatory. Colonists were required to help fence cornfields. Each town appointed a ''fence viewer'' to inspect compliance. Road maintenance was compulsory labor by citizens — roads had to be cleared at least one rod (16 feet) wide.', NULL, NULL, 'incident', 'communal_labor', NULL, NULL, 'economic_interdependence_research.md', 'Fencing was mandatory by law — ''fence viewer'' appointed to inspect. Massachusetts Bay Colony law made fencing mandatory. Colonists were required to help fence cornfields. Each town appointed a ''fence viewer'' to inspect compliance. Road maintenance was compulsory labor by citizens — roads had to be cleared at least one rod (16 feet) wide.', 'public', '["fencing","mandatory","fence_viewer"]', 'salem_project', 1.0, NULL, 1775266565629, 1775266565629, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('watts_lament_1682', 'Jeremiah Watts laments: ''Brother is against brother''', 'A decade after the Porter dam dispute, Jeremiah Watts wrote lamenting Salem Village''s condition, capturing the deep divisions that would eventually erupt in the witch crisis.', '1682-04', 'month', 'incident', 'social', NULL, NULL, 'village_disputes_research.md', 'Jeremiah Watts laments: ''Brother is against brother''. A decade after the Porter dam dispute, Jeremiah Watts wrote lamenting Salem Village''s condition, capturing the deep divisions that would eventually erupt in the witch crisis.', 'public', '["lament","division","quarreling"]', 'salem_project', 1.0, NULL, 1775266565629, 1775266565629, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('final_toll_statistics', 'The final toll — 19 hanged, 1 pressed, 5+ dead in prison, 150-200 imprisoned', 'The final toll of the Salem witch trials: 19 hanged (14 women, 5 men), 1 pressed to death (Giles Corey), at least 5 died in prison (Sarah Osborne, Roger Toothaker, Lydia Dustin, Ann Foster, and infant child of Sarah Good), 150-200 imprisoned, and 4-year-old Dorothy Good permanently mentally damaged.', NULL, NULL, 'incident', 'outcome', NULL, NULL, 'micro_events_daily_chronicle.md', 'The final toll — 19 hanged, 1 pressed, 5+ dead in prison, 150-200 imprisoned. The final toll of the Salem witch trials: 19 hanged (14 women, 5 men), 1 pressed to death (Giles Corey), at least 5 died in prison (Sarah Osborne, Roger Toothaker, Lydia Dustin, Ann Foster, and infant child of Sarah Good), 150-200 imprisoned, and 4-year-old Dorothy Good permanently mentally damaged.', 'public', '["final_toll","19_hanged","1_pressed","statistics"]', 'salem_project', 1.0, NULL, 1775266565629, 1775266565629, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('oyer_terminer_established', 'Court of Oyer and Terminer established by Governor Phips', 'Governor Phips established the Court of Oyer and Terminer on May 27, 1692, appointing nine magistrates. The court''s name means ''to hear and to determine.'' It was created because no legitimate court existed to try the accused witches — the legal vacuum after the overthrow of Andros and before the new charter left court authority uncertain. Phips chose the judges because they ''were persons of the best prudence and figure that could then be pitched upon.''', '1692-05-27', 'exact', 'legal', 'court', NULL, 'william_phips', 'political_events_charter_research.md', 'Court of Oyer and Terminer established by Governor Phips. Governor Phips established the Court of Oyer and Terminer on May 27, 1692, appointing nine magistrates. The court''s name means ''to hear and to determine.'' It was created because no legitimate court existed to try the accused witches — the legal vacuum after the overthrow of Andros and before the new charter left court authority uncertain. Phips chose the judges because they ''were persons of the best prudence and figure that could then be pitched upon.''', 'public', '["court","oyer_terminer","phips","establishment"]', 'salem_project', 1.0, NULL, 1775266565629, 1775266565629, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('nine_judges_profiles', 'The nine judges — six related by marriage, none with legal training', 'The nine judges of the Court of Oyer and Terminer: William Stoughton (60, Chief Justice), John Hathorne (51), Jonathan Corwin (52, replaced Saltonstall), Bartholomew Gedney (52), Samuel Sewall (40), Nathaniel Saltonstall (53, resigned June 13), John Richards (67), Peter Sergeant (53), Waitstill Winthrop (50). Six of nine judges were related by marriage. None had formal legal training.', '1692-05-27', 'exact', 'legal', 'court', NULL, 'william_stoughton', 'political_events_charter_research.md', 'The nine judges — six related by marriage, none with legal training. The nine judges of the Court of Oyer and Terminer: William Stoughton (60, Chief Justice), John Hathorne (51), Jonathan Corwin (52, replaced Saltonstall), Bartholomew Gedney (52), Samuel Sewall (40), Nathaniel Saltonstall (53, resigned June 13), John Richards (67), Peter Sergeant (53), Waitstill Winthrop (50). Six of nine judges were related by marriage. None had formal legal training.', 'public', '["judges","related","untrained"]', 'salem_project', 1.0, NULL, 1775266565629, 1775266565629, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('nurse_petition_39_signers', '39 Salem residents sign pro-Rebecca Nurse petition', '39 Salem residents signed a petition for Rebecca Nurse. Complete list of signers: Israel Porter, Elizabeth Porter, Edward Bishop Sr., Hannah Bishop, Joshua Rea, Sarah Rea, Sarah Leach, John Putnam Sr., Rebecca Putnam, Joseph Hutcheson Sr., Lydia Hutcheson, Joseph Holten Sr., Sarah Holten, Daniel Andrew, Sara Andrew, Jonathan Putnam, Lydia Putnam, Walter Phillips Sr., Nathaniel Felton Sr., Margaret Phillips, Taithia Phillips, Joseph Houlton Jr., Samuel Endicott, Elizabeth Buxton, Samuel Aborn Sr., Isaac Cooke, Benjamin Putnam, Sarah Putnam, Job Swinnerton, Esther Swinnerton, Joseph Herrick Sr., Samuel Sibley, Hephzibah Rea, Elizabeth Cooke, William Osborne, Hannah Osborne, Daniel Rea, Sarah Putnam, Joseph Putman. Notably, Jonathan Putnam — who originally swore out the complaint against Nurse — was among the signers.', '1692-06', 'month', 'legal', 'petition', NULL, 'rebecca_nurse', 'micro_events_daily_chronicle.md', '39 Salem residents sign pro-Rebecca Nurse petition. 39 Salem residents signed a petition for Rebecca Nurse. Complete list of signers: Israel Porter, Elizabeth Porter, Edward Bishop Sr., Hannah Bishop, Joshua Rea, Sarah Rea, Sarah Leach, John Putnam Sr., Rebecca Putnam, Joseph Hutcheson Sr., Lydia Hutcheson, Joseph Holten Sr., Sarah Holten, Daniel Andrew, Sara Andrew, Jonathan Putnam, Lydia Putnam, Walter Phillips Sr., Nathaniel Felton Sr., Margaret Phillips, Taithia Phillips, Joseph Houlton Jr., Samuel Endicott, Elizabeth Buxton, Samuel Aborn Sr., Isaac Cooke, Benjamin Putnam, Sarah Putnam, Job Swinnerton, Esther Swinnerton, Joseph Herrick Sr., Samuel Sibley, Hephzibah Rea, Elizabeth Cooke, William Osborne, Hannah Osborne, Daniel Rea, Sarah Putnam, Joseph Putman. Notably, Jonathan Putnam — who originally swore out the complaint against Nurse — was among the signers.', 'public', '["petition","39_signers","nurse","complete_list"]', 'salem_project', 1.0, NULL, 1775266565629, 1775266565629, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('proctor_petition_13_signers', '13 Salem neighbors sign pro-Proctor petition', '13 of the Proctors'' Salem neighbors signed a petition asserting Proctor and his wife ''lived christian life'' and were ''ever ready to help such as stood in need.''', NULL, NULL, 'legal', 'petition', NULL, 'john_proctor', 'micro_events_daily_chronicle.md', '13 Salem neighbors sign pro-Proctor petition. 13 of the Proctors'' Salem neighbors signed a petition asserting Proctor and his wife ''lived christian life'' and were ''ever ready to help such as stood in need.''', 'public', '["petition","proctor","character_witness"]', 'salem_project', 1.0, NULL, 1775266565629, 1775266565629, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('bradbury_petition_117_signers', '117 Salisbury residents sign petition for Mary Bradbury — still convicted', '117 men and women of Salisbury signed a petition testifying to Mary Bradbury''s character — the largest such petition of the trials. She was still convicted. Her husband reportedly bribed the jailer to secure her escape.', NULL, NULL, 'legal', 'petition', NULL, 'mary_bradbury', 'micro_events_daily_chronicle.md', '117 Salisbury residents sign petition for Mary Bradbury — still convicted. 117 men and women of Salisbury signed a petition testifying to Mary Bradbury''s character — the largest such petition of the trials. She was still convicted. Her husband reportedly bribed the jailer to secure her escape.', 'public', '["petition","117_signers","largest_petition","convicted_anyway"]', 'salem_project', 1.0, NULL, 1775266565629, 1775266565629, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('ipswich_petition_32', '32 Ipswich dissenters petition against spectral evidence', '32 dissenters from Ipswich petitioned and denounced the use of spectral evidence — the belief that the Devil could impersonate innocent people to torment the afflicted.', NULL, NULL, 'legal', 'petition', NULL, NULL, 'micro_events_daily_chronicle.md', '32 Ipswich dissenters petition against spectral evidence. 32 dissenters from Ipswich petitioned and denounced the use of spectral evidence — the belief that the Devil could impersonate innocent people to torment the afflicted.', 'public', '["petition","ipswich","spectral_evidence","dissent"]', 'salem_project', 1.0, NULL, 1775266565629, 1775266565629, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('return_ministers_june_15', 'Return of Several Ministers — caution against spectral evidence (ignored)', 'Drafted by Cotton Mather and presented to Governor Phips by twelve ministers on June 15, 1692. The ministers cautioned against spectral evidence and warned the Devil could assume the form of innocent people. Despite this cautionary advice, the court continued relying on spectral evidence for convictions.', '1692-06-15', 'exact', 'legal', 'advisory', NULL, 'william_phips', 'micro_events_daily_chronicle.md', 'Return of Several Ministers — caution against spectral evidence (ignored). Drafted by Cotton Mather and presented to Governor Phips by twelve ministers on June 15, 1692. The ministers cautioned against spectral evidence and warned the Devil could assume the form of innocent people. Despite this cautionary advice, the court continued relying on spectral evidence for convictions.', 'public', '["ministers","spectral_evidence","ignored","cotton_mather"]', 'salem_project', 1.0, NULL, 1775266565629, 1775266565629, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('corwin_appointed_sheriff', 'George Corwin appointed High Sheriff, begins seizing property', 'George Corwin was appointed High Sheriff of Essex County on May 27, 1692. His duties included confiscating personal property (not land, but belongings — livestock, hay, apples, corn, kettles, pewter, furniture, jewelry) of convicted witches. The seizures were essentially personal enrichment under official cover.', '1692-05-27', 'exact', 'legal', 'appointment', NULL, NULL, 'micro_events_daily_chronicle.md', 'George Corwin appointed High Sheriff, begins seizing property. George Corwin was appointed High Sheriff of Essex County on May 27, 1692. His duties included confiscating personal property (not land, but belongings — livestock, hay, apples, corn, kettles, pewter, furniture, jewelry) of convicted witches. The seizures were essentially personal enrichment under official cover.', 'public', '["sheriff","seizures","property","corwin"]', 'salem_project', 1.0, NULL, 1775266565629, 1775266565629, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('english_property_seized', 'Sheriff Corwin seizes 1,183 pounds of English property', 'While the Englishes were in flight to New York, Sheriff George Corwin and his men seized from English''s house and warehouses: furniture, plates, personal wine cellar, lumber, fish, grain, yard goods, shoes, six pigs and a cow. Total value approximately 1,183 pounds. Neighbors scavenged whatever Corwin''s men left behind. A laborer earned 15-20 pounds per year; a prosperous farmer''s entire estate might be 200-400 pounds.', NULL, NULL, 'legal', 'seizure', NULL, 'philip_english', 'philip_english_merchant_research.md', 'Sheriff Corwin seizes 1,183 pounds of English property. While the Englishes were in flight to New York, Sheriff George Corwin and his men seized from English''s house and warehouses: furniture, plates, personal wine cellar, lumber, fish, grain, yard goods, shoes, six pigs and a cow. Total value approximately 1,183 pounds. Neighbors scavenged whatever Corwin''s men left behind. A laborer earned 15-20 pounds per year; a prosperous farmer''s entire estate might be 200-400 pounds.', 'public', '["seizure","1183_pounds","property","scavenging"]', 'salem_project', 1.0, NULL, 1775266565629, 1775266565629, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('corey_son_in_law_pays', 'Corwin arrives at Corey farm after pressing, son-in-law pays by selling livestock', 'After Giles Corey''s death by pressing on September 19, Corwin arrived at his farm ''to either confiscate his goods or receive payment for Corey''s jail expenses.'' Corey''s son-in-law John Moulton paid Corwin by selling livestock. Corey had strategically deeded his farm to his sons-in-law before his death.', '1692-09-19', 'exact', 'legal', 'seizure', NULL, 'giles_corey', 'micro_events_daily_chronicle.md', 'Corwin arrives at Corey farm after pressing, son-in-law pays by selling livestock. After Giles Corey''s death by pressing on September 19, Corwin arrived at his farm ''to either confiscate his goods or receive payment for Corey''s jail expenses.'' Corey''s son-in-law John Moulton paid Corwin by selling livestock. Corey had strategically deeded his farm to his sons-in-law before his death.', 'public', '["seizure","property_protection","livestock"]', 'salem_project', 1.0, NULL, 1775266565629, 1775266565629, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('parker_sons_protest_seizure', 'Mary Parker''s sons protest seizure, negotiate from 10 to 6 pounds', 'After Mary Parker''s execution on September 22, Corwin sent officers to seize corn, hay, and cattle from her farm. When her sons protested, the demand was negotiated down from 10 pounds to 6 pounds.', '1692-09-22', 'exact', 'legal', 'seizure', NULL, NULL, 'micro_events_daily_chronicle.md', 'Mary Parker''s sons protest seizure, negotiate from 10 to 6 pounds. After Mary Parker''s execution on September 22, Corwin sent officers to seize corn, hay, and cattle from her farm. When her sons protested, the demand was negotiated down from 10 pounds to 6 pounds.', 'public', '["seizure","negotiation","andover"]', 'salem_project', 1.0, NULL, 1775266565629, 1775266565629, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('prison_costs_families', 'Prisoners charged for their own chains, food, and bedding', 'Prisoners were charged for room and board (approximately 2 shillings, sixpence per week) plus a fee for their own chains. They had to pay for their own food and bedding. Food and water were scarce and of poor quality, dependent on what family or friends could provide. Those who couldn''t pay remained imprisoned even after acquittal — Lydia Dustin died in jail after being found not guilty because she couldn''t afford the fees.', NULL, NULL, 'legal', 'prison', NULL, NULL, 'micro_events_daily_chronicle.md', 'Prisoners charged for their own chains, food, and bedding. Prisoners were charged for room and board (approximately 2 shillings, sixpence per week) plus a fee for their own chains. They had to pay for their own food and bedding. Food and water were scarce and of poor quality, dependent on what family or friends could provide. Those who couldn''t pay remained imprisoned even after acquittal — Lydia Dustin died in jail after being found not guilty because she couldn''t afford the fees.', 'public', '["prison_costs","chains","fees","injustice"]', 'salem_project', 1.0, NULL, 1775266565629, 1775266565629, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('osborne_death_prison', 'Sarah Osborne dies in Boston jail, never tried', 'Sarah Osborne, age approximately 49, died in Boston jail on May 10, 1692. She was never brought to trial.', '1692-05-10', 'exact', 'legal', 'prison_death', NULL, 'sarah_osborne', 'births_deaths_illness_research.md', 'Sarah Osborne dies in Boston jail, never tried. Sarah Osborne, age approximately 49, died in Boston jail on May 10, 1692. She was never brought to trial.', 'public', '["prison_death","never_tried"]', 'salem_project', 1.0, NULL, 1775266565629, 1775266565629, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('toothaker_death_prison', 'Roger Toothaker (age 57) dies in Boston prison', 'Roger Toothaker, age 57, died in Boston prison on June 16, 1692. A coroner''s jury ruled ''natural causes.''', '1692-06-16', 'exact', 'legal', 'prison_death', NULL, NULL, 'births_deaths_illness_research.md', 'Roger Toothaker (age 57) dies in Boston prison. Roger Toothaker, age 57, died in Boston prison on June 16, 1692. A coroner''s jury ruled ''natural causes.''', 'public', '["prison_death","natural_causes"]', 'salem_project', 1.0, NULL, 1775266565629, 1775266565629, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('ann_foster_death_prison', 'Ann Foster (age ~75) dies in Salem jail after 21 weeks', 'Ann Foster, age approximately 75, died in Salem jail on December 3, 1692 after 21 weeks of imprisonment.', '1692-12-03', 'exact', 'legal', 'prison_death', NULL, NULL, 'births_deaths_illness_research.md', 'Ann Foster (age ~75) dies in Salem jail after 21 weeks. Ann Foster, age approximately 75, died in Salem jail on December 3, 1692 after 21 weeks of imprisonment.', 'public', '["prison_death","elderly"]', 'salem_project', 1.0, NULL, 1775266565629, 1775266565629, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('lydia_dustin_death_prison', 'Lydia Dustin (age ~80) dies in jail after acquittal — couldn''t pay fees', 'Lydia Dustin, age approximately 80, was found not guilty but could not pay her jail fees. She died in jail on March 10, 1693. Her death exemplifies the injustice of the system — acquittal did not guarantee freedom.', '1693-03-10', 'exact', 'legal', 'prison_death', NULL, NULL, 'births_deaths_illness_research.md', 'Lydia Dustin (age ~80) dies in jail after acquittal — couldn''t pay fees. Lydia Dustin, age approximately 80, was found not guilty but could not pay her jail fees. She died in jail on March 10, 1693. Her death exemplifies the injustice of the system — acquittal did not guarantee freedom.', 'public', '["prison_death","acquitted","fees","injustice"]', 'salem_project', 1.0, NULL, 1775266565629, 1775266565629, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('restitution_1711', '1711 Reversal of Attainder and Restitution Act', 'In 1711, the Massachusetts legislature passed the Reversal of Attainder and Restitution Act, providing financial compensation to families of those executed or imprisoned. The Proctor family received 150 pounds. Philip English was included. Compensation was widely considered inadequate.', '1711', 'year', 'legal', 'aftermath', NULL, 'john_proctor', 'births_deaths_illness_research.md', '1711 Reversal of Attainder and Restitution Act. In 1711, the Massachusetts legislature passed the Reversal of Attainder and Restitution Act, providing financial compensation to families of those executed or imprisoned. The Proctor family received 150 pounds. Philip English was included. Compensation was widely considered inadequate.', 'public', '["restitution","reversal","compensation","aftermath"]', 'salem_project', 1.0, NULL, 1775266565629, 1775266565629, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('sewall_public_repentance', 'Samuel Sewall publicly repents his role — only judge to do so', 'On January 14, 1697, Samuel Sewall stood in the Old South Meeting House in Boston while Rev. Samuel Willard read his confession aloud. He asked pardon from God and people, taking ''the blame and shame of it.'' He was the only judge to publicly repent his role in the trials.', '1697-01-14', 'exact', 'legal', 'aftermath', NULL, 'samuel_sewall', 'political_events_charter_research.md', 'Samuel Sewall publicly repents his role — only judge to do so. On January 14, 1697, Samuel Sewall stood in the Old South Meeting House in Boston while Rev. Samuel Willard read his confession aloud. He asked pardon from God and people, taking ''the blame and shame of it.'' He was the only judge to publicly repent his role in the trials.', 'public', '["repentance","confession","only_judge"]', 'salem_project', 1.0, NULL, 1775266565629, 1775266565629, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('putnam_43_complaints', 'Thomas Putnam Jr. filed or co-signed complaints against 43+ accused', 'Thomas Putnam Jr. filed or co-signed complaints against more than 43 accused witches during 1692. The accused mapped almost perfectly onto the Porter faction''s leadership and other perceived enemies: Daniel Andrew, Philip English, Francis Nurse, George Burroughs.', NULL, NULL, 'legal', 'accusations', NULL, 'thomas_putnam_jr', 'micro_events_daily_chronicle.md', 'Thomas Putnam Jr. filed or co-signed complaints against 43+ accused. Thomas Putnam Jr. filed or co-signed complaints against more than 43 accused witches during 1692. The accused mapped almost perfectly onto the Porter faction''s leadership and other perceived enemies: Daniel Andrew, Philip English, Francis Nurse, George Burroughs.', 'public', '["complaints","43_accused","factional"]', 'salem_project', 1.0, NULL, 1775266565629, 1775266565629, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('tituba_confession_march_1', 'Tituba confesses to witchcraft, describes Devil and witch gatherings', 'On March 1, 1692, Tituba became the first to confess to witchcraft. She described the Devil appearing as a tall man in black, a book with marks, and gatherings of witches. Her confession validated the accusers'' claims and opened the floodgates for further accusations. Without Tituba''s confession, the crisis might have ended with three arrests.', '1692-03-01', 'exact', 'legal', 'confession', NULL, 'tituba', 'micro_events_daily_chronicle.md', 'Tituba confesses to witchcraft, describes Devil and witch gatherings. On March 1, 1692, Tituba became the first to confess to witchcraft. She described the Devil appearing as a tall man in black, a book with marks, and gatherings of witches. Her confession validated the accusers'' claims and opened the floodgates for further accusations. Without Tituba''s confession, the crisis might have ended with three arrests.', 'public', '["confession","devil","first_confession","floodgates"]', 'salem_project', 1.0, NULL, 1775266565629, 1775266565629, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('kennebunk_raid_1688', 'Wabanaki attack Kennebunk, Maine — two families killed', 'Wabanaki warriors attacked Kennebunk, Maine in fall 1688. Two families killed. Distance from Salem: ~85 miles north (3-5 days overland travel). This was one of the first attacks signaling the frontier''s collapse.', '1688-10', 'month', 'military', 'frontier_attack', NULL, NULL, 'frontier_war_timeline_research.md', 'Wabanaki attack Kennebunk, Maine — two families killed. Wabanaki warriors attacked Kennebunk, Maine in fall 1688. Two families killed. Distance from Salem: ~85 miles north (3-5 days overland travel). This was one of the first attacks signaling the frontier''s collapse.', 'public', '["frontier_attack","wabanaki","maine"]', 'salem_project', 1.0, NULL, 1775266565629, 1775266565629, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('dover_massacre_1689', 'Dover massacre — Major Waldron killed in ritualistic revenge', 'Pennacook and Abenaki warriors under Chief Kancamagus and Mesandowit attacked Dover (Cochecho), New Hampshire. 23 killed, 29 taken captive. Major Richard Waldron (age 73) was killed with deliberate ritualistic vengeance. In 1676, Waldron had tricked ~200 Indians into a sham training exercise and sold many into slavery. Native women in the garrison asked to sleep inside; during the night they opened the gates. Waldron was dragged from bed, tortured with his own sword, nose and ears cut off, fingers forced into his mouth. Distance from Salem: ~55 miles.', '1689-06-27', 'exact', 'military', 'frontier_attack', NULL, NULL, 'frontier_war_timeline_research.md', 'Dover massacre — Major Waldron killed in ritualistic revenge. Pennacook and Abenaki warriors under Chief Kancamagus and Mesandowit attacked Dover (Cochecho), New Hampshire. 23 killed, 29 taken captive. Major Richard Waldron (age 73) was killed with deliberate ritualistic vengeance. In 1676, Waldron had tricked ~200 Indians into a sham training exercise and sold many into slavery. Native women in the garrison asked to sleep inside; during the night they opened the gates. Waldron was dragged from bed, tortured with his own sword, nose and ears cut off, fingers forced into his mouth. Distance from Salem: ~55 miles.', 'public', '["dover","massacre","waldron","revenge","frontier_war"]', 'salem_project', 1.0, NULL, 1775266565629, 1775266565629, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('pemaquid_siege_1689', 'Siege of Pemaquid, Maine — French and Abenaki capture the fort', '~100-300 Abenaki plus French Acadian forces, led by Baron de Saint-Castin, Father Louis-Pierre Thury, and Chief Moxus, besieged Pemaquid. 18-30 English soldiers under Captain James Weems defended. French and Abenaki victory; fort captured. Distance from Salem: ~150 miles.', '1689-08-02', 'exact', 'military', 'frontier_attack', NULL, NULL, 'frontier_war_timeline_research.md', 'Siege of Pemaquid, Maine — French and Abenaki capture the fort. ~100-300 Abenaki plus French Acadian forces, led by Baron de Saint-Castin, Father Louis-Pierre Thury, and Chief Moxus, besieged Pemaquid. 18-30 English soldiers under Captain James Weems defended. French and Abenaki victory; fort captured. Distance from Salem: ~150 miles.', 'public', '["pemaquid","siege","french","abenaki"]', 'salem_project', 1.0, NULL, 1775266565629, 1775266565629, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('first_falmouth_destruction_1689', 'First destruction of Falmouth — Mercy Lewis''s parents killed', 'Combined French and Wabanaki force destroyed Falmouth (Portland), Maine. Houses burned, settlers killed or captured, settlement effectively destroyed. This was Falmouth''s second destruction (first in 1676 during King Philip''s War). CRITICAL NPC CONNECTION: Mercy Lewis''s parents, Philip and Mary Lewis, were killed in this attack. Philip Lewis was a blacksmith on Hog Island in Casco Bay. Mercy was approximately sixteen. She survived and was taken in by Rev. George Burroughs at Wells. Distance from Salem: ~105 miles.', '1689-08-20', 'exact', 'military', 'frontier_attack', NULL, 'mercy_lewis', 'frontier_war_timeline_research.md', 'First destruction of Falmouth — Mercy Lewis''s parents killed. Combined French and Wabanaki force destroyed Falmouth (Portland), Maine. Houses burned, settlers killed or captured, settlement effectively destroyed. This was Falmouth''s second destruction (first in 1676 during King Philip''s War). CRITICAL NPC CONNECTION: Mercy Lewis''s parents, Philip and Mary Lewis, were killed in this attack. Philip Lewis was a blacksmith on Hog Island in Casco Bay. Mercy was approximately sixteen. She survived and was taken in by Rev. George Burroughs at Wells. Distance from Salem: ~105 miles.', 'public', '["falmouth","destruction","mercy_lewis","orphan"]', 'salem_project', 1.0, NULL, 1775266565629, 1775266565629, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('schenectady_massacre_1690', 'Schenectady massacre — 60 killed in night attack during snowstorm', '~110-120 French Canadians and 96 Indigenous warriors (Mohawk converts from Kahnawake, Algonquin) attacked Schenectady, New York in a night attack during a snowstorm. Settlement gates had been left open. 60 residents killed, 27 captured. Settlement burned almost entirely. Part of Governor Frontenac''s coordinated three-pronged winter offensive. Distance from Salem: ~175 miles. Word likely reached Salem within 2-3 weeks.', '1690-02-08', 'exact', 'military', 'frontier_attack', NULL, NULL, 'frontier_war_timeline_research.md', 'Schenectady massacre — 60 killed in night attack during snowstorm. ~110-120 French Canadians and 96 Indigenous warriors (Mohawk converts from Kahnawake, Algonquin) attacked Schenectady, New York in a night attack during a snowstorm. Settlement gates had been left open. 60 residents killed, 27 captured. Settlement burned almost entirely. Part of Governor Frontenac''s coordinated three-pronged winter offensive. Distance from Salem: ~175 miles. Word likely reached Salem within 2-3 weeks.', 'public', '["schenectady","massacre","french","snowstorm"]', 'salem_project', 1.0, NULL, 1775266565629, 1775266565629, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('salmon_falls_1690', 'Salmon Falls raid — 34 killed, 54 captured, marched to Quebec', 'French Canadians and Abenaki, Maliseet, Mi''kmaq warriors under Joseph-Francois Hertel de la Fresniere attacked Salmon Falls, New Hampshire. 34 settlers killed, 54 captured. Most of the settlement burned. Captives were forced-marched north to Quebec through winter conditions. Distance from Salem: ~65 miles. Survivors and escapees fled south into Essex County — news likely reached Salem within days.', '1690-03-27', 'exact', 'military', 'frontier_attack', NULL, NULL, 'frontier_war_timeline_research.md', 'Salmon Falls raid — 34 killed, 54 captured, marched to Quebec. French Canadians and Abenaki, Maliseet, Mi''kmaq warriors under Joseph-Francois Hertel de la Fresniere attacked Salmon Falls, New Hampshire. 34 settlers killed, 54 captured. Most of the settlement burned. Captives were forced-marched north to Quebec through winter conditions. Distance from Salem: ~65 miles. Survivors and escapees fled south into Essex County — news likely reached Salem within days.', 'public', '["salmon_falls","raid","captives","quebec"]', 'salem_project', 1.0, NULL, 1775266565630, 1775266565630, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('fort_loyal_1690', 'Battle of Fort Loyal / Second destruction of Falmouth — ~200 killed', '400-500 French and Wabanaki warriors under Courtemanche, Portneuf, Saint-Castin, Hertel de la Fresniere, and Chief Hopehood besieged Fort Loyal and Falmouth for multiple days. Captain Sylvanus Davis surrendered on terms of safe conduct; terms were violated. Approximately 200 killed. Effectively ended organized European presence in most of Maine. Distance from Salem: ~105 miles.', '1690-05-16', 'exact', 'military', 'frontier_attack', NULL, NULL, 'frontier_war_timeline_research.md', 'Battle of Fort Loyal / Second destruction of Falmouth — ~200 killed. 400-500 French and Wabanaki warriors under Courtemanche, Portneuf, Saint-Castin, Hertel de la Fresniere, and Chief Hopehood besieged Fort Loyal and Falmouth for multiple days. Captain Sylvanus Davis surrendered on terms of safe conduct; terms were violated. Approximately 200 killed. Effectively ended organized European presence in most of Maine. Distance from Salem: ~105 miles.', 'public', '["fort_loyal","falmouth","surrender_violated","maine_abandoned"]', 'salem_project', 1.0, NULL, 1775266565630, 1775266565630, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('phips_quebec_failure_1690', 'Phips''s failed Quebec expedition — ~1,000 men lost, humiliating defeat', 'Sir William Phips led ~2,000 colonial troops in 32 vessels against Quebec. The expedition was a humiliating failure — fleet battered by weather and disease, ~1,000 men lost. The theological impact was devastating: God was not granting victory. The failure also caused a financial crisis — Massachusetts issued the first paper bills of credit in the Western world to pay returning soldiers.', '1690-10', 'month', 'military', 'expedition', NULL, 'william_phips', 'frontier_war_timeline_research.md', 'Phips''s failed Quebec expedition — ~1,000 men lost, humiliating defeat. Sir William Phips led ~2,000 colonial troops in 32 vessels against Quebec. The expedition was a humiliating failure — fleet battered by weather and disease, ~1,000 men lost. The theological impact was devastating: God was not granting victory. The failure also caused a financial crisis — Massachusetts issued the first paper bills of credit in the Western world to pay returning soldiers.', 'public', '["quebec","failure","1000_dead","paper_money"]', 'salem_project', 1.0, NULL, 1775266565630, 1775266565630, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('york_massacre_1692', 'Candlemas Massacre at York — the critical frontier event for Salem', 'THE SINGLE MOST IMPORTANT FRONTIER EVENT FOR THE SALEM WITCH TRIALS. 200-300 Abenaki warriors under Chief Madockawando, with Father Louis-Pierre Thury and Sr. de Portneuf, attacked during a snowstorm at dawn on January 24-25, 1692. 75-100 killed, 73-80 captured. Rev. Shubael Dummer — the minister of York — was murdered. 4-year-old Jeremiah Moulton''s parents were killed; his mother hid him under a pile of flax. Captives were forced-marched through winter to Quebec; many died. Captain John Alden Jr. later ransomed some captives. Distance from Salem: ~70 miles. News arrived late January/early February 1692 — between Betty Parris''s first afflictions (mid-January) and the first formal accusations (February 29).', '1692-01-25', 'exact', 'military', 'frontier_attack', NULL, NULL, 'frontier_war_timeline_research.md', 'Candlemas Massacre at York — the critical frontier event for Salem. THE SINGLE MOST IMPORTANT FRONTIER EVENT FOR THE SALEM WITCH TRIALS. 200-300 Abenaki warriors under Chief Madockawando, with Father Louis-Pierre Thury and Sr. de Portneuf, attacked during a snowstorm at dawn on January 24-25, 1692. 75-100 killed, 73-80 captured. Rev. Shubael Dummer — the minister of York — was murdered. 4-year-old Jeremiah Moulton''s parents were killed; his mother hid him under a pile of flax. Captives were forced-marched through winter to Quebec; many died. Captain John Alden Jr. later ransomed some captives. Distance from Salem: ~70 miles. News arrived late January/early February 1692 — between Betty Parris''s first afflictions (mid-January) and the first formal accusations (February 29).', 'public', '["york","candlemas","massacre","minister_killed","critical_timing"]', 'salem_project', 1.0, NULL, 1775266565630, 1775266565630, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('wells_battle_during_trials', 'Battle of Wells during the trials — Burroughs''s former home attacked', '~400 Abenaki, Mi''kmaq, French forces under Baron de Saint-Castin and Father Baudoin attacked Wells, Maine. Captain James Converse with ~31 men in the Joseph Storer garrison successfully defended. This happened during the height of the trials. George Burroughs had been arrested at Wells on May 4. Wells was attacked barely a month later. Distance from Salem: ~75 miles.', '1692-06-10', 'exact', 'military', 'frontier_attack', NULL, 'george_burroughs', 'frontier_war_timeline_research.md', 'Battle of Wells during the trials — Burroughs''s former home attacked. ~400 Abenaki, Mi''kmaq, French forces under Baron de Saint-Castin and Father Baudoin attacked Wells, Maine. Captain James Converse with ~31 men in the Joseph Storer garrison successfully defended. This happened during the height of the trials. George Burroughs had been arrested at Wells on May 4. Wells was attacked barely a month later. Distance from Salem: ~75 miles.', 'public', '["wells","battle","burroughs","during_trials"]', 'salem_project', 1.0, NULL, 1775266565630, 1775266565630, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('king_philips_war_casualties', 'King Philip''s War — 1 in 10 colonists killed, 12 towns destroyed', 'King Philip''s War (1675-1678) killed 3,000 colonists out of 52,000 (nearly 1 in 10 — proportionally the deadliest war in American history). 12 towns completely destroyed, 600 homes burned. Salem Village militia veterans included Thomas Putnam Jr. (Sgt.), Jonathan Walcott, John Pickering II, John Putnam, Nathaniel Ingersoll. The trauma was still raw in 1692 — many accusers'' families had lost relatives.', '1675', 'year', 'military', 'war', NULL, 'thomas_putnam_jr', 'shared_traumas_research.md', 'King Philip''s War — 1 in 10 colonists killed, 12 towns destroyed. King Philip''s War (1675-1678) killed 3,000 colonists out of 52,000 (nearly 1 in 10 — proportionally the deadliest war in American history). 12 towns completely destroyed, 600 homes burned. Salem Village militia veterans included Thomas Putnam Jr. (Sgt.), Jonathan Walcott, John Pickering II, John Putnam, Nathaniel Ingersoll. The trauma was still raw in 1692 — many accusers'' families had lost relatives.', 'public', '["king_philips_war","casualties","trauma","veterans"]', 'salem_project', 1.0, NULL, 1775266565630, 1775266565630, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('great_swamp_fight', 'Corp. John Putnam served in the Great Swamp Fight', 'Corp. John Putnam (1627-1710) served in the Great Swamp Fight of December 1675 against the Narragansett — one of the bloodiest battles of King Philip''s War. This combat experience was shared by multiple Salem Village men who would later participate in or witness the witch crisis.', '1675-12', 'month', 'military', 'battle', NULL, NULL, 'frontier_war_timeline_research.md', 'Corp. John Putnam served in the Great Swamp Fight. Corp. John Putnam (1627-1710) served in the Great Swamp Fight of December 1675 against the Narragansett — one of the bloodiest battles of King Philip''s War. This combat experience was shared by multiple Salem Village men who would later participate in or witness the witch crisis.', 'public', '["great_swamp_fight","narragansett","veteran"]', 'salem_project', 1.0, NULL, 1775266565630, 1775266565630, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('pickering_deerfield_hero', 'Lt. John Pickering II''s heroism at Deerfield defense', 'Lt. John Pickering II (1637-1694) earned heroism at the defense of Deerfield during King Philip''s War in 1675. By 1692, he was ~55 years old. His veteran status gave him standing for measured skepticism during the witch crisis.', '1675', 'year', 'military', 'battle', NULL, NULL, 'frontier_war_timeline_research.md', 'Lt. John Pickering II''s heroism at Deerfield defense. Lt. John Pickering II (1637-1694) earned heroism at the defense of Deerfield during King Philip''s War in 1675. By 1692, he was ~55 years old. His veteran status gave him standing for measured skepticism during the witch crisis.', 'public', '["deerfield","heroism","veteran","skeptic"]', 'salem_project', 1.0, NULL, 1775266565630, 1775266565630, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('walcott_winter_island', 'Jonathan Walcott made wheels for guns at Winter Island fort', 'Captain Jonathan Walcott, King Philip''s War veteran, made wheels for guns at the Winter Island fort during his military service. This technical military knowledge gave him authority as militia captain of the Salem Village military company (elected 1690).', NULL, NULL, 'military', 'service', NULL, 'jonathan_walcott', 'frontier_war_timeline_research.md', 'Jonathan Walcott made wheels for guns at Winter Island fort. Captain Jonathan Walcott, King Philip''s War veteran, made wheels for guns at the Winter Island fort during his military service. This technical military knowledge gave him authority as militia captain of the Salem Village military company (elected 1690).', 'public', '["military","guns","winter_island","walcott"]', 'salem_project', 1.0, NULL, 1775266565630, 1775266565630, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('frontier_war_ptsd', 'Community-wide PTSD — jeremiad framework blamed communities for war', 'The combined trauma of King Philip''s War (1675-78), continuous frontier raids (1688-1692), refugee influx, and the York massacre created community-wide PTSD. The Puritan jeremiad framework interpreted military defeat as divine punishment for communal sin — God was punishing New England because hidden sinners dwelt among them. This theological logic directly fueled the search for witches: if God was punishing the community, the sinners must be found and purged.', NULL, NULL, 'military', 'psychology', NULL, NULL, 'shared_traumas_research.md', 'Community-wide PTSD — jeremiad framework blamed communities for war. The combined trauma of King Philip''s War (1675-78), continuous frontier raids (1688-1692), refugee influx, and the York massacre created community-wide PTSD. The Puritan jeremiad framework interpreted military defeat as divine punishment for communal sin — God was punishing New England because hidden sinners dwelt among them. This theological logic directly fueled the search for witches: if God was punishing the community, the sinners must be found and purged.', 'public', '["ptsd","jeremiad","divine_punishment","theology"]', 'salem_project', 1.0, NULL, 1775266565630, 1775266565630, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('charter_1629', 'Original 1629 Massachusetts Bay Colony Charter — self-governing republic', 'The 1629 charter established Massachusetts as a self-governing charter colony. Governor, Deputy Governor, and Council of Assistants all elected by freemen. Only church members could vote — giving Congregational Puritans total political control. In practice, Massachusetts operated as a near-independent republic for over fifty years.', '1629', 'year', 'political', 'governance', NULL, NULL, 'political_events_charter_research.md', 'Original 1629 Massachusetts Bay Colony Charter — self-governing republic. The 1629 charter established Massachusetts as a self-governing charter colony. Governor, Deputy Governor, and Council of Assistants all elected by freemen. Only church members could vote — giving Congregational Puritans total political control. In practice, Massachusetts operated as a near-independent republic for over fifty years.', 'public', '["charter","self_government","church_members_only"]', 'salem_project', 1.0, NULL, 1775266565630, 1775266565630, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('charter_revoked_1684', 'Massachusetts Bay Charter revoked — colonial self-government ends', 'On October 23, 1684, the charter was declared forfeited by judgment for non-appearance. Edward Randolph''s charges included: Navigation Acts violations, operating an illegal mint (Pine Tree shilling without king''s portrait), refusing to tolerate Church of England, restricting civic participation to Congregationalists, and treating royal directives as advisory.', '1684-10-23', 'exact', 'political', 'governance', NULL, NULL, 'political_events_charter_research.md', 'Massachusetts Bay Charter revoked — colonial self-government ends. On October 23, 1684, the charter was declared forfeited by judgment for non-appearance. Edward Randolph''s charges included: Navigation Acts violations, operating an illegal mint (Pine Tree shilling without king''s portrait), refusing to tolerate Church of England, restricting civic participation to Congregationalists, and treating royal directives as advisory.', 'public', '["charter_revoked","pine_tree_shilling","randolph"]', 'salem_project', 1.0, NULL, 1775266565630, 1775266565630, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('andros_arrives_1686', 'Governor Andros arrives — Dominion of New England begins', 'Edmund Andros arrived in Boston on December 20, 1686 as governor of the Dominion of New England, merging Massachusetts, Connecticut, New Hampshire, Rhode Island (and later New York and New Jersey) under a single royally appointed governor with no elected assembly.', '1686-12-20', 'exact', 'political', 'governance', NULL, NULL, 'political_events_charter_research.md', 'Governor Andros arrives — Dominion of New England begins. Edmund Andros arrived in Boston on December 20, 1686 as governor of the Dominion of New England, merging Massachusetts, Connecticut, New Hampshire, Rhode Island (and later New York and New Jersey) under a single royally appointed governor with no elected assembly.', 'public', '["andros","dominion","no_assembly"]', 'salem_project', 1.0, NULL, 1775266565630, 1775266565630, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('andros_land_titles', 'Andros declares all Massachusetts land titles invalid', 'Andros claimed that no inhabitant of Massachusetts Bay had valid title to their land, arguing that towns had assumed title without proper English authorization. He required all landholders to take out new land patents paying heavy fees. This affected every farmer in Salem Village and Salem Town — a farmer who had worked his land for decades was suddenly told his deed was worthless without a new Crown patent.', NULL, NULL, 'political', 'land', NULL, NULL, 'political_events_charter_research.md', 'Andros declares all Massachusetts land titles invalid. Andros claimed that no inhabitant of Massachusetts Bay had valid title to their land, arguing that towns had assumed title without proper English authorization. He required all landholders to take out new land patents paying heavy fees. This affected every farmer in Salem Village and Salem Town — a farmer who had worked his land for decades was suddenly told his deed was worthless without a new Crown patent.', 'public', '["land_titles","andros","fees","anxiety"]', 'salem_project', 1.0, NULL, 1775266565630, 1775266565630, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('andros_anglican_imposition', 'Andros forces Anglican worship in Puritan meetinghouses', 'On March 23, 1687, Andros ordered the keys to Boston''s Old South Meeting House for Anglican services. On Good Friday 1687, he ordered the sexton to open the doors and ring the bell. On February 10, 1688, he held his wife''s funeral with Anglican pomp at Old South. In 1688, King''s Chapel was built on public land in a Puritan burying ground — first service June 30, 1688.', '1687-03-23', 'exact', 'political', 'religion', NULL, NULL, 'political_events_charter_research.md', 'Andros forces Anglican worship in Puritan meetinghouses. On March 23, 1687, Andros ordered the keys to Boston''s Old South Meeting House for Anglican services. On Good Friday 1687, he ordered the sexton to open the doors and ring the bell. On February 10, 1688, he held his wife''s funeral with Anglican pomp at Old South. In 1688, King''s Chapel was built on public land in a Puritan burying ground — first service June 30, 1688.', 'public', '["anglican","andros","old_south","kings_chapel"]', 'salem_project', 1.0, NULL, 1775266565630, 1775266565630, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('ipswich_tax_revolt_1687', 'Ipswich Tax Revolt — ''Birthplace of American Independence 1687''', 'In March 1687, Andros imposed new taxes without legislative consent. On August 23, 1687, Rev. John Wise led the citizens of Ipswich in refusing the tax. Wise and others were arrested, tried in Boston, imprisoned, and fined heavily. This event is commemorated on Ipswich''s town seal as ''The Birthplace of American Independence 1687.''', '1687-08-23', 'exact', 'political', 'resistance', NULL, NULL, 'political_events_charter_research.md', 'Ipswich Tax Revolt — ''Birthplace of American Independence 1687''. In March 1687, Andros imposed new taxes without legislative consent. On August 23, 1687, Rev. John Wise led the citizens of Ipswich in refusing the tax. Wise and others were arrested, tried in Boston, imprisoned, and fined heavily. This event is commemorated on Ipswich''s town seal as ''The Birthplace of American Independence 1687.''', 'public', '["ipswich","tax_revolt","john_wise","andros"]', 'salem_project', 1.0, NULL, 1775266565630, 1775266565630, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('andros_overthrow_1689', 'Boston overthrows Andros — 2,000 militia, HMS Rose seized', 'On April 18, 1689, 2,000 Massachusetts militia marched against Andros''s garrison. Captain John Nelson seized the frigate HMS Rose in the harbor. Andros surrendered without casualties. A ''Declaration of the Gentlemen, Merchants, and Inhabitants'' was read from the Town House balcony (likely drafted by Cotton Mather). Simon Bradstreet (aged 86) was declared Governor. Thomas Danforth named Deputy Governor.', '1689-04-18', 'exact', 'political', 'revolution', NULL, NULL, 'political_events_charter_research.md', 'Boston overthrows Andros — 2,000 militia, HMS Rose seized. On April 18, 1689, 2,000 Massachusetts militia marched against Andros''s garrison. Captain John Nelson seized the frigate HMS Rose in the harbor. Andros surrendered without casualties. A ''Declaration of the Gentlemen, Merchants, and Inhabitants'' was read from the Town House balcony (likely drafted by Cotton Mather). Simon Bradstreet (aged 86) was declared Governor. Thomas Danforth named Deputy Governor.', 'public', '["overthrow","andros","hms_rose","bradstreet"]', 'salem_project', 1.0, NULL, 1775266565630, 1775266565630, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('legal_vacuum_1689_1692', 'Constitutional vacuum 1689-1692 — no legitimate courts', 'Between the overthrow of Andros and the arrival of Phips with the new charter, Massachusetts existed in a constitutional twilight zone. The old charter had been legally vacated; the Dominion government was overthrown; no new charter had been issued. Courts operated under uncertain authority. This is directly why the Court of Oyer and Terminer had to be specially created — there were no courts with clear authority to try capital cases. Land titles also remained uncertain.', NULL, NULL, 'political', 'governance', NULL, NULL, 'political_events_charter_research.md', 'Constitutional vacuum 1689-1692 — no legitimate courts. Between the overthrow of Andros and the arrival of Phips with the new charter, Massachusetts existed in a constitutional twilight zone. The old charter had been legally vacated; the Dominion government was overthrown; no new charter had been issued. Courts operated under uncertain authority. This is directly why the Court of Oyer and Terminer had to be specially created — there were no courts with clear authority to try capital cases. Land titles also remained uncertain.', 'public', '["legal_vacuum","no_courts","uncertainty"]', 'salem_project', 1.0, NULL, 1775266565630, 1775266565630, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('increase_mather_london', 'Increase Mather departs for London — four years of charter negotiation', 'Increase Mather departed for London in May 1688, originally to petition King James II against the Dominion. The Glorious Revolution transformed his mission. He spent four years negotiating a new charter, ultimately getting an elected council (unusual among American colonies) but losing the elected governor — the Crown now appointed the governor.', '1688-05', 'month', 'political', 'diplomacy', NULL, NULL, 'political_events_charter_research.md', 'Increase Mather departs for London — four years of charter negotiation. Increase Mather departed for London in May 1688, originally to petition King James II against the Dominion. The Glorious Revolution transformed his mission. He spent four years negotiating a new charter, ultimately getting an elected council (unusual among American colonies) but losing the elected governor — the Crown now appointed the governor.', 'public', '["increase_mather","london","charter_negotiation"]', 'salem_project', 1.0, NULL, 1775266565630, 1775266565630, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('new_charter_1691', 'New charter signed — voting shifts from church to property qualification', 'The 1691 charter changed voting qualification from church membership (Congregationalist only) to property ownership (40 pounds or 2 pounds/year rent) — approximately 75% of adult males could now vote. Governor became a Crown appointment instead of elected. Religious freedom extended to all Christians except Roman Catholics. Territory expanded to include Plymouth Colony and Maine.', '1691-10-07', 'exact', 'political', 'governance', NULL, NULL, 'political_events_charter_research.md', 'New charter signed — voting shifts from church to property qualification. The 1691 charter changed voting qualification from church membership (Congregationalist only) to property ownership (40 pounds or 2 pounds/year rent) — approximately 75% of adult males could now vote. Governor became a Crown appointment instead of elected. Religious freedom extended to all Christians except Roman Catholics. Territory expanded to include Plymouth Colony and Maine.', 'public', '["new_charter","property_voting","crown_governor"]', 'salem_project', 1.0, NULL, 1775266565630, 1775266565630, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('phips_arrives_may_14', 'Governor Phips arrives with new charter — jails overflowing', 'Governor William Phips arrived in Boston on May 14, 1692 with the new charter. He stepped directly into the witch crisis — jails were overflowing with accused witches but no legitimate court existed to try them. He established the Court of Oyer and Terminer thirteen days later on May 27.', '1692-05-14', 'exact', 'political', 'governance', NULL, 'william_phips', 'political_events_charter_research.md', 'Governor Phips arrives with new charter — jails overflowing. Governor William Phips arrived in Boston on May 14, 1692 with the new charter. He stepped directly into the witch crisis — jails were overflowing with accused witches but no legitimate court existed to try them. He established the Court of Oyer and Terminer thirteen days later on May 27.', 'public', '["phips_arrival","new_charter","crisis"]', 'salem_project', 1.0, NULL, 1775266565630, 1775266565630, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('court_dissolved_october', 'Governor Phips dissolves the Court of Oyer and Terminer', 'Governor Phips dissolved the Court of Oyer and Terminer on October 29, 1692. Stoughton was furious and continued pursuing convictions as Chief Justice of the replacement Superior Court of Judicature. The new court, however, excluded spectral evidence and acquitted most defendants.', '1692-10-29', 'exact', 'political', 'governance', NULL, 'william_phips', 'political_events_charter_research.md', 'Governor Phips dissolves the Court of Oyer and Terminer. Governor Phips dissolved the Court of Oyer and Terminer on October 29, 1692. Stoughton was furious and continued pursuing convictions as Chief Justice of the replacement Superior Court of Judicature. The new court, however, excluded spectral evidence and acquitted most defendants.', 'public', '["court_dissolved","phips","stoughton_furious"]', 'salem_project', 1.0, NULL, 1775266565630, 1775266565630, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('putnam_sawmill', 'Putnam sawmill at Beaver Brook — economic chokepoint', 'The Putnam family operated a sawmill at Beaver Brook with a 1/16 milling toll. It regulated all grain processing in the area, making every farmer who used it dependent on the Putnam family. This economic control reinforced their social authority.', NULL, NULL, 'economic', 'infrastructure', NULL, 'thomas_putnam_jr', 'economic_interdependence_research.md', 'Putnam sawmill at Beaver Brook — economic chokepoint. The Putnam family operated a sawmill at Beaver Brook with a 1/16 milling toll. It regulated all grain processing in the area, making every farmer who used it dependent on the Putnam family. This economic control reinforced their social authority.', 'public', '["sawmill","milling_toll","economic_power"]', 'salem_project', 1.0, NULL, 1775266565630, 1775266565630, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('porter_dam_1672', 'Porter dam floods Putnam meadows — origins of the feud', 'In 1672, the Porter family built a dam that flooded Putnam meadows. John Putnam Sr. sued but the Putnams lost. This dam dispute was one of the foundational grievances of the Putnam-Porter feud that drove the witch crisis. Joseph Hutchinson was also involved.', '1672', 'year', 'economic', 'dispute', NULL, 'thomas_putnam_jr', 'economic_interdependence_research.md', 'Porter dam floods Putnam meadows — origins of the feud. In 1672, the Porter family built a dam that flooded Putnam meadows. John Putnam Sr. sued but the Putnams lost. This dam dispute was one of the foundational grievances of the Putnam-Porter feud that drove the witch crisis. Joseph Hutchinson was also involved.', 'public', '["dam","flood","lawsuit","feud_origin"]', 'salem_project', 1.0, NULL, 1775266565630, 1775266565630, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('putnam_ironworks_failure', 'Putnam ironworks burns and fails — financial blow to family', 'The Putnam ironworks burned circa 1674. The subsequent litigation and financial losses weakened the family''s economic position. This failure, combined with the inheritance dispute and the Porter dam, contributed to the Putnam family''s growing resentment.', '1674', 'approximate', 'economic', 'business', NULL, 'thomas_putnam_jr', 'economic_interdependence_research.md', 'Putnam ironworks burns and fails — financial blow to family. The Putnam ironworks burned circa 1674. The subsequent litigation and financial losses weakened the family''s economic position. This failure, combined with the inheritance dispute and the Porter dam, contributed to the Putnam family''s growing resentment.', 'semi_private', '["ironworks","fire","financial_loss"]', 'salem_project', 1.0, NULL, 1775266565630, 1775266565630, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('daniel_andrew_wharf', 'Daniel Andrew builds independent wharf on Frost Fish Brook', 'In February 1692, Daniel Andrew (married to Sarah Porter) built an independent wharf on Frost Fish Brook, challenging the Putnam family''s economic grip by providing alternative water access for commerce. This assertion of economic independence may have contributed to his accusation of witchcraft.', '1692-02', 'month', 'economic', 'infrastructure', NULL, 'daniel_andrew', 'economic_interdependence_research.md', 'Daniel Andrew builds independent wharf on Frost Fish Brook. In February 1692, Daniel Andrew (married to Sarah Porter) built an independent wharf on Frost Fish Brook, challenging the Putnam family''s economic grip by providing alternative water access for commerce. This assertion of economic independence may have contributed to his accusation of witchcraft.', 'public', '["wharf","frost_fish_brook","economic_independence"]', 'salem_project', 1.0, NULL, 1775266565630, 1775266565630, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('parris_salary_dispute', 'Anti-Parris committee refuses salary tax — 66 pounds contested', 'In October 1691, the newly elected anti-Parris village committee (Hutchinson, Porter, Andrew, Francis Nurse, Joseph Putnam) refused to collect taxes for Parris''s salary of 66 pounds per year (1/3 money, 2/3 provisions), revoked the parsonage deed, and refused to provide firewood. This left Parris financially desperate and politically embattled.', '1691-10', 'month', 'economic', 'salary', NULL, 'samuel_parris', 'economic_interdependence_research.md', 'Anti-Parris committee refuses salary tax — 66 pounds contested. In October 1691, the newly elected anti-Parris village committee (Hutchinson, Porter, Andrew, Francis Nurse, Joseph Putnam) refused to collect taxes for Parris''s salary of 66 pounds per year (1/3 money, 2/3 provisions), revoked the parsonage deed, and refused to provide firewood. This left Parris financially desperate and politically embattled.', 'public', '["salary","refused","parsonage","firewood"]', 'salem_project', 1.0, NULL, 1775266565630, 1775266565630, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('tax_assessment_factions', 'Tax assessments reveal factional economic divide', 'Tax assessments from 1681 and 1690-1695 reveal the economic divide between factions. Anti-Parris families had a mean tax of 15.82 shillings vs. pro-Parris families at 14.76 shillings — the anti-Parris faction was slightly wealthier. The 1681 assessment lists 94 taxable households; the 1690 assessment lists 100.', '1690', 'year', 'economic', 'taxation', NULL, NULL, 'economic_interdependence_research.md', 'Tax assessments reveal factional economic divide. Tax assessments from 1681 and 1690-1695 reveal the economic divide between factions. Anti-Parris families had a mean tax of 15.82 shillings vs. pro-Parris families at 14.76 shillings — the anti-Parris faction was slightly wealthier. The 1681 assessment lists 94 taxable households; the 1690 assessment lists 100.', 'public', '["tax_assessment","factions","economic_divide"]', 'salem_project', 1.0, NULL, 1775266565630, 1775266565630, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('english_trade_bilbao', 'Philip English''s Bilbao connection — rare and lucrative', 'Philip English maintained trade routes to Bilbao, Spain — particularly lucrative and rare among Salem merchants. East: dried cod (enormous Catholic demand for Lenten fish), barrel staves, furs, whale oil, lumber. West: iron (Biscay was Europe''s great iron region), wine, olive oil, salt, fruits, silks, pieces of eight (Spanish silver coin).', NULL, NULL, 'economic', 'trade', NULL, 'philip_english', 'philip_english_merchant_research.md', 'Philip English''s Bilbao connection — rare and lucrative. Philip English maintained trade routes to Bilbao, Spain — particularly lucrative and rare among Salem merchants. East: dried cod (enormous Catholic demand for Lenten fish), barrel staves, furs, whale oil, lumber. West: iron (Biscay was Europe''s great iron region), wine, olive oil, salt, fruits, silks, pieces of eight (Spanish silver coin).', 'public', '["bilbao","trade","cod","iron","spanish_silver"]', 'salem_project', 1.0, NULL, 1775266565630, 1775266565630, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('english_barbados_trade', 'Philip English''s Caribbean trade — cod for sugar', 'English''s Caribbean trade: South — salt cod, dried fish, barrel staves, lumber, horses, cattle, provisions, candles, shoes. North — muscovado sugar, molasses, rum, cotton, indigo, ginger, dyewoods, bills of exchange. Classic triangular trade with profits at each leg.', NULL, NULL, 'economic', 'trade', NULL, 'philip_english', 'philip_english_merchant_research.md', 'Philip English''s Caribbean trade — cod for sugar. English''s Caribbean trade: South — salt cod, dried fish, barrel staves, lumber, horses, cattle, provisions, candles, shoes. North — muscovado sugar, molasses, rum, cotton, indigo, ginger, dyewoods, bills of exchange. Classic triangular trade with profits at each leg.', 'public', '["barbados","sugar","molasses","rum","triangular_trade"]', 'salem_project', 1.0, NULL, 1775266565631, 1775266565631, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('insurance_rates_wartime', 'Insurance rates jump from 1.5% to 11-14% during King William''s War', 'Maritime insurance rates jumped from approximately 1.5% of cargo value in peacetime to 11-14% during King William''s War — a catastrophic increase that ate into merchant profits and raised prices for everyone.', NULL, NULL, 'economic', 'maritime', NULL, NULL, 'salem_waterfront_trade_research.md', 'Insurance rates jump from 1.5% to 11-14% during King William''s War. Maritime insurance rates jumped from approximately 1.5% of cargo value in peacetime to 11-14% during King William''s War — a catastrophic increase that ate into merchant profits and raised prices for everyone.', 'public', '["insurance","wartime","cargo","rates"]', 'salem_project', 1.0, NULL, 1775266565631, 1775266565631, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('laborer_wage_comparison', 'A laborer earned 15-20 pounds per year — English''s seizure was 60 years'' wages', 'A common laborer earned approximately 15-20 pounds per year. A prosperous farmer''s entire estate might be 200-400 pounds. Philip English''s seized property (1,183 pounds) represented approximately 60-80 years of a laborer''s wages, highlighting the extraordinary scale of the seizures.', NULL, NULL, 'economic', 'wages', NULL, 'philip_english', 'philip_english_merchant_research.md', 'A laborer earned 15-20 pounds per year — English''s seizure was 60 years'' wages. A common laborer earned approximately 15-20 pounds per year. A prosperous farmer''s entire estate might be 200-400 pounds. Philip English''s seized property (1,183 pounds) represented approximately 60-80 years of a laborer''s wages, highlighting the extraordinary scale of the seizures.', 'public', '["wages","comparison","seizure_scale"]', 'salem_project', 1.0, NULL, 1775266565631, 1775266565631, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('three_grades_cod', 'Three grades of dried cod — best to Catholics, worst to enslaved', 'Dried cod was graded into three tiers: best quality (''merchantable'') shipped to Catholic Europe for Lenten demand; middling quality for domestic colonial consumption; ''refuse'' grade — the lowest — shipped to Caribbean plantations to feed enslaved people. This three-tier system was fundamental to New England''s maritime economy.', NULL, NULL, 'economic', 'trade', NULL, NULL, 'piracy_privateering_maritime_research.md', 'Three grades of dried cod — best to Catholics, worst to enslaved. Dried cod was graded into three tiers: best quality (''merchantable'') shipped to Catholic Europe for Lenten demand; middling quality for domestic colonial consumption; ''refuse'' grade — the lowest — shipped to Caribbean plantations to feed enslaved people. This three-tier system was fundamental to New England''s maritime economy.', 'public', '["cod","three_grades","catholic","enslaved"]', 'salem_project', 1.0, NULL, 1775266565631, 1775266565631, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('griggs_diagnosis_pivotal', 'Dr. Griggs''s diagnosis of ''Evil Hand'' — the pivotal medical moment', 'After examining Betty Parris and Abigail Williams, ruling out epilepsy, and finding medications ineffective, Dr. William Griggs declared the girls were ''under an Evil Hand.'' This was the pivotal moment that transformed a household medical crisis into a community-wide witch hunt. Within his Galenic framework, once natural disease was excluded, only bewitchment or divine punishment remained.', '1692-02', 'month', 'medical', 'diagnosis', NULL, 'william_griggs', 'births_deaths_illness_research.md', 'Dr. Griggs''s diagnosis of ''Evil Hand'' — the pivotal medical moment. After examining Betty Parris and Abigail Williams, ruling out epilepsy, and finding medications ineffective, Dr. William Griggs declared the girls were ''under an Evil Hand.'' This was the pivotal moment that transformed a household medical crisis into a community-wide witch hunt. Within his Galenic framework, once natural disease was excluded, only bewitchment or divine punishment remained.', 'public', '["diagnosis","evil_hand","pivotal_moment"]', 'salem_project', 1.0, NULL, 1775266565631, 1775266565631, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('betty_parris_symptoms', 'Betty Parris''s affliction symptoms — barking, crawling, throwing Bible', 'Betty Parris (age 9) showed these symptoms: absentmindedness, staring, making animal noises, seizures, screaming, crawling under furniture, barking like dogs, throwing her Bible across the room. She was eventually sent to cousin Stephen Sewall''s household and recovered.', '1692-01', 'month', 'medical', 'affliction', NULL, 'betty_parris', 'births_deaths_illness_research.md', 'Betty Parris''s affliction symptoms — barking, crawling, throwing Bible. Betty Parris (age 9) showed these symptoms: absentmindedness, staring, making animal noises, seizures, screaming, crawling under furniture, barking like dogs, throwing her Bible across the room. She was eventually sent to cousin Stephen Sewall''s household and recovered.', 'public', '["symptoms","affliction","barking","bible"]', 'salem_project', 1.0, NULL, 1775266565631, 1775266565631, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('prison_150_people', '150 accused in a 20x20 building — chained, charged for their own chains', 'At its peak, 150 accused were held in the Salem jail, a building approximately 20 feet square. Prisoners were chained to walls ''to prevent specters from flying free.'' They were charged for their own chains, food, and bedding (approximately 2 shillings, sixpence per week). Food and water were scarce and dependent on what family or friends could provide.', NULL, NULL, 'medical', 'prison', NULL, NULL, 'births_deaths_illness_research.md', '150 accused in a 20x20 building — chained, charged for their own chains. At its peak, 150 accused were held in the Salem jail, a building approximately 20 feet square. Prisoners were chained to walls ''to prevent specters from flying free.'' They were charged for their own chains, food, and bedding (approximately 2 shillings, sixpence per week). Food and water were scarce and dependent on what family or friends could provide.', 'public', '["prison","overcrowding","chains","fees"]', 'salem_project', 1.0, NULL, 1775266565631, 1775266565631, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('bayley_ministry_1672_1680', 'First ministerial crisis — James Bayley (1672-1680)', 'James Bayley was hired as Salem Village''s first minister in 1672. Nathaniel Putnam led opposition to him. His salary was always in arrears. He was never ordained and left in 1680. This was the first of four ministerial crises that split the village along faction lines.', '1672', 'year', 'social', 'ministry_dispute', NULL, NULL, 'village_disputes_research.md', 'First ministerial crisis — James Bayley (1672-1680). James Bayley was hired as Salem Village''s first minister in 1672. Nathaniel Putnam led opposition to him. His salary was always in arrears. He was never ordained and left in 1680. This was the first of four ministerial crises that split the village along faction lines.', 'public', '["ministry","bayley","first_crisis","salary_arrears"]', 'salem_project', 1.0, NULL, 1775266565631, 1775266565631, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('burroughs_ministry_1680_1683', 'Second ministerial crisis — George Burroughs (1680-1683), arrested for debt', 'George Burroughs served as Salem Village minister 1680-1683. His salary was always in arrears. His wife Hannah died in childbirth. He borrowed 15 pounds from John Putnam for the funeral. On May 3, 1683, he was arrested on Putnam''s order for this debt — an unjust prosecution. Released the next day but left Salem permanently for Wells, Maine. Nine years later, the same community would bring him back to hang him.', '1680', 'year', 'social', 'ministry_dispute', NULL, 'george_burroughs', 'village_disputes_research.md', 'Second ministerial crisis — George Burroughs (1680-1683), arrested for debt. George Burroughs served as Salem Village minister 1680-1683. His salary was always in arrears. His wife Hannah died in childbirth. He borrowed 15 pounds from John Putnam for the funeral. On May 3, 1683, he was arrested on Putnam''s order for this debt — an unjust prosecution. Released the next day but left Salem permanently for Wells, Maine. Nine years later, the same community would bring him back to hang him.', 'public', '["ministry","burroughs","debt_arrest","salary_arrears"]', 'salem_project', 1.0, NULL, 1775266565631, 1775266565631, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('lawson_ministry_1684_1688', 'Third ministerial crisis — Deodat Lawson (1684-1688), ordination controversy', 'Deodat Lawson was hired in 1684. His ordination sparked controversy due to disagreements over his theological views. He left in 1688. He returned to Salem Village in March 1692 after learning that a confessor claimed his wife and child had perished by witchcraft.', '1684', 'year', 'social', 'ministry_dispute', NULL, NULL, 'village_disputes_research.md', 'Third ministerial crisis — Deodat Lawson (1684-1688), ordination controversy. Deodat Lawson was hired in 1684. His ordination sparked controversy due to disagreements over his theological views. He left in 1688. He returned to Salem Village in March 1692 after learning that a confessor claimed his wife and child had perished by witchcraft.', 'public', '["ministry","lawson","ordination","controversy"]', 'salem_project', 1.0, NULL, 1775266565631, 1775266565631, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('putnam_nurse_boundary', 'Putnam-Nurse 300-acre boundary dispute — multiple surveys, courts favor Nurse', 'In 1678, Francis Nurse obtained a lease-to-own for the 300-acre Bishop Farm (Endicott Orchard Farm). The Putnam family claimed overlapping acreage. Multiple surveys were conducted, court rulings consistently favored Nurse. This bitter land dispute is one of the underlying motives for the Putnam family''s accusations against Rebecca Nurse.', '1678', 'year', 'social', 'land_dispute', NULL, 'francis_nurse', 'village_disputes_research.md', 'Putnam-Nurse 300-acre boundary dispute — multiple surveys, courts favor Nurse. In 1678, Francis Nurse obtained a lease-to-own for the 300-acre Bishop Farm (Endicott Orchard Farm). The Putnam family claimed overlapping acreage. Multiple surveys were conducted, court rulings consistently favored Nurse. This bitter land dispute is one of the underlying motives for the Putnam family''s accusations against Rebecca Nurse.', 'public', '["boundary","300_acres","bishop_farm","surveys"]', 'salem_project', 1.0, NULL, 1775266565631, 1775266565631, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('village_faction_split', 'Salem Village split — Putnam (agrarian/autonomous) vs. Porter (mercantile/town)', 'Salem Village was split into two deeply opposed factions. Putnam faction: agrarian, wanted village autonomy from Salem Town, supported Parris, located in western village. Porter faction: mercantile, oriented toward Salem Town''s commercial opportunities, opposed Parris, located in eastern village. The accused — Daniel Andrew, Philip English, Francis Nurse, George Burroughs — mapped almost perfectly onto the Porter faction''s leadership.', NULL, NULL, 'social', 'factions', NULL, 'thomas_putnam_jr', 'micro_events_daily_chronicle.md', 'Salem Village split — Putnam (agrarian/autonomous) vs. Porter (mercantile/town). Salem Village was split into two deeply opposed factions. Putnam faction: agrarian, wanted village autonomy from Salem Town, supported Parris, located in western village. Porter faction: mercantile, oriented toward Salem Town''s commercial opportunities, opposed Parris, located in eastern village. The accused — Daniel Andrew, Philip English, Francis Nurse, George Burroughs — mapped almost perfectly onto the Porter faction''s leadership.', 'public', '["factions","putnam","porter","agrarian","mercantile"]', 'salem_project', 1.0, NULL, 1775266565631, 1775266565631, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('accusation_pipeline', 'Accusation pipeline — parsonage to girls to fits to examinations', 'The accusation process followed a multi-stage pipeline: it began in the parsonage (Parris household), spread to the afflicted girls, manifested as public fits, led to formal complaints and examinations before magistrates, and culminated in public spectacle before hundreds of spectators. The girls'' performances reinforced each other in a feedback loop.', NULL, NULL, 'social', 'accusation', NULL, 'samuel_parris', 'information_flow_research.md', 'Accusation pipeline — parsonage to girls to fits to examinations. The accusation process followed a multi-stage pipeline: it began in the parsonage (Parris household), spread to the afflicted girls, manifested as public fits, led to formal complaints and examinations before magistrates, and culminated in public spectacle before hundreds of spectators. The girls'' performances reinforced each other in a feedback loop.', 'public', '["accusation_pipeline","fits","feedback_loop"]', 'salem_project', 1.0, NULL, 1775266565631, 1775266565631, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('women_visiting_networks', 'Women''s information networks — visiting, lying-in attendance, midwife circles', 'Women maintained their own information networks through visiting patterns, lying-in attendance (attending neighbors during childbirth and recovery), and midwife circles. These networks were parallel to male networks at the tavern and meetinghouse. Gossip about character, behavior, and reputation traveled through these channels.', NULL, NULL, 'social', 'information', NULL, NULL, 'information_flow_research.md', 'Women''s information networks — visiting, lying-in attendance, midwife circles. Women maintained their own information networks through visiting patterns, lying-in attendance (attending neighbors during childbirth and recovery), and midwife circles. These networks were parallel to male networks at the tavern and meetinghouse. Gossip about character, behavior, and reputation traveled through these channels.', 'public', '["women","networks","visiting","lying_in"]', 'salem_project', 1.0, NULL, 1775266565631, 1775266565631, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('ingersolls_nerve_center', 'Ingersoll''s Ordinary — the crossroads nerve center where all news converged', 'Ingersoll''s Ordinary was the nerve center of Salem Village: tavern, inn, community center, and de facto holding cell. Court sessions were held there. Prisoners were kept upstairs. Judges ate and drank during recesses alongside accusers'' families and spectators. Every piece of gossip, news from Boston, frontier war updates, and village politics passed through this building.', NULL, NULL, 'social', 'information', NULL, 'nathaniel_ingersoll', 'information_flow_research.md', 'Ingersoll''s Ordinary — the crossroads nerve center where all news converged. Ingersoll''s Ordinary was the nerve center of Salem Village: tavern, inn, community center, and de facto holding cell. Court sessions were held there. Prisoners were kept upstairs. Judges ate and drank during recesses alongside accusers'' families and spectators. Every piece of gossip, news from Boston, frontier war updates, and village politics passed through this building.', 'public', '["ingersoll","nerve_center","crossroads","information"]', 'salem_project', 1.0, NULL, 1775266565631, 1775266565631, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('meetinghouse_noon_break', 'Meetinghouse noon break — 1-2 hours between services for gossip exchange', 'The meetinghouse had a noon break of 1-2 hours between morning and afternoon services on Sundays. Congregants gathered at the noon-house (a small building with fires for warming). This break was the weekly intelligence exchange where village news was shared, announcements posted, and opinions formed. Seating in the meetinghouse was arranged by social rank, making the hierarchy visible.', NULL, NULL, 'social', 'information', NULL, NULL, 'information_flow_research.md', 'Meetinghouse noon break — 1-2 hours between services for gossip exchange. The meetinghouse had a noon break of 1-2 hours between morning and afternoon services on Sundays. Congregants gathered at the noon-house (a small building with fires for warming). This break was the weekly intelligence exchange where village news was shared, announcements posted, and opinions formed. Seating in the meetinghouse was arranged by social rank, making the hierarchy visible.', 'public', '["noon_break","gossip","intelligence_exchange"]', 'salem_project', 1.0, NULL, 1775266565631, 1775266565631, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('funeral_mourning_gloves', 'Funeral customs — mourning gloves distributed, one minister accumulated 2,940 pairs', 'Puritan funeral customs: community summoned by tolling bells, gender-segregated processions, no sermons or eulogies. Mourning gloves were distributed to attendees — Minister Eliot accumulated 2,940 pairs over his career. Commemorative rings inscribed ''Death Parts United Hearts.'' Headstones with winged skulls. Wakes were lively communal events with substantial food and alcohol — one 1678 funeral featured 8 gallons and 3 quarts of wine.', NULL, NULL, 'social', 'custom', NULL, NULL, 'births_deaths_illness_research.md', 'Funeral customs — mourning gloves distributed, one minister accumulated 2,940 pairs. Puritan funeral customs: community summoned by tolling bells, gender-segregated processions, no sermons or eulogies. Mourning gloves were distributed to attendees — Minister Eliot accumulated 2,940 pairs over his career. Commemorative rings inscribed ''Death Parts United Hearts.'' Headstones with winged skulls. Wakes were lively communal events with substantial food and alcohol — one 1678 funeral featured 8 gallons and 3 quarts of wine.', 'public', '["funeral","mourning_gloves","2940_pairs","wakes"]', 'salem_project', 1.0, NULL, 1775266565631, 1775266565631, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('smallpox_1689_epidemic', '1689-1690 smallpox epidemic — arrived via Barbados, ~320 dead in Boston', 'Smallpox arrived in October 1689 via a ship from Barbados carrying enslaved people. ~320 deaths in Boston alone; ~1,000 across the region. ''Attacked all sorts of people, even children in the bellies of mothers.'' Salem was affected. The epidemic overlapped with King William''s War and political chaos — only two years before the witch crisis.', '1689-10', 'month', 'social', 'disease', NULL, NULL, 'births_deaths_illness_research.md', '1689-1690 smallpox epidemic — arrived via Barbados, ~320 dead in Boston. Smallpox arrived in October 1689 via a ship from Barbados carrying enslaved people. ~320 deaths in Boston alone; ~1,000 across the region. ''Attacked all sorts of people, even children in the bellies of mothers.'' Salem was affected. The epidemic overlapped with King William''s War and political chaos — only two years before the witch crisis.', 'public', '["smallpox","epidemic","barbados","320_dead"]', 'salem_project', 1.0, NULL, 1775266565631, 1775266565631, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('common_diseases_1692', 'Common diseases — smallpox, measles, diphtheria, malaria, yellow fever', 'Common diseases in 1692: smallpox, measles (epidemic in Boston 1687), diphtheria, dysentery, scarlet fever, influenza, whooping cough, typhus/typhoid, malaria (''ague''), yellow fever (New York 1690, Boston 1693). Medical knowledge was limited to humoral theory, herbal remedies, and prayer.', NULL, NULL, 'social', 'disease', NULL, NULL, 'births_deaths_illness_research.md', 'Common diseases — smallpox, measles, diphtheria, malaria, yellow fever. Common diseases in 1692: smallpox, measles (epidemic in Boston 1687), diphtheria, dysentery, scarlet fever, influenza, whooping cough, typhus/typhoid, malaria (''ague''), yellow fever (New York 1690, Boston 1693). Medical knowledge was limited to humoral theory, herbal remedies, and prayer.', 'public', '["diseases","smallpox","malaria","ague"]', 'salem_project', 1.0, NULL, 1775266565631, 1775266565631, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('ergot_theory', 'Ergot theory (Caporael 1976) — contaminated rye caused afflictions — largely rejected', 'Linda Caporael proposed in 1976 (in Science) that convulsive ergotism from contaminated rye caused the afflictions. The theory was rebutted by Spanos and Gottlieb and is largely rejected by scholars today, though it remains popular in public imagination.', '1976', 'year', 'social', 'medical', NULL, NULL, 'births_deaths_illness_research.md', 'Ergot theory (Caporael 1976) — contaminated rye caused afflictions — largely rejected. Linda Caporael proposed in 1976 (in Science) that convulsive ergotism from contaminated rye caused the afflictions. The theory was rebutted by Spanos and Gottlieb and is largely rejected by scholars today, though it remains popular in public imagination.', 'public', '["ergot","theory","rejected","caporael"]', 'salem_project', 1.0, NULL, 1775266565631, 1775266565631, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('parris_tracks_attendance', 'Parris tracked who missed sermons and hounded them to attend', 'Samuel Parris specifically tracked who missed sermons. He ''hounded Nurse''s husband Sam to attend church when they missed even a single sermon.'' This pastoral surveillance reinforced his authority and provided intelligence about which congregants were drifting from loyalty.', NULL, NULL, 'social', 'surveillance', NULL, 'samuel_parris', 'occupational_knowledge_map.md', 'Parris tracked who missed sermons and hounded them to attend. Samuel Parris specifically tracked who missed sermons. He ''hounded Nurse''s husband Sam to attend church when they missed even a single sermon.'' This pastoral surveillance reinforced his authority and provided intelligence about which congregants were drifting from loyalty.', 'semi_private', '["attendance","surveillance","parris","control"]', 'salem_project', 1.0, NULL, 1775266565631, 1775266565631, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('willard_pseudonym', 'Samuel Willard publishes anti-trial tract under pseudonym of two accused witches', 'In October 1692, Rev. Samuel Willard published ''Some Miscellany Observations on Our Present Debates Respecting Witchcraft'' under the assumed initials ''P.E. and J.A.'' — Philip English and John Alden, two accused witches who had fled. It was listed as published in Philadelphia (actually Boston) to protect Willard from prosecution. A minister had to hide behind the names of the accused to criticize the proceedings safely.', '1692-10', 'month', 'social', 'resistance', NULL, 'philip_english', 'micro_events_daily_chronicle.md', 'Samuel Willard publishes anti-trial tract under pseudonym of two accused witches. In October 1692, Rev. Samuel Willard published ''Some Miscellany Observations on Our Present Debates Respecting Witchcraft'' under the assumed initials ''P.E. and J.A.'' — Philip English and John Alden, two accused witches who had fled. It was listed as published in Philadelphia (actually Boston) to protect Willard from prosecution. A minister had to hide behind the names of the accused to criticize the proceedings safely.', 'semi_private', '["willard","pseudonym","resistance","philip_english"]', 'salem_project', 1.0, NULL, 1775266565631, 1775266565631, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('congregationalism_accountability', 'Congregationalism — minister accountable to congregation, could be fired', 'Under Congregationalism, the minister was accountable to the congregation. He could be dismissed by vote. The anti-Parris faction demonstrated his limits: in October 1691, the newly elected village committee refused to collect his salary tax, revoked the parsonage deed, and refused to provide firewood. Parris was under existential threat.', NULL, NULL, 'religious', 'governance', NULL, 'samuel_parris', 'occupational_knowledge_map.md', 'Congregationalism — minister accountable to congregation, could be fired. Under Congregationalism, the minister was accountable to the congregation. He could be dismissed by vote. The anti-Parris faction demonstrated his limits: in October 1691, the newly elected village committee refused to collect his salary tax, revoked the parsonage deed, and refused to provide firewood. Parris was under existential threat.', 'public', '["congregationalism","accountability","minister_authority"]', 'salem_project', 1.0, NULL, 1775266565631, 1775266565631, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('spectral_evidence_debate', 'Spectral evidence — could the Devil impersonate innocent people?', 'The central theological question: could the Devil assume the shape of an innocent person to torment the afflicted? If yes, spectral evidence was worthless — seeing someone''s specter proved nothing. If no, spectral visions identified actual witches. The Return of Several Ministers (June 15) cautioned against it. Increase Mather argued the Devil could impersonate anyone. The court continued using it anyway until Phips dissolved the court.', NULL, NULL, 'religious', 'theology', NULL, 'william_stoughton', 'political_events_charter_research.md', 'Spectral evidence — could the Devil impersonate innocent people?. The central theological question: could the Devil assume the shape of an innocent person to torment the afflicted? If yes, spectral evidence was worthless — seeing someone''s specter proved nothing. If no, spectral visions identified actual witches. The Return of Several Ministers (June 15) cautioned against it. Increase Mather argued the Devil could impersonate anyone. The court continued using it anyway until Phips dissolved the court.', 'public', '["spectral_evidence","theology","devil","debate"]', 'salem_project', 1.0, NULL, 1775266565631, 1775266565631, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('jeremiad_framework', 'Jeremiad theology — military defeat means God punishes hidden sinners', 'The Puritan jeremiad framework interpreted military defeat and social calamity as divine punishment for communal sin. If God was punishing New England with frontier attacks, failed expeditions, and political chaos, the community must harbor hidden sinners whose corruption invited God''s wrath. This theological logic made witch-hunting feel not just justified but spiritually necessary — finding the hidden sinners was the path to restoring God''s favor.', NULL, NULL, 'religious', 'theology', NULL, 'samuel_parris', 'shared_traumas_research.md', 'Jeremiad theology — military defeat means God punishes hidden sinners. The Puritan jeremiad framework interpreted military defeat and social calamity as divine punishment for communal sin. If God was punishing New England with frontier attacks, failed expeditions, and political chaos, the community must harbor hidden sinners whose corruption invited God''s wrath. This theological logic made witch-hunting feel not just justified but spiritually necessary — finding the hidden sinners was the path to restoring God''s favor.', 'public', '["jeremiad","divine_punishment","hidden_sinners"]', 'salem_project', 1.0, NULL, 1775266565631, 1775266565631, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('lined_out_singing', 'Lined-out psalm singing — no instruments, precentor leads line by line', 'Puritan worship used lined-out psalm singing: no musical instruments were permitted. A precentor sang each line of the psalm, then the congregation repeated it. The result was slow, unharmonized, and intense. Combined with preaching that could last 2-3 hours (the hourglass was turned repeatedly), a Sunday service was an endurance test.', NULL, NULL, 'religious', 'worship', NULL, NULL, 'physical_sensory_details_research.md', 'Lined-out psalm singing — no instruments, precentor leads line by line. Puritan worship used lined-out psalm singing: no musical instruments were permitted. A precentor sang each line of the psalm, then the congregation repeated it. The result was slow, unharmonized, and intense. Combined with preaching that could last 2-3 hours (the hourglass was turned repeatedly), a Sunday service was an endurance test.', 'public', '["psalm_singing","no_instruments","precentor"]', 'salem_project', 1.0, NULL, 1775266565631, 1775266565631, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('parris_john_6_70', 'Parris preaches John 6:70 on Sacrament Day — ''one of you is a devil''', 'On Sacrament Day, April 3, 1692, Parris chose John 6:70 as his text: ''Have not I chosen you twelve, and one is a devil?'' — directly implying that a devil lurked among the church members. This provocative sermon choice was the trigger for Sarah Cloyce''s dramatic walkout. It demonstrated how Parris weaponized scripture to support the prosecutions.', '1692-04-03', 'exact', 'religious', 'sermon', NULL, 'samuel_parris', 'micro_events_daily_chronicle.md', 'Parris preaches John 6:70 on Sacrament Day — ''one of you is a devil''. On Sacrament Day, April 3, 1692, Parris chose John 6:70 as his text: ''Have not I chosen you twelve, and one is a devil?'' — directly implying that a devil lurked among the church members. This provocative sermon choice was the trigger for Sarah Cloyce''s dramatic walkout. It demonstrated how Parris weaponized scripture to support the prosecutions.', 'public', '["sermon","john_6_70","sacrament_day","devil_among_us"]', 'salem_project', 1.0, NULL, 1775266565631, 1775266565631, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('memorable_providences_parris_library', 'Cotton Mather''s Memorable Providences (1689) was in Parris''s personal library', 'Cotton Mather''s Memorable Providences Relating to Witchcraft and Possessions (1689), which described witchcraft cases in Boston and provided a framework for interpreting affliction as demonic, was in Samuel Parris''s personal library. This book shaped how Parris understood and responded to the girls'' symptoms.', '1689', 'year', 'religious', 'book', NULL, 'samuel_parris', 'occupational_knowledge_map.md', 'Cotton Mather''s Memorable Providences (1689) was in Parris''s personal library. Cotton Mather''s Memorable Providences Relating to Witchcraft and Possessions (1689), which described witchcraft cases in Boston and provided a framework for interpreting affliction as demonic, was in Samuel Parris''s personal library. This book shaped how Parris understood and responded to the girls'' symptoms.', 'semi_private', '["memorable_providences","cotton_mather","parris_library"]', 'salem_project', 1.0, NULL, 1775266565631, 1775266565631, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('increase_mather_cases_of_conscience', 'Increase Mather''s Cases of Conscience — ''better ten suspected witches escape''', 'On October 3, 1692, Increase Mather read his Cases of Conscience Concerning Evil Spirits to a gathering of ministers. He argued that spectral evidence was insufficient for conviction and declared it ''better that ten suspected witches should escape, than that one innocent person should be condemned.'' This work, along with Brattle''s letter and the accusation of Hale''s wife, helped end the trials.', '1692-10-03', 'exact', 'religious', 'book', NULL, NULL, 'political_events_charter_research.md', 'Increase Mather''s Cases of Conscience — ''better ten suspected witches escape''. On October 3, 1692, Increase Mather read his Cases of Conscience Concerning Evil Spirits to a gathering of ministers. He argued that spectral evidence was insufficient for conviction and declared it ''better that ten suspected witches should escape, than that one innocent person should be condemned.'' This work, along with Brattle''s letter and the accusation of Hale''s wife, helped end the trials.', 'public', '["increase_mather","cases_of_conscience","better_ten_escape"]', 'salem_project', 1.0, NULL, 1775266565632, 1775266565632, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('saltbox_construction', 'Saltbox farmhouse — post-and-beam, wattle-and-daub, hand-riven oak clapboard', 'Post-and-beam construction with massive timbers joined by mortise-and-tenon secured with wooden pegs. Exterior: wattle-and-daub sheathed with hand-riven oak clapboards. Dimensions: ~30-38 feet long, two rooms deep, central chimney. Ceilings ~7 feet. Roofs steeply pitched with riven wooden shingles (cedar or pine). No thatch in Massachusetts.', NULL, NULL, 'sensory', 'architecture', NULL, NULL, 'physical_sensory_details_research.md', 'Saltbox farmhouse — post-and-beam, wattle-and-daub, hand-riven oak clapboard. Post-and-beam construction with massive timbers joined by mortise-and-tenon secured with wooden pegs. Exterior: wattle-and-daub sheathed with hand-riven oak clapboards. Dimensions: ~30-38 feet long, two rooms deep, central chimney. Ceilings ~7 feet. Roofs steeply pitched with riven wooden shingles (cedar or pine). No thatch in Massachusetts.', 'public', '["saltbox","construction","architecture"]', 'salem_project', 1.0, NULL, 1775266565632, 1775266565632, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('no_white_paint', 'No white-painted buildings existed in 1692 — all weathered silvery-gray', 'No white-painted buildings existed in 1692. All exterior surfaces weathered to a silvery-gray patina. The stereotypical white New England buildings came much later. Every building in Salem Village and Salem Town would have been unpainted, weathered wood.', NULL, NULL, 'sensory', 'architecture', NULL, NULL, 'physical_sensory_details_research.md', 'No white-painted buildings existed in 1692 — all weathered silvery-gray. No white-painted buildings existed in 1692. All exterior surfaces weathered to a silvery-gray patina. The stereotypical white New England buildings came much later. Every building in Salem Village and Salem Town would have been unpainted, weathered wood.', 'public', '["unpainted","silvery_gray","myth_debunked"]', 'salem_project', 1.0, NULL, 1775266565632, 1775266565632, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('meetinghouse_dimensions', 'Salem Village Meetinghouse — 34x28x16 feet, no steeple, summoned by drum', 'The Salem Village Meetinghouse was NOT a white-steepled church. 34 feet long, 28 feet wide, 16 feet high. Massive oak timber frame, unpainted clapboard weathered gray. No steeple, no bell tower — congregation summoned by beating drum. Pulpit elevated with sounding board overhead, candle on one side, hourglass on the other. Initially backless benches arranged by social rank. Women east, men west. The tithing man used a long pole to poke anyone who squirmed or slept.', NULL, NULL, 'sensory', 'architecture', NULL, NULL, 'physical_sensory_details_research.md', 'Salem Village Meetinghouse — 34x28x16 feet, no steeple, summoned by drum. The Salem Village Meetinghouse was NOT a white-steepled church. 34 feet long, 28 feet wide, 16 feet high. Massive oak timber frame, unpainted clapboard weathered gray. No steeple, no bell tower — congregation summoned by beating drum. Pulpit elevated with sounding board overhead, candle on one side, hourglass on the other. Initially backless benches arranged by social rank. Women east, men west. The tithing man used a long pole to poke anyone who squirmed or slept.', 'public', '["meetinghouse","no_steeple","drum","dimensions"]', 'salem_project', 1.0, NULL, 1775266565632, 1775266565632, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('meetinghouse_no_heat', 'Meetinghouse had no heating — bread froze, baptismal water froze', 'The meetinghouse had no heating system. Communion bread froze solid — Samuel Sewall recorded it ''rattled sadly into the plates.'' Baptismal water froze. Congregants brought wolf-skin fur bags for warmth. Dogs were brought as living heaters — ''dog-whippers'' were appointed to drive them out when they became disruptive.', NULL, NULL, 'sensory', 'temperature', NULL, 'samuel_sewall', 'physical_sensory_details_research.md', 'Meetinghouse had no heating — bread froze, baptismal water froze. The meetinghouse had no heating system. Communion bread froze solid — Samuel Sewall recorded it ''rattled sadly into the plates.'' Baptismal water froze. Congregants brought wolf-skin fur bags for warmth. Dogs were brought as living heaters — ''dog-whippers'' were appointed to drive them out when they became disruptive.', 'public', '["cold","frozen_bread","wolf_skin","dog_whippers"]', 'salem_project', 1.0, NULL, 1775266565632, 1775266565632, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('ingersolls_taproom', 'Ingersoll''s taproom — sanded floor, firearms on hooks, flip heated with poker', 'The Ingersoll''s Ordinary taproom: large fireplace, bare sanded floor, many stools and chairs. Hooks flanking the fireplace for patrons to hang their firearms. Drinks included hard cider, beer, rum, and flip (beer + rum + eggs/cream + molasses, heated by plunging a red-hot iron poker into the mug, creating a caramelized froth). Also stone fence (rum + cider).', NULL, NULL, 'sensory', 'interior', NULL, 'nathaniel_ingersoll', 'physical_sensory_details_research.md', 'Ingersoll''s taproom — sanded floor, firearms on hooks, flip heated with poker. The Ingersoll''s Ordinary taproom: large fireplace, bare sanded floor, many stools and chairs. Hooks flanking the fireplace for patrons to hang their firearms. Drinks included hard cider, beer, rum, and flip (beer + rum + eggs/cream + molasses, heated by plunging a red-hot iron poker into the mug, creating a caramelized froth). Also stone fence (rum + cider).', 'public', '["taproom","sanded_floor","firearms","flip"]', 'salem_project', 1.0, NULL, 1775266565632, 1775266565632, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('salem_jail_description', 'Salem jail — 20 feet square, dirt floors, stone dungeons, 150 prisoners', 'The Salem jail, built 1684, was approximately 20 feet square, two-story wooden building with two stone-walled dungeons in the basement. Dirt floors, lice, dark. Stank of tobacco and dung. Dungeons ''perpetually dark, bitterly cold, so damp that water ran down the walls.'' At peak, 150 accused were crammed into this tiny space. Prisoners were chained to walls to prevent specters from flying free.', NULL, NULL, 'sensory', 'interior', NULL, NULL, 'physical_sensory_details_research.md', 'Salem jail — 20 feet square, dirt floors, stone dungeons, 150 prisoners. The Salem jail, built 1684, was approximately 20 feet square, two-story wooden building with two stone-walled dungeons in the basement. Dirt floors, lice, dark. Stank of tobacco and dung. Dungeons ''perpetually dark, bitterly cold, so damp that water ran down the walls.'' At peak, 150 accused were crammed into this tiny space. Prisoners were chained to walls to prevent specters from flying free.', 'public', '["jail","20_feet","dungeons","150_prisoners"]', 'salem_project', 1.0, NULL, 1775266565632, 1775266565632, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('english_mansion_description', 'Philip English''s mansion — many-gabled, overhanging stories, secret attic room', 'Philip English''s mansion on Essex Street was the finest and largest private dwelling in Salem. Many gables, overhanging second stories (medieval jetty technique), great porch, secret room discovered in attic when demolished in 1833. Interior: paneled rooms, carved furniture, well-stocked wine cellar, silver plate, pewter, imported textiles, glass windows. Views of both Collins Cove and Salem Harbor. Remained the largest house in Salem for ~100 years.', NULL, NULL, 'sensory', 'architecture', NULL, 'philip_english', 'philip_english_merchant_research.md', 'Philip English''s mansion — many-gabled, overhanging stories, secret attic room. Philip English''s mansion on Essex Street was the finest and largest private dwelling in Salem. Many gables, overhanging second stories (medieval jetty technique), great porch, secret room discovered in attic when demolished in 1833. Interior: paneled rooms, carved furniture, well-stocked wine cellar, silver plate, pewter, imported textiles, glass windows. Views of both Collins Cove and Salem Harbor. Remained the largest house in Salem for ~100 years.', 'public', '["mansion","gables","secret_room","wine_cellar"]', 'salem_project', 1.0, NULL, 1775266565632, 1775266565632, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('windows_types', 'Windows — diamond-paned leaded glass (wealthy), oiled paper (common)', 'Wealthy homes had diamond-paned leaded glass casement windows — small panes in lead cames with wrought-iron hinges. Common homes used oiled paper or wooden shutters. Some had no window covering at all.', NULL, NULL, 'sensory', 'architecture', NULL, NULL, 'physical_sensory_details_research.md', 'Windows — diamond-paned leaded glass (wealthy), oiled paper (common). Wealthy homes had diamond-paned leaded glass casement windows — small panes in lead cames with wrought-iron hinges. Common homes used oiled paper or wooden shutters. Some had no window covering at all.', 'public', '["windows","glass","oiled_paper"]', 'salem_project', 1.0, NULL, 1775266565632, 1775266565632, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('doors_construction', 'Doors — board-and-batten, leather latchstring, rosehead nails', 'Board-and-batten construction. Wooden lift-latches with leather latchstring. Wrought-iron strap hinges for those who could afford them. Hand-forged rosehead nails.', NULL, NULL, 'sensory', 'architecture', NULL, NULL, 'physical_sensory_details_research.md', 'Doors — board-and-batten, leather latchstring, rosehead nails. Board-and-batten construction. Wooden lift-latches with leather latchstring. Wrought-iron strap hinges for those who could afford them. Hand-forged rosehead nails.', 'public', '["doors","latchstring","wrought_iron"]', 'salem_project', 1.0, NULL, 1775266565632, 1775266565632, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('puritans_not_black', 'Puritans did NOT dress in black — ''sadd colors'' meant muted earth tones', 'Puritans did NOT dress in black. Black dye was expensive and faded quickly, reserved for elders, formal occasions, and ministers. The term was ''sadd colors'' — meaning serious/sober. Everyday colors: russet, tawny, murrey (mulberry), dull greens, grays, browns. Available colors included blues (indigo was common), reds, yellows, greens, even purple. Wealthy wore brighter, more saturated colors and imported fabrics.', NULL, NULL, 'sensory', 'clothing', NULL, NULL, 'physical_sensory_details_research.md', 'Puritans did NOT dress in black — ''sadd colors'' meant muted earth tones. Puritans did NOT dress in black. Black dye was expensive and faded quickly, reserved for elders, formal occasions, and ministers. The term was ''sadd colors'' — meaning serious/sober. Everyday colors: russet, tawny, murrey (mulberry), dull greens, grays, browns. Available colors included blues (indigo was common), reds, yellows, greens, even purple. Wealthy wore brighter, more saturated colors and imported fabrics.', 'public', '["clothing","not_black","sadd_colors","myth_debunked"]', 'salem_project', 1.0, NULL, 1775266565632, 1775266565632, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('mens_clothing_1690s', 'Men''s clothing — justaucorps coat, knee breeches, felt hat (no buckle)', 'Men''s 1690s clothing: white linen shirt with full sleeves; cravat at neck (new Steinkirk style popular); fitted long waistcoat over shirt; justaucorps — THE garment of the 1690s, knee-length coat with flared skirts and large turned-back cuffs; knee-length breeches; knit wool or silk stockings above knee; leather shoes with elongated squared toes and small buckles; wide-brimmed felt hat (no buckle — that''s a myth). Wealthy men wore periwigs with center part and long curled ends. Common farmers did not wear wigs.', NULL, NULL, 'sensory', 'clothing', NULL, NULL, 'physical_sensory_details_research.md', 'Men''s clothing — justaucorps coat, knee breeches, felt hat (no buckle). Men''s 1690s clothing: white linen shirt with full sleeves; cravat at neck (new Steinkirk style popular); fitted long waistcoat over shirt; justaucorps — THE garment of the 1690s, knee-length coat with flared skirts and large turned-back cuffs; knee-length breeches; knit wool or silk stockings above knee; leather shoes with elongated squared toes and small buckles; wide-brimmed felt hat (no buckle — that''s a myth). Wealthy men wore periwigs with center part and long curled ends. Common farmers did not wear wigs.', 'public', '["justaucorps","breeches","periwigs","clothing"]', 'salem_project', 1.0, NULL, 1775266565632, 1775266565632, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('womens_clothing', 'Women''s clothing — shift, stays, petticoats, cap always covering hair', 'Women wore a long linen shift (undergarment), stays/bodice laced over it, layered petticoats for warmth, and always an apron. Hair was ALWAYS covered in public with a cap (coif). Women wore the same range of ''sadd colors'' as men.', NULL, NULL, 'sensory', 'clothing', NULL, NULL, 'physical_sensory_details_research.md', 'Women''s clothing — shift, stays, petticoats, cap always covering hair. Women wore a long linen shift (undergarment), stays/bodice laced over it, layered petticoats for warmth, and always an apron. Hair was ALWAYS covered in public with a cap (coif). Women wore the same range of ''sadd colors'' as men.', 'public', '["shift","stays","petticoats","coif","hair_covered"]', 'salem_project', 1.0, NULL, 1775266565632, 1775266565632, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('children_breeching', 'All children wore gowns until breeching at age 6-7', 'Before breeching (birth to 6-7), ALL children — boys and girls — wore gowns/dresses. Breeching was a major rite of passage for boys — receiving first breeches meant entering the male world. After breeching, children dressed as miniature adults.', NULL, NULL, 'sensory', 'clothing', NULL, NULL, 'physical_sensory_details_research.md', 'All children wore gowns until breeching at age 6-7. Before breeching (birth to 6-7), ALL children — boys and girls — wore gowns/dresses. Breeching was a major rite of passage for boys — receiving first breeches meant entering the male world. After breeching, children dressed as miniature adults.', 'public', '["children","gowns","breeching","rite_of_passage"]', 'salem_project', 1.0, NULL, 1775266565632, 1775266565632, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('extraordinary_darkness', 'Colonial darkness — ''darker than anything modern people have experienced''', 'Night was darker than anything modern people have experienced. No street lights, no electricity, no reflected glow. No moon: complete darkness, cannot see hand in front of face. Candlelight illuminated a small sphere, not a room. Hearth glow: warm moving orange — faces close to fire illuminated, everything beyond arm''s reach faded to darkness. Once truly dark, people went to bed. Could not read, sew, or do detail work.', NULL, NULL, 'sensory', 'lighting', NULL, NULL, 'physical_sensory_details_research.md', 'Colonial darkness — ''darker than anything modern people have experienced''. Night was darker than anything modern people have experienced. No street lights, no electricity, no reflected glow. No moon: complete darkness, cannot see hand in front of face. Candlelight illuminated a small sphere, not a room. Hearth glow: warm moving orange — faces close to fire illuminated, everything beyond arm''s reach faded to darkness. Once truly dark, people went to bed. Could not read, sew, or do detail work.', 'public', '["darkness","night","candles","hearth"]', 'salem_project', 1.0, NULL, 1775266565632, 1775266565632, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('milky_way_brilliant', 'The Milky Way was brilliant every clear night — zero light pollution', 'With zero light pollution, the Milky Way was brilliant every clear night. Thousands more visible stars than modern city-dwellers see. Full moon provided enough light to travel, see paths, recognize faces at close distance, and cast sharp shadows.', NULL, NULL, 'sensory', 'lighting', NULL, NULL, 'physical_sensory_details_research.md', 'The Milky Way was brilliant every clear night — zero light pollution. With zero light pollution, the Milky Way was brilliant every clear night. Thousands more visible stars than modern city-dwellers see. Full moon provided enough light to travel, see paths, recognize faces at close distance, and cast sharp shadows.', 'public', '["milky_way","stars","no_light_pollution"]', 'salem_project', 1.0, NULL, 1775266565632, 1775266565632, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('tallow_candles', 'Tallow candles — smoked, stank, barely lit a page of text', 'Tallow candles burned unevenly, smoked, and stank of rendered animal fat. They illuminated only enough for a page of text — not a room. Betty lamps: small iron grease lamps with ''dull, smoky, ill-smelling flame.'' Pine knots (candlewood): bright but extremely smoky, smelled of burning turpentine/pitch. Bayberry candles were rare, clean-burning with subtle evergreen fragrance — special occasions only.', NULL, NULL, 'sensory', 'lighting', NULL, NULL, 'physical_sensory_details_research.md', 'Tallow candles — smoked, stank, barely lit a page of text. Tallow candles burned unevenly, smoked, and stank of rendered animal fat. They illuminated only enough for a page of text — not a room. Betty lamps: small iron grease lamps with ''dull, smoky, ill-smelling flame.'' Pine knots (candlewood): bright but extremely smoky, smelled of burning turpentine/pitch. Bayberry candles were rare, clean-burning with subtle evergreen fragrance — special occasions only.', 'public', '["tallow","candles","betty_lamps","bayberry"]', 'salem_project', 1.0, NULL, 1775266565632, 1775266565632, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('sounds_morning', 'Morning sounds — roosters, cattle, axes, hearth fire, well-rope creak', 'What was ABSENT: no engines, no electrical hum, no mechanical noise, no recorded music. Baseline was natural silence. Morning sounds: roosters (overlapping chorus from different farms), cattle lowing, axes on wood, hearth fire crackling, well-rope creak, splash of bucket.', NULL, NULL, 'sensory', 'sound', NULL, NULL, 'physical_sensory_details_research.md', 'Morning sounds — roosters, cattle, axes, hearth fire, well-rope creak. What was ABSENT: no engines, no electrical hum, no mechanical noise, no recorded music. Baseline was natural silence. Morning sounds: roosters (overlapping chorus from different farms), cattle lowing, axes on wood, hearth fire crackling, well-rope creak, splash of bucket.', 'public', '["sounds","morning","silence","roosters"]', 'salem_project', 1.0, NULL, 1775266565632, 1775266565632, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('sounds_evening', 'Evening sounds — crickets and frogs (wall of sound in summer)', 'Evening sounds: crickets and frogs (wall of sound in summer), wind through branches, family prayer, dogs barking, owl from forest edge. Midday: hammer on anvil (ringing, carrying), mill grinding (deep rumble), children''s voices, livestock bells, wind through pine needles, cart wheels on rutted dirt.', NULL, NULL, 'sensory', 'sound', NULL, NULL, 'physical_sensory_details_research.md', 'Evening sounds — crickets and frogs (wall of sound in summer). Evening sounds: crickets and frogs (wall of sound in summer), wind through branches, family prayer, dogs barking, owl from forest edge. Midday: hammer on anvil (ringing, carrying), mill grinding (deep rumble), children''s voices, livestock bells, wind through pine needles, cart wheels on rutted dirt.', 'public', '["sounds","evening","crickets","frogs"]', 'salem_project', 1.0, NULL, 1775266565632, 1775266565632, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('sounds_meetinghouse', 'Meetinghouse sounds — lined-out psalm singing, drumbeat, tithing man''s pole', 'Meetinghouse sounds: lined-out psalm singing (no instruments — precentor sang each line, congregation repeated). Preaching echoing off sounding board. Coughing. Shuffling. Crying babies. Thump of tithing man''s pole on sleepers. The drumbeat calling to meeting.', NULL, NULL, 'sensory', 'sound', NULL, NULL, 'physical_sensory_details_research.md', 'Meetinghouse sounds — lined-out psalm singing, drumbeat, tithing man''s pole. Meetinghouse sounds: lined-out psalm singing (no instruments — precentor sang each line, congregation repeated). Preaching echoing off sounding board. Coughing. Shuffling. Crying babies. Thump of tithing man''s pole on sleepers. The drumbeat calling to meeting.', 'public', '["sounds","meetinghouse","psalm_singing","drum"]', 'salem_project', 1.0, NULL, 1775266565632, 1775266565632, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('sounds_ingersolls', 'Ingersoll''s sounds — murmuring, tankards, hiss of red-hot poker in flip', 'Sounds at Ingersoll''s Ordinary: low murmuring, tankards on tables, hiss of red-hot poker plunged into flip (creating caramelized froth), fire crackling, door creaking, stools scraping on sanded floor.', NULL, NULL, 'sensory', 'sound', NULL, 'nathaniel_ingersoll', 'physical_sensory_details_research.md', 'Ingersoll''s sounds — murmuring, tankards, hiss of red-hot poker in flip. Sounds at Ingersoll''s Ordinary: low murmuring, tankards on tables, hiss of red-hot poker plunged into flip (creating caramelized froth), fire crackling, door creaking, stools scraping on sanded floor.', 'public', '["sounds","tavern","flip","poker_hiss"]', 'salem_project', 1.0, NULL, 1775266565632, 1775266565632, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('smell_woodsmoke', 'Woodsmoke — the most constant smell, permeated every fabric', 'Woodsmoke was the most constant smell in colonial life — it permeated every fabric and never washed out. Oak smoke was warm, slightly sweet. Pine smoke was sharp and resinous. Every person in Salem Village carried the smell of woodsmoke in their clothing.', NULL, NULL, 'sensory', 'smell', NULL, NULL, 'physical_sensory_details_research.md', 'Woodsmoke — the most constant smell, permeated every fabric. Woodsmoke was the most constant smell in colonial life — it permeated every fabric and never washed out. Oak smoke was warm, slightly sweet. Pine smoke was sharp and resinous. Every person in Salem Village carried the smell of woodsmoke in their clothing.', 'public', '["woodsmoke","smell","constant"]', 'salem_project', 1.0, NULL, 1775266565632, 1775266565632, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('smell_waterfront', 'Salem Town waterfront — tar, hemp rope, drying fish, bilge water', 'Salem Town waterfront smells: salt air, tar (the dominant smell), hemp rope, drying fish on racks, bilge water. The tar smell came from Stockholm tar used to preserve rigging and hulls.', NULL, NULL, 'sensory', 'smell', NULL, NULL, 'physical_sensory_details_research.md', 'Salem Town waterfront — tar, hemp rope, drying fish, bilge water. Salem Town waterfront smells: salt air, tar (the dominant smell), hemp rope, drying fish on racks, bilge water. The tar smell came from Stockholm tar used to preserve rigging and hulls.', 'public', '["waterfront","tar","fish","bilge"]', 'salem_project', 1.0, NULL, 1775266565632, 1775266565632, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('smell_meetinghouse_summer', 'Crowded meetinghouse in summer — unwashed bodies, wool, sweat', 'The crowded meetinghouse in summer: unwashed bodies, wool saturated with woodsmoke and sweat. ''Overwhelming by modern standards.'' The prison was worse: human waste, damp stone, unwashed bodies, tobacco, fear-sweat. 150 people in a 20x20 building.', NULL, NULL, 'sensory', 'smell', NULL, NULL, 'physical_sensory_details_research.md', 'Crowded meetinghouse in summer — unwashed bodies, wool, sweat. The crowded meetinghouse in summer: unwashed bodies, wool saturated with woodsmoke and sweat. ''Overwhelming by modern standards.'' The prison was worse: human waste, damp stone, unwashed bodies, tobacco, fear-sweat. 150 people in a 20x20 building.', 'public', '["smell","summer","unwashed","overwhelming"]', 'salem_project', 1.0, NULL, 1775266565632, 1775266565632, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('not_stone_walls', 'Fences were NOT stone walls — zigzag worm fences of split rails', 'Stone walls are an 18th-19th century feature. In 1692, all fences were worm fences (zigzag/snake fences) of split rails stacked alternately without posts, or post-and-rail for more permanent boundaries.', NULL, NULL, 'sensory', 'landscape', NULL, NULL, 'physical_sensory_details_research.md', 'Fences were NOT stone walls — zigzag worm fences of split rails. Stone walls are an 18th-19th century feature. In 1692, all fences were worm fences (zigzag/snake fences) of split rails stacked alternately without posts, or post-and-rail for more permanent boundaries.', 'public', '["fences","worm_fences","not_stone_walls","myth_debunked"]', 'salem_project', 1.0, NULL, 1775266565632, 1775266565632, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('forest_satans_domain', 'The forest — Satan''s domain in Puritan theology', 'Most of New England was still heavily forested in 1692. The forest pressed close to village clearings. White pine (2-2.5 feet diameter, 200-300 years old), oaks, sugar maple, beech, birch, hemlock, chestnut. In Puritan theology, the forest was the boundary of the known world — the domain of Satan.', NULL, NULL, 'sensory', 'landscape', NULL, NULL, 'physical_sensory_details_research.md', 'The forest — Satan''s domain in Puritan theology. Most of New England was still heavily forested in 1692. The forest pressed close to village clearings. White pine (2-2.5 feet diameter, 200-300 years old), oaks, sugar maple, beech, birch, hemlock, chestnut. In Puritan theology, the forest was the boundary of the known world — the domain of Satan.', 'public', '["forest","satan","wilderness","theology"]', 'salem_project', 1.0, NULL, 1775266565632, 1775266565632, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('mud_season', 'Mud season (March-April) — roads impassable, ruts 2 feet deep', 'Roads were dirt tracks, barely cart-width. During mud season (March-April), they were virtually impassable — ruts 2 feet deep, stumps, slush. 1692 specifically saw ''memorable spring floods.'' The witch crisis accelerated during this exact period.', NULL, NULL, 'sensory', 'landscape', NULL, NULL, 'physical_sensory_details_research.md', 'Mud season (March-April) — roads impassable, ruts 2 feet deep. Roads were dirt tracks, barely cart-width. During mud season (March-April), they were virtually impassable — ruts 2 feet deep, stumps, slush. 1692 specifically saw ''memorable spring floods.'' The witch crisis accelerated during this exact period.', 'public', '["mud_season","roads","impassable","floods"]', 'salem_project', 1.0, NULL, 1775266565633, 1775266565633, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('seasons_daylight', 'Seasonal daylight — 9.5 hours in January, 15.5 hours in June', 'January/February: sunrise ~7:15am, sunset ~4:45pm (9.5 hours daylight). Deep snow, bare hardwoods, frozen streams. June/July: sunrise ~5:00am, sunset ~8:30pm (15.5 hours daylight). Full green, insects, frogs calling. September/October: fall foliage — sugar maples gold/red, oaks russet/bronze, birches yellow. First frosts.', NULL, NULL, 'sensory', 'seasons', NULL, NULL, 'physical_sensory_details_research.md', 'Seasonal daylight — 9.5 hours in January, 15.5 hours in June. January/February: sunrise ~7:15am, sunset ~4:45pm (9.5 hours daylight). Deep snow, bare hardwoods, frozen streams. June/July: sunrise ~5:00am, sunset ~8:30pm (15.5 hours daylight). Full green, insects, frogs calling. September/October: fall foliage — sugar maples gold/red, oaks russet/bronze, birches yellow. First frosts.', 'public', '["seasons","daylight","sunrise","sunset"]', 'salem_project', 1.0, NULL, 1775266565633, 1775266565633, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('sand_floor_patterns', 'Floors covered with sand swept into decorative patterns', 'Wide plank board floors (1-2 feet wide) were covered with sand swept into decorative patterns — scrolls, feathers, herringbones. The sand kept the floors clean and provided traction.', NULL, NULL, 'sensory', 'interior', NULL, NULL, 'physical_sensory_details_research.md', 'Floors covered with sand swept into decorative patterns. Wide plank board floors (1-2 feet wide) were covered with sand swept into decorative patterns — scrolls, feathers, herringbones. The sand kept the floors clean and provided traction.', 'public', '["floors","sand","decorative_patterns"]', 'salem_project', 1.0, NULL, 1775266565633, 1775266565633, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('cooking_equipment', 'Cooking equipment — all wrought iron, iron crane, trammels, lug pole', 'All cooking equipment was wrought iron: iron crane (swinging in/out), pot hooks, trammels (adjustable hangers), lug pole (dangerous green-wood pole in less advanced kitchens), round-bodied three-legged pots, trivets, gridirons, spits, flesh forks, Dutch ovens. The fireplace was ~5 feet wide with an iron crane and chains.', NULL, NULL, 'sensory', 'interior', NULL, NULL, 'physical_sensory_details_research.md', 'Cooking equipment — all wrought iron, iron crane, trammels, lug pole. All cooking equipment was wrought iron: iron crane (swinging in/out), pot hooks, trammels (adjustable hangers), lug pole (dangerous green-wood pole in less advanced kitchens), round-bodied three-legged pots, trivets, gridirons, spits, flesh forks, Dutch ovens. The fireplace was ~5 feet wide with an iron crane and chains.', 'public', '["cooking","wrought_iron","fireplace","crane"]', 'salem_project', 1.0, NULL, 1775266565633, 1775266565633, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('food_hasty_pudding', 'Hasty pudding (cornmeal mush) — the most common food', 'Hasty pudding — cornmeal mush — was the most common daily food. Brown bread (cornmeal, rye, wheat flour) was paired with baked beans for Saturday supper. Succotash (corn and beans) came from Native American cooking. Salt cod was the staple protein, especially in winter. Salt pork/bacon was the primary year-round protein.', NULL, NULL, 'sensory', 'food', NULL, NULL, 'physical_sensory_details_research.md', 'Hasty pudding (cornmeal mush) — the most common food. Hasty pudding — cornmeal mush — was the most common daily food. Brown bread (cornmeal, rye, wheat flour) was paired with baked beans for Saturday supper. Succotash (corn and beans) came from Native American cooking. Salt cod was the staple protein, especially in winter. Salt pork/bacon was the primary year-round protein.', 'public', '["food","hasty_pudding","brown_bread","salt_cod"]', 'salem_project', 1.0, NULL, 1775266565633, 1775266565633, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('drink_hard_cider', 'Hard cider — primary beverage, all ages; water avoided as unsafe', 'Hard cider was the primary beverage for all ages. Small beer (1-2% alcohol) was given to children — considered safer than water. Water was generally avoided as potentially unsafe. Flip (beer + rum + eggs/cream + molasses heated by plunging red-hot iron poker) was a tavern specialty.', NULL, NULL, 'sensory', 'drink', NULL, NULL, 'physical_sensory_details_research.md', 'Hard cider — primary beverage, all ages; water avoided as unsafe. Hard cider was the primary beverage for all ages. Small beer (1-2% alcohol) was given to children — considered safer than water. Water was generally avoided as potentially unsafe. Flip (beer + rum + eggs/cream + molasses heated by plunging red-hot iron poker) was a tavern specialty.', 'public', '["cider","small_beer","children","water_unsafe"]', 'salem_project', 1.0, NULL, 1775266565633, 1775266565633, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('minister_daily_labor', 'Minister''s primary labor — sermon preparation timed by hourglass', 'A Puritan minister''s life revolved around study, prayer, sermon preparation, and pastoral care. The hourglass timed sermon delivery but was frequently turned for a second or third run. Parris kept a sermon notebook (1689-1694). Key sermon themes: Satanic invasion, hidden evil and betrayal, church purity, covenant vs. witchcraft.', NULL, NULL, 'occupational', 'minister', NULL, 'samuel_parris', 'occupational_knowledge_map.md', 'Minister''s primary labor — sermon preparation timed by hourglass. A Puritan minister''s life revolved around study, prayer, sermon preparation, and pastoral care. The hourglass timed sermon delivery but was frequently turned for a second or third run. Parris kept a sermon notebook (1689-1694). Key sermon themes: Satanic invasion, hidden evil and betrayal, church purity, covenant vs. witchcraft.', 'public', '["minister","sermon","hourglass","study"]', 'salem_project', 1.0, NULL, 1775266565633, 1775266565633, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('parris_books', 'Parris''s library — Ames, Perkins, Dalton, Cotton Mather''s Memorable Providences', 'Books Parris would consult: the Bible (Geneva and King James), William Ames''s The Marrow of Theology (main Harvard textbook), William Perkins (practical religion, predestination), Richard Baxter, Richard Sibbes, John Cotton, John Preston, Michael Dalton''s The Country Justice (manual for justices), Richard Bernard''s Guide to Grand-Jury Men (witchcraft prosecution), and critically — Cotton Mather''s Memorable Providences (1689) was in Parris''s personal library.', NULL, NULL, 'occupational', 'minister', NULL, 'samuel_parris', 'occupational_knowledge_map.md', 'Parris''s library — Ames, Perkins, Dalton, Cotton Mather''s Memorable Providences. Books Parris would consult: the Bible (Geneva and King James), William Ames''s The Marrow of Theology (main Harvard textbook), William Perkins (practical religion, predestination), Richard Baxter, Richard Sibbes, John Cotton, John Preston, Michael Dalton''s The Country Justice (manual for justices), Richard Bernard''s Guide to Grand-Jury Men (witchcraft prosecution), and critically — Cotton Mather''s Memorable Providences (1689) was in Parris''s personal library.', 'public', '["books","library","memorable_providences","theology"]', 'salem_project', 1.0, NULL, 1775266565633, 1775266565633, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('magistrate_no_training', 'Colonial magistrates had no formal legal training', 'Colonial magistrates were not professional jurists. They were wealthy men appointed primarily because of social standing. Jonathan Corwin was a prosperous shipbuilder and merchant who ''came by his work as a magistrate primarily because of his wealth.'' Hathorne was a justice of the peace mediating disputes. Available law books: Michael Dalton''s The Country Justice, the Body of Liberties (1641), the Witchcraft Act of 1604.', NULL, NULL, 'occupational', 'magistrate', NULL, 'john_hathorne', 'occupational_knowledge_map.md', 'Colonial magistrates had no formal legal training. Colonial magistrates were not professional jurists. They were wealthy men appointed primarily because of social standing. Jonathan Corwin was a prosperous shipbuilder and merchant who ''came by his work as a magistrate primarily because of his wealth.'' Hathorne was a justice of the peace mediating disputes. Available law books: Michael Dalton''s The Country Justice, the Body of Liberties (1641), the Witchcraft Act of 1604.', 'public', '["magistrate","no_training","wealthy_men"]', 'salem_project', 1.0, NULL, 1775266565633, 1775266565633, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('hathorne_examination_technique', 'Hathorne''s prosecutorial examination style — ''Why do you hurt these children?''', 'Hathorne''s standard opening was prosecutorial: ''Why do you hurt these children?'' He accepted the ''touch test'' and did not give accused adequate time to refute accusations. Historian Charles Upham noted his ''examination was conducted in the form of questions based upon a foregone conclusion of the prisoner''s guilt.''', NULL, NULL, 'occupational', 'magistrate', NULL, 'john_hathorne', 'occupational_knowledge_map.md', 'Hathorne''s prosecutorial examination style — ''Why do you hurt these children?''. Hathorne''s standard opening was prosecutorial: ''Why do you hurt these children?'' He accepted the ''touch test'' and did not give accused adequate time to refute accusations. Historian Charles Upham noted his ''examination was conducted in the form of questions based upon a foregone conclusion of the prisoner''s guilt.''', 'public', '["examination","prosecutorial","touch_test"]', 'salem_project', 1.0, NULL, 1775266565633, 1775266565633, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('farmer_agricultural_year', 'Farmer''s year — 30-50 cords of wood, executions during harvest', 'The farming calendar: January-February: woodcutting (30-50 cords/year), tool repair, spinning. March: fence repair, maple sugaring. April: plowing, harrowing — the crisis accelerated during planting. May: most labor-intensive planting — Court of Oyer and Terminer established May 27. June: constant weeding — Bishop executed June 10. July: hay cutting — five hanged July 19 during haying. August: threshing — five executed August 19 at peak harvest. September: corn harvest, cider pressing — eight hanged September 22 during harvest.', NULL, NULL, 'occupational', 'farmer', NULL, 'thomas_putnam_jr', 'occupational_knowledge_map.md', 'Farmer''s year — 30-50 cords of wood, executions during harvest. The farming calendar: January-February: woodcutting (30-50 cords/year), tool repair, spinning. March: fence repair, maple sugaring. April: plowing, harrowing — the crisis accelerated during planting. May: most labor-intensive planting — Court of Oyer and Terminer established May 27. June: constant weeding — Bishop executed June 10. July: hay cutting — five hanged July 19 during haying. August: threshing — five executed August 19 at peak harvest. September: corn harvest, cider pressing — eight hanged September 22 during harvest.', 'public', '["agricultural_calendar","harvest","executions_during_farming"]', 'salem_project', 1.0, NULL, 1775266565633, 1775266565633, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('farmer_crops_livestock', 'Crops and livestock — corn, rye, ~100,000 sheep in Massachusetts', 'Crops: corn (maize), rye, oats, flax, hay, wheat, barley. Kitchen garden: beans, squash, pumpkins, herbs, peas, turnips, parsnips, onions. Livestock: cattle, pigs, sheep (~100,000 in Massachusetts by 1664), chickens, oxen. A household burned approximately 40 cords of firewood per year.', NULL, NULL, 'occupational', 'farmer', NULL, NULL, 'occupational_knowledge_map.md', 'Crops and livestock — corn, rye, ~100,000 sheep in Massachusetts. Crops: corn (maize), rye, oats, flax, hay, wheat, barley. Kitchen garden: beans, squash, pumpkins, herbs, peas, turnips, parsnips, onions. Livestock: cattle, pigs, sheep (~100,000 in Massachusetts by 1664), chickens, oxen. A household burned approximately 40 cords of firewood per year.', 'public', '["crops","livestock","firewood","40_cords"]', 'salem_project', 1.0, NULL, 1775266565633, 1775266565633, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('constable_duties', 'Constable duties — serving warrants, transporting prisoners, collecting taxes', 'Constable duties included: serving warrants, collecting taxes, maintaining order at examinations, transporting prisoners, supervising elections, testifying in court. Joseph Herrick executed the first warrants on February 29, 1692. He was initially ''persuaded by the accusers; by the end he had become a skeptic.''', NULL, NULL, 'occupational', 'constable', NULL, NULL, 'occupational_knowledge_map.md', 'Constable duties — serving warrants, transporting prisoners, collecting taxes. Constable duties included: serving warrants, collecting taxes, maintaining order at examinations, transporting prisoners, supervising elections, testifying in court. Joseph Herrick executed the first warrants on February 29, 1692. He was initially ''persuaded by the accusers; by the end he had become a skeptic.''', 'public', '["constable","warrants","taxes","prisoners"]', 'salem_project', 1.0, NULL, 1775266565633, 1775266565633, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('merchant_financial_instruments', 'Merchant''s financial instruments — bills of exchange, promissory notes, book credit', 'Financial instruments used by merchants: bills of exchange (primary for international trade), promissory notes (personal IOUs circulating as currency), letters of credit (from London merchant houses), book credit (networks of debt tracked in ledgers). Massachusetts issued the first paper bills of credit in the Western world in 1690 to pay soldiers from the failed Quebec expedition.', NULL, NULL, 'occupational', 'merchant', NULL, 'philip_english', 'occupational_knowledge_map.md', 'Merchant''s financial instruments — bills of exchange, promissory notes, book credit. Financial instruments used by merchants: bills of exchange (primary for international trade), promissory notes (personal IOUs circulating as currency), letters of credit (from London merchant houses), book credit (networks of debt tracked in ledgers). Massachusetts issued the first paper bills of credit in the Western world in 1690 to pay soldiers from the failed Quebec expedition.', 'public', '["bills_of_exchange","promissory_notes","book_credit"]', 'salem_project', 1.0, NULL, 1775266565633, 1775266565633, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('ship_captain_navigation', 'Ship captain''s navigation — The English Pilot, dead reckoning, lead line', 'Navigation tools and methods: The English Pilot (charts, sailing directions, soundings), dead reckoning (the primary method), celestial navigation (latitude by sun and stars), lead line soundings, compass, log line. Captain John Alden Jr. was accused while returning from Quebec where he had ransomed captives from the York massacre.', NULL, NULL, 'occupational', 'ship_captain', NULL, NULL, 'occupational_knowledge_map.md', 'Ship captain''s navigation — The English Pilot, dead reckoning, lead line. Navigation tools and methods: The English Pilot (charts, sailing directions, soundings), dead reckoning (the primary method), celestial navigation (latitude by sun and stars), lead line soundings, compass, log line. Captain John Alden Jr. was accused while returning from Quebec where he had ransomed captives from the York massacre.', 'public', '["navigation","english_pilot","dead_reckoning"]', 'salem_project', 1.0, NULL, 1775266565633, 1775266565633, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('griggs_medical_framework', 'Dr. Griggs''s medical framework — Galenic humoral theory, three diagnostic categories', 'Dr. Griggs practiced Galenic humoral theory — illness from imbalance in blood, phlegm, black bile, yellow bile. Treatments: bloodletting, purging (emetics/cathartics), sweating, mercury, opium, herbal remedies combined with prayer. Three diagnostic categories: 1) Natural disease (treatable), 2) Bewitchment (supernatural), 3) Divine punishment (requiring repentance). When he couldn''t cure the girls'' afflictions, he moved to category 2.', NULL, NULL, 'occupational', 'physician', NULL, 'william_griggs', 'births_deaths_illness_research.md', 'Dr. Griggs''s medical framework — Galenic humoral theory, three diagnostic categories. Dr. Griggs practiced Galenic humoral theory — illness from imbalance in blood, phlegm, black bile, yellow bile. Treatments: bloodletting, purging (emetics/cathartics), sweating, mercury, opium, herbal remedies combined with prayer. Three diagnostic categories: 1) Natural disease (treatable), 2) Bewitchment (supernatural), 3) Divine punishment (requiring repentance). When he couldn''t cure the girls'' afflictions, he moved to category 2.', 'public', '["humoral_theory","bloodletting","diagnosis","bewitchment"]', 'salem_project', 1.0, NULL, 1775266565633, 1775266565633, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('midwife_herbal_remedies', 'Midwife herbal remedies — feverfew, comfrey, sassafras, tobacco, datura', 'Herbal remedies brought from England: feverfew (fevers), burnet, groundivy, Saint-John''s-wort (burns/wounds), clary sage (removing foreign objects from eyes), comfrey (cuts/broken bones), foxglove (obstructions/phlegm). Adopted from Native Americans: white hellebore (wounds, with raccoon grease), birch bark (cuts/bruises), sassafras (fevers/syphilis), tobacco (digestion/gout/toothache), alder bark (burns). Other: black hellebore (madness/epilepsy), saffron (jaundice), datura (spasmodic disorders/hysteria).', NULL, NULL, 'occupational', 'midwife', NULL, NULL, 'births_deaths_illness_research.md', 'Midwife herbal remedies — feverfew, comfrey, sassafras, tobacco, datura. Herbal remedies brought from England: feverfew (fevers), burnet, groundivy, Saint-John''s-wort (burns/wounds), clary sage (removing foreign objects from eyes), comfrey (cuts/broken bones), foxglove (obstructions/phlegm). Adopted from Native Americans: white hellebore (wounds, with raccoon grease), birch bark (cuts/bruises), sassafras (fevers/syphilis), tobacco (digestion/gout/toothache), alder bark (burns). Other: black hellebore (madness/epilepsy), saffron (jaundice), datura (spasmodic disorders/hysteria).', 'public', '["herbal_remedies","native_american","midwifery"]', 'salem_project', 1.0, NULL, 1775266565633, 1775266565633, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('children_labor', 'Children worked from age 5 — carrying wood, carding wool, cooking', 'Children began labor at age 5+: carrying wood, fetching water, carding wool, cooking, spinning. Orphaned and displaced children were ''put out'' as servants: Elizabeth Hubbard (orphan, served Griggs), Mercy Lewis (orphaned 1689, served Burroughs then Putnam), Mary Warren (served Proctor), Sarah Churchill (Maine refugee), Tituba (enslaved in Parris household).', NULL, NULL, 'occupational', 'children', NULL, 'elizabeth_hubbard', 'social_bonds_daily_life.md', 'Children worked from age 5 — carrying wood, carding wool, cooking. Children began labor at age 5+: carrying wood, fetching water, carding wool, cooking, spinning. Orphaned and displaced children were ''put out'' as servants: Elizabeth Hubbard (orphan, served Griggs), Mercy Lewis (orphaned 1689, served Burroughs then Putnam), Mary Warren (served Proctor), Sarah Churchill (Maine refugee), Tituba (enslaved in Parris household).', 'public', '["children","labor","servants","orphans"]', 'salem_project', 1.0, NULL, 1775266565633, 1775266565633, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('childbirth_mortality', 'Childbirth mortality — 1 in 40 maternal deaths, 15-30% infant mortality', 'Childbirth mortality rates: ~1 maternal death per 40 births (2.5%). 1 in 24 babies died within first day; stillbirths = 40% of that number. Infant mortality: 150-300 per 1,000 births (15-30%). Under-5 mortality: 30-50% of all deaths. The birthing chamber was dimly lit, crowded, barely antiseptic. New mothers were extremely vulnerable to infection — risks 20-40x normal.', NULL, NULL, 'occupational', 'midwife', NULL, NULL, 'births_deaths_illness_research.md', 'Childbirth mortality — 1 in 40 maternal deaths, 15-30% infant mortality. Childbirth mortality rates: ~1 maternal death per 40 births (2.5%). 1 in 24 babies died within first day; stillbirths = 40% of that number. Infant mortality: 150-300 per 1,000 births (15-30%). Under-5 mortality: 30-50% of all deaths. The birthing chamber was dimly lit, crowded, barely antiseptic. New mothers were extremely vulnerable to infection — risks 20-40x normal.', 'public', '["childbirth","mortality","infant_death"]', 'salem_project', 1.0, NULL, 1775266565633, 1775266565633, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('salem_harbor_description', 'Salem harbor — South River inlet, 6-12 working wharves, 30-50 vessels', 'Salem harbor was a South River inlet with 6-12 working wharves in 1692. Mudflats at low tide. The fleet numbered approximately 30-50 vessels. Named wharves included Philip English''s (south harbor), Gedney''s shipyard, Hathorne''s wharf, Corwin family wharf, and Daniel Andrew''s (Frost Fish Brook, built February 1692).', NULL, NULL, 'maritime', 'harbor', NULL, 'philip_english', 'salem_waterfront_trade_research.md', 'Salem harbor — South River inlet, 6-12 working wharves, 30-50 vessels. Salem harbor was a South River inlet with 6-12 working wharves in 1692. Mudflats at low tide. The fleet numbered approximately 30-50 vessels. Named wharves included Philip English''s (south harbor), Gedney''s shipyard, Hathorne''s wharf, Corwin family wharf, and Daniel Andrew''s (Frost Fish Brook, built February 1692).', 'public', '["harbor","wharves","fleet"]', 'salem_project', 1.0, NULL, 1775266565633, 1775266565633, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('ketch_specifications', 'Ketches — dominant vessel type, 2 masts, 10-70 tons, crew of 6-12', 'Ketches were the dominant vessel type in Salem''s fleet. Two masts, fore-and-aft rigged, typically 10-70 tons (majority 20-50). Crews of 6-12. Ideal for West Indies and coastal trade. Philip English''s known vessel the Speedwell was a ketch. Sloops (single-masted, 4-80 tons, majority 15-40) were used for coastal and short Caribbean runs.', NULL, NULL, 'maritime', 'vessels', NULL, 'philip_english', 'salem_waterfront_trade_research.md', 'Ketches — dominant vessel type, 2 masts, 10-70 tons, crew of 6-12. Ketches were the dominant vessel type in Salem''s fleet. Two masts, fore-and-aft rigged, typically 10-70 tons (majority 20-50). Crews of 6-12. Ideal for West Indies and coastal trade. Philip English''s known vessel the Speedwell was a ketch. Sloops (single-masted, 4-80 tons, majority 15-40) were used for coastal and short Caribbean runs.', 'public', '["ketch","sloop","specifications","speedwell"]', 'salem_project', 1.0, NULL, 1775266565634, 1775266565634, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('shipbuilding_materials', 'Shipbuilding — oak keel, oak frames, wooden treenails, Stockholm tar', 'Shipbuilding materials: oak keel, oak frames, oak planking, wooden treenails, iron bolts, oakum caulking, white pine masts, Stockholm tar for rigging. Tar was the dominant smell on the waterfront — it permeated everything and came from preserved rigging and hulls.', NULL, NULL, 'maritime', 'construction', NULL, NULL, 'salem_waterfront_trade_research.md', 'Shipbuilding — oak keel, oak frames, wooden treenails, Stockholm tar. Shipbuilding materials: oak keel, oak frames, oak planking, wooden treenails, iron bolts, oakum caulking, white pine masts, Stockholm tar for rigging. Tar was the dominant smell on the waterfront — it permeated everything and came from preserved rigging and hulls.', 'public', '["shipbuilding","oak","tar","treenails"]', 'salem_project', 1.0, NULL, 1775266565634, 1775266565634, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('counting_house', 'Counting house — standing desk, strongbox, sand shaker, sealing wax', 'A merchant''s counting house contained: high standing desk, locked strongbox for coin, shelves of account books, sand shaker for drying ink, quill pens, iron gall ink, sealing wax, scale and weights for weighing coin. Philip English''s counting house in his mansion complex was the nerve center of his 21-vessel trading empire.', NULL, NULL, 'maritime', 'commercial', NULL, 'philip_english', 'salem_waterfront_trade_research.md', 'Counting house — standing desk, strongbox, sand shaker, sealing wax. A merchant''s counting house contained: high standing desk, locked strongbox for coin, shelves of account books, sand shaker for drying ink, quill pens, iron gall ink, sealing wax, scale and weights for weighing coin. Philip English''s counting house in his mansion complex was the nerve center of his 21-vessel trading empire.', 'public', '["counting_house","strongbox","ledgers"]', 'salem_project', 1.0, NULL, 1775266565634, 1775266565634, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('thomas_pound_piracy', 'Thomas Pound — respected Boston pilot turned pirate, captured, pardoned', 'Thomas Pound was a respected Boston harbor pilot who turned pirate in 1689. He commandeered a vessel and raided coastal Massachusetts shipping. Captured in October 1689 at Tarpaulin Cove in a gunfight. Convicted but pardoned through political connections — demonstrating how thin the line was between respectable maritime activity and piracy.', '1689', 'year', 'maritime', 'piracy', NULL, NULL, 'piracy_privateering_maritime_research.md', 'Thomas Pound — respected Boston pilot turned pirate, captured, pardoned. Thomas Pound was a respected Boston harbor pilot who turned pirate in 1689. He commandeered a vessel and raided coastal Massachusetts shipping. Captured in October 1689 at Tarpaulin Cove in a gunfight. Convicted but pardoned through political connections — demonstrating how thin the line was between respectable maritime activity and piracy.', 'public', '["piracy","thomas_pound","pardoned"]', 'salem_project', 1.0, NULL, 1775266565634, 1775266565634, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('french_privateers', 'French privateers terrorizing New England shipping during King William''s War', 'French privateers included Pierre Le Moyne d''Iberville, Pierre Maisonnat dit Baptiste, and Simon-Pierre Denys de Bonaventure. Baron de Saint-Castin operated from the Maine coast. These privateers made every merchant voyage dangerous and drove insurance rates from 1.5% to 11-14% of cargo value.', NULL, NULL, 'maritime', 'piracy', NULL, 'philip_english', 'piracy_privateering_maritime_research.md', 'French privateers terrorizing New England shipping during King William''s War. French privateers included Pierre Le Moyne d''Iberville, Pierre Maisonnat dit Baptiste, and Simon-Pierre Denys de Bonaventure. Baron de Saint-Castin operated from the Maine coast. These privateers made every merchant voyage dangerous and drove insurance rates from 1.5% to 11-14% of cargo value.', 'public', '["privateers","french","diberville","saint_castin"]', 'salem_project', 1.0, NULL, 1775266565634, 1775266565634, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('phips_treasure', 'Phips salvages ~207,000 pounds of Spanish treasure — knighted', 'In 1687, William Phips salvaged approximately 207,000 pounds worth of Spanish treasure from the wrecked Concepción off Hispaniola. He was knighted by King James II for this feat. His journey from illiterate shepherd to treasure hunter to knight to governor was one of the most remarkable social climbs in colonial history.', '1687', 'year', 'maritime', 'treasure', NULL, 'william_phips', 'piracy_privateering_maritime_research.md', 'Phips salvages ~207,000 pounds of Spanish treasure — knighted. In 1687, William Phips salvaged approximately 207,000 pounds worth of Spanish treasure from the wrecked Concepción off Hispaniola. He was knighted by King James II for this feat. His journey from illiterate shepherd to treasure hunter to knight to governor was one of the most remarkable social climbs in colonial history.', 'public', '["treasure","concepcion","knighted","207000_pounds"]', 'salem_project', 1.0, NULL, 1775266565634, 1775266565634, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('village_map_147_dwellings', 'Upham''s 1866 map shows 147 numbered dwellings in Salem Village area', 'Charles Upham''s 1866 map of Salem Village shows 147 numbered dwellings with identified residents. The village was divided roughly into western/Putnam territory and eastern/Porter territory, with central and border zones.', NULL, NULL, 'geographic', 'settlement', NULL, NULL, 'village_geography_research.md', 'Upham''s 1866 map shows 147 numbered dwellings in Salem Village area. Charles Upham''s 1866 map of Salem Village shows 147 numbered dwellings with identified residents. The village was divided roughly into western/Putnam territory and eastern/Porter territory, with central and border zones.', 'public', '["map","upham","147_dwellings"]', 'salem_project', 1.0, NULL, 1775266565634, 1775266565634, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('putnam_territory_west', 'Putnam territory — western Salem Village', 'Western Salem Village was Putnam territory. Key homesteads: #24 Thomas Putnam Jr., #23 Edward Putnam, #37 John Putnam Jr., #41 Jonathan Putnam, #47 Captain John Putnam, #32 Joseph Putnam (the defector who married Elizabeth Porter). #79 Nathaniel Putnam was adjacent to #95 Francis Nurse.', NULL, NULL, 'geographic', 'faction', NULL, 'thomas_putnam_jr', 'village_geography_research.md', 'Putnam territory — western Salem Village. Western Salem Village was Putnam territory. Key homesteads: #24 Thomas Putnam Jr., #23 Edward Putnam, #37 John Putnam Jr., #41 Jonathan Putnam, #47 Captain John Putnam, #32 Joseph Putnam (the defector who married Elizabeth Porter). #79 Nathaniel Putnam was adjacent to #95 Francis Nurse.', 'public', '["territory","putnam","western","homesteads"]', 'salem_project', 1.0, NULL, 1775266565634, 1775266565634, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('porter_territory_east', 'Porter territory — eastern Salem Village, oriented toward Town', 'Eastern Salem Village was Porter territory, oriented toward Salem Town and its commercial opportunities. Key homesteads: #80 Israel Porter, #35 Daniel Andrew (married Sarah Porter), #83 Dr. William Griggs. Beverly border: Old Planter families (Dodge, Herrick, Conant, Balch, Gage).', NULL, NULL, 'geographic', 'faction', NULL, 'israel_porter', 'village_geography_research.md', 'Porter territory — eastern Salem Village, oriented toward Town. Eastern Salem Village was Porter territory, oriented toward Salem Town and its commercial opportunities. Key homesteads: #80 Israel Porter, #35 Daniel Andrew (married Sarah Porter), #83 Dr. William Griggs. Beverly border: Old Planter families (Dodge, Herrick, Conant, Balch, Gage).', 'public', '["territory","porter","eastern","commercial"]', 'salem_project', 1.0, NULL, 1775266565634, 1775266565634, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('putnam_nurse_adjacent', 'Nathaniel Putnam and Francis Nurse homesteads adjacent — feuding neighbors', 'Nathaniel Putnam''s homestead (#79) was adjacent to Francis Nurse''s 300-acre farm (#95). This physical proximity intensified their boundary dispute over the Bishop Farm/Endicott Orchard Farm, which had been the subject of multiple surveys and court rulings.', NULL, NULL, 'geographic', 'proximity', NULL, 'francis_nurse', 'village_geography_research.md', 'Nathaniel Putnam and Francis Nurse homesteads adjacent — feuding neighbors. Nathaniel Putnam''s homestead (#79) was adjacent to Francis Nurse''s 300-acre farm (#95). This physical proximity intensified their boundary dispute over the Bishop Farm/Endicott Orchard Farm, which had been the subject of multiple surveys and court rulings.', 'public', '["adjacent","boundary_dispute","putnam_nurse"]', 'salem_project', 1.0, NULL, 1775266565634, 1775266565634, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('topsfield_border_error', 'Topsfield border dispute originated from 1639 clerical error', 'The Topsfield border dispute originated from a 1639 clerical error in boundary records. Captain John Putnam and sons cut timber on Topsfield land in the 1680s. The Towne/Easty/Wildes families testified against the Putnams in 1686 court proceedings. The court ruled for Topsfield. This is one of the likely motives behind the Putnam family''s accusations against the Towne sisters (Rebecca Nurse, Mary Easty, Sarah Cloyce) — all Topsfield-connected.', '1639', 'year', 'geographic', 'dispute', NULL, 'rebecca_nurse', 'village_disputes_research.md', 'Topsfield border dispute originated from 1639 clerical error. The Topsfield border dispute originated from a 1639 clerical error in boundary records. Captain John Putnam and sons cut timber on Topsfield land in the 1680s. The Towne/Easty/Wildes families testified against the Putnams in 1686 court proceedings. The court ruled for Topsfield. This is one of the likely motives behind the Putnam family''s accusations against the Towne sisters (Rebecca Nurse, Mary Easty, Sarah Cloyce) — all Topsfield-connected.', 'public', '["topsfield","border","clerical_error","motive"]', 'salem_project', 1.0, NULL, 1775266565634, 1775266565634, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('distances_frontier', 'Distances from Salem to frontier attacks — Dover 55mi, York 70mi, Falmouth 105mi', 'Key distances from Salem to frontier attack sites: Dover, NH: ~55 miles (2-3 days overland). Salmon Falls, NH: ~65 miles. York, Maine: ~70 miles (3-7 days for news). Wells, Maine: ~75 miles. Falmouth (Portland), Maine: ~105 miles. Pemaquid, Maine: ~150 miles. Schenectady, NY: ~175 miles (2-3 weeks for news).', NULL, NULL, 'geographic', 'distance', NULL, NULL, 'frontier_war_timeline_research.md', 'Distances from Salem to frontier attacks — Dover 55mi, York 70mi, Falmouth 105mi. Key distances from Salem to frontier attack sites: Dover, NH: ~55 miles (2-3 days overland). Salmon Falls, NH: ~65 miles. York, Maine: ~70 miles (3-7 days for news). Wells, Maine: ~75 miles. Falmouth (Portland), Maine: ~105 miles. Pemaquid, Maine: ~150 miles. Schenectady, NY: ~175 miles (2-3 weeks for news).', 'public', '["distances","frontier","travel_time"]', 'salem_project', 1.0, NULL, 1775266565634, 1775266565634, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('executed_bridget_bishop', 'Bridget Bishop hanged — first execution', 'Bridget Bishop, ~60, of Salem Village. First person executed. Owned two taverns where she allowed gambling and shuffleboard. Previously accused of witchcraft in 1680. Trial featured ''poppets'' (cloth dolls with pins) found in her cellar wall. Hanged June 10, 1692.', '1692-06-10', 'exact', 'legal', 'execution', NULL, 'bridget_bishop', 'micro_events_daily_chronicle.md', 'Bridget Bishop hanged — first execution. Bridget Bishop, ~60, of Salem Village. First person executed. Owned two taverns where she allowed gambling and shuffleboard. Previously accused of witchcraft in 1680. Trial featured ''poppets'' (cloth dolls with pins) found in her cellar wall. Hanged June 10, 1692.', 'public', '["executed","first","tavern_keeper"]', 'salem_project', 1.0, NULL, 1775266565634, 1775266565634, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('executed_rebecca_nurse', 'Rebecca Nurse hanged — jury verdict reversed', 'Rebecca Nurse, ~71, of Salem Village. Full church communicant. 39 neighbors petitioned for her. Jury initially found not guilty; Stoughton sent them back. Her deafness caused her not to respond to a question, interpreted as admission of guilt. Excommunicated July 4. Hanged July 19.', '1692-07-19', 'exact', 'legal', 'execution', NULL, 'rebecca_nurse', 'micro_events_daily_chronicle.md', 'Rebecca Nurse hanged — jury verdict reversed. Rebecca Nurse, ~71, of Salem Village. Full church communicant. 39 neighbors petitioned for her. Jury initially found not guilty; Stoughton sent them back. Her deafness caused her not to respond to a question, interpreted as admission of guilt. Excommunicated July 4. Hanged July 19.', 'public', '["executed","verdict_reversed","deaf"]', 'salem_project', 1.0, NULL, 1775266565634, 1775266565634, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('executed_susannah_martin', 'Susannah Martin hanged — laughed at ''such folly''', 'Susannah Martin, ~67, of Amesbury. Previously accused of witchcraft in 1669. Laughed at the proceedings during her examination: ''Well I may at such folly.'' Hanged July 19, 1692.', '1692-07-19', 'exact', 'legal', 'execution', NULL, NULL, 'micro_events_daily_chronicle.md', 'Susannah Martin hanged — laughed at ''such folly''. Susannah Martin, ~67, of Amesbury. Previously accused of witchcraft in 1669. Laughed at the proceedings during her examination: ''Well I may at such folly.'' Hanged July 19, 1692.', 'public', '["executed","defiant","amesbury"]', 'salem_project', 1.0, NULL, 1775266565634, 1775266565634, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('executed_elizabeth_howe', 'Elizabeth Howe hanged — Topsfield resident, connected to Towne family', 'Elizabeth Howe, ~57, of Topsfield. Her husband was blind. She was accused by the same network that targeted the Towne sisters. Connected to the Topsfield border dispute families. Hanged July 19, 1692.', '1692-07-19', 'exact', 'legal', 'execution', NULL, NULL, 'micro_events_daily_chronicle.md', 'Elizabeth Howe hanged — Topsfield resident, connected to Towne family. Elizabeth Howe, ~57, of Topsfield. Her husband was blind. She was accused by the same network that targeted the Towne sisters. Connected to the Topsfield border dispute families. Hanged July 19, 1692.', 'public', '["executed","topsfield","howe"]', 'salem_project', 1.0, NULL, 1775266565634, 1775266565634, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('executed_sarah_wildes', 'Sarah Wildes hanged — Topsfield, testified against Putnams in border dispute', 'Sarah Wildes, ~65, of Topsfield. Her family had testified against the Putnams in the Topsfield border dispute. Previously accused of witchcraft in 1666. Hanged July 19, 1692.', '1692-07-19', 'exact', 'legal', 'execution', NULL, NULL, 'micro_events_daily_chronicle.md', 'Sarah Wildes hanged — Topsfield, testified against Putnams in border dispute. Sarah Wildes, ~65, of Topsfield. Her family had testified against the Putnams in the Topsfield border dispute. Previously accused of witchcraft in 1666. Hanged July 19, 1692.', 'public', '["executed","topsfield","border_dispute"]', 'salem_project', 1.0, NULL, 1775266565634, 1775266565634, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('executed_george_burroughs', 'George Burroughs hanged — recited Lord''s Prayer, Mather intervened', 'Rev. George Burroughs, ~42, former Salem Village minister. Arrested at Wells, Maine on May 4. Called ''ringleader'' of witch conspiracy. On scaffold, perfectly recited Lord''s Prayer — crowd nearly stopped execution. Cotton Mather intervened from horseback. Accused of superhuman strength. Hanged August 19.', '1692-08-19', 'exact', 'legal', 'execution', NULL, 'george_burroughs', 'micro_events_daily_chronicle.md', 'George Burroughs hanged — recited Lord''s Prayer, Mather intervened. Rev. George Burroughs, ~42, former Salem Village minister. Arrested at Wells, Maine on May 4. Called ''ringleader'' of witch conspiracy. On scaffold, perfectly recited Lord''s Prayer — crowd nearly stopped execution. Cotton Mather intervened from horseback. Accused of superhuman strength. Hanged August 19.', 'public', '["executed","minister","lords_prayer","ringleader"]', 'salem_project', 1.0, NULL, 1775266565634, 1775266565634, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('executed_john_proctor', 'John Proctor hanged — most outspoken opponent of the trials', 'John Proctor, ~60, of Salem Village. Prosperous farmer and tavern keeper. Most vocal opponent — publicly called for hanging the accusers instead. Wrote powerful letter from prison describing torture. Wife Elizabeth saved by pregnancy. Hanged August 19.', '1692-08-19', 'exact', 'legal', 'execution', NULL, 'john_proctor', 'micro_events_daily_chronicle.md', 'John Proctor hanged — most outspoken opponent of the trials. John Proctor, ~60, of Salem Village. Prosperous farmer and tavern keeper. Most vocal opponent — publicly called for hanging the accusers instead. Wrote powerful letter from prison describing torture. Wife Elizabeth saved by pregnancy. Hanged August 19.', 'public', '["executed","opponent","prison_letter"]', 'salem_project', 1.0, NULL, 1775266565634, 1775266565634, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('executed_george_jacobs_sr', 'George Jacobs Sr. hanged — accused by own granddaughter who recanted', 'George Jacobs Sr., ~72, of Salem Village. His granddaughter Margaret accused him to save herself, then recanted the day after his execution. He forgave her before he died. His walking sticks were used as evidence of his ''staff'' for flying. Hanged August 19.', '1692-08-19', 'exact', 'legal', 'execution', NULL, 'george_jacobs_sr', 'micro_events_daily_chronicle.md', 'George Jacobs Sr. hanged — accused by own granddaughter who recanted. George Jacobs Sr., ~72, of Salem Village. His granddaughter Margaret accused him to save herself, then recanted the day after his execution. He forgave her before he died. His walking sticks were used as evidence of his ''staff'' for flying. Hanged August 19.', 'public', '["executed","granddaughter","forgiveness"]', 'salem_project', 1.0, NULL, 1775266565634, 1775266565634, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('executed_john_willard', 'John Willard hanged — deputy constable who refused to arrest more', 'John Willard, ~30, of Salem Village. Initially served as deputy constable arresting accused witches. Refused to make more arrests after witnessing proceedings. Immediately accused himself. Fled to Lancaster, captured, stumbled reciting Lord''s Prayer. Hanged August 19.', '1692-08-19', 'exact', 'legal', 'execution', NULL, 'john_willard', 'micro_events_daily_chronicle.md', 'John Willard hanged — deputy constable who refused to arrest more. John Willard, ~30, of Salem Village. Initially served as deputy constable arresting accused witches. Refused to make more arrests after witnessing proceedings. Immediately accused himself. Fled to Lancaster, captured, stumbled reciting Lord''s Prayer. Hanged August 19.', 'public', '["executed","constable","refused_arrests"]', 'salem_project', 1.0, NULL, 1775266565634, 1775266565634, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('executed_martha_carrier', 'Martha Carrier hanged — Cotton Mather called her ''Queen of Hell''', 'Martha Carrier, ~40, of Andover. Blamed for the 1690 Andover smallpox that killed 13 (7 Carriers). Cotton Mather called her ''a rampant hag'' and ''Queen of Hell.'' From scaffold: ''her voice was heard asserting her innocence refusing to confess to a falsehood so filthy.'' Hanged August 19.', '1692-08-19', 'exact', 'legal', 'execution', NULL, 'martha_carrier', 'micro_events_daily_chronicle.md', 'Martha Carrier hanged — Cotton Mather called her ''Queen of Hell''. Martha Carrier, ~40, of Andover. Blamed for the 1690 Andover smallpox that killed 13 (7 Carriers). Cotton Mather called her ''a rampant hag'' and ''Queen of Hell.'' From scaffold: ''her voice was heard asserting her innocence refusing to confess to a falsehood so filthy.'' Hanged August 19.', 'public', '["executed","queen_of_hell","andover","smallpox"]', 'salem_project', 1.0, NULL, 1775266565635, 1775266565635, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('executed_martha_corey', 'Martha Corey hanged — ''gospel woman'' who laughed at accusers', 'Martha Corey, ~72, of Salem Village. Full church communicant. At examination, asked to pray, demanded evidence, called herself ''a gospel woman.'' Girls called her ''a gospel witch.'' Excommunicated September 11. Hanged September 22. Her husband Giles was pressed to death three days earlier.', '1692-09-22', 'exact', 'legal', 'execution', NULL, 'martha_corey', 'micro_events_daily_chronicle.md', 'Martha Corey hanged — ''gospel woman'' who laughed at accusers. Martha Corey, ~72, of Salem Village. Full church communicant. At examination, asked to pray, demanded evidence, called herself ''a gospel woman.'' Girls called her ''a gospel witch.'' Excommunicated September 11. Hanged September 22. Her husband Giles was pressed to death three days earlier.', 'public', '["executed","gospel_woman","church_member"]', 'salem_project', 1.0, NULL, 1775266565635, 1775266565635, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('executed_mary_easty', 'Mary Easty hanged — wrote the most moving farewell petition', 'Mary Easty, ~58, of Topsfield. Sister of Rebecca Nurse and Sarah Cloyce. Released once, re-arrested when accusers protested. From prison wrote farewell petition: ''I petition your honours not for my own life...but that no more innocent blood be shed.'' Hanged September 22.', '1692-09-22', 'exact', 'legal', 'execution', NULL, 'mary_easty', 'micro_events_daily_chronicle.md', 'Mary Easty hanged — wrote the most moving farewell petition. Mary Easty, ~58, of Topsfield. Sister of Rebecca Nurse and Sarah Cloyce. Released once, re-arrested when accusers protested. From prison wrote farewell petition: ''I petition your honours not for my own life...but that no more innocent blood be shed.'' Hanged September 22.', 'public', '["executed","farewell_petition","towne_sister"]', 'salem_project', 1.0, NULL, 1775266565635, 1775266565635, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('executed_alice_parker', 'Alice Parker hanged — Salem Town resident', 'Alice Parker, ~40, of Salem Town. Accused of bewitching sailors and causing shipwrecks. Her husband was a fisherman. Hanged September 22, 1692.', '1692-09-22', 'exact', 'legal', 'execution', NULL, NULL, 'micro_events_daily_chronicle.md', 'Alice Parker hanged — Salem Town resident. Alice Parker, ~40, of Salem Town. Accused of bewitching sailors and causing shipwrecks. Her husband was a fisherman. Hanged September 22, 1692.', 'public', '["executed","salem_town","sailors"]', 'salem_project', 1.0, NULL, 1775266565635, 1775266565635, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('executed_ann_pudeator', 'Ann Pudeator hanged — Salem Town widow and nurse', 'Ann Pudeator, ~70, of Salem Town. A widow who worked as a nurse. Accused of witchcraft and of killing her second husband by magic. Hanged September 22, 1692.', '1692-09-22', 'exact', 'legal', 'execution', NULL, NULL, 'micro_events_daily_chronicle.md', 'Ann Pudeator hanged — Salem Town widow and nurse. Ann Pudeator, ~70, of Salem Town. A widow who worked as a nurse. Accused of witchcraft and of killing her second husband by magic. Hanged September 22, 1692.', 'public', '["executed","widow","nurse"]', 'salem_project', 1.0, NULL, 1775266565635, 1775266565635, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('executed_wilmot_redd', 'Wilmot Redd hanged — Marblehead resident', 'Wilmot Redd, ~55, of Marblehead. Known for sharp tongue and confrontational personality. Accused of bewitching people who crossed her. Hanged September 22, 1692.', '1692-09-22', 'exact', 'legal', 'execution', NULL, NULL, 'micro_events_daily_chronicle.md', 'Wilmot Redd hanged — Marblehead resident. Wilmot Redd, ~55, of Marblehead. Known for sharp tongue and confrontational personality. Accused of bewitching people who crossed her. Hanged September 22, 1692.', 'public', '["executed","marblehead"]', 'salem_project', 1.0, NULL, 1775266565635, 1775266565635, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('executed_margaret_scott', 'Margaret Scott hanged — Rowley widow, ~77 years old', 'Margaret Scott, ~77, of Rowley. A poor widow who had relied on charity for years. One of the oldest persons executed. Hanged September 22, 1692.', '1692-09-22', 'exact', 'legal', 'execution', NULL, NULL, 'micro_events_daily_chronicle.md', 'Margaret Scott hanged — Rowley widow, ~77 years old. Margaret Scott, ~77, of Rowley. A poor widow who had relied on charity for years. One of the oldest persons executed. Hanged September 22, 1692.', 'public', '["executed","rowley","elderly","poor"]', 'salem_project', 1.0, NULL, 1775266565635, 1775266565635, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('executed_samuel_wardwell', 'Samuel Wardwell hanged — confessed then recanted, fortune teller', 'Samuel Wardwell, ~49, of Andover. A carpenter and fortune teller who initially confessed, then recanted at trial declaring his confession false. His recantation sealed his fate — those who confessed and maintained their confession were spared; those who recanted were hanged. Hanged September 22.', '1692-09-22', 'exact', 'legal', 'execution', NULL, NULL, 'micro_events_daily_chronicle.md', 'Samuel Wardwell hanged — confessed then recanted, fortune teller. Samuel Wardwell, ~49, of Andover. A carpenter and fortune teller who initially confessed, then recanted at trial declaring his confession false. His recantation sealed his fate — those who confessed and maintained their confession were spared; those who recanted were hanged. Hanged September 22.', 'public', '["executed","andover","fortune_teller","recanted"]', 'salem_project', 1.0, NULL, 1775266565635, 1775266565635, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('executed_mary_parker', 'Mary Parker hanged — Andover, sons protested property seizure', 'Mary Parker, ~55, of Andover. After her execution, Sheriff Corwin sent officers to seize corn, hay, and cattle from her farm. Her sons protested and negotiated the demand down from 10 to 6 pounds. Hanged September 22, 1692.', '1692-09-22', 'exact', 'legal', 'execution', NULL, NULL, 'micro_events_daily_chronicle.md', 'Mary Parker hanged — Andover, sons protested property seizure. Mary Parker, ~55, of Andover. After her execution, Sheriff Corwin sent officers to seize corn, hay, and cattle from her farm. Her sons protested and negotiated the demand down from 10 to 6 pounds. Hanged September 22, 1692.', 'public', '["executed","andover","property_seized"]', 'salem_project', 1.0, NULL, 1775266565635, 1775266565635, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('executed_sarah_good', 'Sarah Good hanged — cursed Rev. Noyes from scaffold', 'Sarah Good, ~39, of Salem Village. Impoverished beggar. Baby Mercy died in prison. From the scaffold told Noyes: ''I am no more a witch than you are a wizard, and if you take away my life God will give you blood to drink.'' Noyes died choking on his own blood in 1717. Hanged July 19.', '1692-07-19', 'exact', 'legal', 'execution', NULL, 'sarah_good', 'micro_events_daily_chronicle.md', 'Sarah Good hanged — cursed Rev. Noyes from scaffold. Sarah Good, ~39, of Salem Village. Impoverished beggar. Baby Mercy died in prison. From the scaffold told Noyes: ''I am no more a witch than you are a wizard, and if you take away my life God will give you blood to drink.'' Noyes died choking on his own blood in 1717. Hanged July 19.', 'public', '["executed","curse","scaffold","prophecy"]', 'salem_project', 1.0, NULL, 1775266565635, 1775266565635, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('pressed_giles_corey', 'Giles Corey pressed to death — refused to plead to protect estate', 'Giles Corey, ~80, of Salem Village. Refused to enter a plea (neither guilty nor not guilty). By law, without a plea, no trial could proceed and his property could not be forfeited. He had deeded his farm to his sons-in-law. Pressed with stones for 2-3 days. Only response: ''More weight!'' First and only person pressed to death in American history.', '1692-09-19', 'exact', 'legal', 'execution', NULL, 'giles_corey', 'micro_events_daily_chronicle.md', 'Giles Corey pressed to death — refused to plead to protect estate. Giles Corey, ~80, of Salem Village. Refused to enter a plea (neither guilty nor not guilty). By law, without a plea, no trial could proceed and his property could not be forfeited. He had deeded his farm to his sons-in-law. Pressed with stones for 2-3 days. Only response: ''More weight!'' First and only person pressed to death in American history.', 'public', '["pressed","more_weight","only_in_america","property"]', 'salem_project', 1.0, NULL, 1775266565635, 1775266565635, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('escaped_philip_mary_english', 'Philip and Mary English escape to New York', 'Philip English (~41) and Mary English (~37). Wealthiest accused. Philip hid under dirty laundry to evade initial arrest. Jailed in Boston. Rev. Moody helped them escape to New York where Governor Fletcher refused to honor Massachusetts warrants. Property worth ~1,183 pounds seized. Mary died 1694 from effects of imprisonment.', '1692-09', 'month', 'legal', 'escape', NULL, 'philip_english', 'philip_english_merchant_research.md', 'Philip and Mary English escape to New York. Philip English (~41) and Mary English (~37). Wealthiest accused. Philip hid under dirty laundry to evade initial arrest. Jailed in Boston. Rev. Moody helped them escape to New York where Governor Fletcher refused to honor Massachusetts warrants. Property worth ~1,183 pounds seized. Mary died 1694 from effects of imprisonment.', 'public', '["escaped","wealthiest","new_york"]', 'salem_project', 1.0, NULL, 1775266565635, 1775266565635, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('escaped_john_alden_jr', 'Captain John Alden Jr. escapes Boston jail, flees to New York', 'Captain John Alden Jr. (~69), son of Mayflower Pilgrims. At examination, an accuser was coached by a man whispering in her ear. Escaped Boston jail September 12-16 with friends'' help, fled to New York on horseback. Had been ransoming captives from York massacre when accused.', '1692-09-12', 'approximate', 'legal', 'escape', NULL, NULL, 'micro_events_daily_chronicle.md', 'Captain John Alden Jr. escapes Boston jail, flees to New York. Captain John Alden Jr. (~69), son of Mayflower Pilgrims. At examination, an accuser was coached by a man whispering in her ear. Escaped Boston jail September 12-16 with friends'' help, fled to New York on horseback. Had been ransoming captives from York massacre when accused.', 'public', '["escaped","mayflower","coached_accuser"]', 'salem_project', 1.0, NULL, 1775266565635, 1775266565635, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('escaped_mary_bradbury_2', 'Mary Bradbury (~72-77) escapes despite 117-person petition', 'Mary Bradbury of Salisbury. Over 100 neighbors testified on her behalf — the largest petition of the trials (117 signers). Still convicted. Her husband reportedly bribed the jailer and smuggled her to Maine in a horse and cart. Lived until 1700, dying at ~85.', '1692-09', 'month', 'legal', 'escape', NULL, 'mary_bradbury', 'births_deaths_illness_research.md', 'Mary Bradbury (~72-77) escapes despite 117-person petition. Mary Bradbury of Salisbury. Over 100 neighbors testified on her behalf — the largest petition of the trials (117 signers). Still convicted. Her husband reportedly bribed the jailer and smuggled her to Maine in a horse and cart. Lived until 1700, dying at ~85.', 'semi_private', '["escaped","bribery","117_petition","elderly"]', 'salem_project', 1.0, NULL, 1775266565635, 1775266565635, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('escaped_daniel_andrew', 'Daniel Andrew evades arrest — warrant never served', 'Daniel Andrew of Salem Village. Married to Sarah Porter. Built independent wharf on Frost Fish Brook in February 1692. Elected Salem Town selectman in April 1692. Accused of witchcraft. Evaded arrest — warrant was never served. He had advance warning through Porter faction connections.', NULL, NULL, 'legal', 'escape', NULL, 'daniel_andrew', 'micro_events_daily_chronicle.md', 'Daniel Andrew evades arrest — warrant never served. Daniel Andrew of Salem Village. Married to Sarah Porter. Built independent wharf on Frost Fish Brook in February 1692. Elected Salem Town selectman in April 1692. Accused of witchcraft. Evaded arrest — warrant was never served. He had advance warning through Porter faction connections.', 'semi_private', '["escaped","warrant_never_served","porter_faction"]', 'salem_project', 1.0, NULL, 1775266565635, 1775266565635, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('confessor_tituba_survived', 'Tituba confesses — first confessor, survived because confession spared execution', 'Tituba, enslaved by Parris, was the first to confess (March 1). Her vivid confession validated the accusations and opened the floodgates. The bitter irony: those who confessed were spared execution; those who maintained innocence were hanged. Tituba survived but was imprisoned 13 months because Parris refused to pay her fees.', '1692-03-01', 'exact', 'legal', 'confession', NULL, 'tituba', 'micro_events_daily_chronicle.md', 'Tituba confesses — first confessor, survived because confession spared execution. Tituba, enslaved by Parris, was the first to confess (March 1). Her vivid confession validated the accusations and opened the floodgates. The bitter irony: those who confessed were spared execution; those who maintained innocence were hanged. Tituba survived but was imprisoned 13 months because Parris refused to pay her fees.', 'public', '["confession","survived","first_confessor"]', 'salem_project', 1.0, NULL, 1775266565635, 1775266565635, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('confession_paradox', 'The confession paradox — confess and live, maintain innocence and die', 'The Salem trials created a perverse incentive: those who confessed to witchcraft were spared execution as they were seen as cooperating with the court; those who maintained their innocence were hanged. Of the 19 executed, NONE had confessed. All 19 died insisting on their innocence. Over 50 people confessed — all survived.', NULL, NULL, 'legal', 'system', NULL, NULL, 'micro_events_daily_chronicle.md', 'The confession paradox — confess and live, maintain innocence and die. The Salem trials created a perverse incentive: those who confessed to witchcraft were spared execution as they were seen as cooperating with the court; those who maintained their innocence were hanged. Of the 19 executed, NONE had confessed. All 19 died insisting on their innocence. Over 50 people confessed — all survived.', 'public', '["paradox","confession","innocence","system"]', 'salem_project', 1.0, NULL, 1775266565635, 1775266565635, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('saved_elizabeth_proctor_pregnancy', 'Elizabeth Proctor convicted but saved by pregnancy', 'Elizabeth Proctor convicted August 5 alongside husband John. Execution stayed due to pregnancy (''reprieve for the belly''). John hanged August 19. Baby John Proctor III born January 27, 1693 in prison. Elizabeth released May 1693 with no legal rights as convicted witch. Remarried Daniel Richards 1699.', '1692-08-05', 'exact', 'legal', 'reprieve', NULL, 'elizabeth_proctor', 'births_deaths_illness_research.md', 'Elizabeth Proctor convicted but saved by pregnancy. Elizabeth Proctor convicted August 5 alongside husband John. Execution stayed due to pregnancy (''reprieve for the belly''). John hanged August 19. Baby John Proctor III born January 27, 1693 in prison. Elizabeth released May 1693 with no legal rights as convicted witch. Remarried Daniel Richards 1699.', 'public', '["reprieve","pregnancy","survived"]', 'salem_project', 1.0, NULL, 1775266565635, 1775266565635, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('sarah_cloyce_survived', 'Sarah Cloyce — arrested for walkout, survived the trials', 'Sarah Cloyce, ~55, youngest Towne sister. Dramatically walked out of meetinghouse on Sacrament Day (April 3) when Parris preached ''one of you is a devil.'' Arrested, examined, imprisoned. Never tried. Survived the trials. Lived until ~1703.', NULL, NULL, 'legal', 'survived', NULL, 'sarah_cloyce', 'micro_events_daily_chronicle.md', 'Sarah Cloyce — arrested for walkout, survived the trials. Sarah Cloyce, ~55, youngest Towne sister. Dramatically walked out of meetinghouse on Sacrament Day (April 3) when Parris preached ''one of you is a devil.'' Arrested, examined, imprisoned. Never tried. Survived the trials. Lived until ~1703.', 'public', '["survived","walkout","towne_sister"]', 'salem_project', 1.0, NULL, 1775266565635, 1775266565635, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('chron_jan_15_afflictions_begin', 'Betty Parris and Abigail Williams begin experiencing fits', 'Betty Parris (9) and Abigail Williams (11) begin experiencing fits in the Parris parsonage. They scream, throw things, utter strange sounds, contort their bodies, bark like dogs. Betty throws a Bible across the room. Abigail attempts to launch herself into the air. The household tries fasting, prayer, and home remedies for weeks before seeking medical help.', '1692-01-15', 'approximate', 'incident', 'chronology', NULL, 'betty_parris', 'micro_events_daily_chronicle.md', 'Betty Parris and Abigail Williams begin experiencing fits. Betty Parris (9) and Abigail Williams (11) begin experiencing fits in the Parris parsonage. They scream, throw things, utter strange sounds, contort their bodies, bark like dogs. Betty throws a Bible across the room. Abigail attempts to launch herself into the air. The household tries fasting, prayer, and home remedies for weeks before seeking medical help.', 'public', '["chronology","january","afflictions_begin"]', 'salem_project', 1.0, NULL, 1775266565635, 1775266565635, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('chron_jan_25_york_massacre', 'York massacre — news reaches Salem between afflictions and first accusations', '200-300 Abenaki attack York, Maine. 75-100 killed, 73-80 captured. Rev. Shubael Dummer murdered. News reaches Salem late January/early February — between the start of the afflictions (mid-January) and the first formal accusations (February 29). The timing is critical: the community absorbed the news that a minister was dead and the frontier was collapsing just as the girls'' symptoms were being evaluated.', '1692-01-25', 'exact', 'military', 'chronology', NULL, NULL, 'frontier_war_timeline_research.md', 'York massacre — news reaches Salem between afflictions and first accusations. 200-300 Abenaki attack York, Maine. 75-100 killed, 73-80 captured. Rev. Shubael Dummer murdered. News reaches Salem late January/early February — between the start of the afflictions (mid-January) and the first formal accusations (February 29). The timing is critical: the community absorbed the news that a minister was dead and the frontier was collapsing just as the girls'' symptoms were being evaluated.', 'public', '["chronology","january","york","critical_timing"]', 'salem_project', 1.0, NULL, 1775266565635, 1775266565635, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('chron_feb_griggs_diagnosis', 'Dr. Griggs pronounces the girls bewitched — the pivotal medical moment', 'Dr. William Griggs examines the girls, unable to determine a medical cause. He pronounces them ''under an Evil Hand'' — bewitched. This diagnosis transforms a household medical problem into a supernatural crisis. Within days, the girls will name their tormentors.', '1692-02-15', 'approximate', 'medical', 'chronology', NULL, 'william_griggs', 'births_deaths_illness_research.md', 'Dr. Griggs pronounces the girls bewitched — the pivotal medical moment. Dr. William Griggs examines the girls, unable to determine a medical cause. He pronounces them ''under an Evil Hand'' — bewitched. This diagnosis transforms a household medical problem into a supernatural crisis. Within days, the girls will name their tormentors.', 'public', '["chronology","february","diagnosis"]', 'salem_project', 1.0, NULL, 1775266565635, 1775266565635, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('chron_feb_25_witch_cake', 'Witch cake baked while Parris family away', 'While the Parris family is away hearing another minister, Mary Sibley instructs Tituba and John Indian to bake a witch cake. Ann Putnam Jr. and Elizabeth Hubbard also begin showing affliction symptoms. Elizabeth Hubbard claims a large wolf stalks her.', '1692-02-25', 'exact', 'incident', 'chronology', NULL, 'tituba', 'micro_events_daily_chronicle.md', 'Witch cake baked while Parris family away. While the Parris family is away hearing another minister, Mary Sibley instructs Tituba and John Indian to bake a witch cake. Ann Putnam Jr. and Elizabeth Hubbard also begin showing affliction symptoms. Elizabeth Hubbard claims a large wolf stalks her.', 'public', '["chronology","february","witch_cake"]', 'salem_project', 1.0, NULL, 1775266565635, 1775266565635, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('chron_feb_29_warrants', 'First arrest warrants issued — Tituba, Sarah Good, Sarah Osborne', 'Under pressure, the girls name three women: Tituba, Sarah Good, Sarah Osborne. Arrest warrants are issued for all three on February 29, 1692. Joseph Herrick, constable, executes the warrants. The witch crisis officially begins.', '1692-02-29', 'exact', 'legal', 'chronology', NULL, 'tituba', 'micro_events_daily_chronicle.md', 'First arrest warrants issued — Tituba, Sarah Good, Sarah Osborne. Under pressure, the girls name three women: Tituba, Sarah Good, Sarah Osborne. Arrest warrants are issued for all three on February 29, 1692. Joseph Herrick, constable, executes the warrants. The witch crisis officially begins.', 'public', '["chronology","february","first_warrants"]', 'salem_project', 1.0, NULL, 1775266565635, 1775266565635, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('chron_mar_1_first_examinations', 'First examinations — Tituba confesses, Good and Osborne deny', 'March 1: Examinations at the meetinghouse (moved from Ingersoll''s due to crowds). Tituba confesses in vivid detail — tall man in black, Devil''s book, nine marks. Good denies but accuses Osborne. Osborne denies everything. Tituba''s confession validates the accusers and opens the floodgates.', '1692-03-01', 'exact', 'legal', 'chronology', NULL, 'tituba', 'micro_events_daily_chronicle.md', 'First examinations — Tituba confesses, Good and Osborne deny. March 1: Examinations at the meetinghouse (moved from Ingersoll''s due to crowds). Tituba confesses in vivid detail — tall man in black, Devil''s book, nine marks. Good denies but accuses Osborne. Osborne denies everything. Tituba''s confession validates the accusers and opens the floodgates.', 'public', '["chronology","march","first_examinations"]', 'salem_project', 1.0, NULL, 1775266565636, 1775266565636, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('chron_mar_12_corey_accused', 'Martha Corey accused — first church member targeted', 'Martha Corey accused of witchcraft on March 12. She is a full communicant of the church — the first church member to be accused. This escalation crosses a critical social boundary: previously only marginal women (slave, beggar, absentee) were targeted.', '1692-03-12', 'exact', 'legal', 'chronology', NULL, 'martha_corey', 'micro_events_daily_chronicle.md', 'Martha Corey accused — first church member targeted. Martha Corey accused of witchcraft on March 12. She is a full communicant of the church — the first church member to be accused. This escalation crosses a critical social boundary: previously only marginal women (slave, beggar, absentee) were targeted.', 'public', '["chronology","march","church_member"]', 'salem_project', 1.0, NULL, 1775266565636, 1775266565636, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('chron_mar_19_nurse_accused', 'Rebecca Nurse formally accused — respected 71-year-old grandmother', 'Rebecca Nurse formally accused of witchcraft on March 19. She is 71, a full church communicant, respected grandmother with eight children. Her accusation shocks many in the community. Ann Putnam Jr. had identified her specter on March 13.', '1692-03-19', 'exact', 'legal', 'chronology', NULL, 'rebecca_nurse', 'micro_events_daily_chronicle.md', 'Rebecca Nurse formally accused — respected 71-year-old grandmother. Rebecca Nurse formally accused of witchcraft on March 19. She is 71, a full church communicant, respected grandmother with eight children. Her accusation shocks many in the community. Ann Putnam Jr. had identified her specter on March 13.', 'public', '["chronology","march","nurse_accused"]', 'salem_project', 1.0, NULL, 1775266565636, 1775266565636, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('chron_mar_18_ann_sr_afflicted', 'Ann Putnam Sr. (age 31) begins reporting spectral torment', 'Ann Putnam Sr., age 31, reports spectral torment — ''almost pressed and choked to death.'' She becomes one of the adult accusers, alongside the afflicted girls. Her involvement lends adult credibility to the accusations and reflects her own psychological vulnerability from years of personal loss.', '1692-03-18', 'exact', 'incident', 'chronology', NULL, 'ann_putnam_sr', 'micro_events_daily_chronicle.md', 'Ann Putnam Sr. (age 31) begins reporting spectral torment. Ann Putnam Sr., age 31, reports spectral torment — ''almost pressed and choked to death.'' She becomes one of the adult accusers, alongside the afflicted girls. Her involvement lends adult credibility to the accusations and reflects her own psychological vulnerability from years of personal loss.', 'public', '["chronology","march","adult_accuser"]', 'salem_project', 1.0, NULL, 1775266565636, 1775266565636, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('chron_apr_11_proctor_first_male', 'John Proctor taken into custody — first male accused', 'Deputy Governor Danforth attends hearings. Elizabeth Proctor and Sarah Cloyce examined. John Proctor taken into custody — the first male accused of witchcraft. His outspoken opposition (''Hang them!'') made him a target.', '1692-04-11', 'exact', 'legal', 'chronology', NULL, 'john_proctor', 'micro_events_daily_chronicle.md', 'John Proctor taken into custody — first male accused. Deputy Governor Danforth attends hearings. Elizabeth Proctor and Sarah Cloyce examined. John Proctor taken into custody — the first male accused of witchcraft. His outspoken opposition (''Hang them!'') made him a target.', 'public', '["chronology","april","first_male_accused"]', 'salem_project', 1.0, NULL, 1775266565636, 1775266565636, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('chron_apr_22_nehemiah_abbott_released', 'Mass examination — 9 accused, only Nehemiah Abbott released', 'April 22: Mary Easty, Nehemiah Abbott, William and Deliverance Hobbs, Edward and Sarah Bishop, Mary Black, Mary English, Sarah Wildes examined. Nehemiah Abbott is the ONLY person released after examination — the girls could not agree he was their tormentor. He is the sole example of the process failing to produce an accusation.', '1692-04-22', 'exact', 'legal', 'chronology', NULL, 'mary_easty', 'micro_events_daily_chronicle.md', 'Mass examination — 9 accused, only Nehemiah Abbott released. April 22: Mary Easty, Nehemiah Abbott, William and Deliverance Hobbs, Edward and Sarah Bishop, Mary Black, Mary English, Sarah Wildes examined. Nehemiah Abbott is the ONLY person released after examination — the girls could not agree he was their tormentor. He is the sole example of the process failing to produce an accusation.', 'public', '["chronology","april","mass_examination","only_released"]', 'salem_project', 1.0, NULL, 1775266565636, 1775266565636, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('chron_apr_30_burroughs_accused', 'George Burroughs accused — former minister targeted as ''ringleader''', 'The afflicted girls accuse George Burroughs, former Salem Village minister now living in Wells, Maine. He is named as the ''ringleader'' of the witch conspiracy. A warrant is issued for his arrest at Wells.', '1692-04-30', 'exact', 'legal', 'chronology', NULL, 'george_burroughs', 'micro_events_daily_chronicle.md', 'George Burroughs accused — former minister targeted as ''ringleader''. The afflicted girls accuse George Burroughs, former Salem Village minister now living in Wells, Maine. He is named as the ''ringleader'' of the witch conspiracy. A warrant is issued for his arrest at Wells.', 'public', '["chronology","april","burroughs_accused","ringleader"]', 'salem_project', 1.0, NULL, 1775266565636, 1775266565636, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('chron_may_4_burroughs_arrested_wells', 'Burroughs arrested at Wells, Maine', 'George Burroughs arrested at Wells, Maine on May 4. He is returned to Salem jail on May 7. Wells itself will be attacked by 400+ French and Indian forces barely a month later on June 10.', '1692-05-04', 'exact', 'legal', 'chronology', NULL, 'george_burroughs', 'micro_events_daily_chronicle.md', 'Burroughs arrested at Wells, Maine. George Burroughs arrested at Wells, Maine on May 4. He is returned to Salem jail on May 7. Wells itself will be attacked by 400+ French and Indian forces barely a month later on June 10.', 'public', '["chronology","may","burroughs_arrested"]', 'salem_project', 1.0, NULL, 1775266565636, 1775266565636, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('chron_may_10_osborne_dies', 'Sarah Osborne dies in Boston prison — first casualty', 'Sarah Osborne, ~49, dies in Boston jail on May 10 — the first casualty of the witch crisis. She was never brought to trial. On the same day, George Jacobs Sr. and granddaughter Margaret are examined.', '1692-05-10', 'exact', 'legal', 'chronology', NULL, 'sarah_osborne', 'births_deaths_illness_research.md', 'Sarah Osborne dies in Boston prison — first casualty. Sarah Osborne, ~49, dies in Boston jail on May 10 — the first casualty of the witch crisis. She was never brought to trial. On the same day, George Jacobs Sr. and granddaughter Margaret are examined.', 'public', '["chronology","may","first_death"]', 'salem_project', 1.0, NULL, 1775266565636, 1775266565636, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('chron_may_14_phips_arrives', 'Governor Phips arrives with new charter — steps into crisis', 'Governor Phips arrives in Boston on May 14, 1692 with the new charter. Increase Mather returns from England after four years. Phips finds jails overflowing with accused witches and no legitimate court to try them. He will establish the Court of Oyer and Terminer thirteen days later.', '1692-05-14', 'exact', 'political', 'chronology', NULL, 'william_phips', 'political_events_charter_research.md', 'Governor Phips arrives with new charter — steps into crisis. Governor Phips arrives in Boston on May 14, 1692 with the new charter. Increase Mather returns from England after four years. Phips finds jails overflowing with accused witches and no legitimate court to try them. He will establish the Court of Oyer and Terminer thirteen days later.', 'public', '["chronology","may","phips","new_charter"]', 'salem_project', 1.0, NULL, 1775266565636, 1775266565636, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('chron_jun_10_bishop_wells', 'June 10: Bishop hanged AND 400+ French/Indians attack Wells', 'On the same day Bridget Bishop becomes the first person executed, 400+ Abenaki, Mi''kmaq and French forces attack Wells, Maine — George Burroughs''s former home. The simultaneous execution and frontier attack is one of the most dramatic coincidences of 1692.', '1692-06-10', 'exact', 'incident', 'chronology', NULL, 'bridget_bishop', 'micro_events_daily_chronicle.md', 'June 10: Bishop hanged AND 400+ French/Indians attack Wells. On the same day Bridget Bishop becomes the first person executed, 400+ Abenaki, Mi''kmaq and French forces attack Wells, Maine — George Burroughs''s former home. The simultaneous execution and frontier attack is one of the most dramatic coincidences of 1692.', 'public', '["chronology","june","simultaneous"]', 'salem_project', 1.0, NULL, 1775266565636, 1775266565636, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('chron_jul_19_five_hanged', 'July 19: Five hanged — Nurse, Martin, Howe, Good, Wildes', 'Five executed on July 19 during haying season: Rebecca Nurse, Susannah Martin, Elizabeth Howe, Sarah Good, Sarah Wildes. Sarah Good''s final words curse Rev. Noyes. This is the largest execution day so far.', '1692-07-19', 'exact', 'legal', 'chronology', NULL, 'rebecca_nurse', 'micro_events_daily_chronicle.md', 'July 19: Five hanged — Nurse, Martin, Howe, Good, Wildes. Five executed on July 19 during haying season: Rebecca Nurse, Susannah Martin, Elizabeth Howe, Sarah Good, Sarah Wildes. Sarah Good''s final words curse Rev. Noyes. This is the largest execution day so far.', 'public', '["chronology","july","five_hanged"]', 'salem_project', 1.0, NULL, 1775266565636, 1775266565636, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('chron_aug_19_five_hanged', 'August 19: Five hanged — Burroughs, Proctor, Willard, Jacobs, Carrier', 'Five executed on August 19 at peak harvest: Burroughs (Lord''s Prayer), Proctor (prison letter author), Willard (refused arrests), Jacobs Sr. (forgave granddaughter), Carrier (''Queen of Hell''). Cotton Mather intervenes from horseback after Burroughs''s prayer moves the crowd.', '1692-08-19', 'exact', 'legal', 'chronology', NULL, 'george_burroughs', 'micro_events_daily_chronicle.md', 'August 19: Five hanged — Burroughs, Proctor, Willard, Jacobs, Carrier. Five executed on August 19 at peak harvest: Burroughs (Lord''s Prayer), Proctor (prison letter author), Willard (refused arrests), Jacobs Sr. (forgave granddaughter), Carrier (''Queen of Hell''). Cotton Mather intervenes from horseback after Burroughs''s prayer moves the crowd.', 'public', '["chronology","august","five_hanged","lords_prayer"]', 'salem_project', 1.0, NULL, 1775266565636, 1775266565636, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('chron_sep_22_eight_hanged_last', 'September 22: Eight hanged — THE LAST EXECUTIONS', 'Eight hanged on September 22 during harvest: Martha Corey, Mary Easty, Alice Parker, Ann Pudeator, Wilmot Redd, Margaret Scott, Samuel Wardwell, Mary Parker. Noyes calls them ''eight firebrands of Hell.'' These are the last executions of the Salem witch trials.', '1692-09-22', 'exact', 'legal', 'chronology', NULL, 'martha_corey', 'micro_events_daily_chronicle.md', 'September 22: Eight hanged — THE LAST EXECUTIONS. Eight hanged on September 22 during harvest: Martha Corey, Mary Easty, Alice Parker, Ann Pudeator, Wilmot Redd, Margaret Scott, Samuel Wardwell, Mary Parker. Noyes calls them ''eight firebrands of Hell.'' These are the last executions of the Salem witch trials.', 'public', '["chronology","september","eight_hanged","last_executions"]', 'salem_project', 1.0, NULL, 1775266565636, 1775266565636, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('chron_oct_29_court_dissolved', 'October 29: Phips dissolves Court of Oyer and Terminer', 'Governor Phips dissolves the Court of Oyer and Terminer on October 29, effectively ending the Salem witch trials. The replacement Superior Court of Judicature excludes spectral evidence and acquits most defendants. Stoughton is furious.', '1692-10-29', 'exact', 'political', 'chronology', NULL, 'william_phips', 'political_events_charter_research.md', 'October 29: Phips dissolves Court of Oyer and Terminer. Governor Phips dissolves the Court of Oyer and Terminer on October 29, effectively ending the Salem witch trials. The replacement Superior Court of Judicature excludes spectral evidence and acquits most defendants. Stoughton is furious.', 'public', '["chronology","october","court_dissolved","end"]', 'salem_project', 1.0, NULL, 1775266565636, 1775266565636, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('rel_putnam_parris_patron', 'Thomas Putnam Jr. is Parris''s primary political patron', 'Thomas Putnam Jr. was Rev. Samuel Parris''s primary political supporter. Putnam championed Parris''s hiring, defended his salary, and filed complaints on behalf of the afflicted girls. In return, Parris''s sermons provided theological justification for the accusations that targeted Putnam''s factional enemies. Their alliance was the political engine of the witch crisis.', NULL, NULL, 'social', 'relationship', NULL, 'thomas_putnam_jr', 'village_disputes_research.md', 'Thomas Putnam Jr. is Parris''s primary political patron. Thomas Putnam Jr. was Rev. Samuel Parris''s primary political supporter. Putnam championed Parris''s hiring, defended his salary, and filed complaints on behalf of the afflicted girls. In return, Parris''s sermons provided theological justification for the accusations that targeted Putnam''s factional enemies. Their alliance was the political engine of the witch crisis.', 'public', '["alliance","patron","political_engine"]', 'salem_project', 1.0, NULL, 1775266565636, 1775266565636, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('rel_putnam_parris_complaint_filing', 'Thomas Putnam filed complaints, Parris preached the theology — division of labor', 'The Putnam-Parris partnership operated as a division of labor: Putnam filed or co-signed 43+ formal complaints while Parris preached sermons establishing the theological framework (''Devils as well as Saints in Christ''s Church''). Ann Putnam Jr. (Thomas''s daughter) and Abigail Williams (Parris''s niece) were the most active accusers from their respective households.', NULL, NULL, 'social', 'relationship', NULL, 'thomas_putnam_jr', 'micro_events_daily_chronicle.md', 'Thomas Putnam filed complaints, Parris preached the theology — division of labor. The Putnam-Parris partnership operated as a division of labor: Putnam filed or co-signed 43+ formal complaints while Parris preached sermons establishing the theological framework (''Devils as well as Saints in Christ''s Church''). Ann Putnam Jr. (Thomas''s daughter) and Abigail Williams (Parris''s niece) were the most active accusers from their respective households.', 'public', '["complaints","sermons","division_of_labor"]', 'salem_project', 1.0, NULL, 1775266565636, 1775266565636, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('rel_putnam_nurse_land_war', 'Putnam-Nurse enmity — the 300-acre land war continued by other means', 'The Putnam family lost the Bishop Farm boundary dispute to Francis Nurse. By 1692, every acre of the Nurse farm was, in the Putnam view, territory adjudicated wrongly. Ann Putnam Jr.''s accusation of Rebecca Nurse was, as Boyer and Nissenbaum argued, ''the continuation of a land war by other means.'' The land dispute maps directly onto the witchcraft accusation.', NULL, NULL, 'social', 'relationship', NULL, 'thomas_putnam_jr', 'village_disputes_research.md', 'Putnam-Nurse enmity — the 300-acre land war continued by other means. The Putnam family lost the Bishop Farm boundary dispute to Francis Nurse. By 1692, every acre of the Nurse farm was, in the Putnam view, territory adjudicated wrongly. Ann Putnam Jr.''s accusation of Rebecca Nurse was, as Boyer and Nissenbaum argued, ''the continuation of a land war by other means.'' The land dispute maps directly onto the witchcraft accusation.', 'public', '["land_war","boundary_dispute","accusation_motive"]', 'salem_project', 1.0, NULL, 1775266565636, 1775266565636, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('rel_parris_nurse_attendance', 'Parris tracked the Nurses'' church attendance and hounded them', 'Parris specifically tracked who missed sermons and ''hounded Nurse''s husband Sam to attend church when they missed even a single sermon.'' Francis Nurse was on the anti-Parris committee that voted to cut Parris''s salary. The pastoral surveillance became a weapon when the crisis began.', NULL, NULL, 'social', 'relationship', NULL, 'samuel_parris', 'occupational_knowledge_map.md', 'Parris tracked the Nurses'' church attendance and hounded them. Parris specifically tracked who missed sermons and ''hounded Nurse''s husband Sam to attend church when they missed even a single sermon.'' Francis Nurse was on the anti-Parris committee that voted to cut Parris''s salary. The pastoral surveillance became a weapon when the crisis began.', 'semi_private', '["surveillance","attendance","harassment"]', 'salem_project', 1.0, NULL, 1775266565636, 1775266565636, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('rel_proctor_warren_discipline', 'John Proctor cured Mary Warren''s fits with threat of beating', 'When servant Mary Warren began having fits, master John Proctor put her to work at the spinning wheel and threatened to beat her if she pretended to have more fits. Her fits ceased. When she posted a recovery notice and told the court the girls were lying, the other accusers turned on her. She was accused on April 18 and reversed her recantation under prison pressure.', NULL, NULL, 'social', 'relationship', NULL, 'john_proctor', 'micro_events_daily_chronicle.md', 'John Proctor cured Mary Warren''s fits with threat of beating. When servant Mary Warren began having fits, master John Proctor put her to work at the spinning wheel and threatened to beat her if she pretended to have more fits. Her fits ceased. When she posted a recovery notice and told the court the girls were lying, the other accusers turned on her. She was accused on April 18 and reversed her recantation under prison pressure.', 'public', '["discipline","cure","servant","silenced"]', 'salem_project', 1.0, NULL, 1775266565636, 1775266565636, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('rel_joseph_vs_thomas_putnam', 'Joseph Putnam vs. Thomas Putnam Jr. — brothers on opposite sides', 'Joseph Putnam (youngest brother) married Elizabeth Porter (April 21, 1690) — viewed by the Putnam family as factional betrayal. He confronted Ann Putnam Sr. directly, threatening armed resistance. For six months, a horse was kept saddled at all times for escape. Thomas and Joseph''s split mirrored the village: the same family torn by the same forces.', NULL, NULL, 'social', 'relationship', NULL, 'joseph_putnam', 'micro_events_daily_chronicle.md', 'Joseph Putnam vs. Thomas Putnam Jr. — brothers on opposite sides. Joseph Putnam (youngest brother) married Elizabeth Porter (April 21, 1690) — viewed by the Putnam family as factional betrayal. He confronted Ann Putnam Sr. directly, threatening armed resistance. For six months, a horse was kept saddled at all times for escape. Thomas and Joseph''s split mirrored the village: the same family torn by the same forces.', 'public', '["brothers","factional_split","armed_resistance"]', 'salem_project', 1.0, NULL, 1775266565636, 1775266565636, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('rel_burroughs_putnam_debt', 'Burroughs arrested for funeral debt by John Putnam — humiliation repaid with death warrant', 'Rev. Burroughs''s wife Hannah died in childbirth (1681). He borrowed 15 pounds from Captain John Putnam for the funeral, arranged for the church to repay it. In May 1683, John Putnam had Burroughs arrested for the debt anyway — unjustly, since the village owed Burroughs back salary. Thomas Putnam Jr. inherited the grudge. In 1692, he filed the complaint that brought Burroughs back from Maine to hang. The old financial humiliation was repaid with a death warrant.', '1683-05-03', 'exact', 'social', 'relationship', NULL, 'george_burroughs', 'village_disputes_research.md', 'Burroughs arrested for funeral debt by John Putnam — humiliation repaid with death warrant. Rev. Burroughs''s wife Hannah died in childbirth (1681). He borrowed 15 pounds from Captain John Putnam for the funeral, arranged for the church to repay it. In May 1683, John Putnam had Burroughs arrested for the debt anyway — unjustly, since the village owed Burroughs back salary. Thomas Putnam Jr. inherited the grudge. In 1692, he filed the complaint that brought Burroughs back from Maine to hang. The old financial humiliation was repaid with a death warrant.', 'public', '["debt","funeral","grudge","arrest","death_warrant"]', 'salem_project', 1.0, NULL, 1775266565636, 1775266565636, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('rel_ingersoll_for_sport_paradox', 'Ingersoll filed 11 complaints despite his wife witnessing the ''for sport'' confession', 'Hannah Collins Ingersoll (Nathaniel''s wife) personally heard the afflicted girls admit they were doing it ''for sport, they must have some sport'' on March 28. Yet Nathaniel Ingersoll filed 11 complaints against accused witches in April-May 1692. This is one of the deepest ambiguities of the crisis — did he not believe his wife? Did she not tell him? Or did community pressure override private knowledge?', NULL, NULL, 'social', 'relationship', NULL, 'nathaniel_ingersoll', 'micro_events_daily_chronicle.md', 'Ingersoll filed 11 complaints despite his wife witnessing the ''for sport'' confession. Hannah Collins Ingersoll (Nathaniel''s wife) personally heard the afflicted girls admit they were doing it ''for sport, they must have some sport'' on March 28. Yet Nathaniel Ingersoll filed 11 complaints against accused witches in April-May 1692. This is one of the deepest ambiguities of the crisis — did he not believe his wife? Did she not tell him? Or did community pressure override private knowledge?', 'public', '["paradox","for_sport","ambiguity","complaints"]', 'salem_project', 1.0, NULL, 1775266565636, 1775266565636, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('rel_margaret_jacobs_grandfather', 'Margaret Jacobs accused grandfather George — he forgave her before hanging', 'Margaret Jacobs accused her own grandfather George Jacobs Sr. to save herself. After his death sentence, she wrote to magistrates retracting her testimony and confession. She explained her regret to her grandfather and he forgave her. The day after his execution (August 20), she formally recanted. Their final exchange is one of the most human moments of the crisis.', '1692-08-20', 'exact', 'social', 'relationship', NULL, 'george_jacobs_sr', 'micro_events_daily_chronicle.md', 'Margaret Jacobs accused grandfather George — he forgave her before hanging. Margaret Jacobs accused her own grandfather George Jacobs Sr. to save herself. After his death sentence, she wrote to magistrates retracting her testimony and confession. She explained her regret to her grandfather and he forgave her. The day after his execution (August 20), she formally recanted. Their final exchange is one of the most human moments of the crisis.', 'public', '["grandfather","forgiveness","recantation","family_tragedy"]', 'salem_project', 1.0, NULL, 1775266565636, 1775266565636, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('rel_porter_hathorne_awkward', 'Judge Hathorne examining people accused by faction opposing his sister''s husband', 'Israel Porter was married to Elizabeth Hathorne — Judge John Hathorne''s sister. This meant Hathorne was examining and prosecuting people accused by the Putnam faction, which was politically opposed to his own brother-in-law''s faction. The family connection created an awkward dynamic that neither side could openly acknowledge.', NULL, NULL, 'social', 'relationship', NULL, 'israel_porter', 'social_bonds_marriages.md', 'Judge Hathorne examining people accused by faction opposing his sister''s husband. Israel Porter was married to Elizabeth Hathorne — Judge John Hathorne''s sister. This meant Hathorne was examining and prosecuting people accused by the Putnam faction, which was politically opposed to his own brother-in-law''s faction. The family connection created an awkward dynamic that neither side could openly acknowledge.', 'public', '["cross_faction","marriage","judge","awkward"]', 'salem_project', 1.0, NULL, 1775266565637, 1775266565637, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('rel_griggs_hubbard_household', 'Elizabeth Hubbard served in Dr. Griggs''s household — accuser lived with the diagnoser', 'Elizabeth Hubbard (Rachel Hubbard Griggs''s great-niece) was a maidservant in Dr. Griggs''s household. After Griggs diagnosed the girls as bewitched, Elizabeth began having fits herself. The doctor who diagnosed supernatural affliction had one of the most active accusers living under his own roof. She accused over 30 people.', NULL, NULL, 'social', 'relationship', NULL, 'william_griggs', 'births_deaths_illness_research.md', 'Elizabeth Hubbard served in Dr. Griggs''s household — accuser lived with the diagnoser. Elizabeth Hubbard (Rachel Hubbard Griggs''s great-niece) was a maidservant in Dr. Griggs''s household. After Griggs diagnosed the girls as bewitched, Elizabeth began having fits herself. The doctor who diagnosed supernatural affliction had one of the most active accusers living under his own roof. She accused over 30 people.', 'public', '["household","diagnoser_accuser","conflict_of_interest"]', 'salem_project', 1.0, NULL, 1775266565637, 1775266565637, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('rel_mercy_lewis_putnam_household', 'Mercy Lewis served Burroughs, then Putnams — key connection between accused and accusers', 'Mercy Lewis was orphaned when her parents were killed at Falmouth (1689). She was taken in by Rev. George Burroughs at Wells, then entered service in Thomas Putnam''s household. She later accused Burroughs — her former protector — of witchcraft and supernatural acts. Her testimony against him may reflect transferred trauma: the man who sheltered her after one horror became associated with another.', NULL, NULL, 'social', 'relationship', NULL, 'mercy_lewis', 'frontier_war_timeline_research.md', 'Mercy Lewis served Burroughs, then Putnams — key connection between accused and accusers. Mercy Lewis was orphaned when her parents were killed at Falmouth (1689). She was taken in by Rev. George Burroughs at Wells, then entered service in Thomas Putnam''s household. She later accused Burroughs — her former protector — of witchcraft and supernatural acts. Her testimony against him may reflect transferred trauma: the man who sheltered her after one horror became associated with another.', 'public', '["servant","transferred_trauma","accuser_vs_protector"]', 'salem_project', 1.0, NULL, 1775266565637, 1775266565637, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('rel_cloyce_parris_confrontation', 'Sarah Cloyce publicly defies Parris — walkout as act of sisterly solidarity', 'When Parris chose John 6:70 (''one of you is a devil'') as his Sacrament Day text on April 3, Sarah Cloyce — sister of the already-accused Rebecca Nurse — violently fled the meetinghouse and ''flung the door after her.'' This was both political protest and sisterly solidarity. Parris took the walkout as personal defiance. She was accused within days.', '1692-04-03', 'exact', 'social', 'relationship', NULL, 'sarah_cloyce', 'micro_events_daily_chronicle.md', 'Sarah Cloyce publicly defies Parris — walkout as act of sisterly solidarity. When Parris chose John 6:70 (''one of you is a devil'') as his Sacrament Day text on April 3, Sarah Cloyce — sister of the already-accused Rebecca Nurse — violently fled the meetinghouse and ''flung the door after her.'' This was both political protest and sisterly solidarity. Parris took the walkout as personal defiance. She was accused within days.', 'public', '["walkout","defiance","sisterly_solidarity","retaliation"]', 'salem_project', 1.0, NULL, 1775266565637, 1775266565637, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('rel_topsfield_putnams_decades', 'Topsfield families who testified against Putnams in 1686 were accused in 1692', 'The families who defended Topsfield''s boundary claims against the Putnams — How, Easty, Wildes, Towne — all saw family members accused of witchcraft. Rebecca Nurse (Towne), Mary Easty (married Isaac Easty), Sarah Cloyce (Towne), Sarah Wildes, and Elizabeth How were all accused. Boyer & Nissenbaum called this correlation between land opponents and witchcraft targets one of their most striking findings.', NULL, NULL, 'social', 'relationship', NULL, 'rebecca_nurse', 'village_disputes_research.md', 'Topsfield families who testified against Putnams in 1686 were accused in 1692. The families who defended Topsfield''s boundary claims against the Putnams — How, Easty, Wildes, Towne — all saw family members accused of witchcraft. Rebecca Nurse (Towne), Mary Easty (married Isaac Easty), Sarah Cloyce (Towne), Sarah Wildes, and Elizabeth How were all accused. Boyer & Nissenbaum called this correlation between land opponents and witchcraft targets one of their most striking findings.', 'public', '["topsfield","border_dispute","accusation_pattern","boyer_nissenbaum"]', 'salem_project', 1.0, NULL, 1775266565637, 1775266565637, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('rel_english_community_suspicion', 'Philip English — French accent + extraordinary wealth = suspect', 'Philip English''s French birth, French accent, and extraordinary wealth (21 vessels, 14 buildings) combined to make him suspect in a community terrified of French invasion. He represented a radically different worldview from most Salem residents — thinking in markets, routes, risks while Puritans turned inward toward covenants and salvation. His knowledge of French culture was both his greatest business advantage and greatest liability.', NULL, NULL, 'social', 'relationship', NULL, 'philip_english', 'philip_english_merchant_research.md', 'Philip English — French accent + extraordinary wealth = suspect. Philip English''s French birth, French accent, and extraordinary wealth (21 vessels, 14 buildings) combined to make him suspect in a community terrified of French invasion. He represented a radically different worldview from most Salem residents — thinking in markets, routes, risks while Puritans turned inward toward covenants and salvation. His knowledge of French culture was both his greatest business advantage and greatest liability.', 'public', '["outsider","french","wealth","suspicion"]', 'salem_project', 1.0, NULL, 1775266565637, 1775266565637, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('rel_judges_intermarried', 'Six of nine judges related by marriage — incestuous judicial network', 'Six of the nine judges on the Court of Oyer and Terminer were related by marriage. All were connected to Salem Town''s merchant class and Boston''s governing elite. Jonathan Corwin''s daughter Lydia married Sheriff George Corwin (who seized accused persons'' property). This tight social network meant the judges shared assumptions, social circles, and financial interests.', NULL, NULL, 'social', 'relationship', NULL, 'william_stoughton', 'political_events_charter_research.md', 'Six of nine judges related by marriage — incestuous judicial network. Six of the nine judges on the Court of Oyer and Terminer were related by marriage. All were connected to Salem Town''s merchant class and Boston''s governing elite. Jonathan Corwin''s daughter Lydia married Sheriff George Corwin (who seized accused persons'' property). This tight social network meant the judges shared assumptions, social circles, and financial interests.', 'public', '["judges","intermarried","social_network"]', 'salem_project', 1.0, NULL, 1775266565637, 1775266565637, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('rel_accused_are_porter_faction', 'The accused mapped almost perfectly onto the Porter faction''s leadership', 'The people accused of witchcraft by the Putnam faction mapped almost perfectly onto the Porter faction''s leadership: Daniel Andrew (Porter in-law, wharf builder), Philip English (wealthiest merchant, town selectman), Francis Nurse (boundary dispute opponent), George Burroughs (former minister driven out by Putnams). This pattern reveals the witch crisis as factional warfare conducted through theological channels.', NULL, NULL, 'social', 'faction', NULL, 'daniel_andrew', 'micro_events_daily_chronicle.md', 'The accused mapped almost perfectly onto the Porter faction''s leadership. The people accused of witchcraft by the Putnam faction mapped almost perfectly onto the Porter faction''s leadership: Daniel Andrew (Porter in-law, wharf builder), Philip English (wealthiest merchant, town selectman), Francis Nurse (boundary dispute opponent), George Burroughs (former minister driven out by Putnams). This pattern reveals the witch crisis as factional warfare conducted through theological channels.', 'public', '["factional_warfare","porter_faction","pattern"]', 'salem_project', 1.0, NULL, 1775266565637, 1775266565637, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('parris_born_london_1653', 'Samuel Parris born in London, son of cloth merchant', 'Samuel Parris was born in 1653 in London, the son of Thomas Parris, a cloth merchant of middling prosperity. The family relocated to Barbados around 1662-1665 when Samuel was approximately ten, where his father owned a sugar plantation. This gave Parris formative years in the brutal Caribbean plantation economy.', '1653', 'year', 'biographical', 'origin', NULL, 'samuel_parris', 'npcs/samuel_parris.md', 'Samuel Parris born in London, son of cloth merchant. Samuel Parris was born in 1653 in London, the son of Thomas Parris, a cloth merchant of middling prosperity. The family relocated to Barbados around 1662-1665 when Samuel was approximately ten, where his father owned a sugar plantation. This gave Parris formative years in the brutal Caribbean plantation economy.', 'public', '["birth","london","barbados","plantation"]', 'salem_project', 1.0, NULL, 1775266565637, 1775266565637, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('parris_plantation_worldview', 'Parris''s plantation worldview — hierarchy, control, enslaved labor', 'Growing up on a Barbados sugar plantation gave Parris a worldview rooted in absolute hierarchy: master over slave, order over chaos, authority over dissent. He brought Tituba and John Indian from Barbados — enslaved people in his household. His management style as minister mirrored the plantation: tracking attendance, demanding obedience, seeing opposition as rebellion requiring punishment.', NULL, NULL, 'biographical', 'psychology', NULL, 'samuel_parris', 'npcs/samuel_parris.md', 'Parris''s plantation worldview — hierarchy, control, enslaved labor. Growing up on a Barbados sugar plantation gave Parris a worldview rooted in absolute hierarchy: master over slave, order over chaos, authority over dissent. He brought Tituba and John Indian from Barbados — enslaved people in his household. His management style as minister mirrored the plantation: tracking attendance, demanding obedience, seeing opposition as rebellion requiring punishment.', 'semi_private', '["plantation","hierarchy","control","enslaved"]', 'salem_project', 1.0, NULL, 1775266565637, 1775266565637, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('parris_failed_merchant_theology', 'Parris entered ministry from commercial failure, not spiritual calling', 'Parris worked as a merchant in Barbados then Boston (owning a wharf and warehouse) before entering the ministry. He turned to the church after commercial failure — not from a spiritual calling but from economic necessity. His merchant background gave him skill at negotiation and accounting but left him insecure about his credentials. Ministers like Cotton Mather and Increase Mather completed what he could not at Harvard.', NULL, NULL, 'biographical', 'psychology', NULL, 'samuel_parris', 'npcs/samuel_parris.md', 'Parris entered ministry from commercial failure, not spiritual calling. Parris worked as a merchant in Barbados then Boston (owning a wharf and warehouse) before entering the ministry. He turned to the church after commercial failure — not from a spiritual calling but from economic necessity. His merchant background gave him skill at negotiation and accounting but left him insecure about his credentials. Ministers like Cotton Mather and Increase Mather completed what he could not at Harvard.', 'semi_private', '["merchant","failure","ministry","insecurity"]', 'salem_project', 1.0, NULL, 1775266565637, 1775266565637, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('parris_sermon_notebook', 'Parris kept a sermon notebook 1689-1694 — primary source', 'Parris maintained a sermon notebook from 1689 to 1694, recording his sermon texts, themes, and dates. This document is one of the primary sources for understanding how he shaped the community''s theological response to the afflictions. His sermons were the village''s ''operating system,'' updated weekly.', NULL, NULL, 'biographical', 'documentation', NULL, 'samuel_parris', 'npcs/samuel_parris.md', 'Parris kept a sermon notebook 1689-1694 — primary source. Parris maintained a sermon notebook from 1689 to 1694, recording his sermon texts, themes, and dates. This document is one of the primary sources for understanding how he shaped the community''s theological response to the afflictions. His sermons were the village''s ''operating system,'' updated weekly.', 'public', '["sermon_notebook","primary_source","documentation"]', 'salem_project', 1.0, NULL, 1775266565637, 1775266565637, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('mercy_lewis_1676_infant_survivor', 'Mercy Lewis survived the 1676 Falmouth attack as a 3-year-old', 'Mercy Lewis survived the first attack on Falmouth during King Philip''s War in 1676 when she was approximately 3 years old. She would not remember it directly but grew up among survivors who carried the trauma — flinching at sudden noises, scanning tree lines, conversations stopping at sounds in the woods. Then in 1689, the same settlement was destroyed again, killing both her parents.', '1676', 'year', 'biographical', 'trauma', NULL, 'mercy_lewis', 'npcs/mercy_lewis.md', 'Mercy Lewis survived the 1676 Falmouth attack as a 3-year-old. Mercy Lewis survived the first attack on Falmouth during King Philip''s War in 1676 when she was approximately 3 years old. She would not remember it directly but grew up among survivors who carried the trauma — flinching at sudden noises, scanning tree lines, conversations stopping at sounds in the woods. Then in 1689, the same settlement was destroyed again, killing both her parents.', 'public', '["trauma","infant_survivor","falmouth","double_attack"]', 'salem_project', 1.0, NULL, 1775266565637, 1775266565637, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('mercy_lewis_strategic_accuser', 'Mercy Lewis as strategic accuser — intelligence from Putnam household', 'Living in the Thomas Putnam household, Mercy Lewis had access to the family''s intelligence about who they considered enemies. Her accusations targeted individuals aligned with the Porter faction and Putnam opponents. She accused 50+ individuals and testified in 16 cases — more than any other accuser. Her accusations were not random; they reflected the political geography she absorbed from her masters.', NULL, NULL, 'biographical', 'crisis', NULL, 'mercy_lewis', 'npcs/mercy_lewis.md', 'Mercy Lewis as strategic accuser — intelligence from Putnam household. Living in the Thomas Putnam household, Mercy Lewis had access to the family''s intelligence about who they considered enemies. Her accusations targeted individuals aligned with the Porter faction and Putnam opponents. She accused 50+ individuals and testified in 16 cases — more than any other accuser. Her accusations were not random; they reflected the political geography she absorbed from her masters.', 'semi_private', '["strategic","accuser","intelligence","putnam_household"]', 'salem_project', 1.0, NULL, 1775266565637, 1775266565637, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('abigail_williams_parris_niece', 'Abigail Williams (11) was Parris''s niece, living in the parsonage', 'Abigail Williams, 11 years old in 1692, was Samuel Parris''s niece living in the parsonage. She was the most dramatic of the early accusers — interrupting sermons, claiming to see specters, directing spectral combat at Ingersoll''s. Her disappearance from the historical record after 1692 is nearly complete; her fate is unknown.', NULL, NULL, 'biographical', 'family', NULL, 'abigail_williams', 'npcs/abigail_williams.md', 'Abigail Williams (11) was Parris''s niece, living in the parsonage. Abigail Williams, 11 years old in 1692, was Samuel Parris''s niece living in the parsonage. She was the most dramatic of the early accusers — interrupting sermons, claiming to see specters, directing spectral combat at Ingersoll''s. Her disappearance from the historical record after 1692 is nearly complete; her fate is unknown.', 'public', '["niece","parsonage","dramatic","fate_unknown"]', 'salem_project', 1.0, NULL, 1775266565637, 1775266565637, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('ann_putnam_jr_mothers_instrument', 'Ann Putnam Jr. (12) channeled her mother''s grief and her father''s grudges', 'Ann Putnam Jr., 12 years old, was the daughter of Thomas Putnam Jr. and Ann Putnam Sr. She grew up hearing her mother''s grief over lost children and disinherited family, and her father''s rage over boundary disputes and factional losses. Her accusations mapped precisely onto her father''s enemies. She is the only accuser who publicly apologized (1706), stating she had acted ''ignorantly.''', NULL, NULL, 'biographical', 'psychology', NULL, 'ann_putnam_jr', 'npcs/ann_putnam_jr.md', 'Ann Putnam Jr. (12) channeled her mother''s grief and her father''s grudges. Ann Putnam Jr., 12 years old, was the daughter of Thomas Putnam Jr. and Ann Putnam Sr. She grew up hearing her mother''s grief over lost children and disinherited family, and her father''s rage over boundary disputes and factional losses. Her accusations mapped precisely onto her father''s enemies. She is the only accuser who publicly apologized (1706), stating she had acted ''ignorantly.''', 'public', '["child_accuser","channeled_grief","fathers_grudges"]', 'salem_project', 1.0, NULL, 1775266565637, 1775266565637, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('mary_warren_proctor_servant_20', 'Mary Warren (20) — oldest afflicted girl, servant to Proctor', 'Mary Warren was 20 years old in 1692, the oldest of the afflicted accusers and a servant in John Proctor''s household. When Proctor cured her fits with the spinning wheel, she tried to tell the truth — posting a recovery notice and telling the court the girls ''did but dissemble.'' The other girls immediately accused her of witchcraft. Under prison pressure, she reversed her recantation and resumed accusing.', NULL, NULL, 'biographical', 'status', NULL, 'mary_warren', 'npcs/mary_warren.md', 'Mary Warren (20) — oldest afflicted girl, servant to Proctor. Mary Warren was 20 years old in 1692, the oldest of the afflicted accusers and a servant in John Proctor''s household. When Proctor cured her fits with the spinning wheel, she tried to tell the truth — posting a recovery notice and telling the court the girls ''did but dissemble.'' The other girls immediately accused her of witchcraft. Under prison pressure, she reversed her recantation and resumed accusing.', 'public', '["oldest_accuser","servant","silenced","truth_teller"]', 'salem_project', 1.0, NULL, 1775266565637, 1775266565637, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('hathorne_arabella_lineage', 'John Hathorne — son of William Hathorne who arrived on the Arabella with Winthrop', 'John Hathorne''s father William Hathorne arrived on the Arabella with John Winthrop in 1630 — first generation founding stock. This lineage gave John a sense of colonial aristocracy and unquestionable authority. He conducted examinations with prosecutorial aggression, never questioning whether the accused might be innocent. He never expressed remorse and died May 10, 1717.', NULL, NULL, 'biographical', 'lineage', NULL, 'john_hathorne', 'npcs/john_hathorne.md', 'John Hathorne — son of William Hathorne who arrived on the Arabella with Winthrop. John Hathorne''s father William Hathorne arrived on the Arabella with John Winthrop in 1630 — first generation founding stock. This lineage gave John a sense of colonial aristocracy and unquestionable authority. He conducted examinations with prosecutorial aggression, never questioning whether the accused might be innocent. He never expressed remorse and died May 10, 1717.', 'public', '["arabella","lineage","first_generation","no_remorse"]', 'salem_project', 1.0, NULL, 1775266565637, 1775266565637, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('hathorne_hawthorne_ancestor', 'Nathaniel Hawthorne added the ''w'' to distance himself from Judge Hathorne', 'John Hathorne was the great-great-grandfather of the novelist Nathaniel Hawthorne, who added the ''w'' to his surname to distance himself from his ancestor''s role in the witch trials. Hawthorne''s novel The House of the Seven Gables draws directly on the Salem witch trial legacy and the curse of the condemned.', NULL, NULL, 'biographical', 'legacy', NULL, 'john_hathorne', 'political_events_charter_research.md', 'Nathaniel Hawthorne added the ''w'' to distance himself from Judge Hathorne. John Hathorne was the great-great-grandfather of the novelist Nathaniel Hawthorne, who added the ''w'' to his surname to distance himself from his ancestor''s role in the witch trials. Hawthorne''s novel The House of the Seven Gables draws directly on the Salem witch trial legacy and the curse of the condemned.', 'public', '["hawthorne","novelist","legacy","name_change"]', 'salem_project', 1.0, NULL, 1775266565637, 1775266565637, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('francis_nurse_organized_petition', 'Francis Nurse organized the 39-signer petition door-to-door', 'Francis Nurse organized the pro-Rebecca Nurse petition by going door to door across Salem Village. The petition was signed in different ink, proving it was canvassed rather than gathered at a single meeting. He collected 39 signatures from people willing to put their names on a document defending an accused witch — a courageous act that put signers at risk. At least two petitioners'' families were subsequently accused.', '1692-06', 'month', 'biographical', 'crisis', NULL, 'francis_nurse', 'information_flow_research.md', 'Francis Nurse organized the 39-signer petition door-to-door. Francis Nurse organized the pro-Rebecca Nurse petition by going door to door across Salem Village. The petition was signed in different ink, proving it was canvassed rather than gathered at a single meeting. He collected 39 signatures from people willing to put their names on a document defending an accused witch — a courageous act that put signers at risk. At least two petitioners'' families were subsequently accused.', 'public', '["petition","door_to_door","courage","retaliation_risk"]', 'salem_project', 1.0, NULL, 1775266565637, 1775266565637, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('joseph_putnam_horse_saddled_6_months', 'Joseph Putnam kept a horse saddled for 6 months for instant escape', 'After threatening Ann Putnam Sr. with armed resistance, Joseph Putnam kept one of his fleetest horses saddled at all times and his family armed for six months to guarantee their escape if arrest warrants came. It was widely known he would resist any attempt to take his household ''even though it cost the lives of those who came to take him.'' He was never accused — but the threat of armed resistance may have protected him.', NULL, NULL, 'biographical', 'resistance', NULL, 'joseph_putnam', 'micro_events_daily_chronicle.md', 'Joseph Putnam kept a horse saddled for 6 months for instant escape. After threatening Ann Putnam Sr. with armed resistance, Joseph Putnam kept one of his fleetest horses saddled at all times and his family armed for six months to guarantee their escape if arrest warrants came. It was widely known he would resist any attempt to take his household ''even though it cost the lives of those who came to take him.'' He was never accused — but the threat of armed resistance may have protected him.', 'public', '["armed_resistance","horse_saddled","6_months","deterrence"]', 'salem_project', 1.0, NULL, 1775266565637, 1775266565637, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('tituba_parris_barbados_enslaved', 'Tituba brought from Barbados by Parris — enslaved, no autonomy', 'Tituba was brought from Barbados by Samuel Parris when he relocated to Massachusetts. She was enslaved — she had no autonomy, no legal standing, no right to refuse anything asked of her. Her confession on March 1 may have been coerced or strategically offered to survive. After the trials, Parris refused to pay her jail fees, and she remained imprisoned 13 months until an unknown person paid 7 pounds.', NULL, NULL, 'biographical', 'origin', NULL, 'tituba', 'npcs/tituba.md', 'Tituba brought from Barbados by Parris — enslaved, no autonomy. Tituba was brought from Barbados by Samuel Parris when he relocated to Massachusetts. She was enslaved — she had no autonomy, no legal standing, no right to refuse anything asked of her. Her confession on March 1 may have been coerced or strategically offered to survive. After the trials, Parris refused to pay her jail fees, and she remained imprisoned 13 months until an unknown person paid 7 pounds.', 'public', '["enslaved","barbados","no_autonomy","coerced"]', 'salem_project', 1.0, NULL, 1775266565637, 1775266565637, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('sermon_jan_3_1692_satan_pull_down', 'January 3, 1692 sermon — Parris warns the Devil seeks to ''pull it all down''', 'Two weeks before the afflictions began, Parris preached that ''Christ having begun a new work [in this church], it is the main drift of the Devil to pull it all down.'' This sermon primed the community to interpret any subsequent crisis through a supernatural lens. Every NPC who attended church that Sunday would carry this phrase.', '1692-01-03', 'exact', 'religious', 'sermon', NULL, 'samuel_parris', 'occupational_knowledge_map.md', 'January 3, 1692 sermon — Parris warns the Devil seeks to ''pull it all down''. Two weeks before the afflictions began, Parris preached that ''Christ having begun a new work in this church, it is the main drift of the Devil to pull it all down.'' This sermon primed the community to interpret any subsequent crisis through a supernatural lens. Every NPC who attended church that Sunday would carry this phrase.', 'public', '["sermon","january","satan","priming"]', 'salem_project', 1.0, NULL, 1775266565638, 1775266565638, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('sermon_mar_27_one_is_a_devil', 'March 27 sermon — ''There are Devils as well as Saints in Christs Church''', 'Parris preaches on John 6:70, declaring ''dreadful Witchcraft broke out here a few weeks past'' and warns ''There are Devils as well as Saints in Christs Church.'' He notes one member of his own church is ''vehemently suspected for Shee-Witches.'' This sermon directly names church members as potential witches — an escalation from targeting marginal outsiders to targeting the community''s core.', '1692-03-27', 'exact', 'religious', 'sermon', NULL, 'samuel_parris', 'micro_events_daily_chronicle.md', 'March 27 sermon — ''There are Devils as well as Saints in Christs Church''. Parris preaches on John 6:70, declaring ''dreadful Witchcraft broke out here a few weeks past'' and warns ''There are Devils as well as Saints in Christs Church.'' He notes one member of his own church is ''vehemently suspected for Shee-Witches.'' This sermon directly names church members as potential witches — an escalation from targeting marginal outsiders to targeting the community''s core.', 'public', '["sermon","march","church_members","escalation"]', 'salem_project', 1.0, NULL, 1775266565638, 1775266565638, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('corey_killed_goodale_1676', 'Giles Corey beat Jacob Goodale to death in 1676 — history of violence', 'In 1676, Giles Corey beat his farm laborer Jacob Goodale (son of Robert and Catherine Goodale) with a stick, allegedly over apple theft. Goodale died ten days later. Corey was charged with murder but convicted only of using ''unreasonable force.'' John Proctor testified at the inquest. In 1678, Corey was involved in an arson dispute with John Gloyd over unpaid wages, with Proctor as arbitrator. Corey''s violent history made him an easier target in 1692.', '1676', 'year', 'biographical', 'violence', NULL, 'giles_corey', 'village_disputes_research.md', 'Giles Corey beat Jacob Goodale to death in 1676 — history of violence. In 1676, Giles Corey beat his farm laborer Jacob Goodale (son of Robert and Catherine Goodale) with a stick, allegedly over apple theft. Goodale died ten days later. Corey was charged with murder but convicted only of using ''unreasonable force.'' John Proctor testified at the inquest. In 1678, Corey was involved in an arson dispute with John Gloyd over unpaid wages, with Proctor as arbitrator. Corey''s violent history made him an easier target in 1692.', 'public', '["murder","violence","history","goodale"]', 'salem_project', 1.0, NULL, 1775266565638, 1775266565638, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('parris_ordination_november_1689', 'Parris ordained November 19, 1689 — first ordained Salem Village minister', 'Samuel Parris was ordained on November 19, 1689, with 25-27 founding covenant members. He was the first minister to actually be ordained in Salem Village — all three predecessors (Bayley, Burroughs, Lawson) had served without ordination. By 1691, the church had grown to include 34 additional members plus 14 ''visitors'' from other churches.', '1689-11-19', 'exact', 'biographical', 'career', NULL, 'samuel_parris', 'village_disputes_research.md', 'Parris ordained November 19, 1689 — first ordained Salem Village minister. Samuel Parris was ordained on November 19, 1689, with 25-27 founding covenant members. He was the first minister to actually be ordained in Salem Village — all three predecessors (Bayley, Burroughs, Lawson) had served without ordination. By 1691, the church had grown to include 34 additional members plus 14 ''visitors'' from other churches.', 'public', '["ordination","first_ordained","covenant_members"]', 'salem_project', 1.0, NULL, 1775266565638, 1775266565638, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('parris_parsonage_deed_dispute', 'The parsonage deed dispute — Parris''s existential crisis', 'On October 10, 1689, the village voted to grant Parris the parsonage, barn, and two acres with his heirs to hold in perpetuity — revoking a 1681 agreement that kept the parsonage as village property. The anti-Parris committee of October 1691 revoked this deed, refused to collect salary taxes, and cut off firewood. This left Parris without housing security, income, or heat during the winter of 1691-92 — the winter the afflictions began.', '1689-10-10', 'exact', 'social', 'dispute', NULL, 'samuel_parris', 'village_disputes_research.md', 'The parsonage deed dispute — Parris''s existential crisis. On October 10, 1689, the village voted to grant Parris the parsonage, barn, and two acres with his heirs to hold in perpetuity — revoking a 1681 agreement that kept the parsonage as village property. The anti-Parris committee of October 1691 revoked this deed, refused to collect salary taxes, and cut off firewood. This left Parris without housing security, income, or heat during the winter of 1691-92 — the winter the afflictions began.', 'public', '["parsonage","deed","salary","firewood","existential"]', 'salem_project', 1.0, NULL, 1775266565638, 1775266565638, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('carr_inheritance_one_shilling', 'Elizabeth Carr leaves Ann Putnam Sr. ONE SHILLING — deliberate disinheritance', 'Elizabeth Carr (Ann Putnam Sr.''s mother) died May 6, 1691 and left Ann precisely ONE SHILLING in her will — a deliberate signal of disinheritance, not an oversight. Ann''s father George Carr had already cut her out. Combined with sister Mary Carr Bailey''s death (1688) and the loss of an infant daughter (1689), Ann Sr. entered 1692 psychologically devastated. Her accusations during the trials may have been projection of her family losses.', '1691-05-06', 'exact', 'biographical', 'grievance', NULL, 'ann_putnam_sr', 'village_disputes_research.md', 'Elizabeth Carr leaves Ann Putnam Sr. ONE SHILLING — deliberate disinheritance. Elizabeth Carr (Ann Putnam Sr.''s mother) died May 6, 1691 and left Ann precisely ONE SHILLING in her will — a deliberate signal of disinheritance, not an oversight. Ann''s father George Carr had already cut her out. Combined with sister Mary Carr Bailey''s death (1688) and the loss of an infant daughter (1689), Ann Sr. entered 1692 psychologically devastated. Her accusations during the trials may have been projection of her family losses.', 'semi_private', '["disinheritance","one_shilling","carr_family","psychological"]', 'salem_project', 1.0, NULL, 1775266565638, 1775266565638, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('putnam_jr_downward_mobility', 'Thomas Putnam Jr.''s downward mobility — father was richest, he was modest', 'In the 1681 tax assessment, Thomas Putnam Sr. was assessed at 10-6-3 — the highest in Salem Village. His son Thomas Jr. was assessed at only 2-14, a modest farmer still building his estate. After the senior Putnam''s death, the contested will (which favored the second wife''s children and gave Joseph the ''double portion'') left Thomas Jr. with far less than expected. His sense of economic decline — falling from the village''s most prominent family — fueled his combative approach to village politics.', NULL, NULL, 'economic', 'status', NULL, 'thomas_putnam_jr', 'economic_interdependence_research.md', 'Thomas Putnam Jr.''s downward mobility — father was richest, he was modest. In the 1681 tax assessment, Thomas Putnam Sr. was assessed at 10-6-3 — the highest in Salem Village. His son Thomas Jr. was assessed at only 2-14, a modest farmer still building his estate. After the senior Putnam''s death, the contested will (which favored the second wife''s children and gave Joseph the ''double portion'') left Thomas Jr. with far less than expected. His sense of economic decline — falling from the village''s most prominent family — fueled his combative approach to village politics.', 'public', '["downward_mobility","tax_assessment","inheritance","status_anxiety"]', 'salem_project', 1.0, NULL, 1775266565638, 1775266565638, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('proctor_700_acre_groton', 'John Proctor owned a 700-acre farm in Groton, tavern license for travelers only', 'John Proctor owned a 700-acre farm in Groton in addition to his Salem Village property. His tavern license was restricted to serving non-local travelers only — not village residents. This made him an outsider to the village social scene (he didn''t drink with the locals at Ingersoll''s) while being wealthy enough to be resented. His property was seized after his execution — cattle sold and shipped to the West Indies, even the broth pot taken, children left with nothing.', NULL, NULL, 'biographical', 'property', NULL, 'john_proctor', 'economic_interdependence_research.md', 'John Proctor owned a 700-acre farm in Groton, tavern license for travelers only. John Proctor owned a 700-acre farm in Groton in addition to his Salem Village property. His tavern license was restricted to serving non-local travelers only — not village residents. This made him an outsider to the village social scene (he didn''t drink with the locals at Ingersoll''s) while being wealthy enough to be resented. His property was seized after his execution — cattle sold and shipped to the West Indies, even the broth pot taken, children left with nothing.', 'public', '["700_acres","groton","tavern_travelers_only","property_seized"]', 'salem_project', 1.0, NULL, 1775266565638, 1775266565638, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('ingersoll_expense_account_1692', 'Ingersoll''s 1692 expense account — cakes, rum, oats, guard drinks itemized', 'Nathaniel Ingersoll submitted a detailed expense account for 1692 that itemizes: 4.5 dozen cakes for examinations, rum for officials, oats for horses, drinks for guards watching prisoners. This mundane accounting reveals the crisis as an economic activity — people were fed, housed, guarded, and billed. The tavern keeper profited from the very proceedings he witnessed.', NULL, NULL, 'economic', 'documentation', NULL, 'nathaniel_ingersoll', 'economic_interdependence_research.md', 'Ingersoll''s 1692 expense account — cakes, rum, oats, guard drinks itemized. Nathaniel Ingersoll submitted a detailed expense account for 1692 that itemizes: 4.5 dozen cakes for examinations, rum for officials, oats for horses, drinks for guards watching prisoners. This mundane accounting reveals the crisis as an economic activity — people were fed, housed, guarded, and billed. The tavern keeper profited from the very proceedings he witnessed.', 'semi_private', '["expense_account","cakes","rum","economics_of_crisis"]', 'salem_project', 1.0, NULL, 1775266565638, 1775266565638, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('nurse_excommunication_reversed', 'Rebecca Nurse''s excommunication reversed by the same Rev. Noyes who imposed it', 'Rebecca Nurse was excommunicated on July 3, 1692 by Rev. Nicholas Noyes. On March 6, 1712 — twenty years later — her excommunication was reversed by the same Rev. Noyes. The reversal came after years of pressure from the Nurse family and shifting community sentiment. Noyes himself died in 1717, choking on his own blood, which many viewed as fulfillment of Sarah Good''s scaffold curse.', '1712-03-06', 'exact', 'religious', 'aftermath', NULL, 'rebecca_nurse', 'village_disputes_research.md', 'Rebecca Nurse''s excommunication reversed by the same Rev. Noyes who imposed it. Rebecca Nurse was excommunicated on July 3, 1692 by Rev. Nicholas Noyes. On March 6, 1712 — twenty years later — her excommunication was reversed by the same Rev. Noyes. The reversal came after years of pressure from the Nurse family and shifting community sentiment. Noyes himself died in 1717, choking on his own blood, which many viewed as fulfillment of Sarah Good''s scaffold curse.', 'public', '["excommunication","reversed","noyes","twenty_years"]', 'salem_project', 1.0, NULL, 1775266565638, 1775266565638, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('prop_putnam_mill_chokepoint', 'Putnam sawmill at Beaver Brook — every farmer west of the village depends on it', 'The Putnam family operated a sawmill powered by water from Beaver Brook, with Putnam''s Pond behind the dam. Massachusetts law regulated the miller''s toll at 1/16th of the grain. Constables inspected measures. Every family that grew grain needed a mill; no individual farm could justify building one. The mill owner held structural power — determining when grain was ground, whose grain was prioritized, and whether the toll was fair. Any farmer in western Salem Village who used this mill was economically dependent on the Putnam family. When Thomas Putnam Jr. files witchcraft complaints, the farmer who uses his family mill has to think very carefully about which side to take.', NULL, NULL, 'economic', 'property', NULL, 'thomas_putnam_jr', 'economic_interdependence_research.md', 'Putnam sawmill at Beaver Brook — every farmer west of the village depends on it. The Putnam family operated a sawmill powered by water from Beaver Brook, with Putnam''s Pond behind the dam. Massachusetts law regulated the miller''s toll at 1/16th of the grain. Constables inspected measures. Every family that grew grain needed a mill; no individual farm could justify building one. The mill owner held structural power — determining when grain was ground, whose grain was prioritized, and whether the toll was fair. Any farmer in western Salem Village who used this mill was economically dependent on the Putnam family. When Thomas Putnam Jr. files witchcraft complaints, the farmer who uses his family mill has to think very carefully about which side to take.', 'public', '["mill","chokepoint","economic_power","dependency","beaver_brook"]', 'salem_project', 1.0, NULL, 1775266565638, 1775266565638, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('prop_porter_dam_sawmill', 'Porter dam and sawmill — commercial enterprise that drowned Putnam meadow', 'The Porter family built a dam and sawmill in 1672 that flooded Putnam meadowland used for grazing and hay. The Putnams sued and lost. This was the origin point of the feud: the Porters were building commercial enterprise (sawmill for market timber) while the Putnams were farming (subsistence agriculture). The water that flooded the Putnam meadow flowed from a changing economy — the dam was the physical embodiment of Salem Village''s transition from agrarian past to commercial future.', '1672', 'year', 'economic', 'property', NULL, 'thomas_putnam_jr', 'economic_interdependence_research.md', 'Porter dam and sawmill — commercial enterprise that drowned Putnam meadow. The Porter family built a dam and sawmill in 1672 that flooded Putnam meadowland used for grazing and hay. The Putnams sued and lost. This was the origin point of the feud: the Porters were building commercial enterprise (sawmill for market timber) while the Putnams were farming (subsistence agriculture). The water that flooded the Putnam meadow flowed from a changing economy — the dam was the physical embodiment of Salem Village''s transition from agrarian past to commercial future.', 'public', '["dam","sawmill","flood","feud_origin","commercial_vs_agrarian"]', 'salem_project', 1.0, NULL, 1775266565638, 1775266565638, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('prop_andrew_wharf_frost_fish', 'Daniel Andrew''s wharf on Frost Fish Brook — independent water access', 'In February 1692 — the very month the afflictions began — Daniel Andrew purchased a landing wharf on Frost Fish Brook, which flowed into Frost Fish River. This gave him direct water access to ship agricultural products to Salem Town. Andrew was married to Sarah Porter and was the fourth wealthiest man in Salem Village. A man with a wharf does not depend on village roads or village neighbors. He has his own channel to the outside world. Andrew was elected Salem Town selectman in April 1692 alongside Philip English and Israel Porter. Both Andrew and English were later accused of witchcraft.', '1692-02', 'month', 'economic', 'property', NULL, 'daniel_andrew', 'economic_interdependence_research.md', 'Daniel Andrew''s wharf on Frost Fish Brook — independent water access. In February 1692 — the very month the afflictions began — Daniel Andrew purchased a landing wharf on Frost Fish Brook, which flowed into Frost Fish River. This gave him direct water access to ship agricultural products to Salem Town. Andrew was married to Sarah Porter and was the fourth wealthiest man in Salem Village. A man with a wharf does not depend on village roads or village neighbors. He has his own channel to the outside world. Andrew was elected Salem Town selectman in April 1692 alongside Philip English and Israel Porter. Both Andrew and English were later accused of witchcraft.', 'public', '["wharf","frost_fish_brook","independence","porter_faction"]', 'salem_project', 1.0, NULL, 1775266565638, 1775266565638, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('prop_nurse_300_acres_bishop_farm', 'Francis Nurse''s 300-acre Bishop Farm — the disputed estate', 'In 1678, Francis Nurse entered a lease-to-own agreement for the 300-acre Bishop Farm from Rev. James Allen of Boston. The property was in western Salem Village, adjacent to Putnam holdings. Three overlapping land grants converged: the Bishop Grant, the Endicott Orchard Farm Grant, and the Putnam Holdings. Multiple surveys produced different answers. Courts consistently ruled for Nurse. By 1692, the Nurse family had built it into a prosperous estate: orchards, flax patches, flower gardens, pastures, and fields. Nathaniel Putnam''s homestead was directly adjacent.', '1678', 'year', 'economic', 'property', NULL, 'francis_nurse', 'village_disputes_research.md', 'Francis Nurse''s 300-acre Bishop Farm — the disputed estate. In 1678, Francis Nurse entered a lease-to-own agreement for the 300-acre Bishop Farm from Rev. James Allen of Boston. The property was in western Salem Village, adjacent to Putnam holdings. Three overlapping land grants converged: the Bishop Grant, the Endicott Orchard Farm Grant, and the Putnam Holdings. Multiple surveys produced different answers. Courts consistently ruled for Nurse. By 1692, the Nurse family had built it into a prosperous estate: orchards, flax patches, flower gardens, pastures, and fields. Nathaniel Putnam''s homestead was directly adjacent.', 'public', '["300_acres","bishop_farm","overlapping_grants","adjacent_putnam"]', 'salem_project', 1.0, NULL, 1775266565638, 1775266565638, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('prop_nurse_family_cluster', 'Nurse family cluster — four families connected by private roads', 'Francis Nurse built roads connecting his children''s properties: daughter Mary and husband John Tarbell lived east of him; daughter Rebecca and husband John Preston lived nearby; son Samuel Nurse lived just south. Four families within a few miles, connected by private roads — a self-sufficient Nurse enclave within Salem Village. In June 1696, Samuel Nurse bought three acres from Ephraim Sheldon for 9 pounds and resold half to brother-in-law Tarbell for 4 pounds, 10 shillings.', NULL, NULL, 'economic', 'property', NULL, 'francis_nurse', 'economic_interdependence_research.md', 'Nurse family cluster — four families connected by private roads. Francis Nurse built roads connecting his children''s properties: daughter Mary and husband John Tarbell lived east of him; daughter Rebecca and husband John Preston lived nearby; son Samuel Nurse lived just south. Four families within a few miles, connected by private roads — a self-sufficient Nurse enclave within Salem Village. In June 1696, Samuel Nurse bought three acres from Ephraim Sheldon for 9 pounds and resold half to brother-in-law Tarbell for 4 pounds, 10 shillings.', 'public', '["family_cluster","private_roads","self_sufficient"]', 'salem_project', 1.0, NULL, 1775266565638, 1775266565638, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('prop_nurse_estate_division_1694', 'Francis Nurse divides estate after Rebecca''s execution — 14 pounds/year', 'On December 4, 1694, two years after Rebecca''s execution, the 77-year-old Francis Nurse divided his estate among his heirs, giving them immediate occupancy and directing only that he be paid 14 pounds a year for his own needs. The man who organized the 39-signer petition and fought to save his wife spent his last years supported by his children on the land that had cost Rebecca her life.', '1694-12-04', 'exact', 'economic', 'property', NULL, 'francis_nurse', 'economic_interdependence_research.md', 'Francis Nurse divides estate after Rebecca''s execution — 14 pounds/year. On December 4, 1694, two years after Rebecca''s execution, the 77-year-old Francis Nurse divided his estate among his heirs, giving them immediate occupancy and directing only that he be paid 14 pounds a year for his own needs. The man who organized the 39-signer petition and fought to save his wife spent his last years supported by his children on the land that had cost Rebecca her life.', 'public', '["estate_division","14_pounds","aftermath"]', 'salem_project', 1.0, NULL, 1775266565638, 1775266565638, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('prop_english_21_vessels', 'Philip English''s commercial empire — 21 vessels, 14 buildings, wharves, warehouses', 'Philip English owned at least 21 sailing vessels, 14 buildings in Salem, wharves on Salem Harbor, multiple warehouses (two-story timber-frame buildings stocked with salt cod, sugar, molasses, wine, brandy, lumber, iron from Bilbao, naval stores), and a counting house with strongbox, ledgers, and scales. He employed dozens of shipmasters and hundreds of sailors — one of the largest employers in Essex County. His mansion on Essex Street was the largest private dwelling in Salem for ~100 years. A farmer needing salt, rum, or iron tools was ultimately dependent on trade networks English controlled.', NULL, NULL, 'economic', 'property', NULL, 'philip_english', 'philip_english_merchant_research.md', 'Philip English''s commercial empire — 21 vessels, 14 buildings, wharves, warehouses. Philip English owned at least 21 sailing vessels, 14 buildings in Salem, wharves on Salem Harbor, multiple warehouses (two-story timber-frame buildings stocked with salt cod, sugar, molasses, wine, brandy, lumber, iron from Bilbao, naval stores), and a counting house with strongbox, ledgers, and scales. He employed dozens of shipmasters and hundreds of sailors — one of the largest employers in Essex County. His mansion on Essex Street was the largest private dwelling in Salem for ~100 years. A farmer needing salt, rum, or iron tools was ultimately dependent on trade networks English controlled.', 'public', '["empire","21_vessels","14_buildings","wharves","warehouses"]', 'salem_project', 1.0, NULL, 1775266565638, 1775266565638, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('prop_english_mansion_secret_room', 'English mansion — many-gabled, views of two harbors, secret attic room', 'The English mansion on Essex Street had many gables, overhanging second stories with carved pendants, a great porch, paneled rooms, wine cellar, silver plate, glass windows, and views of both Collins Cove and Salem Harbor. A secret room was discovered in the attic when the house was demolished in 1833 — possibly for smuggling, contraband, or as a strongroom. During the witch crisis, it may have served as a hiding place.', NULL, NULL, 'economic', 'property', NULL, 'philip_english', 'philip_english_merchant_research.md', 'English mansion — many-gabled, views of two harbors, secret attic room. The English mansion on Essex Street had many gables, overhanging second stories with carved pendants, a great porch, paneled rooms, wine cellar, silver plate, glass windows, and views of both Collins Cove and Salem Harbor. A secret room was discovered in the attic when the house was demolished in 1833 — possibly for smuggling, contraband, or as a strongroom. During the witch crisis, it may have served as a hiding place.', 'public', '["mansion","secret_room","gables","wine_cellar"]', 'salem_project', 1.0, NULL, 1775266565638, 1775266565638, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('prop_proctor_tavern_ipswich_road', 'John Proctor''s tavern on Ipswich Road — serves travelers only, not locals', 'John Proctor leased the 700-acre Groton Farm (Downing Farm) since 1666 and received his first tavern license in 1668. His inn sat on the Ipswich Road about a mile south of the Salem Village line. Salem selectmen restricted him to serving only non-local travelers — not village residents. This made Proctor''s tavern the meeting place for strangers while Ingersoll''s served locals. Elizabeth Proctor and the older children ran the tavern while John and eldest son Benjamin tended the extensive farm properties.', NULL, NULL, 'economic', 'property', NULL, 'john_proctor', 'economic_interdependence_research.md', 'John Proctor''s tavern on Ipswich Road — serves travelers only, not locals. John Proctor leased the 700-acre Groton Farm (Downing Farm) since 1666 and received his first tavern license in 1668. His inn sat on the Ipswich Road about a mile south of the Salem Village line. Salem selectmen restricted him to serving only non-local travelers — not village residents. This made Proctor''s tavern the meeting place for strangers while Ingersoll''s served locals. Elizabeth Proctor and the older children ran the tavern while John and eldest son Benjamin tended the extensive farm properties.', 'public', '["tavern","ipswich_road","travelers_only","700_acres","liminal"]', 'salem_project', 1.0, NULL, 1775266565639, 1775266565639, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('prop_proctor_seized_everything', 'Proctor estate seized — cattle shipped to West Indies, broth pot taken, children left nothing', 'After John Proctor''s execution, Sheriff Corwin raided the Proctor farm and confiscated all beer, food, and valuables. Cattle were sold cheaply, slaughtered, or shipped to the West Indies. Beer barrels at the tavern were emptied. A pot of broth was thrown out and the pot taken. The children were left with nothing for support. Approximately 150 pounds in court and jail fees were extracted. Total estate value over 300 pounds.', '1692-08-19', 'exact', 'economic', 'seizure', NULL, 'john_proctor', 'economic_interdependence_research.md', 'Proctor estate seized — cattle shipped to West Indies, broth pot taken, children left nothing. After John Proctor''s execution, Sheriff Corwin raided the Proctor farm and confiscated all beer, food, and valuables. Cattle were sold cheaply, slaughtered, or shipped to the West Indies. Beer barrels at the tavern were emptied. A pot of broth was thrown out and the pot taken. The children were left with nothing for support. Approximately 150 pounds in court and jail fees were extracted. Total estate value over 300 pounds.', 'public', '["seizure","cattle","west_indies","broth_pot","children_destitute"]', 'salem_project', 1.0, NULL, 1775266565639, 1775266565639, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('prop_putnam_sr_will_contest', 'Thomas Putnam Sr.''s will — Joseph gets ''double portion,'' Thomas Jr. ''wronged of my birthright''', 'Thomas Putnam Sr.''s will (dated February 8, 1682/83, proved July 8, 1686) gave the eastern half of his land to Thomas Jr. and the western half to youngest son Joseph — child of the second wife Mary Veren. Thomas Jr. and his brothers contested the will, claiming undue influence. They failed. Joseph — at 18 — became one of the richest men in the village. At 20 he married Elizabeth Porter, uniting Putnam fortune with the rival faction. Thomas Jr. described himself as ''wronged of my birthright.''', '1686-07-08', 'exact', 'economic', 'inheritance', NULL, 'thomas_putnam_jr', 'economic_interdependence_research.md', 'Thomas Putnam Sr.''s will — Joseph gets ''double portion,'' Thomas Jr. ''wronged of my birthright''. Thomas Putnam Sr.''s will (dated February 8, 1682/83, proved July 8, 1686) gave the eastern half of his land to Thomas Jr. and the western half to youngest son Joseph — child of the second wife Mary Veren. Thomas Jr. and his brothers contested the will, claiming undue influence. They failed. Joseph — at 18 — became one of the richest men in the village. At 20 he married Elizabeth Porter, uniting Putnam fortune with the rival faction. Thomas Jr. described himself as ''wronged of my birthright.''', 'public', '["will","inheritance","double_portion","birthright","betrayal"]', 'salem_project', 1.0, NULL, 1775266565639, 1775266565639, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('prop_ingersolls_five_roles', 'Nathaniel Ingersoll held five simultaneous roles — tavern, church, militia, banker, landowner', 'Nathaniel Ingersoll (b. 1633, d. 1719) simultaneously served as: Deacon of the Salem Village Church, Lieutenant in the militia, Proprietor of the ordinary (licensed 1677), unofficial village banker (posted bond for Burroughs, extended credit), and donor of the Training Field at the corner of Centre Street and Ingersoll Street. He donated land for a second meetinghouse adjacent to his tavern in 1701. He was described by historian Charles Upham as ''the Father of the Village.''', NULL, NULL, 'economic', 'property', NULL, 'nathaniel_ingersoll', 'economic_interdependence_research.md', 'Nathaniel Ingersoll held five simultaneous roles — tavern, church, militia, banker, landowner. Nathaniel Ingersoll (b. 1633, d. 1719) simultaneously served as: Deacon of the Salem Village Church, Lieutenant in the militia, Proprietor of the ordinary (licensed 1677), unofficial village banker (posted bond for Burroughs, extended credit), and donor of the Training Field at the corner of Centre Street and Ingersoll Street. He donated land for a second meetinghouse adjacent to his tavern in 1701. He was described by historian Charles Upham as ''the Father of the Village.''', 'public', '["five_roles","deacon","lieutenant","banker","father_of_village"]', 'salem_project', 1.0, NULL, 1775266565639, 1775266565639, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('prop_putnam_territory_western', 'Putnam faction controls western Salem Village — agrarian, inward-facing', 'The Putnam faction dominated western Salem Village: Thomas Putnam Jr. (#24 on Upham''s map), Edward Putnam (#23), John Putnam Jr. (#37), Jonathan Putnam (#41), Captain John Putnam (#47). Their properties were inland, agrarian, oriented away from Salem Town. The Putnam sawmill at Beaver Brook was the economic anchor. Pro-Parris households clustered here. Joseph Putnam (#32) was the geographical exception — a Putnam who married Porter and defected.', NULL, NULL, 'geographic', 'faction', NULL, 'thomas_putnam_jr', 'village_geography_research.md', 'Putnam faction controls western Salem Village — agrarian, inward-facing. The Putnam faction dominated western Salem Village: Thomas Putnam Jr. (#24 on Upham''s map), Edward Putnam (#23), John Putnam Jr. (#37), Jonathan Putnam (#41), Captain John Putnam (#47). Their properties were inland, agrarian, oriented away from Salem Town. The Putnam sawmill at Beaver Brook was the economic anchor. Pro-Parris households clustered here. Joseph Putnam (#32) was the geographical exception — a Putnam who married Porter and defected.', 'public', '["western","putnam_territory","agrarian","inland"]', 'salem_project', 1.0, NULL, 1775266565639, 1775266565639, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('prop_porter_territory_eastern', 'Porter faction controls eastern Salem Village — commercial, town-facing', 'The Porter faction dominated eastern Salem Village: Israel Porter (#80), Daniel Andrew (#35, married Sarah Porter), Dr. William Griggs (#83). Their properties were closer to the Ipswich Road and Salem Town''s commercial economy. Anti-Parris households concentrated here. Beverly border families (Dodge, Herrick, Conant, Balch, Gage) were natural Porter allies. The Porter faction''s economic interests were oriented outward — toward Salem Town, trade, and commerce.', NULL, NULL, 'geographic', 'faction', NULL, 'israel_porter', 'village_geography_research.md', 'Porter faction controls eastern Salem Village — commercial, town-facing. The Porter faction dominated eastern Salem Village: Israel Porter (#80), Daniel Andrew (#35, married Sarah Porter), Dr. William Griggs (#83). Their properties were closer to the Ipswich Road and Salem Town''s commercial economy. Anti-Parris households concentrated here. Beverly border families (Dodge, Herrick, Conant, Balch, Gage) were natural Porter allies. The Porter faction''s economic interests were oriented outward — toward Salem Town, trade, and commerce.', 'public', '["eastern","porter_territory","commercial","ipswich_road"]', 'salem_project', 1.0, NULL, 1775266565639, 1775266565639, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('prop_accused_match_porter_territory', 'The accused live near Ipswich Road; the accusers live inland', 'Geographic analysis reveals a striking pattern: accused witches tended to live near the Ipswich Road corridor (the commercial artery to Salem Town), while their accusers lived in the inland, western part of the village. The accusation pattern follows the economic geography — the commercially oriented eastern village was targeted by the agrarian western village. The witch crisis was a border war conducted through the courts.', NULL, NULL, 'geographic', 'accusation_pattern', NULL, NULL, 'information_flow_research.md', 'The accused live near Ipswich Road; the accusers live inland. Geographic analysis reveals a striking pattern: accused witches tended to live near the Ipswich Road corridor (the commercial artery to Salem Town), while their accusers lived in the inland, western part of the village. The accusation pattern follows the economic geography — the commercially oriented eastern village was targeted by the agrarian western village. The witch crisis was a border war conducted through the courts.', 'public', '["geographic_pattern","ipswich_road","inland","accusation_geography"]', 'salem_project', 1.0, NULL, 1775266565639, 1775266565639, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('prop_common_grazing_nine_acres', 'Common grazing land — nine acres, five ponds, militia training since 1637', 'Salem''s common land (''the pen,'' ''the town swamp'') was approximately nine acres with five ponds and a creek. Used for livestock grazing and militia training since 1637. This shared space required cooperation between factions — a man whose cow grazed alongside his neighbor''s could not avoid that neighbor even during the witch crisis.', NULL, NULL, 'economic', 'shared', NULL, NULL, 'economic_interdependence_research.md', 'Common grazing land — nine acres, five ponds, militia training since 1637. Salem''s common land (''the pen,'' ''the town swamp'') was approximately nine acres with five ponds and a creek. Used for livestock grazing and militia training since 1637. This shared space required cooperation between factions — a man whose cow grazed alongside his neighbor''s could not avoid that neighbor even during the witch crisis.', 'public', '["common_land","grazing","militia_training","shared"]', 'salem_project', 1.0, NULL, 1775266565639, 1775266565639, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('prop_selectmen_april_1692', 'Salem Town selectmen April 1692 — Andrew, English, Porter elected', 'In April 1692, Daniel Andrew, Philip English, and Israel Porter were all elected Salem Town selectmen — placing the Porter faction''s leadership in control of Salem Town governance while the Putnam faction controlled Salem Village''s church and militia. Both Andrew and English were subsequently accused of witchcraft. The accusation of civic leaders suggests the witch crisis was partly an attempt to overthrow the commercial faction''s political gains.', '1692-04', 'month', 'political', 'governance', NULL, 'daniel_andrew', 'economic_interdependence_research.md', 'Salem Town selectmen April 1692 — Andrew, English, Porter elected. In April 1692, Daniel Andrew, Philip English, and Israel Porter were all elected Salem Town selectmen — placing the Porter faction''s leadership in control of Salem Town governance while the Putnam faction controlled Salem Village''s church and militia. Both Andrew and English were subsequently accused of witchcraft. The accusation of civic leaders suggests the witch crisis was partly an attempt to overthrow the commercial faction''s political gains.', 'public', '["selectmen","porter_faction","civic_power","targeted"]', 'salem_project', 1.0, NULL, 1775266565639, 1775266565639, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('prop_corwin_seizure_pattern', 'Sheriff Corwin''s seizures — personal enrichment under official cover', 'Sheriff George Corwin (nephew of Judge Jonathan Corwin, grandson of CT Governor Winthrop) confiscated the belongings of condemned prisoners: livestock, hay, apples, corn, kettles, pewter, furniture, jewelry. He seized Philip English''s property (1,183 pounds), John Proctor''s estate (300+ pounds including cattle shipped to West Indies), Mary Parker''s farm goods. Neighbors scavenged whatever Corwin''s men left behind. The 1711 restitution allocated only 578 pounds, 12 shillings across ALL victims'' families — a fraction of what was taken.', NULL, NULL, 'economic', 'seizure', NULL, 'philip_english', 'economic_interdependence_research.md', 'Sheriff Corwin''s seizures — personal enrichment under official cover. Sheriff George Corwin (nephew of Judge Jonathan Corwin, grandson of CT Governor Winthrop) confiscated the belongings of condemned prisoners: livestock, hay, apples, corn, kettles, pewter, furniture, jewelry. He seized Philip English''s property (1,183 pounds), John Proctor''s estate (300+ pounds including cattle shipped to West Indies), Mary Parker''s farm goods. Neighbors scavenged whatever Corwin''s men left behind. The 1711 restitution allocated only 578 pounds, 12 shillings across ALL victims'' families — a fraction of what was taken.', 'public', '["seizure","corwin","enrichment","restitution_inadequate"]', 'salem_project', 1.0, NULL, 1775266565639, 1775266565639, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('prop_servant_network_accusers', 'Every afflicted servant-girl was a frontier refugee placed in someone else''s home', 'The afflicted accusers who were servants were ALL frontier refugees: Mercy Lewis (orphaned by Falmouth 1689, served Burroughs then Putnam), Mary Warren (Maine refugee, served Proctor), Elizabeth Hubbard (orphan, served Griggs as great-niece), Sarah Churchill (Saco refugee, served George Jacobs Sr., granddaughter of Major Phillips — wealthiest man in Maine, reduced to servant). These girls had no family, no property, no legal standing. Accusation gave them power they had never had in their lives.', NULL, NULL, 'social', 'labor', NULL, 'mercy_lewis', 'economic_interdependence_research.md', 'Every afflicted servant-girl was a frontier refugee placed in someone else''s home. The afflicted accusers who were servants were ALL frontier refugees: Mercy Lewis (orphaned by Falmouth 1689, served Burroughs then Putnam), Mary Warren (Maine refugee, served Proctor), Elizabeth Hubbard (orphan, served Griggs as great-niece), Sarah Churchill (Saco refugee, served George Jacobs Sr., granddaughter of Major Phillips — wealthiest man in Maine, reduced to servant). These girls had no family, no property, no legal standing. Accusation gave them power they had never had in their lives.', 'public', '["servants","refugees","frontier","power","no_standing"]', 'salem_project', 1.0, NULL, 1775266565639, 1775266565639, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('prop_parris_firewood_crisis', 'Anti-Parris committee cuts firewood — Parris freezing during winter afflictions begin', 'The anti-Parris committee of October 1691 (Hutchinson, Porter, Andrew, Francis Nurse, Joseph Putnam) not only refused to collect salary taxes but also refused to provide firewood to heat either the church or the parsonage. During the winter of 1691-92 — the exact winter the afflictions began — Parris was potentially without adequate heating for his household. The man who would declare the village under satanic attack was himself under economic siege by the Porter faction.', '1691-12', 'month', 'economic', 'salary', NULL, 'samuel_parris', 'economic_interdependence_research.md', 'Anti-Parris committee cuts firewood — Parris freezing during winter afflictions begin. The anti-Parris committee of October 1691 (Hutchinson, Porter, Andrew, Francis Nurse, Joseph Putnam) not only refused to collect salary taxes but also refused to provide firewood to heat either the church or the parsonage. During the winter of 1691-92 — the exact winter the afflictions began — Parris was potentially without adequate heating for his household. The man who would declare the village under satanic attack was himself under economic siege by the Porter faction.', 'public', '["firewood","salary","freezing","economic_siege"]', 'salem_project', 1.0, NULL, 1775266565639, 1775266565639, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('prop_tax_1681_top_assessments', '1681 tax assessment — who was richest in the village', 'The December 27, 1681 tax assessment reveals the economic hierarchy: Lt. Thomas Putnam Sr. at 10-6-3 (highest, ~206 pence), Nathaniel Putnam at 9-10 (~190 pence), Lt. John Putnam at 8-0 (~160 pence), Thomas Fuller Sr. at 8-6, Peter Cloyce at 8-6, Joshua Rea at 7-7, George Flint and John Flint at 7-0 each, Joseph Hutchinson at 6-12-3. The Putnam family dominated the top of the tax rolls.', '1681-12-27', 'exact', 'economic', 'taxation', NULL, 'thomas_putnam_jr', 'economic_interdependence_research.md', '1681 tax assessment — who was richest in the village. The December 27, 1681 tax assessment reveals the economic hierarchy: Lt. Thomas Putnam Sr. at 10-6-3 (highest, ~206 pence), Nathaniel Putnam at 9-10 (~190 pence), Lt. John Putnam at 8-0 (~160 pence), Thomas Fuller Sr. at 8-6, Peter Cloyce at 8-6, Joshua Rea at 7-7, George Flint and John Flint at 7-0 each, Joseph Hutchinson at 6-12-3. The Putnam family dominated the top of the tax rolls.', 'public', '["tax","1681","top_assessments","economic_hierarchy"]', 'salem_project', 1.0, NULL, 1775266565639, 1775266565639, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('prop_tax_1681_putnam_jr_modest', 'Thomas Putnam Jr. assessed at only 2-14 — far below his father', 'While his father was assessed at 10-6-3 (highest in the village), Thomas Putnam Jr. was assessed at only 2-14 — a modest young farmer still building his estate. His brother John Jr. was also at 2-14. Edward Putnam was at 1-7, Jonathan Putnam at 1-6. Francis Nurse was at 1-8 (still building). The next generation of Putnams had not yet inherited their father''s wealth — and after the contested will, they never would.', '1681-12-27', 'exact', 'economic', 'taxation', NULL, 'thomas_putnam_jr', 'economic_interdependence_research.md', 'Thomas Putnam Jr. assessed at only 2-14 — far below his father. While his father was assessed at 10-6-3 (highest in the village), Thomas Putnam Jr. was assessed at only 2-14 — a modest young farmer still building his estate. His brother John Jr. was also at 2-14. Edward Putnam was at 1-7, Jonathan Putnam at 1-6. Francis Nurse was at 1-8 (still building). The next generation of Putnams had not yet inherited their father''s wealth — and after the contested will, they never would.', 'public', '["tax","1681","modest","downward_mobility"]', 'salem_project', 1.0, NULL, 1775266565639, 1775266565639, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('prop_tax_divide_pro_anti_parris', 'Anti-Parris families slightly wealthier — 15.82s mean vs 14.76s pro-Parris', 'Using the 1690 tax list, Boyer and Nissenbaum demonstrated: pro-Parris faction mean tax 14.76 shillings (38 individuals), anti-Parris faction mean tax 15.82 shillings (34 individuals). Both groups median 14.00 shillings. The difference is modest but consistent: anti-Parris families were slightly wealthier. The village''s highest taxpayers overwhelmingly opposed Parris; its poorest disproportionately supported him. The geographic pattern reinforced this: pro-Parris inland, anti-Parris along Ipswich Road.', '1690', 'year', 'economic', 'taxation', NULL, NULL, 'economic_interdependence_research.md', 'Anti-Parris families slightly wealthier — 15.82s mean vs 14.76s pro-Parris. Using the 1690 tax list, Boyer and Nissenbaum demonstrated: pro-Parris faction mean tax 14.76 shillings (38 individuals), anti-Parris faction mean tax 15.82 shillings (34 individuals). Both groups median 14.00 shillings. The difference is modest but consistent: anti-Parris families were slightly wealthier. The village''s highest taxpayers overwhelmingly opposed Parris; its poorest disproportionately supported him. The geographic pattern reinforced this: pro-Parris inland, anti-Parris along Ipswich Road.', 'public', '["tax","1690","faction_divide","wealthier_anti_parris"]', 'salem_project', 1.0, NULL, 1775266565639, 1775266565639, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('prop_harvest_labor_exchange', 'Harvest labor exchange — neighbors helping neighbors who later accused each other', 'Grain harvest was time-critical — a few days of rain could destroy a crop. Families exchanged labor during harvest, with neighbors helping each other bring in crops. This created debts of reciprocity: if Putnam helped Nurse bring in his rye, Nurse was expected to help Putnam. During the witch crisis, these bonds of mutual aid existed alongside the accusations. A man who helped you harvest your grain might also sign a warrant for your wife.', NULL, NULL, 'economic', 'communal', NULL, NULL, 'economic_interdependence_research.md', 'Harvest labor exchange — neighbors helping neighbors who later accused each other. Grain harvest was time-critical — a few days of rain could destroy a crop. Families exchanged labor during harvest, with neighbors helping each other bring in crops. This created debts of reciprocity: if Putnam helped Nurse bring in his rye, Nurse was expected to help Putnam. During the witch crisis, these bonds of mutual aid existed alongside the accusations. A man who helped you harvest your grain might also sign a warrant for your wife.', 'public', '["harvest","labor_exchange","reciprocity","paradox"]', 'salem_project', 1.0, NULL, 1775266565639, 1775266565639, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('prop_meetinghouse_communal_build', 'Salem Village meetinghouse built by community labor — Hutchinson donated the land', 'The Salem Village meetinghouse (voted November 1672, 34 feet long, 28 feet broad, 16 feet between joints) was built by community labor. Joseph Hutchinson donated one acre of meadowland for the site. The frame was oak post-and-beam construction, requiring many hands. Twenty years later, Hutchinson was on the anti-Parris committee that cut Parris''s salary. The man who donated the land for the meetinghouse opposed the minister who preached in it.', '1672-11', 'month', 'economic', 'communal', NULL, 'nathaniel_ingersoll', 'economic_interdependence_research.md', 'Salem Village meetinghouse built by community labor — Hutchinson donated the land. The Salem Village meetinghouse (voted November 1672, 34 feet long, 28 feet broad, 16 feet between joints) was built by community labor. Joseph Hutchinson donated one acre of meadowland for the site. The frame was oak post-and-beam construction, requiring many hands. Twenty years later, Hutchinson was on the anti-Parris committee that cut Parris''s salary. The man who donated the land for the meetinghouse opposed the minister who preached in it.', 'public', '["meetinghouse","communal_build","hutchinson","irony"]', 'salem_project', 1.0, NULL, 1775266565639, 1775266565639, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('prop_salem_town_wharves', 'Salem Town named wharves — English, Gedney, Hathorne, Corwin, Andrew', 'Salem harbor''s named wharves reveal who controlled maritime commerce: Philip English''s wharf (south harbor, largest), Gedney''s shipyard (Judge Gedney), Hathorne''s wharf (Judge Hathorne''s family), Corwin family wharf (Judge Corwin''s family), and Daniel Andrew''s new wharf on Frost Fish Brook (February 1692). The judges who tried the accused owned the wharves that profited from trade. The merchant class and the judicial class were the same people.', NULL, NULL, 'maritime', 'property', NULL, 'philip_english', 'salem_waterfront_trade_research.md', 'Salem Town named wharves — English, Gedney, Hathorne, Corwin, Andrew. Salem harbor''s named wharves reveal who controlled maritime commerce: Philip English''s wharf (south harbor, largest), Gedney''s shipyard (Judge Gedney), Hathorne''s wharf (Judge Hathorne''s family), Corwin family wharf (Judge Corwin''s family), and Daniel Andrew''s new wharf on Frost Fish Brook (February 1692). The judges who tried the accused owned the wharves that profited from trade. The merchant class and the judicial class were the same people.', 'public', '["wharves","named","judges_own_wharves","conflict_of_interest"]', 'salem_project', 1.0, NULL, 1775266565639, 1775266565639, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('abigail_hobbs_casco_bay', 'Abigail Hobbs had frontier ties — confession drew on Casco Bay imagery', 'Abigail Hobbs had ties to the frontier and had lived near Casco Bay. Her confession included vivid details that drew on frontier imagery — blending the wilderness terrors of the Maine frontier with the diabolical imagery expected by the court. The refugee presence in Salem Village meant people who had seen their worlds destroyed told their stories to neighbors whose own fears were being amplified by every telling.', '1692', 'year', 'biographical', 'background', NULL, 'abigail_hobbs', 'shared_traumas_research.md', 'Abigail Hobbs had frontier ties — confession drew on Casco Bay imagery. Abigail Hobbs had ties to the frontier and had lived near Casco Bay. Her confession included vivid details that drew on frontier imagery — blending the wilderness terrors of the Maine frontier with the diabolical imagery expected by the court. The refugee presence in Salem Village meant people who had seen their worlds destroyed told their stories to neighbors whose own fears were being amplified by every telling.', 'public', '["hobbs","casco_bay","frontier_imagery","confession"]', 'salem_project', 1.0, NULL, 1775266565639, 1775266565639, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('accused_abigail_barker', 'Abigail Barker accused — Andover group recantation signer', 'Abigail Barker (nee Wheeler) of Andover. Accused September 8, 1692 via touch test and afflicted girls. Part of the group of Andover women — including Mary Osgood, Eunice Frye, Deliverance Dane, Mary Tyler, and Sarah Wilson — who confessed under duress and later issued recantations through Increase Mather. Their neighbors testified they ''have not only lived among us so inoffensively as not to give the least occasion to any that know them to suspect them of witchcraft.'' Confessed. Released after trials ended. Signed group recantation.', '1692-09-08', NULL, 'legal', 'accused', NULL, NULL, 'ACCUSED_LIST.md', 'Abigail Barker accused — Andover group recantation signer. Abigail Barker (nee Wheeler) of Andover. Accused September 8, 1692 via touch test and afflicted girls. Part of the group of Andover women — including Mary Osgood, Eunice Frye, Deliverance Dane, Mary Tyler, and Sarah Wilson — who confessed under duress and later issued recantations through Increase Mather. Their neighbors testified they ''have not only lived among us so inoffensively as not to give the least occasion to any that know them to suspect them of witchcraft.'' Confessed. Released after trials ended. Signed group recantation.', 'public', '["accused","confessed","recanted","released","andover","touch_test","group_recantation"]', 'salem_project', 1.0, NULL, 1775266565639, 1775266565639, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('accused_abigail_faulkner_jr', 'Abigail Faulkner Jr. accused at age 9 — coerced against her mother', 'Abigail Faulkner Jr., age 9, of Andover. Younger daughter of Abigail Faulkner Sr. Accused September 16, 1692. Coerced alongside her 12-year-old sister Dorothy into testifying against their mother. The use of child testimony against parents was a recurring horror of the Andover proceedings. Confessed. Released after trials ended.', '1692-09-16', NULL, 'legal', 'accused', NULL, NULL, 'ACCUSED_LIST.md', 'Abigail Faulkner Jr. accused at age 9 — coerced against her mother. Abigail Faulkner Jr., age 9, of Andover. Younger daughter of Abigail Faulkner Sr. Accused September 16, 1692. Coerced alongside her 12-year-old sister Dorothy into testifying against their mother. The use of child testimony against parents was a recurring horror of the Andover proceedings. Confessed. Released after trials ended.', 'public', '["accused","confessed","released","andover","child_accused","coerced_against_parent","faulkner_family"]', 'salem_project', 1.0, NULL, 1775266565640, 1775266565640, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('accused_abigail_faulkner_sr', 'Abigail Faulkner Sr. accused — daughters coerced to condemn her', 'Abigail Faulkner Sr. of Andover, wife of Francis Faulkner, a prominent landowner. Accused August 11, 1692. Her daughters Dorothy (age 12) and Abigail Jr. (age 9) were also accused and coerced into condemning their own mother — one of the most disturbing episodes of the Andover crisis. Maintained her innocence throughout. Convicted and condemned to death September 17, 1692. Execution stayed due to pregnancy. Pardoned by Governor Phips. Released March 1693. Gave birth shortly after release. In 1703, she successfully petitioned to have her conviction reversed along with Elizabeth Proctor and Sarah Wardwell. A figure of extraordinary resilience.', '1692-08-11', NULL, 'legal', 'accused', NULL, NULL, 'ACCUSED_LIST.md', 'Abigail Faulkner Sr. accused — daughters coerced to condemn her. Abigail Faulkner Sr. of Andover, wife of Francis Faulkner, a prominent landowner. Accused August 11, 1692. Her daughters Dorothy (age 12) and Abigail Jr. (age 9) were also accused and coerced into condemning their own mother — one of the most disturbing episodes of the Andover crisis. Maintained her innocence throughout. Convicted and condemned to death September 17, 1692. Execution stayed due to pregnancy. Pardoned by Governor Phips. Released March 1693. Gave birth shortly after release. In 1703, she successfully petitioned to have her conviction reversed along with Elizabeth Proctor and Sarah Wardwell. A figure of extraordinary resilience.', 'public', '["accused","convicted","reprieved_pregnancy","pardoned","andover","children_coerced","conviction_reversed"]', 'salem_project', 1.0, NULL, 1775266565640, 1775266565640, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('accused_abigail_hobbs', 'Abigail Hobbs accused — confessed readily April 19', 'Abigail Hobbs of Topsfield/Casco Bay, Maine, accused April 18, 1692 by Mercy Lewis, Mary Walcott, and Ann Putnam Jr. A young woman with a reputation for wild behavior — known to have boasted about meeting the Devil in the woods. Had spent time in Falmouth (now Portland), Maine, before frontier attacks drove refugees south. Confessed readily on April 19, providing testimony naming additional accused. Her stepmother Deliverance Hobbs and father William Hobbs were also accused. Later testified against others at trial. Convicted September 17 but never executed as a confessor. Released after trials ended.', '1692-04-18', NULL, 'legal', 'accused', NULL, NULL, 'ACCUSED_LIST.md', 'Abigail Hobbs accused — confessed readily April 19. Abigail Hobbs of Topsfield/Casco Bay, Maine, accused April 18, 1692 by Mercy Lewis, Mary Walcott, and Ann Putnam Jr. A young woman with a reputation for wild behavior — known to have boasted about meeting the Devil in the woods. Had spent time in Falmouth (now Portland), Maine, before frontier attacks drove refugees south. Confessed readily on April 19, providing testimony naming additional accused. Her stepmother Deliverance Hobbs and father William Hobbs were also accused. Later testified against others at trial. Convicted September 17 but never executed as a confessor. Released after trials ended.', 'public', '["accused","confessed","topsfield","maine_frontier","family_cluster"]', 'salem_project', 1.0, NULL, 1775266565640, 1775266565640, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('accused_abigail_johnson', 'Abigail Johnson accused — Andover Johnson family cluster', 'Abigail Johnson of Andover. Accused circa August 29, 1692 by Moses Tyler and afflicted girls. Part of the Johnson family cluster in Andover. Multiple Johnsons — Elizabeth Sr., Elizabeth Jr., Abigail, Stephen, and Rebecca — were accused. Confessed. Released after trials ended.', '1692-08-29', NULL, 'legal', 'accused', NULL, NULL, 'ACCUSED_LIST.md', 'Abigail Johnson accused — Andover Johnson family cluster. Abigail Johnson of Andover. Accused circa August 29, 1692 by Moses Tyler and afflicted girls. Part of the Johnson family cluster in Andover. Multiple Johnsons — Elizabeth Sr., Elizabeth Jr., Abigail, Stephen, and Rebecca — were accused. Confessed. Released after trials ended.', 'public', '["accused","confessed","released","andover","johnson_family"]', 'salem_project', 1.0, NULL, 1775266565640, 1775266565640, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('accused_abigail_rowe', 'Abigail Rowe accused at age 15 — last batch of formal accusations', 'Abigail Rowe, age 15, of Gloucester. Accused November 5, 1692 by James Stevens (same complaint as Dike and Elwell) and afflicted girls. Daughter of Mary Rowe (also accused). The youngest of the Gloucester accused. The last documented batch of formal accusations in the Salem crisis. Never tried. Released.', '1692-11-05', NULL, 'legal', 'accused', NULL, NULL, 'ACCUSED_LIST.md', 'Abigail Rowe accused at age 15 — last batch of formal accusations. Abigail Rowe, age 15, of Gloucester. Accused November 5, 1692 by James Stevens (same complaint as Dike and Elwell) and afflicted girls. Daughter of Mary Rowe (also accused). The youngest of the Gloucester accused. The last documented batch of formal accusations in the Salem crisis. Never tried. Released.', 'public', '["accused","released","gloucester","child_accused","last_accusations","mother_daughter"]', 'salem_project', 1.0, NULL, 1775266565640, 1775266565640, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('accused_abigail_soames', 'Abigail Soames accused — Salem Town resident', 'Abigail Soames, resident of Salem Town. Accused May 13, 1692. Imprisoned at Salem jail. Little documented beyond her Salem Town residence.', '1692-05-13', NULL, 'legal', 'accused', NULL, NULL, 'salem_town_residents_research.md', 'Abigail Soames accused — Salem Town resident. Abigail Soames, resident of Salem Town. Accused May 13, 1692. Imprisoned at Salem jail. Little documented beyond her Salem Town residence.', 'public', '["accused","imprisoned","salem_town"]', 'salem_project', 1.0, NULL, 1775266565640, 1775266565640, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('accused_alice_parker', 'Alice Parker — Executed by hanging, September 22, 1692', 'Alice Parker of Salem Town, wife of John Parker, a Salem fisherman. Accused May 12, 1692 by Mary Warren (who named her during jailhouse examination), Margaret Jacobs; later Mary Walcott, Ann Putnam Jr., and others. Neighbors testified that Parker had bewitched Thomas Westgate, causing his illness, and that she had used image magic. Examined again September 6. Tried September 9, found guilty. Hanged September 22, 1692.', '1692-05-12', NULL, 'legal', 'accused', NULL, NULL, 'research/ACCUSED_LIST.md', 'Alice Parker — Executed by hanging, September 22, 1692. Alice Parker of Salem Town, wife of John Parker, a Salem fisherman. Accused May 12, 1692 by Mary Warren (who named her during jailhouse examination), Margaret Jacobs; later Mary Walcott, Ann Putnam Jr., and others. Neighbors testified that Parker had bewitched Thomas Westgate, causing his illness, and that she had used image magic. Examined again September 6. Tried September 9, found guilty. Hanged September 22, 1692.', 'public', '["accused","executed","salem_town","hanged_sep_22"]', 'salem_project', 1.0, NULL, 1775266565640, 1775266565640, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('accused_ann_dolliver', 'Ann Dolliver accused — daughter of magistrate Rev. John Higginson', 'Ann Dolliver (nee Higginson) of Gloucester (some records say Salem). Accused circa September 1692 by afflicted girls. Daughter of Rev. John Higginson of Salem, who was one of the magistrates involved in the examinations. Her father''s involvement makes her accusation especially significant: the crisis was beginning to consume its own architects. Described as ''crazed in her understanding'' — mentally unwell. Abandoned by her husband; her children were apprenticed. Released. Never tried.', '1692-09-15', NULL, 'legal', 'accused', NULL, NULL, 'ACCUSED_LIST.md', 'Ann Dolliver accused — daughter of magistrate Rev. John Higginson. Ann Dolliver (nee Higginson) of Gloucester (some records say Salem). Accused circa September 1692 by afflicted girls. Daughter of Rev. John Higginson of Salem, who was one of the magistrates involved in the examinations. Her father''s involvement makes her accusation especially significant: the crisis was beginning to consume its own architects. Described as ''crazed in her understanding'' — mentally unwell. Abandoned by her husband; her children were apprenticed. Released. Never tried.', 'public', '["accused","released","gloucester","magistrates_daughter","crisis_consuming_architects"]', 'salem_project', 1.0, NULL, 1775266565640, 1775266565640, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('accused_ann_foster', 'Ann Foster accused — triggered Andover chain reaction, died in prison', 'Ann Foster, elderly widow of Andover, approximately 75 years old. Accused circa July 15, 1692 by Joseph Ballard and the afflicted girls. Examined repeatedly beginning July 15. Under intense pressure, she confessed, describing a ride on a pole with Martha Carrier to a witches'' meeting in Salem Village. Her confession implicated her daughter Mary Lacey Sr. and Martha Carrier. The confession of three generations of this family (Foster, daughter Mary Lacey Sr., granddaughter Mary Lacey Jr.) accelerated the Andover witch hunt dramatically. Convicted and condemned September 17. Died in Salem jail December 3, 1692, after 21 weeks of imprisonment. Never executed, but never freed.', '1692-07-15', NULL, 'legal', 'accused', NULL, NULL, 'ACCUSED_LIST.md', 'Ann Foster accused — triggered Andover chain reaction, died in prison. Ann Foster, elderly widow of Andover, approximately 75 years old. Accused circa July 15, 1692 by Joseph Ballard and the afflicted girls. Examined repeatedly beginning July 15. Under intense pressure, she confessed, describing a ride on a pole with Martha Carrier to a witches'' meeting in Salem Village. Her confession implicated her daughter Mary Lacey Sr. and Martha Carrier. The confession of three generations of this family (Foster, daughter Mary Lacey Sr., granddaughter Mary Lacey Jr.) accelerated the Andover witch hunt dramatically. Convicted and condemned September 17. Died in Salem jail December 3, 1692, after 21 weeks of imprisonment. Never executed, but never freed.', 'public', '["accused","confessed","died_in_prison","andover","andover_catalyst","three_generations"]', 'salem_project', 1.0, NULL, 1775266565640, 1775266565640, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('accused_ann_pudeator', 'Ann Pudeator — Executed by hanging, September 22, 1692', 'Ann Pudeator of Salem Town, a wealthy widow approximately 70 years old who worked as a nurse and midwife. Her first husband Thomas Greenslett died in Falmouth, Maine; she later married blacksmith Jacob Pudeator (20 years younger), who died in 1682. Accused May 12, 1692 by Mary Warren and Sarah Churchill; later Mary Walcott, Mercy Lewis, and other afflicted girls. Mary Warren claimed Pudeator''s specter gave her poppets in jail, told her to torment others, killed both her husbands, and threw John Turner from a cherry tree. Some of Pudeator''s medical supplies (foot ointments) were confiscated and presented as occult objects. Tried September 9, found guilty. Hanged September 22, 1692.', '1692-05-12', NULL, 'legal', 'accused', NULL, NULL, 'research/ACCUSED_LIST.md', 'Ann Pudeator — Executed by hanging, September 22, 1692. Ann Pudeator of Salem Town, a wealthy widow approximately 70 years old who worked as a nurse and midwife. Her first husband Thomas Greenslett died in Falmouth, Maine; she later married blacksmith Jacob Pudeator (20 years younger), who died in 1682. Accused May 12, 1692 by Mary Warren and Sarah Churchill; later Mary Walcott, Mercy Lewis, and other afflicted girls. Mary Warren claimed Pudeator''s specter gave her poppets in jail, told her to torment others, killed both her husbands, and threw John Turner from a cherry tree. Some of Pudeator''s medical supplies (foot ointments) were confiscated and presented as occult objects. Tried September 9, found guilty. Hanged September 22, 1692.', 'public', '["accused","executed","salem_town","hanged_sep_22","midwife"]', 'salem_project', 1.0, NULL, 1775266565640, 1775266565640, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('accused_ann_sears', 'Ann Sears accused — Woburn cluster linked to Dustin family', 'Ann Sears (also rendered Ann Stearns) of Woburn, Massachusetts. Accused late April 1692 in connection with the Reading/Woburn cluster of accusations linked to the Dustin family. Her case received less documentation than others. Eventually released without trial. Survived.', '1692-04-28', NULL, 'legal', 'accused', NULL, NULL, 'ACCUSED_LIST.md', 'Ann Sears accused — Woburn cluster linked to Dustin family. Ann Sears (also rendered Ann Stearns) of Woburn, Massachusetts. Accused late April 1692 in connection with the Reading/Woburn cluster of accusations linked to the Dustin family. Her case received less documentation than others. Eventually released without trial. Survived.', 'public', '["accused","released","woburn","dustin_cluster"]', 'salem_project', 1.0, NULL, 1775266565640, 1775266565640, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('accused_arthur_abbott', 'Arthur Abbott accused — Ipswich area resident', 'Arthur Abbott, described as living ''in a by place something neare Maj. Appleton''s Farm'' in the Ipswich area. Accused May 28, 1692, ''complained of by many'' according to the mass complaint (SWP No. 165). One of eleven persons listed in the same complaint. Released. No trial record survives.', '1692-05-28', NULL, 'legal', 'accused', NULL, NULL, 'ACCUSED_LIST.md', 'Arthur Abbott accused — Ipswich area resident. Arthur Abbott, described as living ''in a by place something neare Maj. Appleton''s Farm'' in the Ipswich area. Accused May 28, 1692, ''complained of by many'' according to the mass complaint (SWP No. 165). One of eleven persons listed in the same complaint. Released. No trial record survives.', 'public', '["accused","released","ipswich","may_28_wave"]', 'salem_project', 1.0, NULL, 1775266565640, 1775266565640, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('accused_benjamin_proctor', 'Benjamin Proctor accused — another Proctor family member', 'Benjamin Proctor of Salem Village (Salem Farms), son of John Proctor (hanged August 19) and Elizabeth Proctor (convicted but reprieved due to pregnancy). Accused May 23, 1692 by afflicted girls. Another member of the Proctor family drawn into the accusations — his father, mother, and brother William were all accused. Released. Never tried. Survived.', '1692-05-23', NULL, 'legal', 'accused', NULL, NULL, 'ACCUSED_LIST.md', 'Benjamin Proctor accused — another Proctor family member. Benjamin Proctor of Salem Village (Salem Farms), son of John Proctor (hanged August 19) and Elizabeth Proctor (convicted but reprieved due to pregnancy). Accused May 23, 1692 by afflicted girls. Another member of the Proctor family drawn into the accusations — his father, mother, and brother William were all accused. Released. Never tried. Survived.', 'public', '["accused","released","salem_village","proctor_family"]', 'salem_project', 1.0, NULL, 1775266565640, 1775266565640, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('accused_bethia_carter_sr_jr', 'Bethia Carter Sr. and Jr. accused — Woburn mother-daughter pair', 'Bethia Carter Sr. and Bethia Carter Jr. (mother and daughter) of Woburn, Massachusetts. Accused late April/early May 1692, connected to the Reading/Woburn cluster linked to the Dustin accusations. Their cases illustrate how accusations radiated outward from Salem Village along social and geographic networks. Both imprisoned. Both released. Survived.', '1692-04-30', NULL, 'legal', 'accused', NULL, NULL, 'ACCUSED_LIST.md', 'Bethia Carter Sr. and Jr. accused — Woburn mother-daughter pair. Bethia Carter Sr. and Bethia Carter Jr. (mother and daughter) of Woburn, Massachusetts. Accused late April/early May 1692, connected to the Reading/Woburn cluster linked to the Dustin accusations. Their cases illustrate how accusations radiated outward from Salem Village along social and geographic networks. Both imprisoned. Both released. Survived.', 'public', '["accused","released","woburn","mother_daughter","dustin_cluster"]', 'salem_project', 1.0, NULL, 1775266565640, 1775266565640, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('accused_bridget_bishop', 'Bridget Bishop — First executed, hanged June 10, 1692', 'Bridget Bishop (nee Playfer; previously Oliver) of Salem Town, approximately 60, owner of an unlicensed tavern/ordinary where cider and games (including shovelboard) were available. Accused April 18 by Ann Putnam Jr., Mercy Lewis, Abigail Williams, Mary Walcott, Elizabeth Hubbard; complaint filed by Thomas Putnam and Ezekiel Cheever. She dressed flamboyantly by Puritan standards (a ''red paragon bodice''). Had been accused of witchcraft once before (1680) and acquitted. Workers repairing her cellar wall testified they found ''poppets'' (dolls with pins) in the walls. Tried first by the Court of Oyer and Terminer on June 2, convicted the same day. Hanged June 10, 1692 — the first person executed in the Salem trials. Her execution prompted Judge Nathaniel Saltonstall to resign from the court in protest. NOTE: Distinct from Sarah Bishop, wife of Edward Bishop Jr.', '1692-04-18', NULL, 'legal', 'accused', NULL, 'npc_bridget_bishop', 'research/ACCUSED_LIST.md', 'Bridget Bishop — First executed, hanged June 10, 1692. Bridget Bishop (nee Playfer; previously Oliver) of Salem Town, approximately 60, owner of an unlicensed tavern/ordinary where cider and games (including shovelboard) were available. Accused April 18 by Ann Putnam Jr., Mercy Lewis, Abigail Williams, Mary Walcott, Elizabeth Hubbard; complaint filed by Thomas Putnam and Ezekiel Cheever. She dressed flamboyantly by Puritan standards (a ''red paragon bodice''). Had been accused of witchcraft once before (1680) and acquitted. Workers repairing her cellar wall testified they found ''poppets'' (dolls with pins) in the walls. Tried first by the Court of Oyer and Terminer on June 2, convicted the same day. Hanged June 10, 1692 — the first person executed in the Salem trials. Her execution prompted Judge Nathaniel Saltonstall to resign from the court in protest. NOTE: Distinct from Sarah Bishop, wife of Edward Bishop Jr.', 'public', '["accused","executed","salem_town","hanged_june_10","first_executed"]', 'salem_project', 1.0, NULL, 1775266565640, 1775266565640, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('accused_candy', 'Candy accused — enslaved Barbadian woman turned tables on owner', 'Candy (also Kandy), enslaved woman of Barbadian origin, owned by Margaret Hawkes of Salem Town. Accused by Ann Putnam Jr., Mary Walcott, and Mary Warren. Examined July 4, 1692. Admitted to being a witch but strategically turned on her enslaver, claiming Margaret Hawkes had made her a witch and forced her to sign the Devil''s book. A deputy escorted her home, where she returned with rags and herbs acting as poppets. Her strategic confession — blaming her mistress — showed remarkable sophistication in navigating the court''s expectations. Indicted January 1693 by the Superior Court. Found not guilty and released.', '1692-07-01', NULL, 'legal', 'accused', NULL, NULL, 'ACCUSED_LIST.md', 'Candy accused — enslaved Barbadian woman turned tables on owner. Candy (also Kandy), enslaved woman of Barbadian origin, owned by Margaret Hawkes of Salem Town. Accused by Ann Putnam Jr., Mary Walcott, and Mary Warren. Examined July 4, 1692. Admitted to being a witch but strategically turned on her enslaver, claiming Margaret Hawkes had made her a witch and forced her to sign the Devil''s book. A deputy escorted her home, where she returned with rags and herbs acting as poppets. Her strategic confession — blaming her mistress — showed remarkable sophistication in navigating the court''s expectations. Indicted January 1693 by the Superior Court. Found not guilty and released.', 'public', '["accused","acquitted","enslaved","salem_town","barbadian","strategic_confession"]', 'salem_project', 1.0, NULL, 1775266565640, 1775266565640, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('accused_captain_john_alden', 'Captain John Alden Jr. — Escaped from prison, survived', 'Captain John Alden Jr. of Boston, approximately 66, son of John and Priscilla Alden of the Mayflower. Prosperous Boston sea captain and merchant, one of the most prominent persons accused. He came to Salem Village voluntarily after receiving a summons. Examined May 31, 1692 by Hathorne, Corwin, and Gedney. Accused by Mary Walcott, Mercy Lewis, Abigail Williams, Ann Putnam Jr., Susannah Sheldon. At his examination, one accuser initially pointed at Captain Hill (wrong man) before being corrected by someone standing behind her. Alden later wrote a scathing account describing the accusers as ''a company of poor distracted, or possessed creatures'' and noting an accuser was prompted by a man behind her. Imprisoned 15 weeks in Boston jail. Escaped mid-September 1692, possibly hiding in Duxbury (family home). Did not return until after the trials ended.', '1692-05-31', NULL, 'legal', 'accused', NULL, 'npc_capt_john_alden', 'research/ACCUSED_LIST.md', 'Captain John Alden Jr. — Escaped from prison, survived. Captain John Alden Jr. of Boston, approximately 66, son of John and Priscilla Alden of the Mayflower. Prosperous Boston sea captain and merchant, one of the most prominent persons accused. He came to Salem Village voluntarily after receiving a summons. Examined May 31, 1692 by Hathorne, Corwin, and Gedney. Accused by Mary Walcott, Mercy Lewis, Abigail Williams, Ann Putnam Jr., Susannah Sheldon. At his examination, one accuser initially pointed at Captain Hill (wrong man) before being corrected by someone standing behind her. Alden later wrote a scathing account describing the accusers as ''a company of poor distracted, or possessed creatures'' and noting an accuser was prompted by a man behind her. Imprisoned 15 weeks in Boston jail. Escaped mid-September 1692, possibly hiding in Duxbury (family home). Did not return until after the trials ended.', 'public', '["accused","escaped","boston","mayflower_descendant","sea_captain"]', 'salem_project', 1.0, NULL, 1775266565640, 1775266565640, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('accused_captain_john_flood', 'Captain John Flood accused — military captain and Indian fighter', 'Captain John Flood (Floyd) of Rumney Marsh (now Chelsea/Revere). Accused May 28, 1692 by Mary Walcott, Abigail Williams, and others. Military captain and Indian fighter. Served in Governor Andros''s 1688 expedition, commanded a post on the Saco River in 1689, and was made captain of a troop at Portsmouth in 1690. His military service on the Maine frontier, involving contact with Indians, likely made him a target — several afflicted girls had been orphaned during Indian attacks in Maine. No examination records survive. Released; apparently never formally examined or indicted.', '1692-05-28', NULL, 'legal', 'accused', NULL, NULL, 'ACCUSED_LIST.md', 'Captain John Flood accused — military captain and Indian fighter. Captain John Flood (Floyd) of Rumney Marsh (now Chelsea/Revere). Accused May 28, 1692 by Mary Walcott, Abigail Williams, and others. Military captain and Indian fighter. Served in Governor Andros''s 1688 expedition, commanded a post on the Saco River in 1689, and was made captain of a troop at Portsmouth in 1690. His military service on the Maine frontier, involving contact with Indians, likely made him a target — several afflicted girls had been orphaned during Indian attacks in Maine. No examination records survive. Released; apparently never formally examined or indicted.', 'public', '["accused","released","rumney_marsh","military","frontier_connection"]', 'salem_project', 1.0, NULL, 1775266565640, 1775266565640, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('accused_daniel_andrew', 'Daniel Andrew — Evaded arrest, never apprehended', 'Daniel Andrew of Salem Village, brother-in-law of Rebecca Jacobs and George Jacobs Jr. A sought-after bricklayer and craftsman, married to Sarah Porter (sister of Joseph, Israel, and Benjamin Porter), and the fourth richest man in the village by 1695. Member of the anti-Parris October 1691 village committee that refused to pay Parris''s salary. Elected Salem Town selectman in April 1692. Warrant issued May 14, 1692 by afflicted girls, but Andrew evaded arrest and was never apprehended during the trials.', '1692-05-14', NULL, 'legal', 'accused', NULL, NULL, 'research/ACCUSED_LIST.md', 'Daniel Andrew — Evaded arrest, never apprehended. Daniel Andrew of Salem Village, brother-in-law of Rebecca Jacobs and George Jacobs Jr. A sought-after bricklayer and craftsman, married to Sarah Porter (sister of Joseph, Israel, and Benjamin Porter), and the fourth richest man in the village by 1695. Member of the anti-Parris October 1691 village committee that refused to pay Parris''s salary. Elected Salem Town selectman in April 1692. Warrant issued May 14, 1692 by afflicted girls, but Andrew evaded arrest and was never apprehended during the trials.', 'public', '["accused","evaded_arrest","salem_village","anti_parris_committee","porter_faction"]', 'salem_project', 1.0, NULL, 1775266565641, 1775266565641, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('accused_deliverance_dane', 'Deliverance Dane accused — Andover touch test group', 'Deliverance Dane (nee Haseltine) of Andover. Accused circa September 1692 via touch test and afflicted girls. Part of the Andover group recantation. Confessed. Released after trials ended. Signed group recantation. Her story was later fictionalized in Katherine Howe''s 2009 novel The Physick Book of Deliverance Dane.', '1692-09-08', NULL, 'legal', 'accused', NULL, NULL, 'ACCUSED_LIST.md', 'Deliverance Dane accused — Andover touch test group. Deliverance Dane (nee Haseltine) of Andover. Accused circa September 1692 via touch test and afflicted girls. Part of the Andover group recantation. Confessed. Released after trials ended. Signed group recantation. Her story was later fictionalized in Katherine Howe''s 2009 novel The Physick Book of Deliverance Dane.', 'public', '["accused","confessed","recanted","released","andover","touch_test","group_recantation"]', 'salem_project', 1.0, NULL, 1775266565641, 1775266565641, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('accused_deliverance_hobbs', 'Deliverance Hobbs accused — key witness at Nurse trial', 'Deliverance Hobbs, wife of William Hobbs and stepmother of Abigail Hobbs, of Topsfield. Accused April 18-21, 1692. Confessed April 22 and became a key witness. Her testimony at Rebecca Nurse''s trial produced the ambiguous moment that led to the jury''s reversal: when Hobbs took the stand, Nurse said ''What, do these persons give in evidence against me now? They used to come among us.'' The jury interpreted ''come among us'' as an admission of attending witch meetings; Nurse later explained she meant Hobbs had been a fellow prisoner. The jury foreman Thomas Fisk asked for clarification; Nurse, partially deaf, did not respond, and Stoughton instructed the jury to reconsider. They reversed the not-guilty verdict.', '1692-04-21', NULL, 'legal', 'accused', NULL, NULL, 'ACCUSED_LIST.md', 'Deliverance Hobbs accused — key witness at Nurse trial. Deliverance Hobbs, wife of William Hobbs and stepmother of Abigail Hobbs, of Topsfield. Accused April 18-21, 1692. Confessed April 22 and became a key witness. Her testimony at Rebecca Nurse''s trial produced the ambiguous moment that led to the jury''s reversal: when Hobbs took the stand, Nurse said ''What, do these persons give in evidence against me now? They used to come among us.'' The jury interpreted ''come among us'' as an admission of attending witch meetings; Nurse later explained she meant Hobbs had been a fellow prisoner. The jury foreman Thomas Fisk asked for clarification; Nurse, partially deaf, did not respond, and Stoughton instructed the jury to reconsider. They reversed the not-guilty verdict.', 'public', '["accused","confessed","topsfield","nurse_trial","key_witness","family_cluster"]', 'salem_project', 1.0, NULL, 1775266565641, 1775266565641, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('accused_dorcas_good', 'Dorcas Good — Imprisoned age 4-5, permanently damaged', 'Dorcas Good (also Dorothy Good), daughter of Sarah Good and William Good, was 4 or 5 years old at the time of her arrest — the youngest person imprisoned during the trials. Named by Ann Putnam Jr., Mercy Lewis, Mary Walcott; complaint filed March 23 by Edward Putnam and Jonathan Putnam. Examined March 24 by Hathorne and Corwin, she reportedly ''confessed'' to having a familiar (a small snake that sucked on her finger). Examiners found a red mark on her finger as evidence. Held in chains in Boston jail for 7-8 months. Released on bond December 10, 1692. Never tried. Her father later petitioned: she ''was in prison seven or eight months and being chain''d in the dungeon was so hardly used and terrified that she hath ever since been very chargeable, having little or no reason to govern herself.'' Permanently psychologically damaged.', '1692-03-23', NULL, 'legal', 'accused', NULL, 'npc_dorcas_good', 'research/ACCUSED_LIST.md', 'Dorcas Good — Imprisoned age 4-5, permanently damaged. Dorcas Good (also Dorothy Good), daughter of Sarah Good and William Good, was 4 or 5 years old at the time of her arrest — the youngest person imprisoned during the trials. Named by Ann Putnam Jr., Mercy Lewis, Mary Walcott; complaint filed March 23 by Edward Putnam and Jonathan Putnam. Examined March 24 by Hathorne and Corwin, she reportedly ''confessed'' to having a familiar (a small snake that sucked on her finger). Examiners found a red mark on her finger as evidence. Held in chains in Boston jail for 7-8 months. Released on bond December 10, 1692. Never tried. Her father later petitioned: she ''was in prison seven or eight months and being chain''d in the dungeon was so hardly used and terrified that she hath ever since been very chargeable, having little or no reason to govern herself.'' Permanently psychologically damaged.', 'public', '["accused","imprisoned","salem_village","child_accused"]', 'salem_project', 1.0, NULL, 1775266565641, 1775266565641, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('accused_dorcas_hoar', 'Dorcas Hoar accused — confessed night before execution to survive', 'Dorcas Hoar, wife of William Hoar of Beverly. Had a longstanding reputation as a fortune-teller. Neighbors testified she predicted the death of her husband (who died under suspicious circumstances). Examined May 2, 1692. Tried September 9, 1692; found guilty and sentenced to death. Confessed the night before her scheduled execution on September 21. Reverends John Hale and Nicholas Noyes petitioned Chief Justice Stoughton for a one-month reprieve, which was granted. By the time a month passed, the Court of Oyer and Terminer had been dissolved. Released from prison March 1693. One of very few who confessed after conviction to save their life.', '1692-04-30', NULL, 'legal', 'accused', NULL, NULL, 'ACCUSED_LIST.md', 'Dorcas Hoar accused — confessed night before execution to survive. Dorcas Hoar, wife of William Hoar of Beverly. Had a longstanding reputation as a fortune-teller. Neighbors testified she predicted the death of her husband (who died under suspicious circumstances). Examined May 2, 1692. Tried September 9, 1692; found guilty and sentenced to death. Confessed the night before her scheduled execution on September 21. Reverends John Hale and Nicholas Noyes petitioned Chief Justice Stoughton for a one-month reprieve, which was granted. By the time a month passed, the Court of Oyer and Terminer had been dissolved. Released from prison March 1693. One of very few who confessed after conviction to save their life.', 'public', '["accused","convicted","confessed","reprieved","beverly","fortune_teller"]', 'salem_project', 1.0, NULL, 1775266565641, 1775266565641, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('accused_dorothy_faulkner', 'Dorothy Faulkner accused at age 12 — coerced to condemn her mother', 'Dorothy Faulkner, age 12, of Andover. Daughter of Abigail Faulkner Sr. Accused September 17, 1692. Arrested one day after her 9-year-old sister Abigail Jr. The children were ''persuaded'' to condemn their own mother as a witch — one of the most disturbing episodes of the Andover crisis. Confessed. Released after trials ended.', '1692-09-17', NULL, 'legal', 'accused', NULL, NULL, 'ACCUSED_LIST.md', 'Dorothy Faulkner accused at age 12 — coerced to condemn her mother. Dorothy Faulkner, age 12, of Andover. Daughter of Abigail Faulkner Sr. Accused September 17, 1692. Arrested one day after her 9-year-old sister Abigail Jr. The children were ''persuaded'' to condemn their own mother as a witch — one of the most disturbing episodes of the Andover crisis. Confessed. Released after trials ended.', 'public', '["accused","confessed","released","andover","child_accused","coerced_against_parent","faulkner_family"]', 'salem_project', 1.0, NULL, 1775266565641, 1775266565641, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('accused_dudley_bradstreet', 'Dudley Bradstreet — JP who refused to issue warrants, accused and fled', 'Dudley Bradstreet, Justice of the Peace in Andover who had issued ~30 arrest warrants. After the mass touch test at Andover meetinghouse September 7, he refused to issue more. The afflicted girls immediately accused him. He and his wife fled and were not apprehended.', '1692-09-07', NULL, 'legal', 'accused', NULL, NULL, 'accused_list_part1-3.md', 'Dudley Bradstreet — JP who refused to issue warrants, accused and fled. Dudley Bradstreet, Justice of the Peace in Andover who had issued ~30 arrest warrants. After the mass touch test at Andover meetinghouse September 7, he refused to issue more. The afflicted girls immediately accused him. He and his wife fled and were not apprehended.', 'public', '["accused","escaped","andover","justice_of_peace","refused_warrants"]', 'salem_project', 1.0, NULL, 1775266565641, 1775266565641, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('accused_edward_bishop_jr_sarah_bishop', 'Edward and Sarah Bishop Jr. accused — escaped from Ipswich jail', 'Edward Bishop Jr. and his wife Sarah Bishop of Salem Village, accused April 21, 1692. Edward operated the tavern/ordinary adjacent to the meetinghouse. Both imprisoned. Both escaped from Ipswich jail and fled the jurisdiction, hiding with relatives outside the area until the crisis ended. Sarah Bishop has been historically confused with Bridget Bishop — they are different people. Returned after the trials ended. Survived.', '1692-04-21', NULL, 'legal', 'accused', NULL, NULL, 'ACCUSED_LIST.md', 'Edward and Sarah Bishop Jr. accused — escaped from Ipswich jail. Edward Bishop Jr. and his wife Sarah Bishop of Salem Village, accused April 21, 1692. Edward operated the tavern/ordinary adjacent to the meetinghouse. Both imprisoned. Both escaped from Ipswich jail and fled the jurisdiction, hiding with relatives outside the area until the crisis ended. Sarah Bishop has been historically confused with Bridget Bishop — they are different people. Returned after the trials ended. Survived.', 'public', '["accused","escaped","salem_village","tavern_keeper","couple"]', 'salem_project', 1.0, NULL, 1775266565641, 1775266565641, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('accused_edward_bishop_sr_sarah_bishop_sr', 'Edward and Sarah Bishop Sr. accused — parents of Jr.', 'Edward Bishop Sr. and Sarah Bishop Sr. of Salem Village, accused April 21-22, 1692. Parents of Edward Bishop Jr. (also accused). Their involvement shows how accusations cascaded through families. Sarah Bishop Sr. had performed folk healing — a ''touch test'' on one of the afflicted — which brought suspicion upon her. Both imprisoned. Released after the trials. Survived.', '1692-04-22', NULL, 'legal', 'accused', NULL, NULL, 'ACCUSED_LIST.md', 'Edward and Sarah Bishop Sr. accused — parents of Jr.. Edward Bishop Sr. and Sarah Bishop Sr. of Salem Village, accused April 21-22, 1692. Parents of Edward Bishop Jr. (also accused). Their involvement shows how accusations cascaded through families. Sarah Bishop Sr. had performed folk healing — a ''touch test'' on one of the afflicted — which brought suspicion upon her. Both imprisoned. Released after the trials. Survived.', 'public', '["accused","released","salem_village","family_cluster","folk_healing"]', 'salem_project', 1.0, NULL, 1775266565641, 1775266565641, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('accused_edward_farrington', 'Edward Farrington accused — escaped from custody', 'Edward Farrington of Lynn (born July 5, 1662). Accused probable June-July 1692 by Mary Warren. One of several accused who broke out of custody. Escaped from prison between September 12-16, 1692, as conditions in overcrowded jails deteriorated. Never tried. One of several accused who fled rather than face the court.', '1692-07-01', NULL, 'legal', 'accused', NULL, NULL, 'ACCUSED_LIST.md', 'Edward Farrington accused — escaped from custody. Edward Farrington of Lynn (born July 5, 1662). Accused probable June-July 1692 by Mary Warren. One of several accused who broke out of custody. Escaped from prison between September 12-16, 1692, as conditions in overcrowded jails deteriorated. Never tried. One of several accused who fled rather than face the court.', 'public', '["accused","escaped","lynn","prison_break"]', 'salem_project', 1.0, NULL, 1775266565641, 1775266565641, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('accused_elizabeth_cary', 'Elizabeth Cary accused — wealthy Charlestown captain''s wife escaped', 'Elizabeth Cary, wife of Captain Nathaniel Cary, a wealthy Charlestown ship captain. Accused May 28, 1692 by Mary Walcott, Abigail Williams, and Mercy Lewis. John Indian testified against her. Her examination included the ''touch test'' — afflicted girls who went into fits recovered when touched by the accused. Captain Cary was outraged and tried legally to move the trial to Charlestown without success. Imprisoned in Boston, then Cambridge. Escaped with her husband''s help — they fled first to Rhode Island, then to New York, aided by Rev. Joshua Moody and Rev. Samuel Willard. Returned to Charlestown after the trials ended.', '1692-05-28', NULL, 'legal', 'accused', NULL, NULL, 'ACCUSED_LIST.md', 'Elizabeth Cary accused — wealthy Charlestown captain''s wife escaped. Elizabeth Cary, wife of Captain Nathaniel Cary, a wealthy Charlestown ship captain. Accused May 28, 1692 by Mary Walcott, Abigail Williams, and Mercy Lewis. John Indian testified against her. Her examination included the ''touch test'' — afflicted girls who went into fits recovered when touched by the accused. Captain Cary was outraged and tried legally to move the trial to Charlestown without success. Imprisoned in Boston, then Cambridge. Escaped with her husband''s help — they fled first to Rhode Island, then to New York, aided by Rev. Joshua Moody and Rev. Samuel Willard. Returned to Charlestown after the trials ended.', 'public', '["accused","escaped","charlestown","wealthy","touch_test"]', 'salem_project', 1.0, NULL, 1775266565641, 1775266565641, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('accused_elizabeth_colson', 'Elizabeth Colson accused — fled to Boston, never captured', 'Elizabeth Colson, single woman of Reading. Warrant issued May 14, 1692, accused by Mary Walcott, Mercy Lewis, and Susannah Sheldon. Constable John Parker reported she ''is fled'' and believed to be in Boston ''in order to bee shipt ofe'' (shipped off). A second warrant was issued May 17, directed to authorities in Boston and Charlestown. A September follow-up noted she remained ''concealed in Bostine.'' One witness described her running away, falling and rising repeatedly, then vanishing near bushes — followed by the appearance of a large cat that also disappeared. Apparently never apprehended during the main trials. Escaped.', '1692-05-14', NULL, 'legal', 'accused', NULL, NULL, 'ACCUSED_LIST.md', 'Elizabeth Colson accused — fled to Boston, never captured. Elizabeth Colson, single woman of Reading. Warrant issued May 14, 1692, accused by Mary Walcott, Mercy Lewis, and Susannah Sheldon. Constable John Parker reported she ''is fled'' and believed to be in Boston ''in order to bee shipt ofe'' (shipped off). A second warrant was issued May 17, directed to authorities in Boston and Charlestown. A September follow-up noted she remained ''concealed in Bostine.'' One witness described her running away, falling and rising repeatedly, then vanishing near bushes — followed by the appearance of a large cat that also disappeared. Apparently never apprehended during the main trials. Escaped.', 'public', '["accused","escaped","reading","fled"]', 'salem_project', 1.0, NULL, 1775266565641, 1775266565641, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('accused_elizabeth_dicer', 'Elizabeth Dicer accused — previously fined for calling neighbor a witch', 'Elizabeth Dicer of Gloucester. Accused September 3, 1692 alongside Margaret Prince by the afflicted Salem Village girls visiting Gloucester. Previously fined in Essex County Court for calling a neighbor a ''black-mouthed witch'' — an earlier, non-fatal kind of witchcraft accusation. Released on own recognizance December 15, 1692. Never tried.', '1692-09-03', NULL, 'legal', 'accused', NULL, NULL, 'ACCUSED_LIST.md', 'Elizabeth Dicer accused — previously fined for calling neighbor a witch. Elizabeth Dicer of Gloucester. Accused September 3, 1692 alongside Margaret Prince by the afflicted Salem Village girls visiting Gloucester. Previously fined in Essex County Court for calling a neighbor a ''black-mouthed witch'' — an earlier, non-fatal kind of witchcraft accusation. Released on own recognizance December 15, 1692. Never tried.', 'public', '["accused","released","gloucester","prior_witchcraft_incident"]', 'salem_project', 1.0, NULL, 1775266565641, 1775266565641, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('accused_elizabeth_fosdick', 'Elizabeth Fosdick accused — Malden carpenter''s wife', 'Elizabeth Fosdick, wife of John Fosdick, carpenter of Malden. Complaint filed May 30, 1692 by Lt. Nathaniel Putnam and Joseph Whipple; apprehended June 3. Accused by Mary Walcott, Mercy Lewis, Abigail Williams, and Ann Putnam Jr. Peter Tufts of Charlestown also complained that Fosdick committed witchcraft against his enslaved woman. Accused alongside Elizabeth Paine of Charlestown. Released; no trial record survives.', '1692-05-30', NULL, 'legal', 'accused', NULL, NULL, 'ACCUSED_LIST.md', 'Elizabeth Fosdick accused — Malden carpenter''s wife. Elizabeth Fosdick, wife of John Fosdick, carpenter of Malden. Complaint filed May 30, 1692 by Lt. Nathaniel Putnam and Joseph Whipple; apprehended June 3. Accused by Mary Walcott, Mercy Lewis, Abigail Williams, and Ann Putnam Jr. Peter Tufts of Charlestown also complained that Fosdick committed witchcraft against his enslaved woman. Accused alongside Elizabeth Paine of Charlestown. Released; no trial record survives.', 'public', '["accused","released","malden"]', 'salem_project', 1.0, NULL, 1775266565641, 1775266565641, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('accused_elizabeth_how', 'Elizabeth How — Executed by hanging, July 19, 1692', 'Elizabeth How (Howe) of Topsfield/Ipswich Farms (Linebrook Parish), approximately 57, lived with her blind husband James How. Accused May 28, 1692 by Mary Walcott, Abigail Williams, and others; complaint filed by Joseph Holton and John Walcott. Had faced accusations for years — in the 1680s, the Perley family of Ipswich blamed her for their daughter Hannah''s mysterious illness and death. Neighbors attributed misfortunes (sick livestock, rotted fence posts, poisoned apples) to How. Constable Ephraim Wildes — whose own mother Sarah Wildes was already accused — arrested her May 29. Despite this history, many neighbors testified in her defense. Her case was entangled with Topsfield-Salem Village border disputes. Tried June 29-30, found guilty. Hanged July 19, 1692.', '1692-05-28', NULL, 'legal', 'accused', NULL, NULL, 'research/ACCUSED_LIST.md', 'Elizabeth How — Executed by hanging, July 19, 1692. Elizabeth How (Howe) of Topsfield/Ipswich Farms (Linebrook Parish), approximately 57, lived with her blind husband James How. Accused May 28, 1692 by Mary Walcott, Abigail Williams, and others; complaint filed by Joseph Holton and John Walcott. Had faced accusations for years — in the 1680s, the Perley family of Ipswich blamed her for their daughter Hannah''s mysterious illness and death. Neighbors attributed misfortunes (sick livestock, rotted fence posts, poisoned apples) to How. Constable Ephraim Wildes — whose own mother Sarah Wildes was already accused — arrested her May 29. Despite this history, many neighbors testified in her defense. Her case was entangled with Topsfield-Salem Village border disputes. Tried June 29-30, found guilty. Hanged July 19, 1692.', 'public', '["accused","executed","topsfield","hanged_july_19","border_dispute"]', 'salem_project', 1.0, NULL, 1775266565641, 1775266565641, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('accused_elizabeth_johnson_jr', 'Elizabeth Johnson Jr. accused — last exonerated in 2022, 329 years later', 'Elizabeth Johnson Jr. of Andover, niece of Abigail Faulkner Sr. and daughter of Elizabeth Johnson Sr. Accused August 10, 1692. Her confession described a gathering of ''about six score'' witches. Convicted and condemned to death by Court of Oyer and Terminer. Reprieved by Governor Phips, January 1693. Not formally exonerated until 2022 — the last Salem accused to be cleared, 329 years after the trials. Massachusetts formally exonerated her by legislative act in 2022.', '1692-08-10', NULL, 'legal', 'accused', NULL, NULL, 'ACCUSED_LIST.md', 'Elizabeth Johnson Jr. accused — last exonerated in 2022, 329 years later. Elizabeth Johnson Jr. of Andover, niece of Abigail Faulkner Sr. and daughter of Elizabeth Johnson Sr. Accused August 10, 1692. Her confession described a gathering of ''about six score'' witches. Convicted and condemned to death by Court of Oyer and Terminer. Reprieved by Governor Phips, January 1693. Not formally exonerated until 2022 — the last Salem accused to be cleared, 329 years after the trials. Massachusetts formally exonerated her by legislative act in 2022.', 'public', '["accused","convicted","reprieved","andover","last_exonerated_2022","johnson_family"]', 'salem_project', 1.0, NULL, 1775266565641, 1775266565641, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('accused_elizabeth_johnson_sr', 'Elizabeth Johnson Sr. accused — mother of Elizabeth Jr.', 'Elizabeth Johnson Sr. of Andover. Accused circa August 29, 1692 by Moses Tyler and afflicted girls. Mother of Elizabeth Johnson Jr. (who was convicted and not exonerated until 2022). Implicated Susanna Post during her examination. The mother-daughter pair illustrates how accusations cascaded through family lines. Confessed. Released after trials ended.', '1692-08-29', NULL, 'legal', 'accused', NULL, NULL, 'ACCUSED_LIST.md', 'Elizabeth Johnson Sr. accused — mother of Elizabeth Jr.. Elizabeth Johnson Sr. of Andover. Accused circa August 29, 1692 by Moses Tyler and afflicted girls. Mother of Elizabeth Johnson Jr. (who was convicted and not exonerated until 2022). Implicated Susanna Post during her examination. The mother-daughter pair illustrates how accusations cascaded through family lines. Confessed. Released after trials ended.', 'public', '["accused","confessed","released","andover","johnson_family","mother_daughter"]', 'salem_project', 1.0, NULL, 1775266565641, 1775266565641, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('accused_elizabeth_paine', 'Elizabeth Paine accused — Charlestown wife', 'Elizabeth Paine, wife of Stephen Paine, husbandman of Charlestown. Complaint filed May 30, 1692 by Lt. Nathaniel Putnam and Joseph Whipple; apprehended June 2. Accused by Mary Warren and Peter Tufts of Charlestown (who complained she afflicted his enslaved woman). Accused alongside Elizabeth Fosdick of Malden. Released. Never tried.', '1692-05-30', NULL, 'legal', 'accused', NULL, NULL, 'ACCUSED_LIST.md', 'Elizabeth Paine accused — Charlestown wife. Elizabeth Paine, wife of Stephen Paine, husbandman of Charlestown. Complaint filed May 30, 1692 by Lt. Nathaniel Putnam and Joseph Whipple; apprehended June 2. Accused by Mary Warren and Peter Tufts of Charlestown (who complained she afflicted his enslaved woman). Accused alongside Elizabeth Fosdick of Malden. Released. Never tried.', 'public', '["accused","released","charlestown"]', 'salem_project', 1.0, NULL, 1775266565641, 1775266565641, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('accused_elizabeth_proctor', 'Elizabeth Proctor — Convicted, reprieved due to pregnancy, survived', 'Elizabeth Proctor (nee Bassett) of Salem Village, a middle-aged wife and mother married to prosperous farmer John Proctor. First named March 26, 1692 by Abigail Williams; formal complaint April 4, filed by Captain Jonathan Walcott and Nathaniel Ingersoll. Her husband John vocally denounced the proceedings and threatened to whip the afflicted girls, leading to his own accusation. Examined April 11 before Deputy Governor Thomas Danforth. Her servant Mary Warren was among the afflicted and testified against her employers. Tried, convicted, and sentenced to death but reprieved because she was pregnant. The general reprieve of 1693 saved her life. After the trials she faced a legal struggle to reclaim her husband''s estate under attainder law.', '1692-03-26', NULL, 'legal', 'accused', NULL, 'npc_elizabeth_proctor', 'research/ACCUSED_LIST.md', 'Elizabeth Proctor — Convicted, reprieved due to pregnancy, survived. Elizabeth Proctor (nee Bassett) of Salem Village, a middle-aged wife and mother married to prosperous farmer John Proctor. First named March 26, 1692 by Abigail Williams; formal complaint April 4, filed by Captain Jonathan Walcott and Nathaniel Ingersoll. Her husband John vocally denounced the proceedings and threatened to whip the afflicted girls, leading to his own accusation. Examined April 11 before Deputy Governor Thomas Danforth. Her servant Mary Warren was among the afflicted and testified against her employers. Tried, convicted, and sentenced to death but reprieved because she was pregnant. The general reprieve of 1693 saved her life. After the trials she faced a legal struggle to reclaim her husband''s estate under attainder law.', 'public', '["accused","convicted_reprieved","salem_village","pregnancy_reprieve"]', 'salem_project', 1.0, NULL, 1775266565642, 1775266565642, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('accused_esther_elwell', 'Esther Elwell accused — prominent Gloucester family', 'Esther Elwell (nee Dutch) of Gloucester. Accused November 5, 1692 by James Stevens (same complaint as Rebecca Dike) and afflicted Salem Village girls. From a prominent Gloucester family. Married Samuel Elwell. Lived the rest of her life in Gloucester. Case dropped due to ban on spectral evidence. Never tried. Released.', '1692-11-05', NULL, 'legal', 'accused', NULL, NULL, 'ACCUSED_LIST.md', 'Esther Elwell accused — prominent Gloucester family. Esther Elwell (nee Dutch) of Gloucester. Accused November 5, 1692 by James Stevens (same complaint as Rebecca Dike) and afflicted Salem Village girls. From a prominent Gloucester family. Married Samuel Elwell. Lived the rest of her life in Gloucester. Case dropped due to ban on spectral evidence. Never tried. Released.', 'public', '["accused","released","gloucester","post_court_dissolution"]', 'salem_project', 1.0, NULL, 1775266565642, 1775266565642, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('accused_eunice_frye', 'Eunice Frye accused — deacon''s wife, no social standing immune', 'Eunice Frye, wife of Deacon Frye of Andover. Accused circa September 8, 1692 via touch test. Named in Mary Osgood''s confession as a companion on the flight to Five Mile Pond. Wife of a church deacon — her accusation shows that no social standing provided immunity by September 1692. Confessed. Released after trials ended. Signed group recantation.', '1692-09-08', NULL, 'legal', 'accused', NULL, NULL, 'ACCUSED_LIST.md', 'Eunice Frye accused — deacon''s wife, no social standing immune. Eunice Frye, wife of Deacon Frye of Andover. Accused circa September 8, 1692 via touch test. Named in Mary Osgood''s confession as a companion on the flight to Five Mile Pond. Wife of a church deacon — her accusation shows that no social standing provided immunity by September 1692. Confessed. Released after trials ended. Signed group recantation.', 'public', '["accused","confessed","recanted","released","andover","touch_test","deacons_wife"]', 'salem_project', 1.0, NULL, 1775266565642, 1775266565642, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('accused_frances_hutchins', 'Frances Hutchins accused — Haverhill Timothy Swan cluster', 'Frances Hutchins (Francis Hutchens) of Haverhill. Accused circa August 18, 1692 by Timothy Swan, who accused multiple Haverhill and Andover residents. Part of the Timothy Swan accusation cluster, which also targeted Mary Ayer Parker and Rebecca Eames. Not tried. Released.', '1692-08-18', NULL, 'legal', 'accused', NULL, NULL, 'ACCUSED_LIST.md', 'Frances Hutchins accused — Haverhill Timothy Swan cluster. Frances Hutchins (Francis Hutchens) of Haverhill. Accused circa August 18, 1692 by Timothy Swan, who accused multiple Haverhill and Andover residents. Part of the Timothy Swan accusation cluster, which also targeted Mary Ayer Parker and Rebecca Eames. Not tried. Released.', 'public', '["accused","released","haverhill","swan_cluster"]', 'salem_project', 1.0, NULL, 1775266565642, 1775266565642, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('accused_george_burroughs', 'Rev. George Burroughs — Executed by hanging, August 19, 1692', 'Rev. George Burroughs, Harvard-educated, non-ordained Puritan minister from Wells, Maine. Formerly Salem Village minister 1680-1683, departing amid a salary dispute with the Putnam faction. Had debts to the Putnams from borrowing money for his first wife''s funeral. Mercy Lewis had been a servant in his household in Maine. Accused April 30, 1692 by Ann Putnam Jr., Mercy Lewis, Abigail Williams, Mary Walcott, Susannah Sheldon, Elizabeth Hubbard; complaint filed by Thomas Putnam and Jonathan Walcott. Arrested in Wells, Maine, over 100 miles away, and brought to Salem. The afflicted called him ''the ringleader of them all.'' Testimony included claims of ''preternatural'' strength — he could lift a heavy musket by inserting a finger in the barrel. Tried August 5. Famously recited the Lord''s Prayer perfectly on the gallows (supposedly impossible for a witch), shaking the crowd''s confidence until Cotton Mather intervened. Hanged August 19, 1692.', '1692-04-30', NULL, 'legal', 'accused', NULL, 'npc_george_burroughs', 'research/ACCUSED_LIST.md', 'Rev. George Burroughs — Executed by hanging, August 19, 1692. Rev. George Burroughs, Harvard-educated, non-ordained Puritan minister from Wells, Maine. Formerly Salem Village minister 1680-1683, departing amid a salary dispute with the Putnam faction. Had debts to the Putnams from borrowing money for his first wife''s funeral. Mercy Lewis had been a servant in his household in Maine. Accused April 30, 1692 by Ann Putnam Jr., Mercy Lewis, Abigail Williams, Mary Walcott, Susannah Sheldon, Elizabeth Hubbard; complaint filed by Thomas Putnam and Jonathan Walcott. Arrested in Wells, Maine, over 100 miles away, and brought to Salem. The afflicted called him ''the ringleader of them all.'' Testimony included claims of ''preternatural'' strength — he could lift a heavy musket by inserting a finger in the barrel. Tried August 5. Famously recited the Lord''s Prayer perfectly on the gallows (supposedly impossible for a witch), shaking the crowd''s confidence until Cotton Mather intervened. Hanged August 19, 1692.', 'public', '["accused","executed","wells_maine","hanged_aug_19","former_minister","ringleader"]', 'salem_project', 1.0, NULL, 1775266565642, 1775266565642, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('accused_george_jacobs_jr', 'George Jacobs Jr. accused — fled, entire family destroyed', 'George Jacobs Jr. of Salem Village, son of George Jacobs Sr. (arrested May 10, later executed), husband of Rebecca Jacobs (also accused), and father of Margaret Jacobs (also accused and coerced into testifying). Warrant issued May 14, 1692. Evaded arrest by fleeing and was never captured during the trials. Returned after the crisis ended. An entire family destroyed by the accusations: father hanged, granddaughter coerced, wife jailed, son fled.', '1692-05-14', NULL, 'legal', 'accused', NULL, NULL, 'ACCUSED_LIST.md', 'George Jacobs Jr. accused — fled, entire family destroyed. George Jacobs Jr. of Salem Village, son of George Jacobs Sr. (arrested May 10, later executed), husband of Rebecca Jacobs (also accused), and father of Margaret Jacobs (also accused and coerced into testifying). Warrant issued May 14, 1692. Evaded arrest by fleeing and was never captured during the trials. Returned after the crisis ended. An entire family destroyed by the accusations: father hanged, granddaughter coerced, wife jailed, son fled.', 'public', '["accused","escaped","salem_village","jacobs_family","family_destroyed"]', 'salem_project', 1.0, NULL, 1775266565642, 1775266565642, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('accused_george_jacobs_sr', 'George Jacobs Sr. — Executed by hanging, August 19, 1692', 'George Jacobs Sr. of Salem Town/Salem Farms, approximately 72, used two walking sticks due to infirmity. Accused May 10, 1692 by Ann Putnam Jr., Mercy Lewis, Mary Walcott; initially named by his own servant Sarah Churchill, and later by his granddaughter Margaret Jacobs (under coercion). At his examination, he called the proceedings ''a lie'' and dismissed the afflicted girls as ''bitch witches.'' His granddaughter Margaret was pressured into testifying against him but later recanted, writing a heartfelt letter from jail confessing she had lied. His son George Jacobs Jr. was also accused but escaped. Tried August 5, found guilty. Hanged August 19, 1692.', '1692-05-10', NULL, 'legal', 'accused', NULL, 'npc_george_jacobs_sr', 'research/ACCUSED_LIST.md', 'George Jacobs Sr. — Executed by hanging, August 19, 1692. George Jacobs Sr. of Salem Town/Salem Farms, approximately 72, used two walking sticks due to infirmity. Accused May 10, 1692 by Ann Putnam Jr., Mercy Lewis, Mary Walcott; initially named by his own servant Sarah Churchill, and later by his granddaughter Margaret Jacobs (under coercion). At his examination, he called the proceedings ''a lie'' and dismissed the afflicted girls as ''bitch witches.'' His granddaughter Margaret was pressured into testifying against him but later recanted, writing a heartfelt letter from jail confessing she had lied. His son George Jacobs Jr. was also accused but escaped. Tried August 5, found guilty. Hanged August 19, 1692.', 'public', '["accused","executed","salem_town","hanged_aug_19"]', 'salem_project', 1.0, NULL, 1775266565642, 1775266565642, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('accused_giles_corey', 'Giles Corey — Pressed to death, September 19, 1692', 'Giles Corey of Salem Village, approximately 80 years old, farmer and husband of already-accused Martha Corey. Accused April 18, 1692 by Ann Putnam Jr., Mercy Lewis, Abigail Williams, Mary Walcott, Elizabeth Hubbard; complaint filed by Thomas Putnam and Ezekiel Cheever. He had initially testified against his wife Martha in March 1692. In 1676, he had been found guilty of beating to death his farmhand Jacob Goodale (fined but not imprisoned). When brought to trial in September, he refused to enter a plea. Under English law, the court ordered peine forte et dure — heavy stones placed on his chest. Over two days (September 17-19), Corey endured the pressing, reportedly saying only ''More weight.'' He died September 19 without entering a plea. His refusal may have been strategic — by avoiding conviction, he preserved his estate from forfeiture for his heirs.', '1692-04-18', NULL, 'legal', 'accused', NULL, 'npc_giles_corey', 'research/ACCUSED_LIST.md', 'Giles Corey — Pressed to death, September 19, 1692. Giles Corey of Salem Village, approximately 80 years old, farmer and husband of already-accused Martha Corey. Accused April 18, 1692 by Ann Putnam Jr., Mercy Lewis, Abigail Williams, Mary Walcott, Elizabeth Hubbard; complaint filed by Thomas Putnam and Ezekiel Cheever. He had initially testified against his wife Martha in March 1692. In 1676, he had been found guilty of beating to death his farmhand Jacob Goodale (fined but not imprisoned). When brought to trial in September, he refused to enter a plea. Under English law, the court ordered peine forte et dure — heavy stones placed on his chest. Over two days (September 17-19), Corey endured the pressing, reportedly saying only ''More weight.'' He died September 19 without entering a plea. His refusal may have been strategic — by avoiding conviction, he preserved his estate from forfeiture for his heirs.', 'public', '["accused","pressed_to_death","salem_village","peine_forte_et_dure"]', 'salem_project', 1.0, NULL, 1775266565642, 1775266565642, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('accused_hannah_carroll', 'Hannah Carroll accused — Salem Town, father accusing on behalf of son', 'Hannah Carroll (Carrell) of Salem Town. Accused September 10, 1692 by Henry Brag, who claimed Carroll and Sarah Cole were afflicting his son William. The father-accusing-on-behalf-of-child pattern mirrors the original accusations in Salem Village. Released. Never tried.', '1692-09-10', NULL, 'legal', 'accused', NULL, NULL, 'ACCUSED_LIST.md', 'Hannah Carroll accused — Salem Town, father accusing on behalf of son. Hannah Carroll (Carrell) of Salem Town. Accused September 10, 1692 by Henry Brag, who claimed Carroll and Sarah Cole were afflicting his son William. The father-accusing-on-behalf-of-child pattern mirrors the original accusations in Salem Village. Released. Never tried.', 'public', '["accused","released","salem_town"]', 'salem_project', 1.0, NULL, 1775266565642, 1775266565642, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('accused_hannah_post', 'Hannah Post accused — age 26, Bridges-Post family network', 'Hannah Post, age 26, of Boxford/Andover. Stepsister to Sarah Bridges and sister to Mary Post and Susanna Post. Accused circa August 25, 1692 by Sarah Bridges (stepsister) and previously accused Mary Parker. The Post and Bridges families were extensively intermarried and targeted as a network. Confessed. Released January 1693.', '1692-08-25', NULL, 'legal', 'accused', NULL, NULL, 'ACCUSED_LIST.md', 'Hannah Post accused — age 26, Bridges-Post family network. Hannah Post, age 26, of Boxford/Andover. Stepsister to Sarah Bridges and sister to Mary Post and Susanna Post. Accused circa August 25, 1692 by Sarah Bridges (stepsister) and previously accused Mary Parker. The Post and Bridges families were extensively intermarried and targeted as a network. Confessed. Released January 1693.', 'public', '["accused","confessed","released","andover","bridges_post_family"]', 'salem_project', 1.0, NULL, 1775266565642, 1775266565642, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('accused_henry_salter', 'Henry Salter accused — Andover touch test', 'Henry Salter of Andover. Accused September 7, 1692 by Rose Foster (Andover afflicted girl). Accused during or around the time of the mass touch test at the Andover meetinghouse. Released. Not tried.', '1692-09-07', NULL, 'legal', 'accused', NULL, NULL, 'ACCUSED_LIST.md', 'Henry Salter accused — Andover touch test. Henry Salter of Andover. Accused September 7, 1692 by Rose Foster (Andover afflicted girl). Accused during or around the time of the mass touch test at the Andover meetinghouse. Released. Not tried.', 'public', '["accused","released","andover","touch_test"]', 'salem_project', 1.0, NULL, 1775266565642, 1775266565642, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('accused_hezekiah_usher', 'Hezekiah Usher named — prominent Boston figure in spectral testimony', 'Hezekiah Usher of Boston, named in spectral testimony in April 1692 by afflicted girls. No formal prosecution. The naming of a prominent Boston figure was one signal that the accusations were expanding dangerously. This alarmed colonial authorities and contributed to the decision to establish a formal court. Later fled house arrest to Rhode Island.', '1692-04-15', NULL, 'legal', 'accused', NULL, NULL, 'ACCUSED_LIST.md', 'Hezekiah Usher named — prominent Boston figure in spectral testimony. Hezekiah Usher of Boston, named in spectral testimony in April 1692 by afflicted girls. No formal prosecution. The naming of a prominent Boston figure was one signal that the accusations were expanding dangerously. This alarmed colonial authorities and contributed to the decision to establish a formal court. Later fled house arrest to Rhode Island.', 'public', '["accused","boston","spectral_testimony","prominent_figure","escaped"]', 'salem_project', 1.0, NULL, 1775266565642, 1775266565642, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('accused_hugh_crosia', 'Hugh Crosia accused — very little survives in records', 'Hugh Crosia (also Crotia, Crosley), possibly from the Salem area. Accused probable June-July 1692 by afflicted persons. Very little survives in the record about this individual. Outcome unknown; likely released.', '1692-07-01', NULL, 'legal', 'accused', NULL, NULL, 'ACCUSED_LIST.md', 'Hugh Crosia accused — very little survives in records. Hugh Crosia (also Crotia, Crosley), possibly from the Salem area. Accused probable June-July 1692 by afflicted persons. Very little survives in the record about this individual. Outcome unknown; likely released.', 'public', '["accused","released","sparse_records"]', 'salem_project', 1.0, NULL, 1775266565642, 1775266565642, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('accused_jane_lilly', 'Jane Lilly accused — Malden, geographically distant', 'Jane Lilly of Malden. Accused September 5, 1692. One of the more geographically distant accusations — Malden is northwest of Boston, well outside the Salem-Andover core. Shows the crisis was threatening to spread across all of eastern Massachusetts. Released. Not tried.', '1692-09-05', NULL, 'legal', 'accused', NULL, NULL, 'ACCUSED_LIST.md', 'Jane Lilly accused — Malden, geographically distant. Jane Lilly of Malden. Accused September 5, 1692. One of the more geographically distant accusations — Malden is northwest of Boston, well outside the Salem-Andover core. Shows the crisis was threatening to spread across all of eastern Massachusetts. Released. Not tried.', 'public', '["accused","released","malden","geographic_spread"]', 'salem_project', 1.0, NULL, 1775266565642, 1775266565642, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('accused_joan_penney', 'Joan Penney accused — Gloucester, land disputes', 'Joan Penney of Gloucester. Accused September 13, 1692 (some records say September 20) by Zebulon Hill. Had land disputes with neighbors — a pattern seen repeatedly in accusations throughout the crisis. The Gloucester cases were generally less severe because the Court of Oyer and Terminer was dissolved before they could be tried. Never tried. Released by May 1693.', '1692-09-13', NULL, 'legal', 'accused', NULL, NULL, 'ACCUSED_LIST.md', 'Joan Penney accused — Gloucester, land disputes. Joan Penney of Gloucester. Accused September 13, 1692 (some records say September 20) by Zebulon Hill. Had land disputes with neighbors — a pattern seen repeatedly in accusations throughout the crisis. The Gloucester cases were generally less severe because the Court of Oyer and Terminer was dissolved before they could be tried. Never tried. Released by May 1693.', 'public', '["accused","released","gloucester","land_dispute"]', 'salem_project', 1.0, NULL, 1775266565642, 1775266565642, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('accused_job_tookey', 'Job Tookey accused — Beverly resident', 'Job Tookey of Beverly. Accused probable June-July 1692 by Mary Warren and Elizabeth Booth. Indicted but not tried during the Oyer and Terminer court. Tried by the Superior Court, January 1693. Released. Survived.', '1692-07-01', NULL, 'legal', 'accused', NULL, NULL, 'ACCUSED_LIST.md', 'Job Tookey accused — Beverly resident. Job Tookey of Beverly. Accused probable June-July 1692 by Mary Warren and Elizabeth Booth. Indicted but not tried during the Oyer and Terminer court. Tried by the Superior Court, January 1693. Released. Survived.', 'public', '["accused","released","beverly"]', 'salem_project', 1.0, NULL, 1775266565642, 1775266565642, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('accused_john_howard', 'John Howard accused — rare Rowley resident accused', 'John Howard of Rowley. Accused August 5, 1692. One of the few Rowley residents accused. The accusations were spreading well beyond Salem Village and Andover by this date. Released. Not tried.', '1692-08-05', NULL, 'legal', 'accused', NULL, NULL, 'ACCUSED_LIST.md', 'John Howard accused — rare Rowley resident accused. John Howard of Rowley. Accused August 5, 1692. One of the few Rowley residents accused. The accusations were spreading well beyond Salem Village and Andover by this date. Released. Not tried.', 'public', '["accused","released","rowley"]', 'salem_project', 1.0, NULL, 1775266565642, 1775266565642, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('accused_john_jackson_sr_jr', 'John Jackson Sr. and Jr. accused — father-son pair from Rowley', 'John Jackson Sr. and John Jackson Jr. of Rowley. Both accused August 5, 1692. The father-son accusation pattern echoed the family targeting seen in Andover. Both released. Neither tried.', '1692-08-05', NULL, 'legal', 'accused', NULL, NULL, 'ACCUSED_LIST.md', 'John Jackson Sr. and Jr. accused — father-son pair from Rowley. John Jackson Sr. and John Jackson Jr. of Rowley. Both accused August 5, 1692. The father-son accusation pattern echoed the family targeting seen in Andover. Both released. Neither tried.', 'public', '["accused","released","rowley","father_son"]', 'salem_project', 1.0, NULL, 1775266565642, 1775266565642, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('accused_john_proctor', 'John Proctor — Executed by hanging, August 19, 1692', 'John Proctor of Salem Village/Salem Farms, approximately 60, a prosperous farmer and tavern keeper. Named by Abigail Williams, Mary Walcott, Mercy Lewis March 26-28; formal complaint April 4 filed by Captain Jonathan Walcott and Nathaniel Ingersoll. The first man accused. He was outspokenly hostile to the proceedings, reportedly saying the afflicted girls should be ''at the whipping post.'' His servant Mary Warren attempted to recant but was accused of witchcraft herself until she rejoined the accusers and testified against the Proctors. From prison, Proctor wrote a desperate letter to the Boston clergy (July 23, 1692) describing torture against the accused and begging for the trials to be moved to Boston. Tried August 5, executed August 19, 1692. At the gallows, he recited the Lord''s Prayer flawlessly — supposedly impossible for a witch — but the court disregarded it.', '1692-03-26', NULL, 'legal', 'accused', NULL, 'npc_john_proctor', 'research/ACCUSED_LIST.md', 'John Proctor — Executed by hanging, August 19, 1692. John Proctor of Salem Village/Salem Farms, approximately 60, a prosperous farmer and tavern keeper. Named by Abigail Williams, Mary Walcott, Mercy Lewis March 26-28; formal complaint April 4 filed by Captain Jonathan Walcott and Nathaniel Ingersoll. The first man accused. He was outspokenly hostile to the proceedings, reportedly saying the afflicted girls should be ''at the whipping post.'' His servant Mary Warren attempted to recant but was accused of witchcraft herself until she rejoined the accusers and testified against the Proctors. From prison, Proctor wrote a desperate letter to the Boston clergy (July 23, 1692) describing torture against the accused and begging for the trials to be moved to Boston. Tried August 5, executed August 19, 1692. At the gallows, he recited the Lord''s Prayer flawlessly — supposedly impossible for a witch — but the court disregarded it.', 'public', '["accused","executed","salem_village","hanged_aug_19"]', 'salem_project', 1.0, NULL, 1775266565642, 1775266565642, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('accused_john_willard', 'John Willard — Executed by hanging, August 19, 1692', 'John Willard of Salem Village, approximately 30, originally from Groton, Massachusetts; married Margaret Wilkins. Had served as a deputy constable charged with arresting accused witches, but quit in protest when he began doubting the legitimacy of the accusations. His refusal to arrest made him a target. Accused May 12, 1692 by Ann Putnam Jr., Mercy Lewis, Susannah Sheldon, Mary Walcott. He fled to Lancaster but was captured by Thomas Putnam Jr. tending his meadows. At his May 18 examination, the magistrates declared his flight proof of guilt. The accusers also charged him with multiple spectral murders. Tried August 5, found guilty. Hanged August 19, 1692.', '1692-05-12', NULL, 'legal', 'accused', NULL, 'npc_john_willard', 'research/ACCUSED_LIST.md', 'John Willard — Executed by hanging, August 19, 1692. John Willard of Salem Village, approximately 30, originally from Groton, Massachusetts; married Margaret Wilkins. Had served as a deputy constable charged with arresting accused witches, but quit in protest when he began doubting the legitimacy of the accusations. His refusal to arrest made him a target. Accused May 12, 1692 by Ann Putnam Jr., Mercy Lewis, Susannah Sheldon, Mary Walcott. He fled to Lancaster but was captured by Thomas Putnam Jr. tending his meadows. At his May 18 examination, the magistrates declared his flight proof of guilt. The accusers also charged him with multiple spectral murders. Tried August 5, found guilty. Hanged August 19, 1692.', 'public', '["accused","executed","salem_village","hanged_aug_19","former_constable"]', 'salem_project', 1.0, NULL, 1775266565642, 1775266565642, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('accused_joseph_emons', 'Joseph Emons accused — rare Manchester resident accused', 'Joseph Emons of Manchester. Accused September 5, 1692 by Elizer Keyser and Simon Willard, who filed complaint claiming Emons was afflicting Mary Warren. One of the few accused from the small coastal town of Manchester. The accusation by Mary Warren (herself a former accused who became an accuser) illustrates the fluid boundary between accuser and accused. Released. Not tried.', '1692-09-05', NULL, 'legal', 'accused', NULL, NULL, 'ACCUSED_LIST.md', 'Joseph Emons accused — rare Manchester resident accused. Joseph Emons of Manchester. Accused September 5, 1692 by Elizer Keyser and Simon Willard, who filed complaint claiming Emons was afflicting Mary Warren. One of the few accused from the small coastal town of Manchester. The accusation by Mary Warren (herself a former accused who became an accuser) illustrates the fluid boundary between accuser and accused. Released. Not tried.', 'public', '["accused","released","manchester"]', 'salem_project', 1.0, NULL, 1775266565642, 1775266565642, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('accused_lydia_dustin', 'Lydia Dustin accused — acquitted but died in prison unable to pay fees', 'Lydia Dustin, elderly woman from Reading, Massachusetts, accused April 30, 1692. Had a longstanding reputation for witchcraft (previously accused in the 1680s, and as early as 1656). Her daughter Sarah Dustin was also accused. Acquitted by the Superior Court of Judicature in February 1693 but could not afford the jail fees required for release. Died in prison March 10, 1693, approximately one week after acquittal. One of the most tragic illustrations of the economic machinery of the justice system: even acquittal did not mean freedom if you could not pay.', '1692-04-30', NULL, 'legal', 'accused', NULL, NULL, 'ACCUSED_LIST.md', 'Lydia Dustin accused — acquitted but died in prison unable to pay fees. Lydia Dustin, elderly woman from Reading, Massachusetts, accused April 30, 1692. Had a longstanding reputation for witchcraft (previously accused in the 1680s, and as early as 1656). Her daughter Sarah Dustin was also accused. Acquitted by the Superior Court of Judicature in February 1693 but could not afford the jail fees required for release. Died in prison March 10, 1693, approximately one week after acquittal. One of the most tragic illustrations of the economic machinery of the justice system: even acquittal did not mean freedom if you could not pay.', 'public', '["accused","died_in_prison","acquitted","reading","jail_fees","prior_accusation"]', 'salem_project', 1.0, NULL, 1775266565642, 1775266565642, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('accused_margaret_hawkes', 'Margaret Hawkes accused — by her own enslaved woman Candy', 'Margaret Hawkes, slaveholder of Salem Town. Complaint filed July 1, 1692 by John Putnam Jr. and Thomas Putnam. Also accused by her own enslaved woman Candy during examination — Candy testified that Hawkes had forced her into witchcraft. The enslaved woman''s defense turned into an accusation against her mistress. Outcome uncertain; no execution record. Likely released after the trials.', '1692-07-01', NULL, 'legal', 'accused', NULL, NULL, 'ACCUSED_LIST.md', 'Margaret Hawkes accused — by her own enslaved woman Candy. Margaret Hawkes, slaveholder of Salem Town. Complaint filed July 1, 1692 by John Putnam Jr. and Thomas Putnam. Also accused by her own enslaved woman Candy during examination — Candy testified that Hawkes had forced her into witchcraft. The enslaved woman''s defense turned into an accusation against her mistress. Outcome uncertain; no execution record. Likely released after the trials.', 'public', '["accused","released","salem_town","slaveholder","accused_by_enslaved"]', 'salem_project', 1.0, NULL, 1775266565643, 1775266565643, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('accused_margaret_jacobs', 'Margaret Jacobs accused — coerced then recanted testimony', 'Margaret Jacobs, approximately 17 years old, granddaughter of George Jacobs Sr., of Salem Town. Accused May 10, 1692. Coerced into confessing and testifying against both her grandfather and Rev. George Burroughs. Later recanted her confession and wrote a moving letter from prison apologizing for her false testimony: she begged forgiveness from her grandfather, knowing her coerced words helped condemn him. Her recantation put her own life at risk — confessors who cooperated were spared, while those who maintained innocence were executed. Indicted but never tried. Released from prison after the trials ended.', '1692-05-10', NULL, 'legal', 'accused', NULL, 'margaret_jacobs', 'ACCUSED_LIST.md', 'Margaret Jacobs accused — coerced then recanted testimony. Margaret Jacobs, approximately 17 years old, granddaughter of George Jacobs Sr., of Salem Town. Accused May 10, 1692. Coerced into confessing and testifying against both her grandfather and Rev. George Burroughs. Later recanted her confession and wrote a moving letter from prison apologizing for her false testimony: she begged forgiveness from her grandfather, knowing her coerced words helped condemn him. Her recantation put her own life at risk — confessors who cooperated were spared, while those who maintained innocence were executed. Indicted but never tried. Released from prison after the trials ended.', 'public', '["accused","confessed","recanted","salem_town","coerced_testimony","jacobs_family"]', 'salem_project', 1.0, NULL, 1775266565643, 1775266565643, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('accused_margaret_prince', 'Margaret Prince accused — first Gloucester resident accused', 'Margaret Prince of Gloucester. Accused September 3, 1692 by afflicted Salem Village girls, brought to Gloucester at Ebenezer Babson''s request to identify who was tormenting his mother Eleanor. Known locally for being ''troublesome and having a sharp tongue.'' First Gloucester resident accused. The Gloucester accusations were triggered when Babson, already seeing spectral visions of French soldiers and Indians, invited the Salem girls to his community. Released on own recognizance December 15, 1692. Never tried.', '1692-09-03', NULL, 'legal', 'accused', NULL, NULL, 'ACCUSED_LIST.md', 'Margaret Prince accused — first Gloucester resident accused. Margaret Prince of Gloucester. Accused September 3, 1692 by afflicted Salem Village girls, brought to Gloucester at Ebenezer Babson''s request to identify who was tormenting his mother Eleanor. Known locally for being ''troublesome and having a sharp tongue.'' First Gloucester resident accused. The Gloucester accusations were triggered when Babson, already seeing spectral visions of French soldiers and Indians, invited the Salem girls to his community. Released on own recognizance December 15, 1692. Never tried.', 'public', '["accused","released","gloucester","first_gloucester_accused"]', 'salem_project', 1.0, NULL, 1775266565643, 1775266565643, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('accused_margaret_scott', 'Margaret Scott — Executed by hanging, September 22, 1692', 'Margaret Scott of Rowley, an impoverished widow approximately 77 years old — the oldest person executed in the Salem trials. Accused c. August 5, 1692 by afflicted persons. Little is documented about her beyond her poverty and advanced age. She was tried, convicted, and hanged on September 22, 1692, alongside Martha Corey, Mary Easty, Alice Parker, Mary Parker, Ann Pudeator, Wilmot Redd, and Samuel Wardwell. Her case illustrates how social marginality — old, poor, widowed — made women targets of accusation.', '1692-08-05', NULL, 'legal', 'accused', NULL, NULL, 'research/ACCUSED_LIST.md', 'Margaret Scott — Executed by hanging, September 22, 1692. Margaret Scott of Rowley, an impoverished widow approximately 77 years old — the oldest person executed in the Salem trials. Accused c. August 5, 1692 by afflicted persons. Little is documented about her beyond her poverty and advanced age. She was tried, convicted, and hanged on September 22, 1692, alongside Martha Corey, Mary Easty, Alice Parker, Mary Parker, Ann Pudeator, Wilmot Redd, and Samuel Wardwell. Her case illustrates how social marginality — old, poor, widowed — made women targets of accusation.', 'public', '["accused","executed","rowley","hanged_sep_22","oldest_executed"]', 'salem_project', 1.0, NULL, 1775266565643, 1775266565643, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('accused_margaret_toothaker', 'Margaret Toothaker accused — 10-year-old daughter', 'Margaret Toothaker, approximately 10 years old, daughter of Roger and Mary Toothaker, of Billerica. Accused May 28, 1692 by Mary Walcott and Abigail Williams, listed alongside her mother. One of several children accused during the trials. Her father died in jail before she was examined. Released. Never tried. Survived.', '1692-05-28', NULL, 'legal', 'accused', NULL, NULL, 'ACCUSED_LIST.md', 'Margaret Toothaker accused — 10-year-old daughter. Margaret Toothaker, approximately 10 years old, daughter of Roger and Mary Toothaker, of Billerica. Accused May 28, 1692 by Mary Walcott and Abigail Williams, listed alongside her mother. One of several children accused during the trials. Her father died in jail before she was examined. Released. Never tried. Survived.', 'public', '["accused","released","billerica","child_accused","toothaker_family"]', 'salem_project', 1.0, NULL, 1775266565643, 1775266565643, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('accused_martha_carrier', 'Martha Carrier — Executed by hanging, August 19, 1692', 'Martha Carrier of Andover, approximately 33-40 years old, daughter of Andrew Allen, one of Andover''s original settlers. Accused May 28, 1692 by Mary Walcott, Abigail Williams, Susannah Sheldon, Elizabeth Hubbard, Ann Putnam Jr.; also neighbor Benjamin Abbot. Her family had been blamed for an 1690 smallpox outbreak that killed 13 people in Andover; the Carriers were barred from public places. Neighbor Benjamin Abbot testified she bewitched him after a land dispute. At the trials, the afflicted girls screamed they could see the ghosts of the 13 smallpox victims behind her. Cotton Mather called her ''the Queen of Hell.'' Her sons Richard (18) and Andrew (15) were tortured — hung by their heels ''until the blood was ready to come out of their noses'' — until they testified against her. Her daughter Sarah (7) and son Thomas (10) were also imprisoned. Tried August 2-5, found guilty. Hanged August 19, 1692. Maintained her innocence throughout.', '1692-05-28', NULL, 'legal', 'accused', NULL, 'npc_martha_carrier', 'research/ACCUSED_LIST.md', 'Martha Carrier — Executed by hanging, August 19, 1692. Martha Carrier of Andover, approximately 33-40 years old, daughter of Andrew Allen, one of Andover''s original settlers. Accused May 28, 1692 by Mary Walcott, Abigail Williams, Susannah Sheldon, Elizabeth Hubbard, Ann Putnam Jr.; also neighbor Benjamin Abbot. Her family had been blamed for an 1690 smallpox outbreak that killed 13 people in Andover; the Carriers were barred from public places. Neighbor Benjamin Abbot testified she bewitched him after a land dispute. At the trials, the afflicted girls screamed they could see the ghosts of the 13 smallpox victims behind her. Cotton Mather called her ''the Queen of Hell.'' Her sons Richard (18) and Andrew (15) were tortured — hung by their heels ''until the blood was ready to come out of their noses'' — until they testified against her. Her daughter Sarah (7) and son Thomas (10) were also imprisoned. Tried August 2-5, found guilty. Hanged August 19, 1692. Maintained her innocence throughout.', 'public', '["accused","executed","andover","hanged_aug_19","queen_of_hell"]', 'salem_project', 1.0, NULL, 1775266565643, 1775266565643, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('accused_martha_corey', 'Martha Corey — Executed by hanging, September 22, 1692', 'Martha Corey (nee Rich, previously Panon/Pennoyer) of Salem Village was a full covenanted church member — her accusation was a watershed moment crossing the social boundary from outcasts to respectable church members. Named by Ann Putnam Jr. on March 12, 1692; warrant issued March 19. Formal complaint filed by Edward Putnam and Henry Kenney. She was vocal in her skepticism of the trials, reportedly saying she ''did not think there were witches,'' which was itself suspicious in Puritan theology. During her examination on March 21, when afflicted girls mimicked her movements, she laughed, which was held against her. She had a mixed-race son from a premarital relationship, used to damage her character. Her husband Giles initially testified against her but later refused to cooperate, leading to his own arrest and death. Excommunicated before her execution on September 22, 1692.', '1692-03-12', NULL, 'legal', 'accused', NULL, 'npc_martha_corey', 'research/ACCUSED_LIST.md', 'Martha Corey — Executed by hanging, September 22, 1692. Martha Corey (nee Rich, previously Panon/Pennoyer) of Salem Village was a full covenanted church member — her accusation was a watershed moment crossing the social boundary from outcasts to respectable church members. Named by Ann Putnam Jr. on March 12, 1692; warrant issued March 19. Formal complaint filed by Edward Putnam and Henry Kenney. She was vocal in her skepticism of the trials, reportedly saying she ''did not think there were witches,'' which was itself suspicious in Puritan theology. During her examination on March 21, when afflicted girls mimicked her movements, she laughed, which was held against her. She had a mixed-race son from a premarital relationship, used to damage her character. Her husband Giles initially testified against her but later refused to cooperate, leading to his own arrest and death. Excommunicated before her execution on September 22, 1692.', 'public', '["accused","executed","salem_village","hanged_sep_22","church_member"]', 'salem_project', 1.0, NULL, 1775266565643, 1775266565643, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('accused_martha_emerson', 'Martha Emerson accused — daughter of Roger Toothaker who ''killed a witch''', 'Martha Emerson (nee Toothaker) of Andover, formerly Billerica. Accused circa July 22, 1692 by Mary Warren and Mary Lacey Jr. Daughter of Roger Toothaker (died in jail June 16) and Mary Toothaker (accused May 28). Her father had boasted for years that she had ''killed a witch'' using folk remedies. Wife of Joseph Emerson of Andover. The Toothaker family was devastated by the trials — father dead in prison, mother and daughter both accused. Case thrown out for lack of evidence. Released.', '1692-07-22', NULL, 'legal', 'accused', NULL, NULL, 'ACCUSED_LIST.md', 'Martha Emerson accused — daughter of Roger Toothaker who ''killed a witch''. Martha Emerson (nee Toothaker) of Andover, formerly Billerica. Accused circa July 22, 1692 by Mary Warren and Mary Lacey Jr. Daughter of Roger Toothaker (died in jail June 16) and Mary Toothaker (accused May 28). Her father had boasted for years that she had ''killed a witch'' using folk remedies. Wife of Joseph Emerson of Andover. The Toothaker family was devastated by the trials — father dead in prison, mother and daughter both accused. Case thrown out for lack of evidence. Released.', 'public', '["accused","released","andover","toothaker_family","folk_remedies"]', 'salem_project', 1.0, NULL, 1775266565643, 1775266565643, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('accused_mary_barker', 'Mary Barker accused — age 13, niece of William Barker Sr.', 'Mary Barker, age 13, of Andover. Niece of William Barker Sr. (daughter of eldest Barker son John). Accused August 29, 1692 by Samuel Martin. Her youth did not protect her from accusation. Part of the Barker family cluster. Confessed. Released after trials ended.', '1692-08-29', NULL, 'legal', 'accused', NULL, NULL, 'ACCUSED_LIST.md', 'Mary Barker accused — age 13, niece of William Barker Sr.. Mary Barker, age 13, of Andover. Niece of William Barker Sr. (daughter of eldest Barker son John). Accused August 29, 1692 by Samuel Martin. Her youth did not protect her from accusation. Part of the Barker family cluster. Confessed. Released after trials ended.', 'public', '["accused","confessed","released","andover","child_accused","barker_family"]', 'salem_project', 1.0, NULL, 1775266565643, 1775266565643, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('accused_mary_black', 'Mary Black accused — enslaved woman in Putnam household', 'Mary Black, enslaved woman in the household of Nathaniel Putnam in Salem Village, accused April 21, 1692. Like Tituba, she was extremely vulnerable to accusation due to her enslaved status. During her examination, she was asked to look at the afflicted, and they fell into fits. She denied everything. Her case received relatively little attention in the records. Eventually released when the trials collapsed. Survived.', '1692-04-21', NULL, 'legal', 'accused', NULL, NULL, 'ACCUSED_LIST.md', 'Mary Black accused — enslaved woman in Putnam household. Mary Black, enslaved woman in the household of Nathaniel Putnam in Salem Village, accused April 21, 1692. Like Tituba, she was extremely vulnerable to accusation due to her enslaved status. During her examination, she was asked to look at the afflicted, and they fell into fits. She denied everything. Her case received relatively little attention in the records. Eventually released when the trials collapsed. Survived.', 'public', '["accused","released","enslaved","salem_village","putnam_household"]', 'salem_project', 1.0, NULL, 1775266565643, 1775266565643, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('accused_mary_bradbury', 'Mary Bradbury — Convicted, escaped before execution, survived', 'Mary Bradbury of Salisbury, approximately 75-77 years old, wife of Captain Thomas Bradbury, one of Salisbury''s most distinguished citizens. Married 55 years. Accused May 26, 1692 by Mary Marshall of Reading, Mary Walcott, Mercy Lewis, Ann Putnam Jr., Elizabeth Hubbard, Sarah Bibber, Mary Warren. Charged with tormenting Timothy Swan of Andover. Over 100 people signed a petition in her defense — the largest number of supporters for any accused person. Her husband submitted a statement calling her ''a loveing & faithfull wife.'' Tried September 6, found guilty, sentenced to death. Escaped before execution — her husband reportedly bribed the jailer and took her to Maine by horse and cart. Returned to Massachusetts after the trials ended. Died 1700, aged approximately 85.', '1692-05-26', NULL, 'legal', 'accused', NULL, NULL, 'research/ACCUSED_LIST.md', 'Mary Bradbury — Convicted, escaped before execution, survived. Mary Bradbury of Salisbury, approximately 75-77 years old, wife of Captain Thomas Bradbury, one of Salisbury''s most distinguished citizens. Married 55 years. Accused May 26, 1692 by Mary Marshall of Reading, Mary Walcott, Mercy Lewis, Ann Putnam Jr., Elizabeth Hubbard, Sarah Bibber, Mary Warren. Charged with tormenting Timothy Swan of Andover. Over 100 people signed a petition in her defense — the largest number of supporters for any accused person. Her husband submitted a statement calling her ''a loveing & faithfull wife.'' Tried September 6, found guilty, sentenced to death. Escaped before execution — her husband reportedly bribed the jailer and took her to Maine by horse and cart. Returned to Massachusetts after the trials ended. Died 1700, aged approximately 85.', 'public', '["accused","convicted_escaped","salisbury","largest_petition"]', 'salem_project', 1.0, NULL, 1775266565643, 1775266565643, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('accused_mary_bridges_jr', 'Mary Bridges Jr. accused — age 13, Andover child dragnet', 'Mary Bridges Jr., age 13, of Andover. Daughter of Mary Tyler Post Bridges Sr. Accused circa August 1692 by Rose Foster and Martha Sprague, examined in September. Another child caught in the Andover dragnet. Her examination produced further accusations against her stepsiblings. Confessed. Found not guilty, May 1693. Released.', '1692-08-25', NULL, 'legal', 'accused', NULL, NULL, 'ACCUSED_LIST.md', 'Mary Bridges Jr. accused — age 13, Andover child dragnet. Mary Bridges Jr., age 13, of Andover. Daughter of Mary Tyler Post Bridges Sr. Accused circa August 1692 by Rose Foster and Martha Sprague, examined in September. Another child caught in the Andover dragnet. Her examination produced further accusations against her stepsiblings. Confessed. Found not guilty, May 1693. Released.', 'public', '["accused","confessed","acquitted","andover","child_accused","bridges_post_family"]', 'salem_project', 1.0, NULL, 1775266565643, 1775266565643, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('accused_mary_bridges_sr', 'Mary Bridges Sr. accused — expanding Andover outbreak', 'Mary Bridges Sr. of Andover. Accused July 28, 1692 by afflicted girls and Andover confessors. Part of the expanding Andover outbreak, accused as confessions of Foster and the Laceys created a chain reaction. Released after the trials.', '1692-07-28', NULL, 'legal', 'accused', NULL, NULL, 'ACCUSED_LIST.md', 'Mary Bridges Sr. accused — expanding Andover outbreak. Mary Bridges Sr. of Andover. Accused July 28, 1692 by afflicted girls and Andover confessors. Part of the expanding Andover outbreak, accused as confessions of Foster and the Laceys created a chain reaction. Released after the trials.', 'public', '["accused","released","andover","andover_outbreak"]', 'salem_project', 1.0, NULL, 1775266565643, 1775266565643, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('accused_mary_clarke', 'Mary Clarke accused — Haverhill resident', 'Mary Clarke of Haverhill. Accused circa August 3, 1692. One of several Haverhill residents swept up in the expanding geography of accusations during August. Released. Never tried.', '1692-08-03', NULL, 'legal', 'accused', NULL, NULL, 'ACCUSED_LIST.md', 'Mary Clarke accused — Haverhill resident. Mary Clarke of Haverhill. Accused circa August 3, 1692. One of several Haverhill residents swept up in the expanding geography of accusations during August. Released. Never tried.', 'public', '["accused","released","haverhill"]', 'salem_project', 1.0, NULL, 1775266565643, 1775266565643, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('accused_mary_derich', 'Mary DeRich accused — yet another Proctor connection', 'Mary DeRich (also De Rich, Derrich) of Salem Village. Accused probable May-June 1692 (some sources say July 26). Another sister-in-law of Elizabeth Proctor, continuing the pattern of accusations targeting the Proctor family network. Seven Proctor family members and connections were accused in total. Never indicted. Released. Survived.', '1692-07-26', NULL, 'legal', 'accused', NULL, NULL, 'ACCUSED_LIST.md', 'Mary DeRich accused — yet another Proctor connection. Mary DeRich (also De Rich, Derrich) of Salem Village. Accused probable May-June 1692 (some sources say July 26). Another sister-in-law of Elizabeth Proctor, continuing the pattern of accusations targeting the Proctor family network. Seven Proctor family members and connections were accused in total. Never indicted. Released. Survived.', 'public', '["accused","released","salem_village","proctor_family"]', 'salem_project', 1.0, NULL, 1775266565643, 1775266565643, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('accused_mary_easty', 'Mary Easty — Executed by hanging, September 22, 1692', 'Mary Easty (nee Towne) of Topsfield, approximately 58, the third Towne sister accused (after Rebecca Nurse and Sarah Cloyce). Accused April 21, 1692 by Mercy Lewis, Ann Putnam Jr., Mary Walcott, Abigail Williams; complaint filed by Thomas Putnam. Described as dignified and composed. Examined April 22 and imprisoned. In a remarkable turn, she was released on May 18 when the afflicted girls'' accusations temporarily ceased — but Mercy Lewis immediately suffered violent fits, and Easty was re-arrested May 20. Her petition to the court before her execution is one of the most powerful documents of the trials: ''I petition to your Honours not for my own life, for I know I must die, and my appointed time is set; but the Lord he knows it is that, if it be possible, no more innocent blood may be shed, which undoubtedly cannot be avoided in the way and course you go in.'' Hanged September 22, 1692.', '1692-04-21', NULL, 'legal', 'accused', NULL, 'npc_mary_easty', 'research/ACCUSED_LIST.md', 'Mary Easty — Executed by hanging, September 22, 1692. Mary Easty (nee Towne) of Topsfield, approximately 58, the third Towne sister accused (after Rebecca Nurse and Sarah Cloyce). Accused April 21, 1692 by Mercy Lewis, Ann Putnam Jr., Mary Walcott, Abigail Williams; complaint filed by Thomas Putnam. Described as dignified and composed. Examined April 22 and imprisoned. In a remarkable turn, she was released on May 18 when the afflicted girls'' accusations temporarily ceased — but Mercy Lewis immediately suffered violent fits, and Easty was re-arrested May 20. Her petition to the court before her execution is one of the most powerful documents of the trials: ''I petition to your Honours not for my own life, for I know I must die, and my appointed time is set; but the Lord he knows it is that, if it be possible, no more innocent blood may be shed, which undoubtedly cannot be avoided in the way and course you go in.'' Hanged September 22, 1692.', 'public', '["accused","executed","topsfield","hanged_sep_22","towne_sisters"]', 'salem_project', 1.0, NULL, 1775266565643, 1775266565643, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('accused_mary_english', 'Mary English — Escaped to New York, survived but health broken', 'Mary English (nee Hollingworth) of Salem Town, wife of Philip English, the wealthiest merchant in Salem Town. Accused April 21, 1692 by afflicted girls. Her accusation — along with her husband''s — represented the extension of the crisis into Salem Town''s commercial elite. Imprisoned. Escaped with her husband Philip English to New York with the help of sympathetic clergy, including Rev. Joshua Moody. Sheriff George Corwin seized their substantial property during their absence (approximately 1,500 pounds worth). Mary''s health never recovered from the imprisonment; she died within a few years of returning to Salem, approximately age 42. Her family attributed her death to the ordeal.', '1692-04-21', NULL, 'legal', 'accused', NULL, 'npc_philip_english', 'research/ACCUSED_LIST.md', 'Mary English — Escaped to New York, survived but health broken. Mary English (nee Hollingworth) of Salem Town, wife of Philip English, the wealthiest merchant in Salem Town. Accused April 21, 1692 by afflicted girls. Her accusation — along with her husband''s — represented the extension of the crisis into Salem Town''s commercial elite. Imprisoned. Escaped with her husband Philip English to New York with the help of sympathetic clergy, including Rev. Joshua Moody. Sheriff George Corwin seized their substantial property during their absence (approximately 1,500 pounds worth). Mary''s health never recovered from the imprisonment; she died within a few years of returning to Salem, approximately age 42. Her family attributed her death to the ordeal.', 'public', '["accused","escaped","salem_town","commercial_elite"]', 'salem_project', 1.0, NULL, 1775266565643, 1775266565643, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('accused_mary_ireson', 'Mary Ireson accused — Lynn resident', 'Mary Ireson, resident of Lynn. Accused circa June 4, 1692 by Elizabeth Booth, Abigail Williams, and others. Edward Putnam filed complaints against her for afflicting the girls of Salem Village. Released. Never tried. Survived.', '1692-06-04', NULL, 'legal', 'accused', NULL, NULL, 'ACCUSED_LIST.md', 'Mary Ireson accused — Lynn resident. Mary Ireson, resident of Lynn. Accused circa June 4, 1692 by Elizabeth Booth, Abigail Williams, and others. Edward Putnam filed complaints against her for afflicting the girls of Salem Village. Released. Never tried. Survived.', 'public', '["accused","released","lynn"]', 'salem_project', 1.0, NULL, 1775266565644, 1775266565644, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('accused_mary_lacey_jr', 'Mary Lacey Jr. accused — three generations accused simultaneously', 'Mary Lacey Jr. of Andover, granddaughter of Ann Foster, daughter of Mary Lacey Sr., approximately 18 years old. Accused July 19-20, 1692 by Joseph Ballard and afflicted girls. Three generations of one family accused simultaneously. She confessed and became an accuser herself, naming others. Released on bond October 1692. Found not guilty by the Superior Court, January 1693.', '1692-07-20', NULL, 'legal', 'accused', NULL, NULL, 'ACCUSED_LIST.md', 'Mary Lacey Jr. accused — three generations accused simultaneously. Mary Lacey Jr. of Andover, granddaughter of Ann Foster, daughter of Mary Lacey Sr., approximately 18 years old. Accused July 19-20, 1692 by Joseph Ballard and afflicted girls. Three generations of one family accused simultaneously. She confessed and became an accuser herself, naming others. Released on bond October 1692. Found not guilty by the Superior Court, January 1693.', 'public', '["accused","confessed","acquitted","andover","three_generations","became_accuser"]', 'salem_project', 1.0, NULL, 1775266565644, 1775266565644, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('accused_mary_lacey_sr', 'Mary Lacey Sr. accused — confessed to witch flight on a pole', 'Mary Lacey Sr. of Andover, daughter of Ann Foster, approximately 40 years old. Accused July 19-20, 1692 by Joseph Ballard and afflicted girls. Examined with her mother present. Confessed to riding on a pole with her mother and Martha Carrier to a witches'' meeting in Salem Village. Her confession corroborating her mother''s was devastating to the accused. Convicted by Court of Oyer and Terminer September 17, 1692. Released 1693 after the trials were discredited.', '1692-07-20', NULL, 'legal', 'accused', NULL, NULL, 'ACCUSED_LIST.md', 'Mary Lacey Sr. accused — confessed to witch flight on a pole. Mary Lacey Sr. of Andover, daughter of Ann Foster, approximately 40 years old. Accused July 19-20, 1692 by Joseph Ballard and afflicted girls. Examined with her mother present. Confessed to riding on a pole with her mother and Martha Carrier to a witches'' meeting in Salem Village. Her confession corroborating her mother''s was devastating to the accused. Convicted by Court of Oyer and Terminer September 17, 1692. Released 1693 after the trials were discredited.', 'public', '["accused","confessed","convicted","released","andover","three_generations"]', 'salem_project', 1.0, NULL, 1775266565644, 1775266565644, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('accused_mary_lovett_tyler', 'Mary Lovett Tyler accused — pressured by brother and minister', 'Mary Lovett Tyler, age 40, of Andover. Mother of Hannah, Martha, and Joannah Tyler (all accused). Accused circa early September 1692 via touch test by Ralph Farnum and Hannah Foster. Initially refused to confess, but her brother John Bridges and Rev. John Emerson pressured her. In Salem, she found herself ''flanked by John Bridges and Mr. John Emerson, both utterly convinced of her guilt and quick to contradict any denial.'' Confessed under duress. Found not guilty, January 1693. Released. Signed group recantation with Osgood, Frye, Dane, Barker, and Wilson.', '1692-09-08', NULL, 'legal', 'accused', NULL, NULL, 'ACCUSED_LIST.md', 'Mary Lovett Tyler accused — pressured by brother and minister. Mary Lovett Tyler, age 40, of Andover. Mother of Hannah, Martha, and Joannah Tyler (all accused). Accused circa early September 1692 via touch test by Ralph Farnum and Hannah Foster. Initially refused to confess, but her brother John Bridges and Rev. John Emerson pressured her. In Salem, she found herself ''flanked by John Bridges and Mr. John Emerson, both utterly convinced of her guilt and quick to contradict any denial.'' Confessed under duress. Found not guilty, January 1693. Released. Signed group recantation with Osgood, Frye, Dane, Barker, and Wilson.', 'public', '["accused","confessed","recanted","acquitted","andover","touch_test","pressured_by_family","tyler_family"]', 'salem_project', 1.0, NULL, 1775266565644, 1775266565644, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('accused_mary_marston', 'Mary Marston accused — Andover, Barker family connection', 'Mary Marston (nee Osgood), age 27, of Andover. Stepdaughter of Hannah Barker and niece-by-marriage to William Barker Sr. Accused August 29, 1692 by Moses Tyler, Samuel Martin, and afflicted girls. Her accusation followed the family-network pattern characteristic of the Andover crisis. Confessed. Released after trials ended.', '1692-08-29', NULL, 'legal', 'accused', NULL, NULL, 'ACCUSED_LIST.md', 'Mary Marston accused — Andover, Barker family connection. Mary Marston (nee Osgood), age 27, of Andover. Stepdaughter of Hannah Barker and niece-by-marriage to William Barker Sr. Accused August 29, 1692 by Moses Tyler, Samuel Martin, and afflicted girls. Her accusation followed the family-network pattern characteristic of the Andover crisis. Confessed. Released after trials ended.', 'public', '["accused","confessed","released","andover","barker_family"]', 'salem_project', 1.0, NULL, 1775266565644, 1775266565644, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('accused_mary_osgood', 'Mary Osgood accused — prominent wife, key recantation document', 'Mary Osgood (nee Clements), wife of Captain John Osgood, a prominent Andover citizen. Accused September 8, 1692 via touch test and afflicted girls. Confessed to an 11-year covenant with the Devil: described seeing a cat at the end of her house, praying to the Devil instead of God, being baptized by the Devil at Five Mile Pond, and riding through the air on a pole with Deacon Frye''s wife and Goody Tyler. On October 19, 1692, gave a recantation to Increase Mather declaring her confession ''wholly false'' and that she had been subjected to ''violent urging and unreasonable pressings.'' Her recantation is one of the key documents demonstrating the coercive nature of the proceedings. Acquitted January 12, 1693. Released.', '1692-09-08', NULL, 'legal', 'accused', NULL, NULL, 'ACCUSED_LIST.md', 'Mary Osgood accused — prominent wife, key recantation document. Mary Osgood (nee Clements), wife of Captain John Osgood, a prominent Andover citizen. Accused September 8, 1692 via touch test and afflicted girls. Confessed to an 11-year covenant with the Devil: described seeing a cat at the end of her house, praying to the Devil instead of God, being baptized by the Devil at Five Mile Pond, and riding through the air on a pole with Deacon Frye''s wife and Goody Tyler. On October 19, 1692, gave a recantation to Increase Mather declaring her confession ''wholly false'' and that she had been subjected to ''violent urging and unreasonable pressings.'' Her recantation is one of the key documents demonstrating the coercive nature of the proceedings. Acquitted January 12, 1693. Released.', 'public', '["accused","confessed","recanted","acquitted","andover","touch_test","key_recantation"]', 'salem_project', 1.0, NULL, 1775266565644, 1775266565644, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('accused_mary_parker', 'Mary Parker — Executed by hanging, September 22, 1692', 'Mary Parker (nee Ayer) of Andover, approximately 55, widow of Nathan Parker. Accused c. September 1-2, 1692 by Hannah Bixby, Sarah Phelps, Martha Sprague; also named by Mercy Wardwell and others. Maintained her innocence throughout, stating: ''I know nothing of witchcraft.'' Initially confused in some testimony with a different Mary Parker of Andover. Convicted September 17. One of the eight hanged on the final execution day, September 22, 1692. One of three Andover residents executed.', '1692-09-01', NULL, 'legal', 'accused', NULL, NULL, 'research/ACCUSED_LIST.md', 'Mary Parker — Executed by hanging, September 22, 1692. Mary Parker (nee Ayer) of Andover, approximately 55, widow of Nathan Parker. Accused c. September 1-2, 1692 by Hannah Bixby, Sarah Phelps, Martha Sprague; also named by Mercy Wardwell and others. Maintained her innocence throughout, stating: ''I know nothing of witchcraft.'' Initially confused in some testimony with a different Mary Parker of Andover. Convicted September 17. One of the eight hanged on the final execution day, September 22, 1692. One of three Andover residents executed.', 'public', '["accused","executed","andover","hanged_sep_22"]', 'salem_project', 1.0, NULL, 1775266565644, 1775266565644, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('accused_mary_post', 'Mary Post convicted — pardoned by Governor Phips', 'Mary Post (nee Bridges) of Rowley (originally Andover). Accused August 2, 1692 by Timothy Swan, Ann Putnam Jr., and Mary Walcott. Daughter of Mary Tyler Post Bridges Sr. Part of the extended Bridges-Post family network targeted in Andover. Convicted by Court of Oyer and Terminer, September 1692; condemned to death. One of three convicted by the Superior Court in January 1693 who were immediately reprieved and pardoned by Governor Phips. Released.', '1692-08-02', NULL, 'legal', 'accused', NULL, NULL, 'ACCUSED_LIST.md', 'Mary Post convicted — pardoned by Governor Phips. Mary Post (nee Bridges) of Rowley (originally Andover). Accused August 2, 1692 by Timothy Swan, Ann Putnam Jr., and Mary Walcott. Daughter of Mary Tyler Post Bridges Sr. Part of the extended Bridges-Post family network targeted in Andover. Convicted by Court of Oyer and Terminer, September 1692; condemned to death. One of three convicted by the Superior Court in January 1693 who were immediately reprieved and pardoned by Governor Phips. Released.', 'public', '["accused","convicted","pardoned","rowley","andover","bridges_post_family"]', 'salem_project', 1.0, NULL, 1775266565644, 1775266565644, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('accused_mary_rowe', 'Mary Rowe accused — Gloucester, daughter also accused', 'Mary Rowe of Gloucester. Accused circa September 1692 by afflicted girls. Mother of Abigail Rowe (also accused). Another mother-daughter accusation pair. Held at Ipswich jail. Released or acquitted by May 1693.', '1692-09-15', NULL, 'legal', 'accused', NULL, NULL, 'ACCUSED_LIST.md', 'Mary Rowe accused — Gloucester, daughter also accused. Mary Rowe of Gloucester. Accused circa September 1692 by afflicted girls. Mother of Abigail Rowe (also accused). Another mother-daughter accusation pair. Held at Ipswich jail. Released or acquitted by May 1693.', 'public', '["accused","released","gloucester","mother_daughter"]', 'salem_project', 1.0, NULL, 1775266565644, 1775266565644, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('accused_mary_taylor', 'Mary Taylor — acquitted at Charlestown trial', 'Mary Taylor, tried at Charlestown in January-February 1693 by the Superior Court. Found not guilty and released. One of five tried at the Charlestown session.', '1692-09-01', NULL, 'legal', 'accused', NULL, NULL, 'accused_list_part1-3.md', 'Mary Taylor — acquitted at Charlestown trial. Mary Taylor, tried at Charlestown in January-February 1693 by the Superior Court. Found not guilty and released. One of five tried at the Charlestown session.', 'public', '["accused","acquitted","charlestown_trial"]', 'salem_project', 1.0, NULL, 1775266565644, 1775266565644, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('accused_mary_toothaker', 'Mary Toothaker accused — wife of Roger, sister of Martha Carrier', 'Mary Toothaker of Billerica, wife of Roger Toothaker (accused May 18, died in prison June 16) and sister of Martha Carrier (accused May 28, hanged August 19). Accused May 28, 1692 by Mary Walcott and Abigail Williams. Examined July 30 by Judges Gedney, Hathorne, Corwin, and Higginson. During examination, she confessed to being a witch and accused others, including her sister Martha Carrier and Carrier''s son Richard. Found not guilty by the Superior Court, February 1693. Released. Survived.', '1692-05-28', NULL, 'legal', 'accused', NULL, NULL, 'ACCUSED_LIST.md', 'Mary Toothaker accused — wife of Roger, sister of Martha Carrier. Mary Toothaker of Billerica, wife of Roger Toothaker (accused May 18, died in prison June 16) and sister of Martha Carrier (accused May 28, hanged August 19). Accused May 28, 1692 by Mary Walcott and Abigail Williams. Examined July 30 by Judges Gedney, Hathorne, Corwin, and Higginson. During examination, she confessed to being a witch and accused others, including her sister Martha Carrier and Carrier''s son Richard. Found not guilty by the Superior Court, February 1693. Released. Survived.', 'public', '["accused","confessed","acquitted","billerica","toothaker_family","carrier_sister"]', 'salem_project', 1.0, NULL, 1775266565644, 1775266565644, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('accused_mary_warren', 'Mary Warren accused after attempting to recant', 'Mary Warren, 20-year-old servant in the Proctor household and one of the afflicted girls, accused April 18, 1692 after she wavered in her accusations, reportedly saying the afflicted ''did but dissemble'' (pretend). The other afflicted girls immediately accused her of witchcraft. Under pressure at her April 19 examination, she had fits, recanted her doubts, confessed to signing the Devil''s book, and rejoined the accusers. Subsequently testified against the Proctors, her own employers. Her case demonstrates the self-policing mechanism of the accuser group: dissent was punished with accusation.', '1692-04-18', NULL, 'legal', 'accused', NULL, 'mary_warren', 'ACCUSED_LIST.md', 'Mary Warren accused after attempting to recant. Mary Warren, 20-year-old servant in the Proctor household and one of the afflicted girls, accused April 18, 1692 after she wavered in her accusations, reportedly saying the afflicted ''did but dissemble'' (pretend). The other afflicted girls immediately accused her of witchcraft. Under pressure at her April 19 examination, she had fits, recanted her doubts, confessed to signing the Devil''s book, and rejoined the accusers. Subsequently testified against the Proctors, her own employers. Her case demonstrates the self-policing mechanism of the accuser group: dissent was punished with accusation.', 'public', '["accused","confessed","afflicted_girl","self_policing","proctor_household","salem_village"]', 'salem_project', 1.0, NULL, 1775266565644, 1775266565644, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('accused_mary_witheridge', 'Mary Witheridge accused alongside mother Sarah Buckley', 'Mary Witheridge (also Witheredge/Whittredge), widowed daughter of Sarah Buckley (also accused), of Salem Village. Accused May 14, 1692 by afflicted girls. Complaint filed by Lt. Nathaniel Ingersoll. Imprisoned 8 months. Acquitted but forced to pay jail fees before release, leaving the family destitute. Another case of mother-daughter pairs caught up in the accusations.', '1692-05-14', NULL, 'legal', 'accused', NULL, NULL, 'ACCUSED_LIST.md', 'Mary Witheridge accused alongside mother Sarah Buckley. Mary Witheridge (also Witheredge/Whittredge), widowed daughter of Sarah Buckley (also accused), of Salem Village. Accused May 14, 1692 by afflicted girls. Complaint filed by Lt. Nathaniel Ingersoll. Imprisoned 8 months. Acquitted but forced to pay jail fees before release, leaving the family destitute. Another case of mother-daughter pairs caught up in the accusations.', 'public', '["accused","acquitted","salem_village","jail_fees","mother_daughter"]', 'salem_project', 1.0, NULL, 1775266565644, 1775266565644, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('accused_mercy_wardwell', 'Mercy Wardwell accused — age 19, accused others to save father', 'Mercy Wardwell, age 19, daughter of Samuel Wardwell, of Andover. Accused circa September 1, 1692 by William Barker Sr. in his confession. Confessed and accused others — including Mary Parker and Mary Lacey — possibly hoping to save her father. Her father was executed regardless on September 22. Found not guilty, January 1693. Released. After the trials, she lived with the knowledge that her coerced accusations contributed to the death of Mary Parker.', '1692-09-01', NULL, 'legal', 'accused', NULL, NULL, 'ACCUSED_LIST.md', 'Mercy Wardwell accused — age 19, accused others to save father. Mercy Wardwell, age 19, daughter of Samuel Wardwell, of Andover. Accused circa September 1, 1692 by William Barker Sr. in his confession. Confessed and accused others — including Mary Parker and Mary Lacey — possibly hoping to save her father. Her father was executed regardless on September 22. Found not guilty, January 1693. Released. After the trials, she lived with the knowledge that her coerced accusations contributed to the death of Mary Parker.', 'public', '["accused","confessed","acquitted","andover","accused_others","father_executed"]', 'salem_project', 1.0, NULL, 1775266565644, 1775266565644, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('accused_nehemiah_abbott_jr', 'Nehemiah Abbott Jr. released — only person cleared at examination', 'Nehemiah Abbott Jr. of Topsfield, accused April 21, 1692 by Ann Putnam Jr., Mary Walcott, and others. The singular exception in the examination process. When brought before the afflicted girls on April 22, some could not agree he was the specter they had seen. Ann Putnam Jr. said he was ''not the man.'' His appearance did not match: he was described as a ''hilly-faced man'' (pockmarked or ruddy), and the girls'' descriptions differed. After a careful look, the afflicted agreed he was not the right person. He was released — the only documented instance of an accused person being cleared at the examination stage.', '1692-04-21', NULL, 'legal', 'accused', NULL, 'nehemiah_abbott', 'ACCUSED_LIST.md', 'Nehemiah Abbott Jr. released — only person cleared at examination. Nehemiah Abbott Jr. of Topsfield, accused April 21, 1692 by Ann Putnam Jr., Mary Walcott, and others. The singular exception in the examination process. When brought before the afflicted girls on April 22, some could not agree he was the specter they had seen. Ann Putnam Jr. said he was ''not the man.'' His appearance did not match: he was described as a ''hilly-faced man'' (pockmarked or ruddy), and the girls'' descriptions differed. After a careful look, the afflicted agreed he was not the right person. He was released — the only documented instance of an accused person being cleared at the examination stage.', 'public', '["accused","released_at_examination","topsfield","only_exception"]', 'salem_project', 1.0, NULL, 1775266565644, 1775266565644, 0);
INSERT OR REPLACE INTO historical_facts (id, title, description, date, date_precision, category, subcategory, poi_id, figure_id, source_citation, narration_script, confidentiality, tags, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('accused_nicholas_frost', 'Nicholas Frost accused — mariner from Manchester', 'Nicholas Frost, described as a mariner, of Manchester (some records say Marblehead). Accused September 5, 1692 by Thomas Dodd, who believed Frost was afflicting Dodd''s daughter Johanna. The accusation of a seafaring man from a port town shows the geographic and social breadth of the crisis by September. Released. Not tried.', '1692-09-05', NULL, 'legal', 'accused', NULL, NULL, 'ACCUSED_LIST.md', 'Nicholas Frost accused — mariner from Manchester. Nicholas Frost, described as a mariner, of Manchester (some records say Marblehead). Accused September 5, 1692 by Thomas Dodd, who believed Frost was afflicting Dodd''s daughter Johanna. The accusation of a seafaring man from a port town shows the geographic and social breadth of the crisis by September. Released. Not tried.', 'public', '["accused","released","manchester","mariner"]', 'salem_project', 1.0, NULL, 1775266565644, 1775266565644, 0);

