INSERT OR REPLACE INTO primary_sources (id, title, source_type, author, date, full_text, excerpt, figure_id, poi_id, narration_script, citation, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('psc_swp_34_10', 'SWP 34:  Deposition of Isaac Wellman v. Sarah Cole ', 'deposition', 'SWP 34 —  Deposition of Isaac Wellman v. Sarah Cole  (SWP No. 34.10)', NULL, '( Deposition of Isaac Wellman v. Sarah Cole )

[January 11, 1693 ]

The Deposition of Isaac Welman Aged forty five years, this Deponant Testifieth & saith, that I have often heard the Wife of Jno Cole of Linn, wish harm to her Husband, & one time being both at my house having some words, s''d Sarah Cole wished her Husband might Dye if ever he came within Daniell Eattons Doore any more

Isaac Welman owned the abovs''d before the Grand jury

Jan''y. 11''th 1692/3 upon the oath hee had taken

*Robert Payne Foreman:

(Reverse) Isa: Wellman

( Suffolk Court Files, vol. 32 docket 2712 p. 49, Massachusetts Supreme Judicial Court, Judicial Archives, Massachusetts State Archives. Boston, MA. )', ' Deposition of Isaac Wellman v. Sarah Cole ', 'isaac_redington', NULL, 'From a deposition. By SWP 34 —  Deposition of Isaac Wellman v. Sarah Cole  (SWP No. 34.10). Deposition of Isaac Wellman v. Sarah Cole', 'SWP No. 34.10', 'salem_project', 1.0, NULL, 1775266565649, 1775266565649, 0);
INSERT OR REPLACE INTO primary_sources (id, title, source_type, author, date, full_text, excerpt, figure_id, poi_id, narration_script, citation, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('psc_swp_64_2', 'SWP 64:  Records of the Salem and Ipswich Court of General Sessions of the Peace (1692–1693), p. 8. Massachusetts Supreme Judicial Court, Judicial Archives, Massachusetts State Archives, Boston, MA. ', 'deposition', 'SWP 64 —  Records of the Salem and Ipswich Court of General Sessions of the Peace (1692–1693), p. 8. Massachusetts Supreme Judicial Court, Judicial Archives, Massachusetts State Archives, Boston, MA. , September 22, 1692 (SWP No. 64.2)', '1692-09-22', 'Judgment v. John Shepherd for Assisting Mary Green to Escape

[September 22, 1692]

John Shepard of Rowley bound over by Thomas Wade Esq for Assisting and helping to Convey Mary Green a Prisoner for the Crime of Witchcraft out of their Majtes Goal in Ipswitch: Confest the fact.

The Courts Judgemt is That he pay a fine of 30li money and Costs of Court. Vpon his Confession and Petition the Court Respits 25li Till further Orders, that he stand Committed till the five pounds and Costs be paid/

( Records of the Salem and Ipswich Court of General Sessions of the Peace (1692–1693), p. 8. Massachusetts Supreme Judicial Court, Judicial Archives, Massachusetts State Archives, Boston, MA. )', ' Records of the Salem and Ipswich Court of General Sessions of the Peace (1692–1693), p. 8. Massachusetts Supreme Judicial Court, Judicial Archives, Massachusetts State Archives, Boston, MA. ', 'salem_village_petition_signers_and_witnesses', NULL, 'From a deposition. By SWP 64 —  Records of the Salem and Ipswich Court of General Sessions of the Peace (1692–1693), p. 8. Massachusetts Supreme Judicial Court, Judicial Archives, Massachusetts State Archives, Boston, MA. , September 22, 1692 (SWP No. 64.2). Dated 1692-09-22. Records of the Salem and Ipswich Court of General Sessions of the Peace (1692–1693), p. 8. Massachusetts Supreme Judicial Court, Judicial Archives, Massachusetts State Archives, Boston, MA.', 'SWP No. 64.2', 'salem_project', 1.0, NULL, 1775266565649, 1775266565649, 0);
INSERT OR REPLACE INTO primary_sources (id, title, source_type, author, date, full_text, excerpt, figure_id, poi_id, narration_script, citation, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('psc_swp_69_11', 'Abigail Hobbs: Deposition of Ann Putnam, Jr. v. Abigail Hobbs ', 'deposition', 'Abigail Hobbs — Deposition of Ann Putnam, Jr. v. Abigail Hobbs  (SWP No. 69.11)', NULL, '(Deposition of Ann Putnam, Jr. v. Abigail Hobbs )

[+ April 19, 1692]

The Deposistion of Ann putnam who testifieth and saith that about the 13th of April 1692 I saw the Apperishtion of Abigail Hoobs the daughter of william Hoobs com and afflect me by biting pinching and almost choaking me urging me to writ in hir book and so she continewed by times hurting me twll the 19th of April being the day of hir Examination but as soon as she began to confess she left ofe hurting me

(Reverse) Ann puttnam. Ag''st Abigall. Hobbs

( Essex County Court Archives, Salem -- Witchcraft Vol. 1 no. 162, Massachusetts Supreme Judicial Court, Judicial Archives, Massachusetts State Archives, Boston, MA. )', 'Deposition of Ann Putnam, Jr. v. Abigail Hobbs ', 'abigail_hobbs', NULL, 'From a deposition. By Abigail Hobbs — Deposition of Ann Putnam, Jr. v. Abigail Hobbs  (SWP No. 69.11). Deposition of Ann Putnam, Jr. v. Abigail Hobbs', 'SWP No. 69.11', 'salem_project', 1.0, NULL, 1775266565649, 1775266565649, 0);
INSERT OR REPLACE INTO primary_sources (id, title, source_type, author, date, full_text, excerpt, figure_id, poi_id, narration_script, citation, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('psc_swp_125_8', 'Tituba: Deposition of Ann Putnam, Jr. v. Tituba ', 'deposition', 'Tituba — Deposition of Ann Putnam, Jr. v. Tituba  (SWP No. 125.8)', NULL, '(Deposition of Ann Putnam, Jr. v. Tituba )

[+ March 1, 1692]

The deposition of Ann putnam who testifieth and saith that on the 25''th of february 1691/92 I saw the Apperishtion of Tituba M''r parishes Indian woman which did tortor me most greviously by pricking and pinching me most dreadfully tell the first day of march being the day of hir Examination and then also most greviously allso at the beginning of hir examination: but senc she confesed she has hurt me #(be) but little

(Reverse) Ann putnam ag''st Tittuba Indian

( Essex County Court Archives, Salem -- Witchcraft Vol. 1, no. 35, Massachusetts Supreme Judicial Court, Judicial Archives, Massachusetts State Archives, Boston, MA. )', 'Deposition of Ann Putnam, Jr. v. Tituba ', 'ann_putnam_sr', NULL, 'From a deposition. By Tituba — Deposition of Ann Putnam, Jr. v. Tituba  (SWP No. 125.8). Deposition of Ann Putnam, Jr. v. Tituba', 'SWP No. 125.8', 'salem_project', 1.0, NULL, 1775266565649, 1775266565649, 0);
INSERT OR REPLACE INTO primary_sources (id, title, source_type, author, date, full_text, excerpt, figure_id, poi_id, narration_script, citation, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('psc_swp_173_71', 'Reversal of Attainder: Order of John Nurse et al.for Payment, Case of Rebeccca Nurse ', 'deposition', 'Reversal of Attainder — Order of John Nurse et al.for Payment, Case of Rebeccca Nurse , February 19, 1712 (SWP No. 173.71)', '1712-02-19', '(Order of John Nurse et al.for Payment, Case of Rebeccca Nurse )

[February 19, 1712]

Wheareas wee are Informed the Generall Court hath apointed a Committe to ditribute to the parties Concearnd what the s''d Court hath alowed to make Reparatian to the Sufferers in the year 1692

Therefore wee doe desire and herby Impowr our Brother Samuel Nurs to receive what is alowed to us and to give receipt for the same

*John nurs

*John tarbell

*Rebeka preston

*willem rusel

*martha bouden

*francis nurs

(Reverse) Nurses''s order

( Essex County Court Archives, Salem -- Witchcraft Vol 2, no.148. Massachusetts Supreme Judicial Court, Judicial Archives. Massachusetts State Archives, Boston, MA )', 'Order of John Nurse et al.for Payment, Case of Rebeccca Nurse ', 'john_tarbell_2', NULL, 'From a deposition. By Reversal of Attainder — Order of John Nurse et al.for Payment, Case of Rebeccca Nurse , February 19, 1712 (SWP No. 173.71). Dated 1712-02-19. Order of John Nurse et al.for Payment, Case of Rebeccca Nurse', 'SWP No. 173.71', 'salem_project', 1.0, NULL, 1775266565649, 1775266565649, 0);
INSERT OR REPLACE INTO primary_sources (id, title, source_type, author, date, full_text, excerpt, figure_id, poi_id, narration_script, citation, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('psc_swp_173_70', 'Reversal of Attainder: Order of Benjamin Nurse et al. for Payment, Case of Rebeccca Nurse ', 'deposition', 'Reversal of Attainder — Order of Benjamin Nurse et al. for Payment, Case of Rebeccca Nurse , May 8, 1712 (SWP No. 173.70)', '1712-05-08', '(Order of Benjamin Nurse et al. for Payment, Case of Rebeccca Nurse )

[May 8, 1712]

To the Comittey appointed by the Generall Court to distribute what was allow''d by the s''d Court towards restitution to the relations of those whoe suffered in the Sorrowfull times called the Witchcraft times. /

pleas to pay & deliver what share & proportion belongs to me on that score unto my Brother Mr Samuel Nurse of Salem & his receipt shall be a full & sufficient discharge from

your friend &c. *Benjamin Nurse

May 8th. anno Dom 1712

( Essex County Court Archives, Salem -- Witchcraft Vol. 2, no. 146. Massachusetts Supreme Judicial Court, Judicial Archives. Massachusetts State Archives, Boston, MA )', 'Order of Benjamin Nurse et al. for Payment, Case of Rebeccca Nurse ', 'other_documented_accused', NULL, 'From a deposition. By Reversal of Attainder — Order of Benjamin Nurse et al. for Payment, Case of Rebeccca Nurse , May 8, 1712 (SWP No. 173.70). Dated 1712-05-08. Order of Benjamin Nurse et al. for Payment, Case of Rebeccca Nurse', 'SWP No. 173.70', 'salem_project', 1.0, NULL, 1775266565649, 1775266565649, 0);
INSERT OR REPLACE INTO primary_sources (id, title, source_type, author, date, full_text, excerpt, figure_id, poi_id, narration_script, citation, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('psc_swp_45_9', 'Mary Esty:  Statement of John and Mary Arnold for Mary Esty and Sarah Cloyce ', 'deposition', 'Mary Esty —  Statement of John and Mary Arnold for Mary Esty and Sarah Cloyce  (SWP No. 45.9)', NULL, '( Statement of John and Mary Arnold for Mary Esty and Sarah Cloyce )

[++ September 9, 1692 ]

These may Cartify home it may Consarne that wee hous names are underritten being dasired by sum of the Realeations of Mary estwek and sarah Cloise to give our obsarvation how they behaved tham sales while thay Remained in Bostorn prison we dow affirme [th] at wee [torn] saw noe ill Carreg or Behavor in tham But that thare daportment wase verey sobere and Civell as wittnes our hands

John Arnold

Marey Arnold

this is truee copie

( Essex County Court Archives, Salem -- Witchcraft Vol. 1, no. 296. Massachusetts Supreme Judicial Court, Judicial Archives, Massachusetts State Archives, Boston, MA. )', ' Statement of John and Mary Arnold for Mary Esty and Sarah Cloyce ', 'sarah_cloyes', NULL, 'From a deposition. By Mary Esty —  Statement of John and Mary Arnold for Mary Esty and Sarah Cloyce  (SWP No. 45.9). Statement of John and Mary Arnold for Mary Esty and Sarah Cloyce', 'SWP No. 45.9', 'salem_project', 1.0, NULL, 1775266565649, 1775266565649, 0);
