INSERT OR REPLACE INTO tour_pois (id, name, lat, lng, address, category, subcategories, short_narration, long_narration, description, historical_period, admission_info, hours, phone, website, image_asset, geofence_radius_m, requires_transportation, wheelchair_accessible, seasonal, priority, data_source, confidence, verified_date, created_at, updated_at, stale_after) VALUES ('salem_ferry_terminal', 'Salem Ferry Terminal', 42.5185, -70.8789, '10 Blaney St, Salem, MA 01970', 'visitor_services', '["ferry","transit","seasonal"]', 'The Salem Ferry provides seasonal high-speed catamaran service to Boston''s Long Wharf. The scenic fifty-minute ride across the harbor is an attraction in itself.', NULL, 'Seasonal high-speed ferry to Boston''s Long Wharf (~50 min). Operates late June through October. Scenic harbor crossing.', NULL, NULL, 'Seasonal — June through October', NULL, 'https://www.salemferry.com', NULL, 40, 0, 1, 1, 2, 'manual_curated', 1.0, '2026-04-03', 1775266565655, 1775266565655, 0);
